ated","main_translations_es":["Anulado","Descontinuado","Suspendido"],"collocations":["cancelled flight","cancelled order","cancelled event","cancelled subscription"],"synonyms_en":["called off","aborted","voided"],"example_sentence":"The flight was cancelled.","example_es":"El vuelo fue cancelado.","example_en":"The flight was cancelled.","mnemonic_en":"Imagine a red stamp reading CANCELADO over the word cancelled","cloze_distractors_en":["Transparent","Submerged","Illiterate"],"examples":[{"es":"El vuelo fue cancelado.","en":"The flight was cancelled."},{"es":"Debido a la tormenta, el tren ha sido cancelado.","en":"Due to the storm, the train has been cancelled."},{"es":"Mi reserva de hotel aparece como cancelado en el sistema.","en":"My hotel reservation appears as cancelled in the system."}]},{"spanish_text":"Llegada","english_text":"Arrival","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"the act or process of arriving at a destination","main_translations_es":["Entrada","Aparición","Incorporación"],"collocations":["arrival time","arrival date","arrival flight","arrival ceremony"],"synonyms_en":["coming","entrance","advent"],"example_sentence":"The arrival of the train was delayed by an hour.","example_es":"La llegada del tren se retrasó una hora.","example_en":"The arrival of the train was delayed by an hour.","mnemonic_en":"The train pulls in, and the big board flashes LLEGADA, signaling the arrival.","cloze_distractors_en":["Location","Direction","Operation"],"examples":[{"es":"La llegada del tren se retrasó una hora.","en":"The arrival of the train was delayed by an hour."},{"es":"Por favor, consulte la pantalla para ver la hora exacta de llegada de su vuelo.","en":"Please check the screen to see the exact arrival time of your flight."},{"es":"Por favor, diríjase a la puerta de llegada para recoger a sus familiares.","en":"Please head to the arrival gate to pick up your relatives."}]},{"spanish_text":"Salida","english_text":"Departur