cross join jsonb_to_recordset('[{"spanish_text":"Hipótesis","english_text":"Hypothesis","section_name":"Academic English","part_of_speech":"noun","definition_en":"A proposed explanation for a phenomenon that can be tested through observation or experiment.","main_translations_es":["Suposición","Conjetura","Teoría"],"collocations":["test the hypothesis","form a hypothesis","null hypothesis","working hypothesis"],"synonyms_en":["theory","supposition","conjecture"],"example_sentence":"My hypothesis is that the rise in temperature affects bird migration.","example_es":"Mi hipótesis es que el aumento de la temperatura afecta la migración de las aves.","example_en":"My hypothesis is that the rise in temperature affects bird migration.","mnemonic_en":"Picture a hippo presenting a thesis on a lab table, the hippo''s hypothesis.","cloze_distractors_en":["Hyperbole","Hypotenuse","Hypochondria","Hypostasis"],"examples":[{"es":"Mi hipótesis es que el aumento de la temperatura afecta la migración de las aves.","en":"My hypothesis is that the rise in temperature affects bird migration."},{"es":"Los investigadores formularon una hipótesis para explicar los resultados inesperados del experimento.","en":"The researchers formulated a hypothesis to explain the unexpected results of the experiment."},{"es":"El equipo científico debe realizar más pruebas para confirmar su hipótesis inicial sobre la estructura celular.","en":"The scientific team must conduct further tests to confirm their initial hypothesis regarding the cellular structure."}]},{"spanish_text":"Variable","english_text":"Variable","section_name":"Academic English","part_of_speech":"noun","definition_en":"A symbol or quantity that can change or take on different values.","main_translations_es":["Variable","Cambiante","Inestable"],"collocations":["variable cost","variable rate","variable speed","variable temperature"],"synonyms_en":[],"example_sentence":"The temperature is variable in this region.","example_es":"La temperatura es variable en esta región.","example_en":"The temperature is variable in this region.","mnemonic_en":null,"cloze_distractors_en":[],"examples":[{"es":"La temperatura es variable en esta región.","en":"The temperature is variable in this region."}]},{"spanish_text":"Metodología","english_text":"Methodology","section_name":"Academic English","part_of_speech":"noun","definition_en":"A systematic set of methods and principles used in a particular field of study or practice.","main_translations_es":["Método","Procedimiento","Enfoque"],"collocations":["research methodology","methodology section","methodology of the study"],"synonyms_en":["approach","technique","procedure"],"example_sentence":"The methodology the researcher used ensured reliable results.","example_es":"La metodología que utilizó el investigador garantizó resultados fiables.","example_en":"The methodology the researcher used ensured reliable results.","mnemonic_en":"Methodology sounds like Met a dog O'' Lia, a methodical dog named Lia.","cloze_distractors_en":["Philosophy","Ideology","Chronology"],"examples":[{"es":"La metodología que utilizó el investigador garantizó resultados fiables.","en":"The methodology the researcher used ensured reliable results."},{"es":"El comité académico cuestionó la metodología empleada en el estudio sobre el cambio climático.","en":"The academic committee questioned the methodology employed in the climate change study."},{"es":"Debemos detallar nuestra metodología en el primer capítulo de la tesis doctoral.","en":"We must detail our methodology in the first chapter of the doctoral thesis."}]},{"spanish_text":"Revisión bibliográfica","english_text":"Literature review","section_name":"Academic English","part_of_speech":"noun","definition_en":"A comprehensive summary and analysis of existing research and publications on a particular topic.","main_translations_es":["Revisión de la literatura","Estado del arte","Análisis bibliográfico"],"collocations":["conduct a literature review","comprehensive literature review","literature review section","literature review methodology"],"synonyms_en":["bibliographic survey","scholarly overview","research synthesis"],"example_sentence":"For my thesis, I conducted an exhaustive literature review of recent studies.","example_es":"Para mi tesis, realicé una revisión bibliográfica exhaustiva de los estudios recientes.","example_en":"For my thesis, I conducted an exhaustive literature review of recent studies.","mnemonic_en":"Picture a librarian revising a mountain of books, doing a literature review.","cloze_distractors_en":["Narrative critique","Hypothetical prologue","Statistical monologue","Methodological prologue"],"examples":[{"es":"Para mi tesis, realicé una revisión bibliográfica exhaustiva de los estudios recientes.","en":"For my thesis, I conducted an exhaustive literature review of recent studies."},{"es":"El primer capítulo de su disertación doctoral consiste en una revisión bibliográfica sobre el impacto del cambio climático.","en":"The first chapter of her doctoral dissertation consists of a literature review on the impact of climate change."},{"es":"Antes de comenzar el experimento, el equipo publicó una revisión bibliográfica para identificar los vacíos en la investigación actual.","en":"Before starting the experiment, the team published a literature review to identify gaps in current research."}]},{"spanish_text":"Revisión por pares","english_text":"Peer review","section_name":"Academic English","part_of_speech":"noun","definition_en":"A process in which experts evaluate each other''s work, such as academic articles, to ensure quality and validity.","main_translations_es":["Evaluación por pares","Revisión entre colegas","Revisión de pares"],"collocations":["peer review process","peer review article","peer review system","peer review committee"],"synonyms_en":["expert assessment","scholarly review","evaluation by peers"],"example_sentence":"Peer review is essential to ensure the quality of scientific articles.","example_es":"La revisión por pares es esencial para garantizar la calidad de los artículos científicos.","example_en":"Peer review is essential to ensure the quality of scientific articles.","mnemonic_en":"Picture a pair of peers hunched over a manuscript, doing a review.","cloze_distractors_en":["Public opinion","Market research","Patent litigation","Corporate auditing"],"examples":[{"es":"La revisión por pares es esencial para garantizar la calidad de los artículos científicos.","en":"Peer review is essential to ensure the quality of scientific articles."},{"es":"El manuscrito fue aceptado para su publicación después de superar con éxito el proceso de revisión por pares.","en":"The manuscript was accepted for publication after successfully passing the peer review process."},{"es":"Los investigadores suelen recibir críticas constructivas de otros expertos durante la revisión por pares.","en":"Researchers often receive constructive criticism from other experts during peer review."}]},{"spanish_text":"Empírico","english_text":"Empirical","section_name":"Academic English","part_of_speech":"adjective","definition_en":"Based on observation or experience rather than theory or pure logic.","main_translations_es":["basado en la experiencia","práctico","experimental"],"collocations":["empirical evidence","empirical data","empirical research","empirical study"],"synonyms_en":["experimental","based on observation","observational"],"example_sentence":"The empirical method relies on direct observation of phenomena.","example_es":"El método empírico se basa en la observación directa de los fenómenos.","example_en":"The empirical method relies on direct observation of phenomena.","mnemonic_en":"Picture an empire of test tubes, the empírico lab where evidence rules","cloze_distractors_en":["Speculative","Subjective","Hypothetical"],"examples":[{"es":"El método empírico se basa en la observación directa de los fenómenos.","en":"The empirical method relies on direct observation of phenomena."},{"es":"Los investigadores presentaron pruebas empíricas que respaldan su teoría sobre el cambio climático.","en":"The researchers presented empirical evidence to support their theory on climate change."},{"es":"Es necesario realizar un estudio empírico para validar los resultados obtenidos en el laboratorio.","en":"It is necessary to conduct an empirical study to validate the results obtained in the laboratory."}]},{"spanish_text":"Cualitativo","english_text":"Qualitative","section_name":"Academic English","part_of_speech":"adjective","definition_en":"relating to the qualities or characteristics of something rather than its quantity","main_translations_es":["cualitativo","de carácter cualitativo","de naturaleza cualitativa"],"collocations":["qualitative analysis","qualitative research","qualitative data","qualitative methods"],"synonyms_en":["descriptive","non-numerical","subjective"],"example_sentence":"The study used a qualitative approach to understand patients'' experiences.","example_es":"El estudio utilizó un enfoque cualitativo para comprender las experiencias de los pacientes.","example_en":"The study used a qualitative approach to understand patients'' experiences.","mnemonic_en":"Picture a cup labeled cual measuring traits, that cup shows the qualitative data","cloze_distractors_en":["Geometrical","Hypothetical","Chronological"],"examples":[{"es":"El estudio utilizó un enfoque cualitativo para comprender las experiencias de los pacientes.","en":"The study used a qualitative approach to understand patients'' experiences."},{"es":"Los investigadores realizaron un análisis cualitativo de las entrevistas para identificar los temas recurrentes.","en":"The researchers performed a qualitative analysis of the interviews to identify recurring themes."},{"es":"La tesis doctoral incorpora datos de carácter cualitativo para profundizar en el impacto social del proyecto.","en":"The doctoral thesis incorporates qualitative data to delve into the social impact of the project."}]},{"spanish_text":"Cuantitativo","english_text":"Quantitative","section_name":"Academic English","part_of_speech":"adjective","definition_en":"Relating to, measuring, or expressed in terms of quantity.","main_translations_es":["de tipo cuantitativo","numérico","medible"],"collocations":["quantitative analysis","quantitative research","quantitative data","quantitative methods"],"synonyms_en":["numerical","measurable","statistical"],"example_sentence":"The quantitative analysis showed a 15% increase in sales.","example_es":"El análisis cuantitativo mostró un aumento del 15% en las ventas.","example_en":"The quantitative analysis showed a 15% increase in sales.","mnemonic_en":"Picture a scientist counting cuántos beans, showing Quantitative data about how many.","cloze_distractors_en":["Speculative","Subjective","Hypothetical"],"examples":[{"es":"El análisis cuantitativo mostró un aumento del 15% en las ventas.","en":"The quantitative analysis showed a 15% increase in sales."},{"es":"Los investigadores prefieren un enfoque cuantitativo para medir la eficacia del nuevo fármaco.","en":"The researchers prefer a quantitative approach to measure the efficacy of the new drug."},{"es":"El estudio proporciona datos cuantitativos sobre el impacto del cambio climático en la agricultura local.","en":"The study provides quantitative data on the impact of climate change on local agriculture."}]},{"spanish_text":"Tamaño de la muestra","english_text":"Sample size","section_name":"Academic English","part_of_speech":"noun","definition_en":"The number of observations or items included in a statistical sample.","main_translations_es":["Tamaño muestral","Número de muestra","Tamaño de la muestra"],"collocations":["determine the sample size","increase the sample size","sample size calculation","optimal sample size"],"synonyms_en":["sample count","study size","group size"],"example_sentence":"The sample size must be large enough to obtain reliable results.","example_es":"El tamaño de la muestra debe ser suficientemente grande para obtener resultados fiables.","example_en":"The sample size must be large enough to obtain reliable results.","mnemonic_en":"Imagine a sample of soup the size of a giant ''tamaño'' banner.","cloze_distractors_en":["Research budget","Theory margin","Academic motive","Method outcome"],"examples":[{"es":"El tamaño de la muestra debe ser suficientemente grande para obtener resultados fiables.","en":"The sample size must be large enough to obtain reliable results."},{"es":"Debido a que el tamaño de la muestra era demasiado pequeño, el estudio no pudo demostrar una correlación estadística significativa.","en":"Because the sample size was too small, the study failed to demonstrate a statistically significant correlation."},{"es":"Los investigadores decidieron aumentar el tamaño de la muestra para reducir el margen de error en la encuesta nacional.","en":"The researchers decided to increase the sample size to reduce the margin of error in the national survey."}]},{"spanish_text":"Hallazgos","english_text":"Findings","section_name":"Academic English","part_of_speech":"noun","definition_en":"Results or conclusions drawn from an investigation or study.","main_translations_es":["Descubrimientos","Resultados","Conclusiones"],"collocations":["research findings","key findings","preliminary findings","significant findings"],"synonyms_en":["results","conclusions","discoveries"],"example_sentence":"The findings of the study suggest that diet affects cardiovascular health.","example_es":"Los hallazgos del estudio sugieren que la dieta afecta la salud cardiovascular.","example_en":"The findings of the study suggest that diet affects cardiovascular health.","mnemonic_en":"In a hall scientists discover findings like hidden treasures.","cloze_distractors_en":["Stagnations","Precedents","Incentives","Refinements"],"examples":[{"es":"Los hallazgos del estudio sugieren que la dieta afecta la salud cardiovascular.","en":"The findings of the study suggest that diet affects cardiovascular health."},{"es":"El comité revisó los hallazgos de la investigación antes de publicar el informe final.","en":"The committee reviewed the research findings before publishing the final report."},{"es":"Debemos discutir los hallazgos inesperados que surgieron durante el experimento de laboratorio.","en":"We must discuss the unexpected findings that emerged during the laboratory experiment."}]},{"spanish_text":"Implicaciones","english_text":"Implications","section_name":"Academic English","part_of_speech":"noun","definition_en":"The possible results or effects that may follow from an action, decision, or event.","main_translations_es":["Consecuencias","Repercusiones","Efectos"],"collocations":["the implications of","far‑reaching implications","implications for","implications on"],"synonyms_en":["consequences","ramifications","effects"],"example_sentence":"The implications of his decision will be felt throughout the company.","example_es":"Las implicaciones de su decisión se sentirán en toda la empresa.","example_en":"The implications of his decision will be felt throughout the company.","mnemonic_en":"The imp''s footprints spread, showing the implications of his mischief.","cloze_distractors_en":["Fabrications","Allocations","Certifications","Indications"],"examples":[{"es":"Las implicaciones de su decisión se sentirán en toda la empresa.","en":"The implications of his decision will be felt throughout the company."},{"es":"El estudio analiza las implicaciones éticas del uso de inteligencia artificial en la medicina.","en":"The study analyzes the ethical implications of using artificial intelligence in medicine."},{"es":"Debemos considerar cuidadosamente todas las implicaciones económicas antes de aprobar este nuevo presupuesto.","en":"We must carefully consider all the economic implications before approving this new budget."}]},{"spanish_text":"Limitaciones","english_text":"Limitations","section_name":"Academic English","part_of_speech":"noun","definition_en":"Restrictions or constraints that limit what can be done or achieved.","main_translations_es":["Restricciones","Límites","Condiciones"],"collocations":["limitations of the study","legal limitations","technical limitations","limitations and constraints"],"synonyms_en":["restrictions","constraints","boundaries"],"example_sentence":"The limitations of the new software are evident in its performance.","example_es":"Las limitaciones del nuevo software son evidentes en su rendimiento.","example_en":"The limitations of the new software are evident in its performance.","mnemonic_en":"Picture a line stopping cans labeled Limitaciones, the limit on the cans.","cloze_distractors_en":["Decorations","Incentives","Foundations"],"examples":[{"es":"Las limitaciones del nuevo software son evidentes en su rendimiento.","en":"The limitations of the new software are evident in its performance."},{"es":"El investigador reconoció las limitaciones de su metodología durante la presentación.","en":"The researcher acknowledged the limitations of his methodology during the presentation."},{"es":"Debido a las limitaciones presupuestarias, el proyecto no pudo completarse a tiempo.","en":"Due to budgetary limitations, the project could not be completed on time."}]},{"spanish_text":"Marco teórico","english_text":"Theoretical framework","section_name":"Academic English","part_of_speech":"noun","definition_en":"A set of concepts and theories that provides a basis for understanding and analyzing a particular research topic.","main_translations_es":["Marco teórico","Marco conceptual","Marco de referencia"],"collocations":["develop a theoretical framework","theoretical framework of the study","underlying theoretical framework","theoretical framework and methodology"],"synonyms_en":["conceptual framework","theoretical model","conceptual model"],"example_sentence":"The theoretical framework of the study is based on contemporary sociological theories.","example_es":"El marco teórico del estudio se basa en teorías sociológicas contemporáneas.","example_en":"The theoretical framework of the study is based on contemporary sociological theories.","mnemonic_en":"Marco builds a theoretical framework like a picture frame for his ideas.","cloze_distractors_en":["Empirical magnitude","Statistical consensus","Methodological prejudice","Categorical imperative"],"examples":[{"es":"El marco teórico del estudio se basa en teorías sociológicas contemporáneas.","en":"The theoretical framework of the study is based on contemporary sociological theories."},{"es":"Para desarrollar su tesis doctoral, el estudiante debe establecer primero un marco teórico sólido.","en":"To develop his doctoral thesis, the student must first establish a solid theoretical framework."},{"es":"La investigación analiza el fenómeno migratorio utilizando un marco teórico interdisciplinario.","en":"The research analyzes the migration phenomenon using an interdisciplinary theoretical framework."}]},{"spanish_text":"Investigación previa","english_text":"Previous research","section_name":"Academic English","part_of_speech":"noun","definition_en":"Research that has been conducted earlier on a given topic.","main_translations_es":["Estudio previo","Investigación preliminar","Revisión previa"],"collocations":["according to previous research","build on previous research","previous research has shown","previous research indicates"],"synonyms_en":["prior studies","earlier investigations","preliminary research"],"example_sentence":"Previous research suggests that the method is effective.","example_es":"La investigación previa sugiere que el método es efectivo.","example_en":"Previous research suggests that the method is effective.","mnemonic_en":"Picture a scientist shouting Prev-ya as he opens an old research file","cloze_distractors_en":["Future intuition","Random speculation","Subjective opinion","Unverified gossip"],"examples":[{"es":"La investigación previa sugiere que el método es efectivo.","en":"Previous research suggests that the method is effective."},{"es":"Debemos analizar la investigación previa antes de formular nuestra propia hipótesis.","en":"We must analyze previous research before formulating our own hypothesis."},{"es":"El artículo académico ignora gran parte de la investigación previa sobre el cambio climático.","en":"The academic paper ignores a large body of previous research regarding climate change."}]},{"spanish_text":"Cuerpo de evidencia","english_text":"Body of evidence","section_name":"Academic English","part_of_speech":"noun phrase","definition_en":"A collection of facts, testimony, or other information that together support a particular conclusion or argument.","main_translations_es":["Conjunto de pruebas","Cuerpo probatorio","Colección de evidencia"],"collocations":["a substantial body of evidence","the body of evidence suggests","the body of evidence points to","the body of evidence is compelling"],"synonyms_en":["evidence base","proof corpus","supporting material"],"example_sentence":"The body of evidence presented at the trial was sufficient to convict the defendant.","example_es":"El cuerpo de evidencia presentado en el juicio fue suficiente para condenar al acusado.","example_en":"The body of evidence presented at the trial was sufficient to convict the defendant.","mnemonic_en":"Visualize a cuerpo (body) stacked with piles of evidence.","cloze_distractors_en":["Collection of rumors","Series of anecdotes","Sequence of opinions","Cluster of conjectures"],"examples":[{"es":"El cuerpo de evidencia presentado en el juicio fue suficiente para condenar al acusado.","en":"The body of evidence presented at the trial was sufficient to convict the defendant."},{"es":"Los investigadores han reunido un cuerpo de evidencia que respalda la teoría del cambio climático.","en":"Researchers have gathered a body of evidence that supports the theory of climate change."},{"es":"El comité médico revisó todo el cuerpo de evidencia antes de aprobar el nuevo fármaco experimental.","en":"The medical committee reviewed the entire body of evidence before approving the new experimental drug."}]},{"spanish_text":"Conjunto de datos","english_text":"Dataset","section_name":"Academic English","part_of_speech":"noun","definition_en":"A collection of data, typically organized for analysis or reference.","main_translations_es":["Conjunto de datos","Base de datos","Colección de datos"],"collocations":["large dataset","training dataset","public dataset","dataset analysis"],"synonyms_en":["data collection","data bank","data repository"],"example_sentence":"The research team analyzed the dataset to identify patterns in consumer behavior.","example_es":"El equipo de investigación analizó el conjunto de datos para identificar patrones en el comportamiento del consumidor.","example_en":"The research team analyzed the dataset to identify patterns in consumer behavior.","mnemonic_en":"Picture a set of datos stacked like books on a shelf.","cloze_distractors_en":["Footnote","Headset","Diagram","Backdrop"],"examples":[{"es":"El equipo de investigación analizó el conjunto de datos para identificar patrones en el comportamiento del consumidor.","en":"The research team analyzed the dataset to identify patterns in consumer behavior."},{"es":"Es necesario limpiar el conjunto de datos antes de proceder con el análisis estadístico del experimento.","en":"It is necessary to clean the dataset before proceeding with the statistical analysis of the experiment."},{"es":"El profesor compartió un conjunto de datos extenso con los estudiantes para que practicaran sus habilidades de programación.","en":"The professor shared an extensive dataset with the students so they could practice their programming skills."}]},{"spanish_text":"Interpretar","english_text":"Interpret","section_name":"Academic English","part_of_speech":"verb","definition_en":"To explain the meaning of something, or to understand and convey it in a particular way.","main_translations_es":["Interpretar","Entender","Descifrar"],"collocations":["interpret the data","interpret a text","interpret the results","interpret the meaning"],"synonyms_en":["explain","translate","construe"],"example_sentence":"The translator must interpret the text accurately.","example_es":"El traductor debe interpretar el texto con precisión.","example_en":"The translator must interpret the text accurately.","mnemonic_en":"Imagine a judge interpreting a tale, muttering inter‑pretty while opening a book titled interpretar.","cloze_distractors_en":["Fabricate","Exacerbate","Obliterate","Resuscitate"],"examples":[{"es":"El traductor debe interpretar el texto con precisión.","en":"The translator must interpret the text accurately."},{"es":"Los científicos intentan interpretar los datos obtenidos en el experimento.","en":"The scientists are trying to interpret the data obtained from the experiment."},{"es":"Es difícil interpretar el significado de este poema antiguo sin contexto histórico.","en":"It is difficult to interpret the meaning of this ancient poem without historical context."}]},{"spanish_text":"Analizar","english_text":"Analyze","section_name":"Academic English","part_of_speech":"verb","definition_en":"To examine methodically by breaking something into its components and studying their relationships.","main_translations_es":["Examinar","Estudiar","Evaluar"],"collocations":["analyze data","analyze the results","analyze the situation","analyze trends"],"synonyms_en":["examine","evaluate","scrutinize"],"example_sentence":"Scientists must analyze the data before publishing their conclusions.","example_es":"Los científicos deben analizar los datos antes de publicar sus conclusiones.","example_en":"Scientists must analyze the data before publishing their conclusions.","mnemonic_en":"Imagine a lab scientist saying analyze while reading the Spanish word analizar on a test tube label.","cloze_distractors_en":["Fabricate","Disregard","Circulate","Improvise"],"examples":[{"es":"Los científicos deben analizar los datos antes de publicar sus conclusiones.","en":"Scientists must analyze the data before publishing their conclusions."},{"es":"El comité se reunió para analizar las causas del fracaso del proyecto.","en":"The committee met to analyze the causes of the project''s failure."},{"es":"Es necesario analizar el mercado financiero para tomar decisiones de inversión seguras.","en":"It is necessary to analyze the financial market to make secure investment decisions."}]},{"spanish_text":"Sintetizar","english_text":"Synthesize","section_name":"Academic English","part_of_speech":"verb","definition_en":"To combine different ideas, information, or substances into a unified whole.","main_translations_es":["Resumir","Compilar","Integrar"],"collocations":["synthesize information","synthesize data","synthesize findings","synthesize ideas"],"synonyms_en":["combine","integrate","fuse"],"example_sentence":"The chemist managed to synthesize a new molecule in the lab.","example_es":"El químico logró sintetizar una nueva molécula en el laboratorio.","example_en":"The chemist managed to synthesize a new molecule in the lab.","mnemonic_en":"Imagine a chef shouting ''sin tetsar'' as he blends ingredients to synthesize a new sauce.","cloze_distractors_en":["Subjugate","Fabricate","Exacerbate","Obliterate"],"examples":[{"es":"El químico logró sintetizar una nueva molécula en el laboratorio.","en":"The chemist managed to synthesize a new molecule in the lab."},{"es":"Los estudiantes deben sintetizar la información de varias fuentes para redactar su ensayo final.","en":"Students must synthesize information from several sources to write their final essay."},{"es":"El autor intenta sintetizar las teorías económicas más complejas en un solo capítulo introductorio.","en":"The author attempts to synthesize the most complex economic theories into a single introductory chapter."}]},{"spanish_text":"Evaluar","english_text":"Evaluate","section_name":"Academic English","part_of_speech":"verb","definition_en":"To assess or judge the value, quality, or significance of something.","main_translations_es":["Valorar","Calificar","Analizar"],"collocations":["evaluate the results","evaluate the performance","evaluate the data","evaluate the situation"],"synonyms_en":["assess","appraise","judge"],"example_sentence":"The committee must evaluate the experiment''s results before publishing the report.","example_es":"El comité debe evaluar los resultados del experimento antes de publicar el informe.","example_en":"The committee must evaluate the experiment''s results before publishing the report.","mnemonic_en":"Picture a judge holding a scale saying eval uate while checking a Spanish evaluar exam.","cloze_distractors_en":["Fabricate","Exaggerate","Disseminate","Infiltrate"],"examples":[{"es":"El comité debe evaluar los resultados del experimento antes de publicar el informe.","en":"The committee must evaluate the experiment''s results before publishing the report."},{"es":"Es necesario evaluar el impacto ambiental de este proyecto de construcción a largo plazo.","en":"It is necessary to evaluate the environmental impact of this construction project in the long term."},{"es":"Los profesores suelen evaluar la participación de los estudiantes durante los seminarios académicos.","en":"Professors typically evaluate student participation during academic seminars."}]},{"spanish_text":"Criticar","english_text":"Critique","section_name":"Academic English","part_of_speech":"noun","definition_en":"A detailed analysis and assessment of something, especially a work of art, literature, or performance.","main_translations_es":["Reprochar","Censurar","Juzgar"],"collocations":["constructive critique","critical review","peer critique","artistic critique"],"synonyms_en":["review","evaluate","assess"],"example_sentence":"The critic decided to critique the new movie for its lack of originality.","example_es":"El crítico decidió criticar la nueva película por su falta de originalidad.","example_en":"The critic decided to critique the new movie for its lack of originality.","mnemonic_en":"Imagine a critic sipping tea, shouting critique as he points to a sign that reads criticar.","cloze_distractors_en":["Fabricate","Ameliorate","Exacerbate"],"examples":[{"es":"El crítico decidió criticar la nueva película por su falta de originalidad.","en":"The critic decided to critique the new movie for its lack of originality."},{"es":"Los estudiantes deben criticar el artículo académico antes de presentar sus conclusiones en clase.","en":"Students must critique the academic article before presenting their findings in class."},{"es":"Es necesario criticar el diseño del experimento para identificar posibles sesgos en los resultados.","en":"It is necessary to critique the experimental design to identify potential biases in the results."}]},{"spanish_text":"Argumentar","english_text":"Argue","section_name":"Academic English","part_of_speech":"verb","definition_en":"To give reasons for or against something, often in a discussion or debate.","main_translations_es":["Discutir","Razonar","Debatir"],"collocations":["argue a point","argue with","argue about","argue that"],"synonyms_en":["debate","dispute","contend"],"example_sentence":"It''s important to know how to argue your ideas during the debate.","example_es":"Es importante saber argumentar tus ideas durante el debate.","example_en":"It''s important to know how to argue your ideas during the debate.","mnemonic_en":"Imagine a courtroom where the lawyer shouts argue like a fierce Spanish argumentar duel.","cloze_distractors_en":["Fabricate","Illuminate","Navigate","Regulate"],"examples":[{"es":"Es importante saber argumentar tus ideas durante el debate.","en":"It''s important to know how to argue your ideas during the debate."},{"es":"El autor intenta argumentar que las políticas económicas actuales han exacerbado la desigualdad social.","en":"The author attempts to argue that current economic policies have exacerbated social inequality."},{"es":"El abogado intentó argumentar que el contrato original carecía de validez legal.","en":"The lawyer attempted to argue that the original contract lacked legal validity."}]},{"spanish_text":"Demostrar","english_text":"Demonstrate","section_name":"Academic English","part_of_speech":"verb","definition_en":"To show or prove something clearly by giving evidence, examples, or a practical display.","main_translations_es":["Mostrar","Comprobar","Evidenciar"],"collocations":["demonstrate a point","demonstrate the ability","demonstrate commitment","demonstrate how"],"synonyms_en":["show","prove","illustrate"],"example_sentence":"The scientist managed to demonstrate his theory with the new experiments.","example_es":"El científico logró demostrar su teoría con los nuevos experimentos.","example_en":"The scientist managed to demonstrate his theory with the new experiments.","mnemonic_en":"A demo show (demostrar) proves the product works, so you demonstrate it.","cloze_distractors_en":["Fabricate","Obfuscate","Exacerbate","Confiscate"],"examples":[{"es":"El científico logró demostrar su teoría con los nuevos experimentos.","en":"The scientist managed to demonstrate his theory with the new experiments."},{"es":"Los estudiantes deben demostrar su comprensión del tema mediante un ensayo argumentativo.","en":"Students must demonstrate their understanding of the topic through an argumentative essay."},{"es":"La empresa utilizó datos estadísticos para demostrar la viabilidad del proyecto ante los inversores.","en":"The company used statistical data to demonstrate the project''s viability to the investors."}]},{"spanish_text":"Ilustrar","english_text":"Illustrate","section_name":"Academic English","part_of_speech":"verb","definition_en":"to explain or make something clear by using examples, pictures, or diagrams","main_translations_es":["Dibujar","Representar","Mostrar"],"collocations":["illustrate a point","illustrate with examples","illustrate the concept","illustrate the differences"],"synonyms_en":["depict","show","demonstrate"],"example_sentence":"The teacher used diagrams to illustrate the concept of kinetic energy.","example_es":"El profesor utilizó diagramas para ilustrar el concepto de energía cinética.","example_en":"The teacher used diagrams to illustrate the concept of kinetic energy.","mnemonic_en":"I lustrate the picture, just like Ilustrar means to draw a clear image.","cloze_distractors_en":["Obfuscate","Fabricate","Confiscate","Exacerbate"],"examples":[{"es":"El profesor utilizó diagramas para ilustrar el concepto de energía cinética.","en":"The teacher used diagrams to illustrate the concept of kinetic energy."},{"es":"La autora incluyó varios estudios de caso para ilustrar los efectos de la inflación en la economía local.","en":"The author included several case studies to illustrate the effects of inflation on the local economy."},{"es":"El investigador presentó datos estadísticos para ilustrar la correlación entre el sueño y el rendimiento académico.","en":"The researcher presented statistical data to illustrate the correlation between sleep and academic performance."}]},{"spanish_text":"Justificar","english_text":"Justify","section_name":"Academic English","part_of_speech":"verb","definition_en":"To provide reasons or arguments that show something is right or reasonable.","main_translations_es":["Explicar","Fundamentar","Razonar"],"collocations":["justify the decision","justify the cost","justify the means","justify the claim"],"synonyms_en":["validate","warrant","defend"],"example_sentence":"I need to justify my absence from the meeting with a medical note.","example_es":"Necesito justificar mi ausencia en la reunión con una nota médica.","example_en":"I need to justify my absence from the meeting with a medical note.","mnemonic_en":"Imagine a judge justifying a case with a ruler while the word justificar rings in the courtroom.","cloze_distractors_en":["Fabricate","Obfuscate","Inculcate","Ameliorate"],"examples":[{"es":"Necesito justificar mi ausencia en la reunión con una nota médica.","en":"I need to justify my absence from the meeting with a medical note."},{"es":"El autor intenta justificar sus conclusiones mediante el análisis de datos estadísticos recientes.","en":"The author attempts to justify his conclusions through the analysis of recent statistical data."},{"es":"Es difícil justificar un gasto tan elevado sin presentar un presupuesto detallado.","en":"It is difficult to justify such a high expense without presenting a detailed budget."}]},{"spanish_text":"Respaldar","english_text":"Support","section_name":"Academic English","part_of_speech":"verb","definition_en":"To give assistance, encouragement, or approval to someone or something.","main_translations_es":["Apoyar","Sustentar","Avalar"],"collocations":["provide support","support system","financial support","emotional support"],"synonyms_en":["assist","back","aid"],"example_sentence":"The statistical data collected in the study serve to support the researcher''s main hypothesis.","example_es":"Los datos estadísticos recopilados en el estudio sirven para respaldar la hipótesis principal del investigador.","example_en":"The statistical data collected in the study serve to support the researcher''s main hypothesis.","mnemonic_en":"Picture a strong support that backs you, like a Spanish ''respaldo'' holding you up.","cloze_distractors_en":["Refute","Subvert","Obfuscate","Contradict"],"examples":[{"es":"Los datos estadísticos recopilados en el estudio sirven para respaldar la hipótesis principal del investigador.","en":"The statistical data collected in the study serve to support the researcher''s main hypothesis."},{"es":"El profesor presentó pruebas documentales adicionales para respaldar su argumento durante el debate académico.","en":"The professor presented additional documentary evidence to support his argument during the academic debate."},{"es":"Es necesario citar fuentes bibliográficas confiables para respaldar las afirmaciones realizadas en el ensayo.","en":"It is necessary to cite reliable bibliographic sources to support the claims made in the essay."}]},{"spanish_text":"Contradecir","english_text":"Contradict","section_name":"Academic English","part_of_speech":"verb","definition_en":"To assert the opposite of a statement or claim, thereby denying or opposing it.","main_translations_es":["oponerse","refutar","desmentir"],"collocations":["contradict the evidence","contradict each other","contradict the statement","contradict the findings"],"synonyms_en":["oppose","dispute","refute"],"example_sentence":"You shouldn''t contradict your boss in public.","example_es":"No deberías contradecir a tu jefe en público.","example_en":"You shouldn''t contradict your boss in public.","mnemonic_en":"Imagine a counter (contra) rolling a dice (dict) that says no, contradicting everything.","cloze_distractors_en":["Circulate","Navigate","Regulate","Infiltrate"],"examples":[{"es":"No deberías contradecir a tu jefe en público.","en":"You shouldn''t contradict your boss in public."},{"es":"Los datos del estudio parecen contradecir las conclusiones iniciales del informe.","en":"The study data seem to contradict the initial findings of the report."},{"es":"Es arriesgado contradecir la teoría principal durante una presentación académica.","en":"It is risky to contradict the main theory during an academic presentation."}]},{"spanish_text":"Cuestionar","english_text":"Question","section_name":"Academic English","part_of_speech":"verb","definition_en":"To ask about something in order to obtain information or to express doubt about it.","main_translations_es":["interrogar","dudar","poner en duda"],"collocations":["ask a question","raise a question","question the decision"],"synonyms_en":["ask","inquire","interrogate"],"example_sentence":"You shouldn''t question his motives without knowing the facts.","example_es":"No deberías cuestionar sus motivos sin conocer los hechos.","example_en":"You shouldn''t question his motives without knowing the facts.","mnemonic_en":"Picture a pool cue asking a question, a cue-tion, echoing cuestionar","cloze_distractors_en":["Fabricate","Illuminate","Subjugate","Accumulate"],"examples":[{"es":"No deberías cuestionar sus motivos sin conocer los hechos.","en":"You shouldn''t question his motives without knowing the facts."},{"es":"Los científicos decidieron cuestionar la validez de los resultados obtenidos en el experimento.","en":"The scientists decided to question the validity of the results obtained in the experiment."},{"es":"Es necesario cuestionar las suposiciones tradicionales para fomentar la innovación en el sector.","en":"It is necessary to question traditional assumptions to foster innovation in the sector."}]},{"spanish_text":"Reformular","english_text":"Rephrase","section_name":"Academic English","part_of_speech":"verb","definition_en":"To express something again using different words, often to clarify or improve it.","main_translations_es":["Parafrasear","Reexpresar","Reformular"],"collocations":["rephrase the sentence","rephrase your question","rephrase for clarity"],"synonyms_en":["paraphrase","put differently","restated"],"example_sentence":"Could you rephrase the question to make it clearer?","example_es":"¿Podrías reformular la pregunta para que sea más clara?","example_en":"Could you rephrase the question to make it clearer?","mnemonic_en":"Imagine a writer re-phrasing a sentence, like a sculptor reformulating a clay statue.","cloze_distractors_en":[],"examples":[{"es":"¿Podrías reformular la pregunta para que sea más clara?","en":"Could you rephrase the question to make it clearer?"}]},{"spanish_text":"Afirmar","english_text":"Claim","section_name":"Academic English","part_of_speech":"verb","definition_en":"To assert that something is true, typically without providing proof.","main_translations_es":["Declarar","Aseverar","Sostener"],"collocations":["make a claim","file a claim","claim responsibility","claim that"],"synonyms_en":["assert","maintain","allege"],"example_sentence":"The author dares to claim in his thesis that economic growth does not always guarantee social welfare.","example_es":"El autor se atreve a afirmar en su tesis que el crecimiento económico no siempre garantiza el bienestar social.","example_en":"The author dares to claim in his thesis that economic growth does not always guarantee social welfare.","mnemonic_en":"Picture a clay seal stamped with the Spanish word afirmar as you make a claim.","cloze_distractors_en":["Fabricate","Disregard","Exaggerate"],"examples":[{"es":"El autor se atreve a afirmar en su tesis que el crecimiento económico no siempre garantiza el bienestar social.","en":"The author dares to claim in his thesis that economic growth does not always guarantee social welfare."},{"es":"Los investigadores se apresuraron a afirmar que los resultados preliminares del estudio son estadísticamente significativos.","en":"The researchers were quick to claim that the preliminary results of the study are statistically significant."},{"es":"Es difícil afirmar con certeza si el cambio climático es el único factor responsable de la sequía actual.","en":"It is difficult to claim with certainty whether climate change is the sole factor responsible for the current drought."}]},{"spanish_text":"Sugerir","english_text":"Suggest","section_name":"Academic English","part_of_speech":"verb","definition_en":"To propose an idea, plan, or course of action for consideration.","main_translations_es":["proponer","recomendar","aconsejar"],"collocations":["suggest a solution","suggest that","suggest an idea"],"synonyms_en":["propose","recommend","advise"],"example_sentence":"The consultant dared to suggest a complete restructuring of the department to optimize financial results.","example_es":"El consultor se atrevió a sugerir una reestructuración completa del departamento para optimizar los resultados financieros.","example_en":"The consultant dared to suggest a complete restructuring of the department to optimize financial results.","mnemonic_en":"Picture a sugar jar that whispers suggestions.","cloze_distractors_en":["Submerge","Fabricate","Dispel","Exhume"],"examples":[{"es":"El consultor se atrevió a sugerir una reestructuración completa del departamento para optimizar los resultados financieros.","en":"The consultant dared to suggest a complete restructuring of the department to optimize financial results."},{"es":"Durante la reunión, los expertos se reunieron para sugerir nuevas estrategias que mejoren la eficiencia del proyecto.","en":"During the meeting, the experts gathered to suggest new strategies that improve the project''s efficiency."},{"es":"El comité de revisión va a sugerir cambios importantes en el manuscrito antes de su publicación final.","en":"The review committee is going to suggest significant changes to the manuscript before its final publication."}]},{"spanish_text":"Señalar","english_text":"Indicate","section_name":"Academic English","part_of_speech":"verb","definition_en":"To point out or show something, making it known.","main_translations_es":["indicar","apuntar","marcar"],"collocations":["indicate that","indicate a preference","indicate the direction","indicate the results"],"synonyms_en":["show","point out","signal"],"example_sentence":"Please indicate the correct answer on the exam.","example_es":"Por favor, señale la respuesta correcta en el examen.","example_en":"Please indicate the correct answer on the exam.","mnemonic_en":"I indicate by waving a bright señal like a signal flag","cloze_distractors_en":["Fabricate","Obliterate","Confiscate"],"examples":[{"es":"Por favor, señale la respuesta correcta en el examen.","en":"Please indicate the correct answer on the exam."},{"es":"Los datos del gráfico señalan una tendencia al alza en las ventas trimestrales.","en":"The data in the chart indicate an upward trend in quarterly sales."},{"es":"El autor debe señalar las limitaciones de su estudio en la sección de conclusiones.","en":"The author must indicate the limitations of their study in the conclusion section."}]},{"spanish_text":"Destacar","english_text":"Highlight","section_name":"Academic English","part_of_speech":"verb","definition_en":"To emphasize or make something stand out.","main_translations_es":["Resaltar","Sobresalir","Enfatizar"],"collocations":["highlight the main points","highlight a text","highlight a feature","highlight the issue"],"synonyms_en":["emphasize","underscore","spotlight"],"example_sentence":"The report must highlight the most important results of the experiment.","example_es":"El informe debe destacar los resultados más importantes del experimento.","example_en":"The report must highlight the most important results of the experiment.","mnemonic_en":"Imagine a high light shining on a star, making it destacar.","cloze_distractors_en":["Obscure","Fabricate","Disregard","Contradict"],"examples":[{"es":"El informe debe destacar los resultados más importantes del experimento.","en":"The report must highlight the most important results of the experiment."},{"es":"La presentación busca destacar la necesidad urgente de implementar nuevas políticas ambientales.","en":"The presentation aims to highlight the urgent need to implement new environmental policies."},{"es":"El autor utiliza gráficos para destacar las tendencias de crecimiento en el mercado global.","en":"The author uses charts to highlight the growth trends in the global market."}]},{"spanish_text":"Enfatizar","english_text":"Emphasize","section_name":"Academic English","part_of_speech":"verb","definition_en":"To give special importance or attention to something.","main_translations_es":["Resaltar","Destacar","Poner énfasis"],"collocations":["emphasize the importance","emphasize the need","emphasize that","emphasize the point"],"synonyms_en":["highlight","stress","underscore"],"example_sentence":"The teacher wanted to emphasize the importance of punctuality.","example_es":"El profesor quiso enfatizar la importancia de la puntualidad.","example_en":"The teacher wanted to emphasize the importance of punctuality.","mnemonic_en":"Picture a teacher in a theater shouting ''ENFA'' to emphasize the lesson.","cloze_distractors_en":["Fabricate","Masticate","Obliterate"],"examples":[{"es":"El profesor quiso enfatizar la importancia de la puntualidad.","en":"The teacher wanted to emphasize the importance of punctuality."},{"es":"El informe debe enfatizar los beneficios económicos del nuevo proyecto.","en":"The report must emphasize the economic benefits of the new project."},{"es":"La autora decidió enfatizar las diferencias culturales en su análisis sociológico.","en":"The author decided to emphasize the cultural differences in her sociological analysis."}]},{"spanish_text":"En consecuencia","english_text":"Consequently","section_name":"Academic English","part_of_speech":"adverb","definition_en":"As a result; therefore.","main_translations_es":["Por lo tanto","Así que","De ese modo"],"collocations":["Consequently, the project was delayed.","Consequently, we decided to cancel the event.","Consequently, the results were inconclusive.","Consequently, sales increased dramatically."],"synonyms_en":["as a result","therefore","hence"],"example_sentence":"Consequently, the project was cancelled.","example_es":"En consecuencia, el proyecto fue cancelado.","example_en":"Consequently, the project was cancelled.","mnemonic_en":"Picture dominoes, each consequence lands in (en) order—consequently.","cloze_distractors_en":["Conversely","Simultaneously","Superficially"],"examples":[{"es":"En consecuencia, el proyecto fue cancelado.","en":"Consequently, the project was cancelled."},{"es":"No se realizaron las inversiones necesarias; en consecuencia, la empresa perdió su posición en el mercado.","en":"The necessary investments were not made; consequently, the company lost its market position."},{"es":"El estudiante no entregó el ensayo a tiempo y, en consecuencia, recibió una calificación reprobatoria.","en":"The student did not submit the essay on time and, consequently, received a failing grade."}]},{"spanish_text":"Sin embargo","english_text":"However","section_name":"Academic English","part_of_speech":"adverb","definition_en":"It introduces a contrast or exception to what has just been said.","main_translations_es":["no obstante","aun así","con todo"],"collocations":["however you like","however you want","however possible"],"synonyms_en":["Nevertheless","Nonetheless","But"],"example_sentence":"The team conducted an exhaustive investigation; however, they failed to find sufficient evidence to support their hypothesis.","example_es":"El equipo realizó una investigación exhaustiva; sin embargo, no lograron encontrar evidencia suficiente para respaldar su hipótesis.","example_en":"The team conducted an exhaustive investigation; however, they failed to find sufficient evidence to support their hypothesis.","mnemonic_en":"Picture a hay you VERify, though it''s a sin embargo moment.","cloze_distractors_en":["Therefore","Furthermore","Consequently","Similarly"],"examples":[{"es":"El equipo realizó una investigación exhaustiva; sin embargo, no lograron encontrar evidencia suficiente para respaldar su hipótesis.","en":"The team conducted an exhaustive investigation; however, they failed to find sufficient evidence to support their hypothesis."},{"es":"Los datos sugieren una tendencia al alza en el consumo; sin embargo, las proyecciones para el próximo trimestre indican una posible desaceleración.","en":"The data suggests an upward trend in consumption; however, the projections for the next quarter indicate a possible slowdown."},{"es":"La política educativa ha mejorado el acceso a la formación técnica; sin embargo, todavía existen brechas significativas en la calidad de la enseñanza rural.","en":"The educational policy has improved access to technical training; however, significant gaps in the quality of rural instruction still persist."}]},{"spanish_text":"Además","english_text":"Furthermore","section_name":"Academic English","part_of_speech":"adverb","definition_en":"In addition; used to introduce an additional point.","main_translations_es":["También","Encima","Aparte"],"collocations":["Furthermore, ...","Furthermore, the study shows","Furthermore, we find","Furthermore, it is important"],"synonyms_en":["also","moreover","in addition"],"example_sentence":"Furthermore, the preliminary results indicate a substantial improvement in student academic performance.","example_es":"Además, los resultados preliminares indican una mejora sustancial en el rendimiento académico de los estudiantes.","example_en":"Furthermore, the preliminary results indicate a substantial improvement in student academic performance.","mnemonic_en":"Imagine adding more items to a list, because \"además\" sounds like \"add more\" meaning furthermore.","cloze_distractors_en":["Reluctantly","Indifferently","Unnecessarily","Superficially"],"examples":[{"es":"Además, los resultados preliminares indican una mejora sustancial en el rendimiento académico de los estudiantes.","en":"Furthermore, the preliminary results indicate a substantial improvement in student academic performance."},{"es":"Además, los datos recopilados durante el experimento demuestran una correlación significativa entre las variables.","en":"Furthermore, the data collected during the experiment demonstrate a significant correlation between the variables."},{"es":"Además, la implementación de esta nueva política reducirá los costos operativos a largo plazo.","en":"Furthermore, the implementation of this new policy will reduce operating costs in the long term."}]},{"spanish_text":"Por el contrario","english_text":"Conversely","section_name":"Academic English","part_of_speech":"adverb","definition_en":"In a contrasting or opposite manner, used to introduce a statement that reverses the previous one.","main_translations_es":["En cambio","Al contrario","Por otro lado"],"collocations":["Conversely, the opposite is true","Conversely, if you increase the temperature, the pressure drops","Conversely, the results suggest a different trend"],"synonyms_en":["On the other hand","In contrast","Oppositely"],"example_sentence":"He doesn''t like coffee; conversely, he prefers tea.","example_es":"No le gusta el café; por el contrario, prefiere el té.","example_en":"He doesn''t like coffee; conversely, he prefers tea.","mnemonic_en":"Picture a courtroom where the lawyer flips the script, shouting Por el contrario, and you answer Conversely like a mirror","cloze_distractors_en":["Consequently","Furthermore","Accordingly","Simultaneously"],"examples":[{"es":"No le gusta el café; por el contrario, prefiere el té.","en":"He doesn''t like coffee; conversely, he prefers tea."},{"es":"El grupo de control mostró una mejora notable en el rendimiento académico; por el contrario, los estudiantes sin intervención no presentaron cambios significativos.","en":"The control group showed a notable improvement in academic performance; conversely, the students without intervention did not show any significant changes."},{"es":"Muchos expertos creen que la tecnología mejora la educación; por el contrario, otros argumentan que genera distracciones constantes.","en":"Many experts believe technology improves education; conversely, others argue that it creates constant distractions."}]},{"spanish_text":"Del mismo modo","english_text":"Similarly","section_name":"Academic English","part_of_speech":"adverb","definition_en":"In a similar way; in the same manner.","main_translations_es":["Igualmente","De la misma forma","De igual manera"],"collocations":["Similarly, ...","Similarly to","Similarly, the results show","Similarly, we can see"],"synonyms_en":["Likewise","In the same way","In a similar fashion"],"example_sentence":"Similarly, the researchers observed that the use of active learning strategies fosters greater student participation in the classroom.","example_es":"Del mismo modo, los investigadores observaron que el uso de estrategias de aprendizaje activo fomenta una mayor participación de los estudiantes en el aula.","example_en":"Similarly, the researchers observed that the use of active learning strategies fosters greater student participation in the classroom.","mnemonic_en":"Imagine building a SAME LEGO set in the SAME way, just like del mismo modo","cloze_distractors_en":["Conversely","Indisputably","Subsequently","Hypothetically"],"examples":[{"es":"Del mismo modo, los investigadores observaron que el uso de estrategias de aprendizaje activo fomenta una mayor participación de los estudiantes en el aula.","en":"Similarly, the researchers observed that the use of active learning strategies fosters greater student participation in the classroom."},{"es":"Del mismo modo, la reducción de los impuestos corporativos ha fomentado un crecimiento significativo en el sector manufacturero.","en":"Similarly, the reduction in corporate taxes has fostered significant growth within the manufacturing sector."},{"es":"Del mismo modo, el aumento en la inversión en energías renovables ha impulsado una transición más rápida hacia la sostenibilidad ambiental.","en":"Similarly, the increase in investment in renewable energy has driven a faster transition toward environmental sustainability."}]},{"spanish_text":"No obstante","english_text":"Nonetheless","section_name":"Academic English","part_of_speech":"adverb","definition_en":"It means ''in spite of that'' or ''nevertheless''.","main_translations_es":["Sin embargo","A pesar de eso","Con todo"],"collocations":["Nonetheless, ...","Nonetheless, we must","Nonetheless, it is"],"synonyms_en":["Nevertheless","still","even so"],"example_sentence":"Nonetheless, he decided to continue with the project.","example_es":"No obstante, decidió continuar con el proyecto.","example_en":"Nonetheless, he decided to continue with the project.","mnemonic_en":"Picture a stubborn no obstinate man shouting Nonetheless to push forward","cloze_distractors_en":["Consequently","Additionally","Furthermore","Similarly"],"examples":[{"es":"No obstante, decidió continuar con el proyecto.","en":"Nonetheless, he decided to continue with the project."},{"es":"Los resultados del experimento fueron inconsistentes; no obstante, el equipo decidió publicar sus hallazgos.","en":"The experimental results were inconsistent; nonetheless, the team decided to publish their findings."},{"es":"El presupuesto inicial era limitado; no obstante, logramos implementar todas las mejoras necesarias.","en":"The initial budget was limited; nonetheless, we managed to implement all the necessary improvements."}]},{"spanish_text":"Por lo tanto","english_text":"Therefore","section_name":"Academic English","part_of_speech":"adverb","definition_en":"As a result; for that reason.","main_translations_es":["Así que","Por consiguiente","En consecuencia"],"collocations":["therefore, we conclude","therefore, it follows","therefore, the results show"],"synonyms_en":["Consequently","Thus","Hence"],"example_sentence":"The project budget was cut; therefore, we had to cancel the research.","example_es":"El presupuesto del proyecto fue recortado; por lo tanto, tuvimos que cancelar la investigación.","example_en":"The project budget was cut; therefore, we had to cancel the research.","mnemonic_en":"I pour low tango sauce, therefore the dance stops.","cloze_distractors_en":["Nevertheless","Conversely","Alternatively","Simultaneously"],"examples":[{"es":"El presupuesto del proyecto fue recortado; por lo tanto, tuvimos que cancelar la investigación.","en":"The project budget was cut; therefore, we had to cancel the research."},{"es":"Los datos muestran una tendencia al alza; por lo tanto, se espera un aumento en las ventas este trimestre.","en":"The data show an upward trend; therefore, an increase in sales is expected this quarter."},{"es":"La evidencia científica es concluyente; por lo tanto, debemos reconsiderar nuestra estrategia actual.","en":"The scientific evidence is conclusive; therefore, we must reconsider our current strategy."}]},{"spanish_text":"En cambio","english_text":"In contrast","section_name":"Academic English","part_of_speech":"expression","definition_en":"Used to introduce a statement that differs from or opposes what has just been mentioned.","main_translations_es":["Por el contrario","A diferencia de","En contraste"],"collocations":["in contrast to","in contrast with","in contrast, however"],"synonyms_en":["by contrast","on the other hand","conversely"],"example_sentence":"The first group completed the task quickly; in contrast, the second group needed more time to finish.","example_es":"El primer grupo completó la tarea rápidamente; en cambio, el segundo grupo necesitó más tiempo para terminar.","example_en":"The first group completed the task quickly; in contrast, the second group needed more time to finish.","mnemonic_en":"In contrast, picture a light switch saying ''en cambio'' as it flips to the opposite side.","cloze_distractors_en":["Furthermore","Consequently","Additionally","Accordingly"],"examples":[{"es":"El primer grupo completó la tarea rápidamente; en cambio, el segundo grupo necesitó más tiempo para terminar.","en":"The first group completed the task quickly; in contrast, the second group needed more time to finish."},{"es":"Las zonas rurales han experimentado un descenso poblacional; en cambio, las grandes ciudades siguen creciendo de forma acelerada.","en":"Rural areas have experienced a population decline; in contrast, large cities continue to grow rapidly."},{"es":"El candidato conservador propone reducir los impuestos; en cambio, su oponente aboga por aumentar el gasto público.","en":"The conservative candidate proposes cutting taxes; in contrast, his opponent advocates for increasing public spending."}]},{"spanish_text":"Por ejemplo","english_text":"For instance","section_name":"Academic English","part_of_speech":"phrase","definition_en":"Used to introduce an example.","main_translations_es":["Por ejemplo","A modo de ejemplo","Ejemplo"],"collocations":["for instance, ...","for instance, consider","for instance, such as"],"synonyms_en":["e.g.","as an example","to illustrate"],"example_sentence":"Emerging economies face various structural challenges; for instance, the lack of basic infrastructure limits commercial growth.","example_es":"Las economías emergentes enfrentan diversos desafíos estructurales; por ejemplo, la falta de infraestructura básica limita el crecimiento comercial.","example_en":"Emerging economies face various structural challenges; for instance, the lack of basic infrastructure limits commercial growth.","mnemonic_en":"Picture a poor man holding a four as an example.","cloze_distractors_en":["Conversely","Regardless","Nevertheless","Subsequently"],"examples":[{"es":"Las economías emergentes enfrentan diversos desafíos estructurales; por ejemplo, la falta de infraestructura básica limita el crecimiento comercial.","en":"Emerging economies face various structural challenges; for instance, the lack of basic infrastructure limits commercial growth."},{"es":"Existen varias fuentes de energía renovable; por ejemplo, la energía solar es muy eficiente.","en":"There are several sources of renewable energy; for instance, solar power is very efficient."},{"es":"Muchos mamíferos viven en climas extremos; por ejemplo, los osos polares habitan en el Ártico.","en":"Many mammals live in extreme climates; for instance, polar bears inhabit the Arctic."}]},{"spanish_text":"Es decir","english_text":"That is to say","section_name":"Academic English","part_of_speech":"expression","definition_en":"A phrase used to introduce a clarification or restatement of something previously said.","main_translations_es":["O sea","En otras palabras","Dicho de otro modo"],"collocations":["that is to say, the project is delayed","that is to say, in other words","that is to say, we need to act"],"synonyms_en":["in other words","i.e.","to put it another way"],"example_sentence":"I didn''t like the movie; that is to say, I found it boring.","example_es":"No me gustó la película; es decir, la encontré aburrida.","example_en":"I didn''t like the movie; that is to say, I found it boring.","mnemonic_en":"Visualize a teacher holding a sign that reads ES and saying, ''That is to say''.","cloze_distractors_en":["By all means","On the contrary","In any event","For the most part"],"examples":[{"es":"No me gustó la película; es decir, la encontré aburrida.","en":"I didn''t like the movie; that is to say, I found it boring."},{"es":"El candidato no cumple con los requisitos mínimos; es decir, no tiene la experiencia necesaria para el puesto.","en":"The candidate does not meet the minimum requirements; that is to say, he lacks the necessary experience for the position."},{"es":"La empresa ha decidido reducir sus operaciones en el extranjero; es decir, cerrará todas sus sucursales en Europa el próximo mes.","en":"The company has decided to scale back its overseas operations; that is to say, it will close all of its European branches next month."}]},{"spanish_text":"A grandes rasgos","english_text":"Broadly speaking","section_name":"Academic English","part_of_speech":"expression","definition_en":"Used to introduce a general summary or overview of a topic.","main_translations_es":["En términos generales","En líneas generales","De manera general"],"collocations":["Broadly speaking, the results are positive.","Broadly speaking, we can conclude that...","Broadly speaking, the plan works.","Broadly speaking, it''s a good approach."],"synonyms_en":["generally","in general","overall"],"example_sentence":"Broadly speaking, the project involves developing a mobile app for task management.","example_es":"A grandes rasgos, el proyecto consiste en desarrollar una aplicación móvil para la gestión de tareas.","example_en":"Broadly speaking, the project involves developing a mobile app for task management.","mnemonic_en":"A broad map with a raspy goose speaking about big features.","cloze_distractors_en":["Narrowly acting","Briefly thinking","Deeply listening"],"examples":[{"es":"A grandes rasgos, el proyecto consiste en desarrollar una aplicación móvil para la gestión de tareas.","en":"Broadly speaking, the project involves developing a mobile app for task management."},{"es":"A grandes rasgos, los resultados de la encuesta indican que la mayoría de los estudiantes prefiere el aprendizaje híbrido.","en":"Broadly speaking, the survey results indicate that the majority of students prefer hybrid learning."},{"es":"A grandes rasgos, la nueva política económica busca reducir la inflación mediante el control del gasto público.","en":"Broadly speaking, the new economic policy aims to reduce inflation by controlling public spending."}]},{"spanish_text":"En primer lugar","english_text":"In the first place","section_name":"Academic English","part_of_speech":"expression","definition_en":"Used to introduce the first reason or point in a discussion.","main_translations_es":["Primero","En primer término","Ante todo"],"collocations":["Why did you do that in the first place?","In the first place, we should consider the costs.","It wasn''t necessary in the first place."],"synonyms_en":["first of all","to begin with","initially"],"example_sentence":"In the first place, we must review the documents before proceeding with the audit.","example_es":"En primer lugar, debemos revisar los documentos antes de proceder con la auditoría.","example_en":"In the first place, we must review the documents before proceeding with the audit.","mnemonic_en":"Picture a prime (primer) athlete stepping into the first place on the podium.","cloze_distractors_en":["In the last resort","In the same breath","In the off chance","In the dark ages"],"examples":[{"es":"En primer lugar, debemos revisar los documentos antes de proceder con la auditoría.","en":"In the first place, we must review the documents before proceeding with the audit."},{"es":"En primer lugar, el autor argumenta que el cambio climático es una amenaza inminente para la biodiversidad.","en":"In the first place, the author argues that climate change is an imminent threat to biodiversity."},{"es":"En primer lugar, los investigadores deben establecer una metodología clara para garantizar la validez de los resultados.","en":"In the first place, researchers must establish a clear methodology to ensure the validity of the results."}]},{"spanish_text":"En segundo lugar","english_text":"Secondly","section_name":"Academic English","part_of_speech":"adverb","definition_en":"Used to introduce the second item in a list or sequence of points.","main_translations_es":["En segundo término","En segundo punto","En segundo orden"],"collocations":["Firstly, ... Secondly, ...","Secondly, we need to...","Secondly, the results show..."],"synonyms_en":["In addition","Moreover","Also"],"example_sentence":"Secondly, we must consider the budget.","example_es":"En segundo lugar, debemos considerar el presupuesto.","example_en":"Secondly, we must consider the budget.","mnemonic_en":"Imagine a runner in second place yelling ''Secondly!'' as if saying Spanish ''segundo''.","cloze_distractors_en":["Randomly","Silently","Blindly","Carelessly"],"examples":[{"es":"En segundo lugar, debemos considerar el presupuesto.","en":"Secondly, we must consider the budget."},{"es":"En segundo lugar, el informe analiza el impacto ambiental del proyecto.","en":"Secondly, the report analyzes the environmental impact of the project."},{"es":"En segundo lugar, el orador presentó los datos estadísticos sobre el crecimiento demográfico.","en":"Secondly, the speaker presented the statistical data regarding population growth."}]},{"spanish_text":"En términos generales","english_text":"In general terms","section_name":"Academic English","part_of_speech":"expression","definition_en":"A phrase used to indicate that something applies broadly or in a general sense.","main_translations_es":["En general","En términos generales","De forma general"],"collocations":["in general terms, ...","to put it in general terms","in general terms, the result is","in general terms, we can say"],"synonyms_en":["generally","overall","broadly speaking"],"example_sentence":"In general terms, the project will be completed by the end of the year.","example_es":"En términos generales, el proyecto será completado a finales de año.","example_en":"In general terms, the project will be completed by the end of the year.","mnemonic_en":"A general signs a contract titled In general terms on a big board.","cloze_distractors_en":["In brief intervals","In stark defiance","In rigid sequences"],"examples":[{"es":"En términos generales, el proyecto será completado a finales de año.","en":"In general terms, the project will be completed by the end of the year."},{"es":"En términos generales, los resultados de la encuesta indican una mayor satisfacción entre los empleados.","en":"In general terms, the survey results indicate higher satisfaction among employees."},{"es":"En términos generales, la nueva política educativa busca reducir la brecha de desigualdad en las escuelas rurales.","en":"In general terms, the new education policy seeks to reduce the inequality gap in rural schools."}]},{"spanish_text":"En última instancia","english_text":"Ultimately","section_name":"Academic English","part_of_speech":"adverb","definition_en":"In the end, after all other considerations or events have taken place.","main_translations_es":["Al fin y al cabo","En definitiva","A fin de cuentas"],"collocations":["Ultimately, it comes down to","Ultimately, the decision rests with","Ultimately, we need to","Ultimately, the outcome depends on"],"synonyms_en":["in the end","finally","eventually"],"example_sentence":"Ultimately, the success of the research depends on the accuracy of the collected data.","example_es":"En última instancia, el éxito de la investigación depende de la precisión de los datos recolectados.","example_en":"Ultimately, the success of the research depends on the accuracy of the collected data.","mnemonic_en":"Imagine the last ''última'' chapter flipping open, revealing the ultimate outcome.","cloze_distractors_en":["Arbitrarily","Superficially","Negligently","Erroneously"],"examples":[{"es":"En última instancia, el éxito de la investigación depende de la precisión de los datos recolectados.","en":"Ultimately, the success of the research depends on the accuracy of the collected data."},{"es":"Aunque discutimos varias alternativas, en última instancia elegimos el modelo más rentable para la empresa.","en":"Although we discussed several alternatives, ultimately we chose the most cost-effective model for the company."},{"es":"En última instancia, es responsabilidad del comité académico aprobar o rechazar la tesis doctoral.","en":"Ultimately, it is the responsibility of the academic committee to approve or reject the doctoral thesis."}]},{"spanish_text":"Cabe señalar que","english_text":"It should be noted that","section_name":"Academic English","part_of_speech":"expression","definition_en":"A phrase used to introduce a statement that the speaker wants to emphasize or draw attention to.","main_translations_es":["Cabe destacar que","Hay que señalar que","Es importante señalar que"],"collocations":["It should be noted that...","It should be noted that the data...","It should be noted that this is..."],"synonyms_en":["It is worth noting that","Note that","One should note that"],"example_sentence":"It should be noted that the report will be presented tomorrow.","example_es":"Cabe señalar que el informe será presentado mañana.","example_en":"It should be noted that the report will be presented tomorrow.","mnemonic_en":"Imagine a note on a signal flag, reminding you it should be noted that.","cloze_distractors_en":["In spite of which","On account of this","Regardless of how","In light of where"],"examples":[{"es":"Cabe señalar que el informe será presentado mañana.","en":"It should be noted that the report will be presented tomorrow."},{"es":"Cabe señalar que los resultados del experimento no fueron concluyentes.","en":"It should be noted that the results of the experiment were not conclusive."},{"es":"Cabe señalar que la tasa de desempleo ha disminuido significativamente este trimestre.","en":"It should be noted that the unemployment rate has decreased significantly this quarter."}]},{"spanish_text":"Se puede sostener que","english_text":"It can be argued that","section_name":"Academic English","part_of_speech":"expression","definition_en":"A phrase used to introduce a statement that may be debated or supported with reasoning.","main_translations_es":["Se puede afirmar que","Se podría sostener que","Se puede decir que"],"collocations":["It can be argued that the data supports this","It can be argued that this is the case","It can be argued that there are alternatives","It can be argued that the policy is ineffective"],"synonyms_en":["One could argue that","It may be claimed that","It is debatable that"],"example_sentence":"It can be argued that the implementation of this new educational policy will improve graduation rates in the long term.","example_es":"Se puede sostener que la implementación de esta nueva política educativa mejorará las tasas de graduación a largo plazo.","example_en":"It can be argued that the implementation of this new educational policy will improve graduation rates in the long term.","mnemonic_en":"Visualize a sturdy ''sostener'' shelf holding a debate sign, reminding you ''It can be argued that''.","cloze_distractors_en":["It remains silent that","It is rarely seen that","It is widely denied that"],"examples":[{"es":"Se puede sostener que la implementación de esta nueva política educativa mejorará las tasas de graduación a largo plazo.","en":"It can be argued that the implementation of this new educational policy will improve graduation rates in the long term."},{"es":"Se puede sostener que el aumento en las temperaturas globales es la causa principal de la reciente inestabilidad climática.","en":"It can be argued that the rise in global temperatures is the primary cause of recent climate instability."},{"es":"Se puede sostener que los avances en inteligencia artificial transformarán radicalmente el mercado laboral en la próxima década.","en":"It can be argued that advancements in artificial intelligence will radically transform the labor market over the next decade."}]},{"spanish_text":"Parece evidente que","english_text":"It seems evident that","section_name":"Academic English","part_of_speech":"expression","definition_en":"A phrase used to indicate that something appears clear or obvious.","main_translations_es":["Resulta evidente que","Es evidente que","Se ve evidente que"],"collocations":["It seems evident that...","It seems evident that the data show...","It seems evident that we need to act","It seems evident that this is the case"],"synonyms_en":["It appears clear that","It looks obvious that","It seems obvious that"],"example_sentence":"It seems evident that the evidence supports his theory.","example_es":"Parece evidente que la evidencia apoya su teoría.","example_en":"It seems evident that the evidence supports his theory.","mnemonic_en":"It seems evident that a pair of evidence makes it obvious.","cloze_distractors_en":["It proves impossible unless","It sounds ridiculous since","It feels uncertain despite"],"examples":[{"es":"Parece evidente que la evidencia apoya su teoría.","en":"It seems evident that the evidence supports his theory."},{"es":"Parece evidente que los resultados del experimento son concluyentes.","en":"It seems evident that the results of the experiment are conclusive."},{"es":"Parece evidente que el cambio climático está afectando la biodiversidad global.","en":"It seems evident that climate change is affecting global biodiversity."}]},{"spanish_text":"Está ampliamente aceptado","english_text":"It is widely accepted","section_name":"Academic English","part_of_speech":"expression","definition_en":"A statement indicating that something is generally approved or recognized by many people.","main_translations_es":["Se acepta ampliamente","Es de aceptación general","Goza de amplio reconocimiento"],"collocations":["widely accepted practice","widely accepted theory","widely accepted standard"],"synonyms_en":["It is generally accepted","It is commonly accepted","It is broadly accepted"],"example_sentence":"It is widely accepted that the rise in global temperatures is due to human activity.","example_es":"Está ampliamente aceptado que el aumento de las temperaturas globales se debe a la actividad humana.","example_en":"It is widely accepted that the rise in global temperatures is due to human activity.","mnemonic_en":"See a wide (wide) hallway where everyone nods, saying ''ampliamente aceptado''.","cloze_distractors_en":["It is fiercely ignored","It is seldom observed","It is strictly forbidden","It is vaguely imagined"],"examples":[{"es":"Está ampliamente aceptado que el aumento de las temperaturas globales se debe a la actividad humana.","en":"It is widely accepted that the rise in global temperatures is due to human activity."},{"es":"Está ampliamente aceptado en la comunidad científica que la vacunación reduce significativamente la propagación de enfermedades.","en":"It is widely accepted in the scientific community that vaccination significantly reduces the spread of diseases."},{"es":"Está ampliamente aceptado que la educación bilingüe mejora las capacidades cognitivas de los estudiantes jóvenes.","en":"It is widely accepted that bilingual education improves the cognitive abilities of young students."}]},{"spanish_text":"Permanecer incierto","english_text":"Remain uncertain","section_name":"Academic English","part_of_speech":"verb phrase","definition_en":"To stay in a state of uncertainty.","main_translations_es":["Seguir sin estar claro","Quedarse en duda","Mantenerse incierto"],"collocations":["remain uncertain about","remain uncertain whether","remain uncertain at this point"],"synonyms_en":["be unsure","stay unclear","remain doubtful"],"example_sentence":"The outcome of the trial will remain uncertain.","example_es":"El resultado del juicio seguirá permaneciendo incierto.","example_en":"The outcome of the trial will remain uncertain.","mnemonic_en":"Picture a RE-MAINING sign that reads IN-CERTAIN, swaying like an unsure flag.","cloze_distractors_en":["Become fully verified","Require immediate expansion","Exhibit total transparency","Undergo rapid transformation"],"examples":[{"es":"El resultado del juicio seguirá permaneciendo incierto.","en":"The outcome of the trial will remain uncertain."},{"es":"Debido a la falta de datos, la viabilidad del proyecto debe permanecer incierto.","en":"Due to the lack of data, the project''s viability must remain uncertain."},{"es":"Aunque los expertos analizaron las pruebas, el origen del fenómeno parece permanecer incierto.","en":"Although experts analyzed the evidence, the origin of the phenomenon seems to remain uncertain."}]},{"spanish_text":"Tener en cuenta","english_text":"Take into consideration","section_name":"Academic English","part_of_speech":"verb phrase","definition_en":"To consider something carefully when making a decision.","main_translations_es":["Considerar","Tener presente","Tomar en cuenta"],"collocations":["take into consideration the costs","take into consideration the risks","take into consideration the feedback","take into consideration the circumstances"],"synonyms_en":["consider","keep in mind","take into account"],"example_sentence":"You should take into consideration the doctor''s recommendations before starting the treatment.","example_es":"Debes tener en cuenta las recomendaciones del médico antes de iniciar el tratamiento.","example_en":"You should take into consideration the doctor''s recommendations before starting the treatment.","mnemonic_en":"Take a ten, then consider it carefully.","cloze_distractors_en":["Fabricate the evidence","Underestimate the gravity","Disregard the consequences","Misinterpret the guidelines"],"examples":[{"es":"Debes tener en cuenta las recomendaciones del médico antes de iniciar el tratamiento.","en":"You should take into consideration the doctor''s recommendations before starting the treatment."},{"es":"El comité debe tener en cuenta los posibles riesgos financieros antes de aprobar el nuevo proyecto de inversión.","en":"The committee must take into consideration the potential financial risks before approving the new investment project."},{"es":"Al redactar el ensayo, es fundamental tener en cuenta las diversas perspectivas culturales sobre el cambio climático.","en":"When writing the essay, it is essential to take into consideration the diverse cultural perspectives on climate change."}]},{"spanish_text":"Sacar una conclusión","english_text":"Draw a conclusion","section_name":"Academic English","part_of_speech":"verb phrase","definition_en":"to form a judgment or inference based on evidence","main_translations_es":["Llegar a una conclusión","Concluir","Formular una conclusión"],"collocations":["draw a conclusion from the data","draw a conclusion about","draw a conclusion based on the evidence","draw a conclusion that"],"synonyms_en":["reach a conclusion","make a deduction","infer"],"example_sentence":"Based on the experiment results, the researchers were able to draw a conclusion regarding the efficacy of the new drug.","example_es":"Basándose en los resultados del experimento, los investigadores pudieron sacar una conclusión sobre la eficacia del nuevo fármaco.","example_en":"Based on the experiment results, the researchers were able to draw a conclusion regarding the efficacy of the new drug.","mnemonic_en":"Picture yourself drawing a final line that pulls out the answer, like you ''sacar'' a conclusion","cloze_distractors_en":["paint a landscape","flee a consequence","trace a philosophy","spill a confidence"],"examples":[{"es":"Basándose en los resultados del experimento, los investigadores pudieron sacar una conclusión sobre la eficacia del nuevo fármaco.","en":"Based on the experiment results, the researchers were able to draw a conclusion regarding the efficacy of the new drug."},{"es":"El comité necesita analizar todas las pruebas antes de sacar una conclusión sobre el incidente.","en":"The committee needs to analyze all the evidence before they draw a conclusion about the incident."},{"es":"Es prematuro sacar una conclusión sin haber escuchado los argumentos de ambas partes.","en":"It is premature to draw a conclusion without having heard the arguments from both sides."}]},{"spanish_text":"Llegar a una conclusión","english_text":"Reach a conclusion","section_name":"Academic English","part_of_speech":"verb","definition_en":"to arrive at a decision or judgment after considering the evidence","main_translations_es":["Sacar una conclusión","Concluir","Llegar a una decisión"],"collocations":["reach a conclusion about","reach a conclusion after","reach a conclusion that","reach a conclusion quickly"],"synonyms_en":["draw a conclusion","come to a conclusion","conclude"],"example_sentence":"After evaluating the experiment results, the researchers were able to reach a conclusion regarding the drug''s efficacy.","example_es":"Tras evaluar los resultados del experimento, los investigadores pudieron llegar a una conclusión sobre la eficacia del fármaco.","example_en":"After evaluating the experiment results, the researchers were able to reach a conclusion regarding the drug''s efficacy.","mnemonic_en":"I reach, I ''llegar'' at the conclusion podium.","cloze_distractors_en":["Fabricate a hypothesis","Abandon a consensus","Distort a perspective"],"examples":[{"es":"Tras evaluar los resultados del experimento, los investigadores pudieron llegar a una conclusión sobre la eficacia del fármaco.","en":"After evaluating the experiment results, the researchers were able to reach a conclusion regarding the drug''s efficacy."},{"es":"El tribunal escuchó todos los testimonios antes de llegar a una conclusión sobre el caso.","en":"The court heard all the testimonies before they could reach a conclusion about the case."},{"es":"Los expertos debatieron durante horas antes de llegar a una conclusión unánime sobre el cambio climático.","en":"The experts debated for hours before they could reach a conclusion on climate change."}]},{"spanish_text":"A modo de conclusión","english_text":"By way of conclusion","section_name":"Academic English","part_of_speech":"expression","definition_en":"A phrase used to introduce a final statement or summary.","main_translations_es":["En conclusión","Para concluir","En síntesis"],"collocations":["By way of conclusion, we can see that...","By way of conclusion, the study suggests...","By way of conclusion, it is evident that...","By way of conclusion, I recommend..."],"synonyms_en":["In conclusion","To sum up","In summary"],"example_sentence":"By way of conclusion, the report highlights the urgent need to implement stricter sustainability policies.","example_es":"A modo de conclusión, el informe destaca la necesidad urgente de implementar políticas de sostenibilidad más estrictas.","example_en":"By way of conclusion, the report highlights the urgent need to implement stricter sustainability policies.","mnemonic_en":"Press the mode button to end, by way of conclusion.","cloze_distractors_en":["By means of contrast","By way of omission","By virtue of evidence","By force of habit"],"examples":[{"es":"A modo de conclusión, el informe destaca la necesidad urgente de implementar políticas de sostenibilidad más estrictas.","en":"By way of conclusion, the report highlights the urgent need to implement stricter sustainability policies."},{"es":"A modo de conclusión, los investigadores sugieren que se realicen estudios adicionales para verificar estos resultados preliminares.","en":"By way of conclusion, the researchers suggest that further studies be conducted to verify these preliminary results."},{"es":"A modo de conclusión, la presentación resumió los principales desafíos económicos que enfrentará la empresa durante el próximo año fiscal.","en":"By way of conclusion, the presentation summarized the main economic challenges the company will face during the next fiscal year."}]},{"spanish_text":"Tesis","english_text":"Thesis","section_name":"Academic English","part_of_speech":"noun","definition_en":"A written document presenting the author''s research and findings, typically submitted for an academic degree.","main_translations_es":["Trabajo de investigación","Disertación","Monografía"],"collocations":["thesis statement","doctoral thesis","master''s thesis","thesis defense"],"synonyms_en":["dissertation","research paper","treatise"],"example_sentence":"I am working on my doctoral thesis.","example_es":"Estoy trabajando en mi tesis de doctorado.","example_en":"I am working on my doctoral thesis.","mnemonic_en":"Picture a student holding a thick test paper that says teh-sis as the thesis","cloze_distractors_en":["Stasis","Phasis","Genesis","Hypnosis"],"examples":[{"es":"Estoy trabajando en mi tesis de doctorado.","en":"I am working on my doctoral thesis."},{"es":"El estudiante debe defender su tesis ante un comité de expertos.","en":"The student must defend his thesis before a committee of experts."},{"es":"La tesis principal del artículo sostiene que la tecnología mejora el aprendizaje.","en":"The main thesis of the article argues that technology improves learning."}]},{"spanish_text":"Antítesis","english_text":"Counterargument","section_name":"Academic English","part_of_speech":"noun","definition_en":"A statement or set of reasons presented in opposition to another argument.","main_translations_es":["Contraposición","Oposición","Contraste"],"collocations":["present a counterargument","raise a counterargument","offer a counterargument","counterargument to"],"synonyms_en":["rebuttal","opposing view","contrary point"],"example_sentence":"The lawyer presented a detailed counterargument to invalidate the evidence provided by the prosecution.","example_es":"El abogado presentó una antítesis detallada para invalidar la evidencia presentada por la fiscalía.","example_en":"The lawyer presented a detailed counterargument to invalidate the evidence provided by the prosecution.","mnemonic_en":"On a kitchen counter, the antítesis debates the recipe, a perfect counterargument.","cloze_distractors_en":["Substantiation","Corroboration","Verification","Elucidation"],"examples":[{"es":"El abogado presentó una antítesis detallada para invalidar la evidencia presentada por la fiscalía.","en":"The lawyer presented a detailed counterargument to invalidate the evidence provided by the prosecution."},{"es":"El autor presentó una antítesis sólida para cuestionar los hallazgos del estudio.","en":"The author presented a solid counterargument to challenge the study''s findings."},{"es":"Debes incluir una antítesis en tu ensayo para demostrar que has considerado perspectivas opuestas.","en":"You must include a counterargument in your essay to show that you have considered opposing perspectives."}]},{"spanish_text":"Postura","english_text":"Stance","section_name":"Academic English","part_of_speech":"noun","definition_en":"a person''s attitude or position on a particular issue","main_translations_es":["Actitud","Posición","Postura"],"collocations":["take a stance","firm stance","political stance","stance on"],"synonyms_en":["position","attitude","viewpoint"],"example_sentence":"His stance on the change was very clear.","example_es":"Su postura frente al cambio fue muy clara.","example_en":"His stance on the change was very clear.","mnemonic_en":"Picture a solid stance, like a perfect postura on a mountain ledge.","cloze_distractors_en":["Staple","Stanza","Stasis","Stigma"],"examples":[{"es":"Su postura frente al cambio fue muy clara.","en":"His stance on the change was very clear."},{"es":"La universidad adoptó una postura firme contra el plagio académico.","en":"The university adopted a firm stance against academic plagiarism."},{"es":"El autor defiende su postura mediante un análisis detallado de los datos.","en":"The author defends his stance through a detailed analysis of the data."}]},{"spanish_text":"Razonamiento","english_text":"Reasoning","section_name":"Academic English","part_of_speech":"noun","definition_en":"The mental process of drawing conclusions or making inferences based on evidence or logical principles.","main_translations_es":["Lógica","Pensamiento","Análisis"],"collocations":["critical reasoning","logical reasoning","deductive reasoning","reasoning skills"],"synonyms_en":["logic","thinking","rationale"],"example_sentence":"His reasoning was impeccable during the debate.","example_es":"Su razonamiento fue impecable durante el debate.","example_en":"His reasoning was impeccable during the debate.","mnemonic_en":"A razor sharp mind slices a puzzle, revealing the reasoning.","cloze_distractors_en":["Seasoning","Partition","Dimension","Condition"],"examples":[{"es":"Su razonamiento fue impecable durante el debate.","en":"His reasoning was impeccable during the debate."},{"es":"El comité cuestionó el razonamiento detrás de la nueva propuesta presupuestaria.","en":"The committee questioned the reasoning behind the new budget proposal."},{"es":"Debes explicar el razonamiento lógico que te llevó a esa conclusión científica.","en":"You must explain the logical reasoning that led you to that scientific conclusion."}]},{"spanish_text":"Premisa","english_text":"Premise","section_name":"Academic English","part_of_speech":"noun","definition_en":"A statement or proposition that serves as a basis for reasoning or argument.","main_translations_es":["Supuesto","Postulado","Axioma"],"collocations":["on the premise that","basic premise","underlying premise","premise of the argument"],"synonyms_en":["assumption","proposition","presupposition"],"example_sentence":"The premise of the argument is that all human beings seek happiness.","example_es":"La premisa del argumento es que todos los seres humanos buscan la felicidad.","example_en":"The premise of the argument is that all human beings seek happiness.","mnemonic_en":"Picture a pre‑meeting where you set the premise, hearing pre‑me‑sa echo in the room.","cloze_distractors_en":["Fragment","Pretext","Presence","Pinnacle"],"examples":[{"es":"La premisa del argumento es que todos los seres humanos buscan la felicidad.","en":"The premise of the argument is that all human beings seek happiness."},{"es":"El estudio científico se basa en la premisa de que el clima está cambiando rápidamente.","en":"The scientific study is based on the premise that the climate is changing rapidly."},{"es":"Debemos cuestionar la premisa fundamental sobre la que se construyó esta teoría económica.","en":"We must question the fundamental premise upon which this economic theory was built."}]},{"spanish_text":"Inferencia","english_text":"Inference","section_name":"Academic English","part_of_speech":"noun","definition_en":"A conclusion drawn from evidence and reasoning.","main_translations_es":["Razonamiento","Deducción"],"collocations":["make an inference","draw an inference","inference based on evidence"],"synonyms_en":["deduction","conclusion","reasoning"],"example_sentence":"Based on the data, he made an inference about the future behavior of the market.","example_es":"A partir de los datos, hizo una inferencia sobre el comportamiento futuro del mercado.","example_en":"Based on the data, he made an inference about the future behavior of the market.","mnemonic_en":"Imagine a detective reading the ''infer'' in Inferencia to uncover hidden clues.","cloze_distractors_en":["Indulgence","Inherence","Impedance","Insolence"],"examples":[{"es":"A partir de los datos, hizo una inferencia sobre el comportamiento futuro del mercado.","en":"Based on the data, he made an inference about the future behavior of the market."},{"es":"El detective llegó a una inferencia lógica tras analizar todas las pistas encontradas en la escena del crimen.","en":"The detective reached a logical inference after analyzing all the clues found at the crime scene."},{"es":"Los estudiantes deben extraer una inferencia válida del texto científico para completar su ensayo de investigación.","en":"Students must draw a valid inference from the scientific text to complete their research essay."}]},{"spanish_text":"Validez","english_text":"Validity","section_name":"Academic English","part_of_speech":"noun","definition_en":"The quality of being logically sound or legally acceptable.","main_translations_es":["Validez","Legitimidad","Vigencia"],"collocations":["question the validity","prove the validity","validity period","validity of the claim"],"synonyms_en":["legitimacy","soundness","authenticity"],"example_sentence":"The researcher questioned the validity of the data collected during the experiment.","example_es":"El investigador cuestionó la validez de los datos recopilados durante el experimento.","example_en":"The researcher questioned the validity of the data collected during the experiment.","mnemonic_en":"Imagine a valid ID stamped validez that opens the door to the party.","cloze_distractors_en":["Volatility","Visibility","Vulnerability","Versatility"],"examples":[{"es":"El investigador cuestionó la validez de los datos recopilados durante el experimento.","en":"The researcher questioned the validity of the data collected during the experiment."},{"es":"Para publicar el estudio, debemos demostrar la validez de nuestra metodología ante el comité académico.","en":"To publish the study, we must demonstrate the validity of our methodology to the academic committee."},{"es":"Los resultados de la encuesta perdieron su validez debido a un error en el diseño de las preguntas.","en":"The survey results lost their validity due to a flaw in the design of the questions."}]},{"spanish_text":"Fiabilidad","english_text":"Reliability","section_name":"Academic English","part_of_speech":"noun","definition_en":"The quality of being trustworthy or dependable.","main_translations_es":["Confiabilidad","Seguridad"],"collocations":["reliability of the system","high reliability","reliability engineering","reliability testing"],"synonyms_en":["dependability","trustworthiness","consistency"],"example_sentence":"The reliability of the data collected during the experiment was questioned by the reviewers.","example_es":"La fiabilidad de los datos recopilados durante el experimento fue cuestionada por los revisores.","example_en":"The reliability of the data collected during the experiment was questioned by the reviewers.","mnemonic_en":"Imagine a trusty robot labeled Fiabilidad that never fails, proving reliability.","cloze_distractors_en":["Flexibility","Visibility","Capability","Probability"],"examples":[{"es":"La fiabilidad de los datos recopilados durante el experimento fue cuestionada por los revisores.","en":"The reliability of the data collected during the experiment was questioned by the reviewers."},{"es":"Para publicar un estudio científico, es necesario demostrar la fiabilidad de la metodología empleada.","en":"To publish a scientific study, it is necessary to demonstrate the reliability of the methodology employed."},{"es":"El informe destaca la fiabilidad de las fuentes primarias utilizadas para el análisis histórico.","en":"The report highlights the reliability of the primary sources used for the historical analysis."}]},{"spanish_text":"Sesgo","english_text":"Bias","section_name":"Academic English","part_of_speech":"noun","definition_en":"A tendency to favor or prejudice a particular perspective, group, or outcome.","main_translations_es":["Prejuicio","Tendencia","Parcialidad"],"collocations":["bias towards","bias against","cognitive bias","implicit bias"],"synonyms_en":["prejudice","partiality","preconception"],"example_sentence":"The bias of the survey made the results unrepresentative.","example_es":"El sesgo de la encuesta hizo que los resultados no fueran representativos.","example_en":"The bias of the survey made the results unrepresentative.","mnemonic_en":"Picture a tilted scale labeled sesgo to remember bias.","cloze_distractors_en":["Stance","Scale","State"],"examples":[{"es":"El sesgo de la encuesta hizo que los resultados no fueran representativos.","en":"The bias of the survey made the results unrepresentative."},{"es":"Los investigadores deben reconocer cualquier sesgo potencial en su metodología para garantizar la objetividad del estudio.","en":"Researchers must acknowledge any potential bias in their methodology to ensure the objectivity of the study."},{"es":"Es fundamental analizar los datos con cuidado para evitar que el sesgo del observador afecte las conclusiones finales.","en":"It is essential to analyze the data carefully to prevent observer bias from affecting the final conclusions."}]},{"spanish_text":"Objetividad","english_text":"Objectivity","section_name":"Academic English","part_of_speech":"noun","definition_en":"The quality of being objective, or the ability to consider facts without personal bias or emotion.","main_translations_es":["Imparcialidad","Neutralidad","Objetividad"],"collocations":["maintain objectivity","objectivity in reporting","objectivity and fairness","objectivity of the study"],"synonyms_en":["impartiality","neutrality","detachment"],"example_sentence":"The scientist must maintain objectivity when analyzing the data.","example_es":"El científico debe mantener la objetividad al analizar los datos.","example_en":"The scientist must maintain objectivity when analyzing the data.","mnemonic_en":"Visualize a plain object wearing glasses that read OBJETIVIDAD, showing pure objectivity.","cloze_distractors_en":["Subjectivity","Partiality","Ambiguity","Volatility"],"examples":[{"es":"El científico debe mantener la objetividad al analizar los datos.","en":"The scientist must maintain objectivity when analyzing the data."},{"es":"El comité editorial exige total objetividad en los artículos de investigación publicados.","en":"The editorial board demands total objectivity in the published research papers."},{"es":"Es difícil conservar la objetividad cuando se evalúa un proyecto en el que uno mismo ha trabajado.","en":"It is difficult to preserve objectivity when evaluating a project on which you have worked yourself."}]},{"spanish_text":"Subjetividad","english_text":"Subjectivity","section_name":"Academic English","part_of_speech":"noun","definition_en":"The quality of being based on personal feelings, tastes, or opinions rather than objective facts.","main_translations_es":["Subjetividad","Perspectiva personal","Punto de vista subjetivo"],"collocations":["subjectivity of perception","subjectivity in art","subjectivity bias","subjectivity of experience"],"synonyms_en":["personal perspective","individual bias","personal viewpoint"],"example_sentence":"The subjectivity of the author is reflected in every chapter of the book.","example_es":"La subjetividad del autor se refleja en cada capítulo del libro.","example_en":"The subjectivity of the author is reflected in every chapter of the book.","mnemonic_en":"A subject flies a jet, seeing the world from his own perspective.","cloze_distractors_en":["Submergence","Subservience","Substantiation","Subjugation"],"examples":[{"es":"La subjetividad del autor se refleja en cada capítulo del libro.","en":"The subjectivity of the author is reflected in every chapter of the book."},{"es":"Debido a la subjetividad inherente a las entrevistas cualitativas, los investigadores deben ser muy cuidadosos al analizar los datos.","en":"Due to the subjectivity inherent in qualitative interviews, researchers must be very careful when analyzing the data."},{"es":"El comité académico criticó el ensayo por su excesiva subjetividad al tratar temas que requieren un análisis objetivo.","en":"The academic committee criticized the essay for its excessive subjectivity when addressing topics that require objective analysis."}]},{"spanish_text":"Correlación","english_text":"Correlation","section_name":"Academic English","part_of_speech":"noun","definition_en":"A statistical measure that describes the extent to which two variables change together.","main_translations_es":["Relación estadística","Correspondencia","Vínculo"],"collocations":["high correlation","strong correlation","positive correlation","negative correlation"],"synonyms_en":["association","relationship","linkage"],"example_sentence":"There is a strong correlation between sugar consumption and the incidence of diabetes.","example_es":"Existe una fuerte correlación entre el consumo de azúcar y la incidencia de diabetes.","example_en":"There is a strong correlation between sugar consumption and the incidence of diabetes.","mnemonic_en":"Picture a coral reef where fish swim in perfect correlation, echoing the Spanish correlación.","cloze_distractors_en":["Contradiction","Dislocation","Fabrication","Indication"],"examples":[{"es":"Existe una fuerte correlación entre el consumo de azúcar y la incidencia de diabetes.","en":"There is a strong correlation between sugar consumption and the incidence of diabetes."},{"es":"El estudio demostró una correlación directa entre las horas de estudio y las calificaciones finales de los alumnos.","en":"The study demonstrated a direct correlation between study hours and students'' final grades."},{"es":"Los investigadores no pudieron establecer ninguna correlación significativa entre el clima y el comportamiento del mercado bursátil.","en":"The researchers could not establish any significant correlation between the weather and stock market behavior."}]},{"spanish_text":"Causalidad","english_text":"Causation","section_name":"Academic English","part_of_speech":"noun","definition_en":"The relationship in which one event or action causes another to occur.","main_translations_es":["Causa","Relación causal"],"collocations":["cause and effect","causation and correlation","prove causation"],"synonyms_en":["cause","causal relationship","cause-effect"],"example_sentence":"The causation between smoking and lung cancer is well established.","example_es":"La causalidad entre fumar y el cáncer de pulmón está bien establecida.","example_en":"The causation between smoking and lung cancer is well established.","mnemonic_en":"Picture a cause chain labeled causa linking events, reminding you that causalidad means causation.","cloze_distractors_en":["Cohesion","Collusion","Coalescence","Contention"],"examples":[{"es":"La causalidad entre fumar y el cáncer de pulmón está bien establecida.","en":"The causation between smoking and lung cancer is well established."},{"es":"Los investigadores tuvieron dificultades para demostrar la causalidad directa entre el nuevo fármaco y los efectos secundarios observados.","en":"The researchers struggled to demonstrate a direct causation between the new drug and the observed side effects."},{"es":"Es fundamental distinguir entre una simple correlación estadística y una verdadera causalidad en los estudios sociológicos.","en":"It is essential to distinguish between a mere statistical correlation and true causation in sociological studies."}]},{"spanish_text":"Distribución","english_text":"Distribution","section_name":"Academic English","part_of_speech":"noun","definition_en":"The act of giving out or spreading something, or the way in which something is shared or dispersed.","main_translations_es":["Distribución","Reparto"],"collocations":["distribution network","probability distribution","distribution channel","distribution system"],"synonyms_en":["dispersion","allocation","supply"],"example_sentence":"The distribution of the resources was carried out equitably.","example_es":"La distribución de los recursos se realizó de manera equitativa.","example_en":"The distribution of the resources was carried out equitably.","mnemonic_en":"Picture a distributor handing out pizza slices, a vivid distribución of food across the table.","cloze_distractors_en":["Contradiction","Substitution","Contribution","Constitution"],"examples":[{"es":"La distribución de los recursos se realizó de manera equitativa.","en":"The distribution of the resources was carried out equitably."},{"es":"El estudio analiza la distribución geográfica de las especies en peligro de extinción.","en":"The study analyzes the geographic distribution of endangered species."},{"es":"La empresa optimizó la distribución de sus productos a través de una nueva red logística.","en":"The company optimized the distribution of its products through a new logistics network."}]},{"spanish_text":"Desviación","english_text":"Deviation","section_name":"Academic English","part_of_speech":"noun","definition_en":"A departure from a standard, norm, or expected course.","main_translations_es":["Desviación"],"collocations":["standard deviation","deviation from the norm","maximum deviation","acceptable deviation"],"synonyms_en":["divergence","variance","drift"],"example_sentence":"The deviation of the experimental results from the initial hypothesis suggests an error in the procedure.","example_es":"La desviación de los resultados experimentales respecto a la hipótesis inicial sugiere un error en el procedimiento.","example_en":"The deviation of the experimental results from the initial hypothesis suggests an error in the procedure.","mnemonic_en":"Imagine a road that deviates like a sign saying Desviación pointing off the main path.","cloze_distractors_en":["Concession","Affiliation","Allocation"],"examples":[{"es":"La desviación de los resultados experimentales respecto a la hipótesis inicial sugiere un error en el procedimiento.","en":"The deviation of the experimental results from the initial hypothesis suggests an error in the procedure."},{"es":"El informe estadístico analiza la desviación estándar de los ingresos familiares durante la última década.","en":"The statistical report analyzes the standard deviation of household income over the last decade."},{"es":"Cualquier desviación significativa del protocolo de seguridad debe ser reportada inmediatamente al comité de ética.","en":"Any significant deviation from the safety protocol must be reported immediately to the ethics committee."}]},{"spanish_text":"Consistencia","english_text":"Consistency","section_name":"Academic English","part_of_speech":"noun","definition_en":"The quality of being consistent, or the ability to remain the same over time or across situations.","main_translations_es":["Coherencia","Uniformidad","Solidez"],"collocations":["consistency is key","maintain consistency","lack of consistency","consistency over time"],"synonyms_en":["uniformity","coherence","stability"],"example_sentence":"The consistency of the data in the report is fundamental to ensure the validity of the results.","example_es":"La consistencia de los datos en el informe es fundamental para garantizar la validez de los resultados.","example_en":"The consistency of the data in the report is fundamental to ensure the validity of the results.","mnemonic_en":"Picture a solid brick wall labeled consistencia that never wavers, teaching consistency.","cloze_distractors_en":["Volatility","Fragility","Ambiguity"],"examples":[{"es":"La consistencia de los datos en el informe es fundamental para garantizar la validez de los resultados.","en":"The consistency of the data in the report is fundamental to ensure the validity of the results."},{"es":"El profesor destacó la falta de consistencia en los argumentos presentados durante el debate académico.","en":"The professor highlighted the lack of consistency in the arguments presented during the academic debate."},{"es":"Para lograr un éxito duradero, es necesario mantener una consistencia rigurosa en la metodología de investigación.","en":"To achieve lasting success, it is necessary to maintain rigorous consistency in the research methodology."}]},{"spanish_text":"Precisión","english_text":"Accuracy","section_name":"Academic English","part_of_speech":"noun","definition_en":"The quality or state of being correct, exact, or precise.","main_translations_es":["Exactitud","Precisión","Fidelidad"],"collocations":["high accuracy","accuracy rate","accuracy of the measurement","accuracy level"],"synonyms_en":["precision","exactness","correctness"],"example_sentence":"The accuracy of the Swiss watch is impressive.","example_es":"La precisión del reloj suizo es impresionante.","example_en":"The accuracy of the Swiss watch is impressive.","mnemonic_en":"Picture a precise city (precisión) where every arrow hits the bullseye, showing perfect accuracy.","cloze_distractors_en":["Optimism","Reluctance","Negligence"],"examples":[{"es":"La precisión del reloj suizo es impresionante.","en":"The accuracy of the Swiss watch is impressive."},{"es":"El científico destacó la precisión de los datos obtenidos durante el experimento.","en":"The scientist highlighted the accuracy of the data obtained during the experiment."},{"es":"Se requiere una gran precisión al realizar mediciones en el laboratorio de química.","en":"Great accuracy is required when taking measurements in the chemistry laboratory."}]},{"spanish_text":"Relevancia","english_text":"Relevance","section_name":"Academic English","part_of_speech":"noun","definition_en":"The quality of being relevant or applicable to a particular matter.","main_translations_es":["Importancia","Pertinencia","Significancia"],"collocations":["of relevance","relevance to the issue","in terms of relevance","relevance in the context"],"synonyms_en":["importance","significance","pertinence"],"example_sentence":"The relevance of scientific data is essential for making informed decisions.","example_es":"La relevancia de los datos científicos es fundamental para tomar decisiones informadas.","example_en":"The relevance of scientific data is essential for making informed decisions.","mnemonic_en":"Picture a bright badge labeled relevancia that marks the most relevant piece of information.","cloze_distractors_en":["Negligence","Compliance","Resilience","Eloquence"],"examples":[{"es":"La relevancia de los datos científicos es fundamental para tomar decisiones informadas.","en":"The relevance of scientific data is essential for making informed decisions."},{"es":"El comité cuestionó la relevancia de incluir estadísticas históricas en un informe sobre tendencias futuras.","en":"The committee questioned the relevance of including historical statistics in a report on future trends."},{"es":"Debemos evaluar la relevancia de cada fuente bibliográfica antes de integrarla en nuestra tesis doctoral.","en":"We must evaluate the relevance of each bibliographic source before integrating it into our doctoral thesis."}]},{"spanish_text":"Pertinencia","english_text":"Appropriateness","section_name":"Academic English","part_of_speech":"noun","definition_en":"The quality of being suitable or fitting for a particular purpose, situation, or person.","main_translations_es":["Relevancia","Adecuación","Conveniencia"],"collocations":["appropriateness of the decision","assess the appropriateness","in terms of appropriateness","question of appropriateness"],"synonyms_en":["suitability","relevance","fit"],"example_sentence":"The appropriateness of his remarks improved the group''s discussion.","example_es":"La pertinencia de sus comentarios mejoró la discusión del grupo.","example_en":"The appropriateness of his remarks improved the group''s discussion.","mnemonic_en":"Picture a proper teen sailing a sea, perfectly fitting the situation—like pertinencia.","cloze_distractors_en":["Unwillingness","Displacement","Insolvency","Immediacy"],"examples":[{"es":"La pertinencia de sus comentarios mejoró la discusión del grupo.","en":"The appropriateness of his remarks improved the group''s discussion."},{"es":"El comité evaluó la pertinencia de los datos presentados en el informe financiero.","en":"The committee evaluated the appropriateness of the data presented in the financial report."},{"es":"Debemos cuestionar la pertinencia de incluir este gráfico complejo en una presentación tan breve.","en":"We must question the appropriateness of including this complex chart in such a brief presentation."}]},{"spanish_text":"Muestra representativa","english_text":"Representative sample","section_name":"Academic English","part_of_speech":"noun","definition_en":"A subset of a population that accurately reflects the characteristics of the whole group.","main_translations_es":["Muestra típica","Muestra representativa","Muestra aleatoria representativa"],"collocations":["a representative sample of the population","representative sample size","representative sample data","representative sample study"],"synonyms_en":["typical sample","illustrative sample","exemplary sample"],"example_sentence":"For the study, we took a representative sample of the population.","example_es":"Para el estudio, tomamos una muestra representativa de la población.","example_en":"For the study, we took a representative sample of the population.","mnemonic_en":"A rep hands out a sample of muestra, showing the perfect representative sample","cloze_distractors_en":["Contradictory segment","Hypothetical fraction","Inconsistent portion","Unreliable fragment"],"examples":[{"es":"Para el estudio, tomamos una muestra representativa de la población.","en":"For the study, we took a representative sample of the population."},{"es":"El investigador seleccionó una muestra representativa de los estudiantes para analizar sus hábitos de lectura.","en":"The researcher selected a representative sample of the students to analyze their reading habits."},{"es":"Los resultados de la encuesta no son válidos porque no se utilizó una muestra representativa de los consumidores.","en":"The survey results are not valid because they did not use a representative sample of the consumers."}]},{"spanish_text":"Criterio de selección","english_text":"Selection criteria","section_name":"Academic English","part_of_speech":"noun","definition_en":"Selection criteria are the standards or requirements used to choose among alternatives.","main_translations_es":["Criterio de elección","Parámetro de selección","Criterio de escogencia"],"collocations":["meet the selection criteria","selection criteria for","establish selection criteria","selection criteria include"],"synonyms_en":["eligibility standards","qualification requirements","choice parameters"],"example_sentence":"The committee established a rigorous selection criteria to filter the candidates for the research position.","example_es":"El comité estableció un criterio de selección riguroso para filtrar a los candidatos al puesto de investigador.","example_en":"The committee established a rigorous selection criteria to filter the candidates for the research position.","mnemonic_en":"Picture a judge ticking a ''selection criteria'' list titled ''Criterio de selección''.","cloze_distractors_en":["Evolutionary hypothesis","Geographical boundaries","Institutional narratives","Experimental anomalies"],"examples":[{"es":"El comité estableció un criterio de selección riguroso para filtrar a los candidatos al puesto de investigador.","en":"The committee established a rigorous selection criteria to filter the candidates for the research position."},{"es":"Debemos revisar el criterio de selección antes de proceder con la compra de los nuevos equipos de laboratorio.","en":"We must review the selection criteria before proceeding with the purchase of the new laboratory equipment."},{"es":"El criterio de selección para publicar en esta revista científica exige una metodología experimental impecable.","en":"The selection criteria for publishing in this scientific journal requires an impeccable experimental methodology."}]},{"spanish_text":"Recopilar datos","english_text":"Collect data","section_name":"Academic English","part_of_speech":"verb","definition_en":"To gather or obtain information, typically for analysis or record-keeping.","main_translations_es":["Recoger datos","Obtener datos","Compilar datos"],"collocations":["collect data from","collect data on","collect data for analysis","collect data efficiently"],"synonyms_en":["gather data","compile data","record data"],"example_sentence":"The team needs to collect data before presenting the report.","example_es":"El equipo necesita recopilar datos antes de presentar el informe.","example_en":"The team needs to collect data before presenting the report.","mnemonic_en":"I collect data, re‑cop all the facts like a copycat scientist.","cloze_distractors_en":["Fabricate evidence","Disregard logic","Exaggerate findings","Abandon consensus"],"examples":[{"es":"El equipo necesita recopilar datos antes de presentar el informe.","en":"The team needs to collect data before presenting the report."},{"es":"Los investigadores deben recopilar datos mediante encuestas para validar su hipótesis.","en":"Researchers must collect data through surveys to validate their hypothesis."},{"es":"Durante el experimento, es fundamental recopilar datos precisos sobre la temperatura del sistema.","en":"During the experiment, it is essential to collect data regarding the system temperature."}]},{"spanish_text":"Procesar datos","english_text":"Process data","section_name":"Academic English","part_of_speech":"verb","definition_en":"To manipulate or handle data in order to extract information or perform operations on it.","main_translations_es":["Tratar datos","Manejar datos","Analizar datos"],"collocations":["process data efficiently","process data in real time","process large datasets","process data securely"],"synonyms_en":["handle data","manage data","analyze data"],"example_sentence":"We need to process data before generating the report.","example_es":"Necesitamos procesar datos antes de generar el informe.","example_en":"We need to process data before generating the report.","mnemonic_en":"Picture a processor blending raw numbers like a kitchen blender, turning data into smooth info.","cloze_distractors_en":["Fabricate evidence","Circulate rumors","Navigate obstacles","Exaggerate findings"],"examples":[{"es":"Necesitamos procesar datos antes de generar el informe.","en":"We need to process data before generating the report."},{"es":"El departamento de finanzas utiliza algoritmos avanzados para procesar datos financieros de miles de transacciones diarias.","en":"The finance department uses advanced algorithms to process data from thousands of daily transactions."},{"es":"El equipo de investigación tardará varias semanas en procesar datos provenientes de los experimentos.","en":"The research team will take several weeks to process data gathered from the experiments."}]},{"spanish_text":"Respaldado por evidencia","english_text":"Evidence-based","section_name":"Academic English","part_of_speech":"adjective","definition_en":"Based on or derived from evidence.","main_translations_es":["Basado en evidencia","Fundamentado en evidencia","Sustentado por evidencia"],"collocations":["evidence-based practice","evidence-based approach","evidence-based medicine","evidence-based policy"],"synonyms_en":["empirically supported","data-driven","research-backed"],"example_sentence":"The new treatment is evidence-based, relying on rigorous clinical trials.","example_es":"El nuevo tratamiento está respaldado por evidencia científica.","example_en":"The new treatment is evidence-based, relying on rigorous clinical trials.","mnemonic_en":"Picture a sturdy back supporting piles of evidence like a bookshelf.","cloze_distractors_en":["Intuition-led","Emotion-based","Opinion-driven","Speculation-led"],"examples":[{"es":"El nuevo tratamiento está respaldado por evidencia científica.","en":"The new treatment is evidence-based, relying on rigorous clinical trials."},{"es":"La política educativa debe ser respaldado por evidencia para mejorar el rendimiento escolar.","en":"The school board insists that all curriculum changes must be evidence-based to ensure student success."},{"es":"Las políticas de salud pública deben ser respaldadas por evidencia para garantizar que las intervenciones sean realmente efectivas.","en":"Public health policies must be evidence-based to ensure that interventions are truly effective."}]},{"spanish_text":"Sustancial","english_text":"Substantial","section_name":"Academic English","part_of_speech":"adjective","definition_en":"Considerable in amount, size, or importance; significant.","main_translations_es":["significativo","considerable","importante"],"collocations":["substantial amount","substantial evidence","substantial increase","substantial impact"],"synonyms_en":["considerable","significant","sizeable"],"example_sentence":"The increase in investment was substantial this year.","example_es":"El aumento de la inversión fue sustancial este año.","example_en":"The increase in investment was substantial this year.","mnemonic_en":"A SUBstantial pillar sustains the building, showing how big and essential it is.","cloze_distractors_en":["Subservient","Subliminal","Subaqueous"],"examples":[{"es":"El aumento de la inversión fue sustancial este año.","en":"The increase in investment was substantial this year."},{"es":"El equipo de investigación encontró una diferencia sustancial en los resultados del experimento.","en":"The research team found a substantial difference in the experiment results."},{"es":"La nueva normativa ha provocado un cambio sustancial en la gestión de los residuos industriales.","en":"The new regulation has caused a substantial change in the management of industrial waste."}]},{"spanish_text":"Marginal","english_text":"Marginal","section_name":"Academic English","part_of_speech":"adjective","definition_en":"Existing or situated at the edge or margin, or being only barely sufficient.","main_translations_es":["periférico","secundario","de poca importancia"],"collocations":["marginal cost","marginal benefit","marginal increase","marginally"],"synonyms_en":[],"example_sentence":"The marginal increase in price will not affect most consumers.","example_es":"El aumento marginal del precio no afectará a la mayoría de los consumidores.","example_en":"The marginal increase in price will not affect most consumers.","mnemonic_en":null,"cloze_distractors_en":[],"examples":[{"es":"El aumento marginal del precio no afectará a la mayoría de los consumidores.","en":"The marginal increase in price will not affect most consumers."}]},{"spanish_text":"Significativo","english_text":"Significant","section_name":"Academic English","part_of_speech":"adjective","definition_en":"Important or notable enough to be worthy of attention.","main_translations_es":["Importante","Relevante","Notable"],"collocations":["significant impact","significant difference","significant role","significant amount"],"synonyms_en":["important","meaningful","notable"],"example_sentence":"This finding is significant for the research.","example_es":"Este hallazgo es significativo para la investigación.","example_en":"This finding is significant for the research.","mnemonic_en":"A bright sign on the hill marks a significant moment, just like significativo means important.","cloze_distractors_en":["Vegetative","Punctual","Symmetrical","Melodramatic"],"examples":[{"es":"Este hallazgo es significativo para la investigación.","en":"This finding is significant for the research."},{"es":"Hubo un cambio significativo en los resultados después de ajustar las variables.","en":"There was a significant change in the results after adjusting the variables."},{"es":"La empresa reportó un incremento significativo en sus beneficios trimestrales.","en":"The company reported a significant increase in its quarterly profits."}]},{"spanish_text":"Insignificante","english_text":"Negligible","section_name":"Academic English","part_of_speech":"adjective","definition_en":"so small or unimportant that it is not worth considering","main_translations_es":["Irrelevante","Trivial","Mínimo"],"collocations":["negligible amount","negligible impact","negligible risk","negligible difference"],"synonyms_en":["insignificant","trivial","minor"],"example_sentence":"The impact of that mistake is negligible on the final result.","example_es":"El impacto de ese error es insignificante en el resultado final.","example_en":"The impact of that mistake is negligible on the final result.","mnemonic_en":"Picture a negligible speck of dust that the word insignificant (insignificante) can’t even notice.","cloze_distractors_en":["Compulsory","Formidable","Plausible","Voluminous"],"examples":[{"es":"El impacto de ese error es insignificante en el resultado final.","en":"The impact of that mistake is negligible on the final result."},{"es":"La diferencia de temperatura entre las dos muestras resultó ser insignificante para el experimento.","en":"The temperature difference between the two samples proved to be negligible for the experiment."},{"es":"Debido a la insignificante cantidad de residuos químicos, no se requiere un protocolo de limpieza especial.","en":"Due to the negligible amount of chemical residue, no special cleaning protocol is required."}]},{"spanish_text":"Rigurosidad","english_text":"Rigor","section_name":"Academic English","part_of_speech":"noun","definition_en":"strictness or exactness in standards, procedures, or analysis","main_translations_es":["rigor","exigencia","meticulosidad"],"collocations":["academic rigor","rigor of the test","rigor in methodology","rigor and precision"],"synonyms_en":["strictness","severity","exactness"],"example_sentence":"The rigor of the scientific method ensures reliable results.","example_es":"La rigurosidad del método científico garantiza resultados confiables.","example_en":"The rigor of the scientific method ensures reliable results.","mnemonic_en":"Imagine a strict ruler measuring with rigor, echoing the Spanish riguroso in every precise line.","cloze_distractors_en":["Vigor","Stigma","Fervor","Rancor"],"examples":[{"es":"La rigurosidad del método científico garantiza resultados confiables.","en":"The rigor of the scientific method ensures reliable results."},{"es":"El comité editorial elogió la rigurosidad con la que se analizaron los datos estadísticos.","en":"The editorial committee praised the rigor with which the statistical data were analyzed."},{"es":"Se requiere mayor rigurosidad en la revisión de las fuentes bibliográficas para evitar errores de citación.","en":"Greater rigor is required in the review of bibliographic sources to avoid citation errors."}]},{"spanish_text":"Coherencia","english_text":"Coherence","section_name":"Academic English","part_of_speech":"noun","definition_en":"The quality of being logical, consistent, and forming a unified whole.","main_translations_es":["Consistencia","Lógica","Congruencia"],"collocations":["lack of coherence","maintain coherence","coherence theory","coherence in writing"],"synonyms_en":["consistency","logicality","unity"],"example_sentence":"The coherence of the argument made everyone accept it.","example_es":"La coherencia del argumento hizo que todos lo aceptaran.","example_en":"The coherence of the argument made everyone accept it.","mnemonic_en":"Picture a coherent choir chanting coherencia in perfect harmony.","cloze_distractors_en":["Compliance","Conjecture","Concordance"],"examples":[{"es":"La coherencia del argumento hizo que todos lo aceptaran.","en":"The coherence of the argument made everyone accept it."},{"es":"El profesor señaló que al ensayo le faltaba coherencia entre los párrafos introductorios y la conclusión.","en":"The professor pointed out that the essay lacked coherence between the introductory paragraphs and the conclusion."},{"es":"Para mejorar la coherencia de su presentación, el estudiante utilizó conectores lógicos entre las diapositivas.","en":"To improve the coherence of his presentation, the student used logical connectors between the slides."}]},{"spanish_text":"Claridad","english_text":"Clarity","section_name":"Academic English","part_of_speech":"noun","definition_en":"The quality of being clear, easily understood, or transparent.","main_translations_es":["Nitidez","Lucidez","Transparencia"],"collocations":["crystal clear","gain clarity","lack of clarity","clear as day"],"synonyms_en":["clearness","lucidity","transparency"],"example_sentence":"The clarity of the lake''s water was impressive.","example_es":"La claridad del agua del lago era impresionante.","example_en":"The clarity of the lake''s water was impressive.","mnemonic_en":"Picture a crystal clear lake called Claridad reflecting perfect clarity","cloze_distractors_en":["Density","Gravity","Velocity","Humidity"],"examples":[{"es":"La claridad del agua del lago era impresionante.","en":"The clarity of the lake''s water was impressive."},{"es":"El profesor insistió en la claridad de los argumentos presentados en el ensayo.","en":"The professor insisted on the clarity of the arguments presented in the essay."},{"es":"El orador se esforzó por mantener la claridad durante toda su presentación técnica.","en":"The speaker strived to maintain clarity throughout his technical presentation."}]},{"spanish_text":"Concisión","english_text":"Conciseness","section_name":"Academic English","part_of_speech":"noun","definition_en":"The quality of being brief and to the point in speech or writing.","main_translations_es":["Brevedad","Precisión","Sucintez"],"collocations":["value of conciseness","conciseness is key","in the interest of conciseness","conciseness and clarity"],"synonyms_en":["brevity","succinctness","terse style"],"example_sentence":"The professor emphasized that conciseness is essential for readers to quickly grasp the main arguments of an essay.","example_es":"El profesor enfatizó que la concisión es fundamental para que los lectores comprendan rápidamente los argumentos principales de un ensayo.","example_en":"The professor emphasized that conciseness is essential for readers to quickly grasp the main arguments of an essay.","mnemonic_en":"A tiny cactus says concisión while staying short and sharp.","cloze_distractors_en":["Verbosity","Redundancy","Complexity","Ambiguity"],"examples":[{"es":"El profesor enfatizó que la concisión es fundamental para que los lectores comprendan rápidamente los argumentos principales de un ensayo.","en":"The professor emphasized that conciseness is essential for readers to quickly grasp the main arguments of an essay."},{"es":"Para mejorar la calidad de su informe técnico, debe priorizar la concisión y eliminar cualquier detalle irrelevante que distraiga al lector.","en":"To improve the quality of your technical report, you must prioritize conciseness and remove any irrelevant details that distract the reader."},{"es":"Durante la presentación, el orador fue elogiado por su notable concisión al explicar conceptos complejos en muy poco tiempo.","en":"During the presentation, the speaker was praised for his remarkable conciseness in explaining complex concepts in very little time."}]},{"spanish_text":"Ampliar","english_text":"Elaborate on","section_name":"Academic English","part_of_speech":"verb","definition_en":"To give more detail or expand upon something.","main_translations_es":["Extender","Desarrollar","Expandir"],"collocations":["elaborate on the details","elaborate on the plan","elaborate on his statement"],"synonyms_en":["expound upon","go into detail","provide details"],"example_sentence":"The professor asked the student to elaborate on his argument regarding climate change.","example_es":"El profesor pidió al estudiante que ampliara su argumento sobre el cambio climático.","example_en":"The professor asked the student to elaborate on his argument regarding climate change.","mnemonic_en":"Picture a lab that expands—ampliar the lab—to elaborate on the experiment.","cloze_distractors_en":["Fabricate on","Exaggerate on","Contradict on","Obfuscate on"],"examples":[{"es":"El profesor pidió al estudiante que ampliara su argumento sobre el cambio climático.","en":"The professor asked the student to elaborate on his argument regarding climate change."},{"es":"Durante la entrevista, el candidato tuvo que ampliar su experiencia previa en gestión de proyectos.","en":"During the interview, the candidate had to elaborate on his previous experience in project management."},{"es":"Es necesario ampliar la metodología utilizada en este estudio para entender mejor los resultados.","en":"It is necessary to elaborate on the methodology used in this study to better understand the results."}]},{"spanish_text":"Resumir","english_text":"Summarize","section_name":"Academic English","part_of_speech":"verb","definition_en":"To give a brief statement of the main points of something.","main_translations_es":["Sintetizar","Abreviar","Compendiar"],"collocations":["summarize the main points","summarize the findings","summarize the report","summarize briefly"],"synonyms_en":["condense","recap","give an overview"],"example_sentence":"Please summarize the article in three sentences.","example_es":"Por favor, resume el artículo en tres frases.","example_en":"Please summarize the article in three sentences.","mnemonic_en":"Summarize feels like a résumé being trimmed, just as the Spanish Resumir means to condense.","cloze_distractors_en":["Fabricate","Exaggerate","Complicate"],"examples":[{"es":"Por favor, resume el artículo en tres frases.","en":"Please summarize the article in three sentences."},{"es":"El profesor pidió a los estudiantes que resuman los hallazgos principales de su investigación.","en":"The professor asked the students to summarize the main findings of their research."},{"es":"Es necesario resumir los datos estadísticos para que la audiencia comprenda las tendencias actuales.","en":"It is necessary to summarize the statistical data so that the audience understands the current trends."}]},{"spanish_text":"Parafrasear","english_text":"Paraphrase","section_name":"Academic English","part_of_speech":"noun","definition_en":"A restatement of a text or passage using different words, especially to achieve greater clarity.","main_translations_es":["Reformular","Expresar con otras palabras","Decir de otra manera"],"collocations":["to paraphrase the text","in other words","to paraphrase the author","as a paraphrase"],"synonyms_en":["restate","reword","put in other words"],"example_sentence":"Can you paraphrase what I said to make it clearer?","example_es":"¿Puedes parafrasear lo que dije para que sea más claro?","example_en":"Can you paraphrase what I said to make it clearer?","mnemonic_en":"Imagine a pair of phrase books dancing, each saying para-phrase as they paraphrase.","cloze_distractors_en":["Fabricate","Circumvent","Contradict"],"examples":[{"es":"¿Puedes parafrasear lo que dije para que sea más claro?","en":"Can you paraphrase what I said to make it clearer?"},{"es":"Es necesario parafrasear las citas directas para evitar el plagio en tu ensayo académico.","en":"It is necessary to paraphrase direct quotes to avoid plagiarism in your academic essay."},{"es":"El profesor nos pidió parafrasear el texto original usando nuestras propias palabras.","en":"The professor asked us to paraphrase the original text using our own words."}]},{"spanish_text":"Citar","english_text":"Cite","section_name":"Academic English","part_of_speech":"verb","definition_en":"To quote or refer to a source as evidence or support.","main_translations_es":["Citar","Mencionar","Referenciar"],"collocations":["cite a source","cite evidence","cite references","cite in APA style"],"synonyms_en":["quote","reference","mention"],"example_sentence":"The article cites several experts on climate change.","example_es":"El artículo cita a varios expertos sobre el cambio climático.","example_en":"The article cites several experts on climate change.","mnemonic_en":"Picture a chef sprinkling citations like a chef saying citar to flavor a dish","cloze_distractors_en":[],"examples":[{"es":"El artículo cita a varios expertos sobre el cambio climático.","en":"The article cites several experts on climate change."},{"es":"Es obligatorio citar todas las fuentes bibliográficas al final del ensayo académico.","en":"It is mandatory to cite all bibliographic sources at the end of the academic essay."},{"es":"El abogado decidió citar un precedente legal para fortalecer su argumento ante el juez.","en":"The lawyer decided to cite a legal precedent to strengthen his argument before the judge."}]},{"spanish_text":"Referenciar","english_text":"Reference","section_name":"Academic English","part_of_speech":"noun","definition_en":"A source of information that is cited or consulted.","main_translations_es":["Citar","Mencionar","Aludir"],"collocations":["reference letter","reference point","make reference to","for reference"],"synonyms_en":["citation","source","mention"],"example_sentence":"It is important to reference all sources in your research paper.","example_es":"Es importante referenciar todas las fuentes en tu trabajo de investigación.","example_en":"It is important to reference all sources in your research paper.","mnemonic_en":"Picture a referee handing out a reference sheet, just like you referenciar a source.","cloze_distractors_en":["Fabricate","Disregard","Exaggerate","Contaminate"],"examples":[{"es":"Es importante referenciar todas las fuentes en tu trabajo de investigación.","en":"It is important to reference all sources in your research paper."},{"es":"El profesor pidió a los estudiantes referenciar cada cita directa en sus ensayos académicos.","en":"The professor asked the students to reference every direct quote in their academic essays."},{"es":"Debes referenciar los datos estadísticos que utilizaste para respaldar tu argumento principal.","en":"You must reference the statistical data you used to support your main argument."}]},{"spanish_text":"Notas a pie de página","english_text":"Footnotes","section_name":"Academic English","part_of_speech":"noun","definition_en":"Notes placed at the bottom of a page that give additional information or citations.","main_translations_es":["Notas al pie","Notas de pie de página","Referencias al pie"],"collocations":["in the footnotes","footnotes section","footnotes and endnotes","footnotes reference"],"synonyms_en":["endnotes","annotations","reference notes"],"example_sentence":"The footnotes explain the technical terms of the article.","example_es":"Las notas a pie de página explican los términos técnicos del artículo.","example_en":"The footnotes explain the technical terms of the article.","mnemonic_en":"Imagine tiny feet writing notes at the bottom of a page.","cloze_distractors_en":["Headlines","Backdrops","Thumbnails","Benchmarks"],"examples":[{"es":"Las notas a pie de página explican los términos técnicos del artículo.","en":"The footnotes explain the technical terms of the article."},{"es":"El profesor pidió que incluyéramos las referencias bibliográficas en las notas a pie de página.","en":"The professor requested that we include the bibliographic references in the footnotes."},{"es":"Debes revisar las notas a pie de página para verificar la fuente de esta cita histórica.","en":"You must check the footnotes to verify the source of this historical quote."}]},{"spanish_text":"Apéndice","english_text":"Appendix","section_name":"Academic English","part_of_speech":"noun","definition_en":"A supplementary section at the end of a book or document, or a small organ attached to the large intestine.","main_translations_es":["Anexo","Suplemento","Apéndice"],"collocations":["in the appendix","appendix A","see the appendix","appendix section"],"synonyms_en":["addendum","supplement","annex"],"example_sentence":"The appendix of the book contains additional information about the history.","example_es":"El apéndice del libro contiene información adicional sobre la historia.","example_en":"The appendix of the book contains additional information about the history.","mnemonic_en":"Picture a tiny appendix attached to a book, just like the Spanish apéndice sticks onto the page.","cloze_distractors_en":["Preamble","Synopsis","Epilogue","Abstract"],"examples":[{"es":"El apéndice del libro contiene información adicional sobre la historia.","en":"The appendix of the book contains additional information about the history."},{"es":"Por favor, consulte el apéndice para ver las tablas estadísticas detalladas del estudio.","en":"Please consult the appendix to view the detailed statistical tables from the study."},{"es":"El autor incluyó un apéndice con los documentos originales para respaldar sus argumentos.","en":"The author included an appendix with the original documents to support his arguments."}]},{"spanish_text":"Resumen ejecutivo","english_text":"Executive summary","section_name":"Academic English","part_of_speech":"noun","definition_en":"A brief overview of a document''s main points, usually placed at the beginning.","main_translations_es":["Síntesis ejecutiva","Informe ejecutivo","Resumen de gestión"],"collocations":["prepare an executive summary","include an executive summary","the executive summary outlines","executive summary section"],"synonyms_en":["summary","overview","brief"],"example_sentence":"The consultant drafted an executive summary to present the report''s key findings to the board of directors.","example_es":"El consultor redactó un resumen ejecutivo para presentar los hallazgos principales del informe a la junta directiva.","example_en":"The consultant drafted an executive summary to present the report''s key findings to the board of directors.","mnemonic_en":"Think of a boss (executive) giving a quick sum—''re-sum-en'' as the executive summary.","cloze_distractors_en":["Executive manifesto","Executive curriculum","Executive hypothesis","Executive bibliography"],"examples":[{"es":"El consultor redactó un resumen ejecutivo para presentar los hallazgos principales del informe a la junta directiva.","en":"The consultant drafted an executive summary to present the report''s key findings to the board of directors."},{"es":"Antes de leer el documento completo de cincuenta páginas, los inversores revisaron el resumen ejecutivo para evaluar la viabilidad del proyecto.","en":"Before reading the full fifty-page document, the investors reviewed the executive summary to assess the project''s viability."},{"es":"La directora solicitó que el resumen ejecutivo fuera conciso y destacara únicamente las recomendaciones estratégicas más importantes.","en":"The director requested that the executive summary be concise and highlight only the most important strategic recommendations."}]},{"spanish_text":"Pregunta de investigación","english_text":"Research question","section_name":"Academic English","part_of_speech":"noun","definition_en":"A question that guides the focus and direction of a research study.","main_translations_es":["Cuestión de investigación","Pregunta de estudio","Interrogante de investigación"],"collocations":["formulate a research question","address the research question","answer the research question","research question formulation"],"synonyms_en":["investigative query","study question","inquiry"],"example_sentence":"The research question of my thesis is how climate change affects biodiversity.","example_es":"La pregunta de investigación de mi tesis es cómo afecta el cambio climático a la biodiversidad.","example_en":"The research question of my thesis is how climate change affects biodiversity.","mnemonic_en":"A researcher knocks on a door marked PRETTY GUNTA, demanding the answer to his question.","cloze_distractors_en":["Research feedback","Research limitation","Research background","Research conclusion"],"examples":[{"es":"La pregunta de investigación de mi tesis es cómo afecta el cambio climático a la biodiversidad.","en":"The research question of my thesis is how climate change affects biodiversity."},{"es":"Antes de comenzar el experimento, el profesor nos pidió que formuláramos una pregunta de investigación clara y concisa.","en":"Before starting the experiment, the professor asked us to formulate a clear and concise research question."},{"es":"El comité evaluador rechazó el proyecto porque la pregunta de investigación no estaba suficientemente delimitada.","en":"The review committee rejected the project because the research question was not sufficiently defined."}]},{"spanish_text":"Ámbito de estudio","english_text":"Scope of the study","section_name":"Academic English","part_of_speech":"noun phrase","definition_en":"The range or extent of topics covered by the study.","main_translations_es":["Campo de estudio","Área de estudio","Rama de estudio"],"collocations":["the scope of the study includes","within the scope of the study","the scope of the study was limited","scope of the study determines"],"synonyms_en":["research scope","study range","extent of the study"],"example_sentence":"The scope of the study is molecular biology.","example_es":"El ámbito de estudio de la investigación es la biología molecular.","example_en":"The scope of the study is molecular biology.","mnemonic_en":"Picture a scope zooming over the study''s ambient field.","cloze_distractors_en":["Scale of the perception","Scheme of the biography","Stance of the hypothesis","Sector of the methodology"],"examples":[{"es":"El ámbito de estudio de la investigación es la biología molecular.","en":"The scope of the study is molecular biology."},{"es":"Debemos definir claramente el ámbito de estudio para evitar resultados irrelevantes en el informe.","en":"We must clearly define the scope of the study to avoid irrelevant results in the report."},{"es":"El comité académico decidió ampliar el ámbito de estudio para incluir datos demográficos adicionales.","en":"The academic committee decided to expand the scope of the study to include additional demographic data."}]},{"spanish_text":"Línea de investigación","english_text":"Research line","section_name":"Academic English","part_of_speech":"noun","definition_en":"A specific area or focus within a broader field of study or investigation.","main_translations_es":["Área de investigación","Campo de investigación","Tema de investigación"],"collocations":["establish a research line","follow a research line","new research line","research line in biology"],"synonyms_en":["research focus","study area","investigative track"],"example_sentence":"My research line focuses on artificial intelligence.","example_es":"Mi línea de investigación se centra en la inteligencia artificial.","example_en":"My research line focuses on artificial intelligence.","mnemonic_en":"Visualize a scientist drawing a bright red research line across a map, like a Spanish línea","cloze_distractors_en":["Research lane","Research cord","Research edge"],"examples":[{"es":"Mi línea de investigación se centra en la inteligencia artificial.","en":"My research line focuses on artificial intelligence."},{"es":"El departamento ha definido una nueva línea de investigación sobre el cambio climático en zonas costeras.","en":"The department has defined a new research line regarding climate change in coastal areas."},{"es":"Para su tesis doctoral, ella eligió una línea de investigación poco explorada en la literatura económica.","en":"For her doctoral thesis, she chose a research line that is rarely explored in economic literature."}]},{"spanish_text":"Marco conceptual","english_text":"Conceptual framework","section_name":"Academic English","part_of_speech":"noun","definition_en":"A set of ideas and concepts that provides a structure for understanding or analyzing something.","main_translations_es":["Marco teórico","Estructura conceptual","Esquema conceptual"],"collocations":["within the conceptual framework","conceptual framework of","conceptual framework for","under the conceptual framework"],"synonyms_en":["theoretical model","conceptual model","theoretical framework"],"example_sentence":"The researcher presented a new conceptual framework to understand urban migration.","example_es":"El investigador presentó un nuevo marco conceptual para entender la migración urbana.","example_en":"The researcher presented a new conceptual framework to understand urban migration.","mnemonic_en":"Picture a FRAME (marco) that holds a CONCEPT, a conceptual framework.","cloze_distractors_en":["Categorical blueprint","Empirical landscape","Methodological byproduct","Systemic centerpiece"],"examples":[{"es":"El investigador presentó un nuevo marco conceptual para entender la migración urbana.","en":"The researcher presented a new conceptual framework to understand urban migration."},{"es":"La tesis doctoral propone un marco conceptual sólido para analizar el impacto de la inteligencia artificial en el mercado laboral.","en":"The doctoral thesis proposes a solid conceptual framework to analyze the impact of artificial intelligence on the job market."},{"es":"Antes de iniciar el experimento, el equipo estableció un marco conceptual que define las variables clave del estudio.","en":"Before starting the experiment, the team established a conceptual framework that defines the key variables of the study."}]},{"spanish_text":"Vacío de investigación","english_text":"Research gap","section_name":"Academic English","part_of_speech":"noun","definition_en":"A research gap is an area or topic that has not yet been studied or is insufficiently explored in existing literature.","main_translations_es":["laguna de investigación","hueco de investigación","brecha de investigación"],"collocations":["identify a research gap","address the research gap","fill the research gap","research gap analysis"],"synonyms_en":["knowledge gap","investigative void","unexplored area"],"example_sentence":"The study identifies a research gap in the relationship between diet and mental health.","example_es":"El estudio identifica un vacío de investigación en la relación entre la dieta y la salud mental.","example_en":"The study identifies a research gap in the relationship between diet and mental health.","mnemonic_en":"Picture a vacant (vacío) research lab with a big hole (gap) in the data.","cloze_distractors_en":["Research bridge","Research summit","Research vessel","Research fabric"],"examples":[{"es":"El estudio identifica un vacío de investigación en la relación entre la dieta y la salud mental.","en":"The study identifies a research gap in the relationship between diet and mental health."},{"es":"La tesis doctoral aborda un vacío de investigación sobre el impacto de la inteligencia artificial en el mercado laboral rural.","en":"The doctoral thesis addresses a research gap regarding the impact of artificial intelligence on the rural labor market."},{"es":"Los autores señalan un vacío de investigación importante al no existir datos suficientes sobre el comportamiento de los consumidores en mercados emergentes.","en":"The authors point out a significant research gap due to the lack of sufficient data on consumer behavior in emerging markets."}]},{"spanish_text":"Hallazgo clave","english_text":"Key finding","section_name":"Academic English","part_of_speech":"noun","definition_en":"A significant or important result discovered in a study or investigation.","main_translations_es":["Descubrimiento importante","Resultado principal","Conclusión esencial"],"collocations":["key finding of the study","key finding suggests","key finding highlights","key finding reveals"],"synonyms_en":["major discovery","principal result","main conclusion"],"example_sentence":"The key finding of the study was the relationship between diet and cardiovascular health.","example_es":"El hallazgo clave del estudio fue la relación entre la dieta y la salud cardiovascular.","example_en":"The key finding of the study was the relationship between diet and cardiovascular health.","mnemonic_en":"Picture a golden key finding a hidden hallazgo in a dusty chest","cloze_distractors_en":["Minor anecdote","Casual observation","Random deviation"],"examples":[{"es":"El hallazgo clave del estudio fue la relación entre la dieta y la salud cardiovascular.","en":"The key finding of the study was the relationship between diet and cardiovascular health."},{"es":"Tras analizar los datos, los investigadores presentaron el hallazgo clave que explica el descenso en las ventas.","en":"After analyzing the data, the researchers presented the key finding that explains the decline in sales."},{"es":"El informe final destaca un hallazgo clave sobre la eficacia de las nuevas políticas educativas en zonas rurales.","en":"The final report highlights a key finding regarding the effectiveness of the new educational policies in rural areas."}]},{"spanish_text":"Trabajo seminal","english_text":"Seminal work","section_name":"Academic English","part_of_speech":"noun","definition_en":"A highly influential piece of research or writing that forms the basis for later developments.","main_translations_es":["Obra seminal","Estudio pionero","Trabajo fundamental"],"collocations":["seminal work on","seminal work in","seminal work that","seminal work has"],"synonyms_en":["groundbreaking study","foundational research","pioneering work"],"example_sentence":"Adam Smith''s treatise on the wealth of nations is considered a seminal work that established the fundamental principles of modern economics.","example_es":"El tratado de Adam Smith sobre la riqueza de las naciones se considera un trabajo seminal que estableció los principios fundamentales de la economía moderna.","example_en":"Adam Smith''s treatise on the wealth of nations is considered a seminal work that established the fundamental principles of modern economics.","mnemonic_en":"Picture a seed (seminal) sprouting a giant work of art.","cloze_distractors_en":["Fictitious draft","Superficial gloss","Peripheral scrap","Erroneous glitch"],"examples":[{"es":"El tratado de Adam Smith sobre la riqueza de las naciones se considera un trabajo seminal que estableció los principios fundamentales de la economía moderna.","en":"Adam Smith''s treatise on the wealth of nations is considered a seminal work that established the fundamental principles of modern economics."},{"es":"La profesora citó el trabajo seminal de Keynes para explicar los fundamentos de la macroeconomía moderna.","en":"The professor cited the seminal work of Keynes to explain the foundations of modern macroeconomics."},{"es":"Su tesis doctoral se convirtió en un trabajo seminal que transformó nuestra comprensión sobre la inteligencia artificial.","en":"Her doctoral thesis became a seminal work that transformed our understanding of artificial intelligence."}]},{"spanish_text":"Contribución original","english_text":"Original contribution","section_name":"Academic English","part_of_speech":"noun","definition_en":"A contribution that is new, unique, or created for the first time.","main_translations_es":["Aporte original","Contribución inicial","Aportación original"],"collocations":["make an original contribution","original contribution to the field","significant original contribution","original contribution was recognized"],"synonyms_en":["novel input","unique offering","fresh contribution"],"example_sentence":"His original contribution to the project was essential for gaining the committee''s approval.","example_es":"Su contribución original al proyecto fue fundamental para obtener la aprobación del comité.","example_en":"His original contribution to the project was essential for gaining the committee''s approval.","mnemonic_en":"Think of an original piece as a ''contribución'' to the exhibit.","cloze_distractors_en":["Superficial obstruction","Erroneous withdrawal","Mandatory resignation","Fragmented limitation"],"examples":[{"es":"Su contribución original al proyecto fue fundamental para obtener la aprobación del comité.","en":"His original contribution to the project was essential for gaining the committee''s approval."},{"es":"La tesis doctoral destaca por ser una contribución original al campo de la astrofísica moderna.","en":"The doctoral thesis stands out for being an original contribution to the field of modern astrophysics."},{"es":"El autor busca realizar una contribución original que desafíe las teorías económicas establecidas.","en":"The author seeks to make an original contribution that challenges established economic theories."}]},{"spanish_text":"Líneas futuras","english_text":"Further avenues","section_name":"Academic English","part_of_speech":"noun phrase","definition_en":"Additional possible paths or options for exploration.","main_translations_es":["Nuevas vías","Posibles caminos","Opciones futuras"],"collocations":["explore further avenues","open further avenues","pursue further avenues"],"synonyms_en":["additional paths","new directions","other possibilities"],"example_sentence":"The study concludes by suggesting further avenues of research regarding the impact of climate change on agriculture.","example_es":"El estudio concluye sugiriendo líneas futuras de investigación sobre el impacto del cambio climático en la agricultura.","example_en":"The study concludes by suggesting further avenues of research regarding the impact of climate change on agriculture.","mnemonic_en":"Picture a road of future lines, a further avenue stretching into tomorrow.","cloze_distractors_en":["Previous obstacles","Internal contradictions","Random fluctuations","Hostile environments"],"examples":[{"es":"El estudio concluye sugiriendo líneas futuras de investigación sobre el impacto del cambio climático en la agricultura.","en":"The study concludes by suggesting further avenues of research regarding the impact of climate change on agriculture."},{"es":"Tras analizar los datos actuales, el comité propuso líneas futuras para expandir la presencia de la empresa en mercados internacionales.","en":"After analyzing the current data, the committee proposed further avenues to expand the company''s presence in international markets."},{"es":"La tesis identifica varias líneas futuras que permitirían aplicar este modelo matemático a problemas de ingeniería civil.","en":"The thesis identifies several further avenues that would allow for the application of this mathematical model to civil engineering problems."}]}]'::jsonb) as x(
  spanish_text text, english_text text, section_name text, part_of_speech text, definition_en text,
  main_translations_es jsonb, collocations jsonb, synonyms_en jsonb, example_sentence text, example_es text, example_en text, mnemonic_en text, cloze_distractors_en jsonb, examples jsonb
)
where c.deck_id = dk.id
  and lower(c.spanish_text) = lower(x.spanish_text)
  and lower(c.english_text) = lower(x.english_text);

-- english-news-and-society (104 cards)
update public.decks set
  title = 'News and Society', description = 'Advanced vocabulary for current affairs, social issues, media, technology, and global events.',
  language_from = 'es', language_to = 'en'
where slug = 'english-news-and-society';

update public.cards c set
  section_name = x.section_name, part_of_speech = x.part_of_speech, definition_en = x.definition_en,
  main_translations_es = coalesce(x.main_translations_es, '[]'::jsonb),
  collocations = coalesce(x.collocations, '[]'::jsonb),
  synonyms_en = coalesce(x.synonyms_en, '[]'::jsonb),
  example_sentence = x.example_sentence, example_es = x.example_es, example_en = x.example_en,
  mnemonic_en = coalesce(x.mnemonic_en, c.mnemonic_en),
  cloze_distractors_en = case when jsonb_array_length(coalesce(x.cloze_distractors_en, '[]'::jsonb)) > 0
                              then x.cloze_distractors_en else c.cloze_distractors_en end,
  examples = case when jsonb_array_length(coalesce(x.examples, '[]'::jsonb)) > 0
                  then x.examples else c.examples end
from (select id from public.decks where slug = 'english-news-and-society') dk
cross join jsonb_to_recordset('[{"spanish_text":"Titular","english_text":"Headline","section_name":"News and Society","part_of_speech":"noun","definition_en":"A headline is a brief, attention‑grabbing title that appears at the top of a news article or other written piece.","main_translations_es":["encabezado","título","cabecera"],"collocations":["headline news","catchy headline","headline story","make headlines"],"synonyms_en":["title","heading","banner"],"example_sentence":"The headline in the newspaper announced the team''s victory.","example_es":"El titular del periódico anunciaba la victoria del equipo.","example_en":"The headline in the newspaper announced the team''s victory.","mnemonic_en":"Picture a head with a line of headlines stitched across its crown like a title.","cloze_distractors_en":["Footnote","Deadline","Baseline","Pipeline"],"examples":[{"es":"El titular del periódico anunciaba la victoria del equipo.","en":"The headline in the newspaper announced the team''s victory."},{"es":"El periodista escribió un titular impactante para captar la atención de los lectores.","en":"The journalist wrote a shocking headline to grab the readers'' attention."},{"es":"Todo el mundo comentaba el titular principal sobre la nueva ley económica.","en":"Everyone was discussing the main headline about the new economic law."}]},{"spanish_text":"Cobertura mediática","english_text":"Media coverage","section_name":"News and Society","part_of_speech":"noun","definition_en":"The reporting of an event or topic by various media outlets.","main_translations_es":["Cobertura de prensa","Cobertura informativa","Cobertura periodística"],"collocations":["extensive media coverage","media coverage of the event","receive media coverage","limited media coverage"],"synonyms_en":["press coverage","news reporting","media attention"],"example_sentence":"The media coverage of the accident was extensive and continuous.","example_es":"La cobertura mediática del accidente fue extensa y constante.","example_en":"The media coverage of the accident was extensive and continuous.","mnemonic_en":"The media spreads a blanket (cobertura) over the story.","cloze_distractors_en":["Public ignorance","Social tolerance","Global indifference","Private negligence"],"examples":[{"es":"La cobertura mediática del accidente fue extensa y constante.","en":"The media coverage of the accident was extensive and continuous."},{"es":"El candidato se quejó de que la cobertura mediática estaba sesgada en su contra.","en":"The candidate complained that the media coverage was biased against him."},{"es":"La organización benéfica espera obtener más cobertura mediática para su campaña de recaudación de fondos.","en":"The charity hopes to gain more media coverage for its fundraising campaign."}]},{"spanish_text":"Artículo de fondo","english_text":"Feature article","section_name":"News and Society","part_of_speech":"noun","definition_en":"A feature article is a detailed, in‑depth newspaper or magazine story that explores a topic more comprehensively than a news report.","main_translations_es":["Artículo de fondo","Reportaje de fondo","Artículo extenso"],"collocations":["write a feature article","publish a feature article","feature article series"],"synonyms_en":["in-depth article","cover story","special report"],"example_sentence":"I read a feature article about the climate crisis in the newspaper.","example_es":"Leí un artículo de fondo sobre la crisis climática en el periódico.","example_en":"I read a feature article about the climate crisis in the newspaper.","mnemonic_en":"Imagine a feature article perched on the fondo of a desk like a prized painting.","cloze_distractors_en":["Weather forecast","Public opinion","Market research","Social contract"],"examples":[{"es":"Leí un artículo de fondo sobre la crisis climática en el periódico.","en":"I read a feature article about the climate crisis in the newspaper."},{"es":"La revista publicó un artículo de fondo analizando el impacto de la inteligencia artificial en el empleo.","en":"The magazine published a feature article analyzing the impact of artificial intelligence on employment."},{"es":"El periodista pasó tres meses investigando para escribir su artículo de fondo sobre la pobreza urbana.","en":"The journalist spent three months investigating to write his feature article about urban poverty."}]},{"spanish_text":"Editorial","english_text":"Editorial","section_name":"News and Society","part_of_speech":"noun","definition_en":"An article expressing the opinion of the editor or the publication.","main_translations_es":["artículo de opinión","publicación","opinión"],"collocations":["editorial board","editorial policy","editorial staff","editorial decision"],"synonyms_en":[],"example_sentence":"I read the editorial in the newspaper about the climate crisis.","example_es":"Leí la editorial del periódico sobre la crisis climática.","example_en":"I read the editorial in the newspaper about the climate crisis.","mnemonic_en":null,"cloze_distractors_en":[],"examples":[{"es":"Leí la editorial del periódico sobre la crisis climática.","en":"I read the editorial in the newspaper about the climate crisis."}]},{"spanish_text":"Fuente fiable","english_text":"Reliable source","section_name":"News and Society","part_of_speech":"noun","definition_en":"A source that can be trusted to provide accurate and trustworthy information.","main_translations_es":["Fuente confiable","Fuente segura","Fuente fidedigna"],"collocations":["according to reliable sources","a reliable source of information","from a reliable source","reliable source of news"],"synonyms_en":["trustworthy source","dependable source","authoritative source"],"example_sentence":"This article is a reliable source for studying history.","example_es":"Este artículo es una fuente fiable para estudiar la historia.","example_en":"This article is a reliable source for studying history.","mnemonic_en":"A reliable source is like a steady fountain (fuente) that never stops flowing truth.","cloze_distractors_en":["Mechanical gear","Biological specimen","Geological formation"],"examples":[{"es":"Este artículo es una fuente fiable para estudiar la historia.","en":"This article is a reliable source for studying history."},{"es":"El periodista siempre verifica la información con una fuente fiable antes de publicar la noticia.","en":"The journalist always verifies the information with a reliable source before publishing the news."},{"es":"Es difícil encontrar una fuente fiable sobre este tema en las redes sociales.","en":"It is difficult to find a reliable source on this topic on social media."}]},{"spanish_text":"Desinformación","english_text":"Misinformation","section_name":"News and Society","part_of_speech":"noun","definition_en":"False or inaccurate information that is spread deliberately or unintentionally.","main_translations_es":["Información errónea","Noticias falsas","Información falsa"],"collocations":["spread misinformation","combat misinformation","misinformation campaign","misinformation about"],"synonyms_en":["false information","disinformation","fake news"],"example_sentence":"Misinformation about the vaccine is causing fear.","example_es":"La desinformación sobre la vacuna está generando miedo.","example_en":"Misinformation about the vaccine is causing fear.","mnemonic_en":"Picture a missed info sign exploding, spreading desinformación everywhere.","cloze_distractors_en":["Inoculation","Transparency","Verification"],"examples":[{"es":"La desinformación sobre la vacuna está generando miedo.","en":"Misinformation about the vaccine is causing fear."},{"es":"Las redes sociales facilitan la rápida propagación de la desinformación durante las elecciones.","en":"Social media facilitates the rapid spread of misinformation during elections."},{"es":"El gobierno lanzó una campaña para combatir la desinformación en los medios digitales.","en":"The government launched a campaign to combat misinformation in digital media."}]},{"spanish_text":"Información falsa","english_text":"False information","section_name":"News and Society","part_of_speech":"noun","definition_en":"Information that is incorrect or misleading.","main_translations_es":["Datos falsos","Información errónea","Noticias falsas"],"collocations":["spread false information","contain false information","correct false information"],"synonyms_en":["misinformation","disinformation","fake news"],"example_sentence":"The government launched a campaign to educate citizens on how to identify false information in the news.","example_es":"El gobierno lanzó una campaña para educar a los ciudadanos sobre cómo identificar información falsa en las noticias.","example_en":"The government launched a campaign to educate citizens on how to identify false information in the news.","mnemonic_en":"Picture a newspaper headline stamped with the Spanish word falso, showing false information.","cloze_distractors_en":["Public enthusiasm","Historical archives","Scientific consensus"],"examples":[{"es":"El gobierno lanzó una campaña para educar a los ciudadanos sobre cómo identificar información falsa en las noticias.","en":"The government launched a campaign to educate citizens on how to identify false information in the news."},{"es":"Es preocupante ver cómo se propaga información falsa durante los procesos electorales en el país.","en":"It is worrying to see how false information spreads during the country''s electoral processes."},{"es":"La empresa tecnológica fue multada por no eliminar la información falsa que circulaba en su plataforma.","en":"The tech company was fined for failing to remove the false information circulating on its platform."}]},{"spanish_text":"Noticia de última hora","english_text":"Breaking news","section_name":"News and Society","part_of_speech":"noun","definition_en":"Urgent or newly received news that is reported immediately.","main_translations_es":["Última hora","Noticias de última hora","Últimas noticias"],"collocations":["breaking news alert","breaking news story","breaking news coverage","breaking news update"],"synonyms_en":["latest update","urgent report","flash bulletin"],"example_sentence":"Breaking news! The president has announced his resignation.","example_es":"¡Noticia de última hora! El presidente ha anunciado su renuncia.","example_en":"Breaking news! The president has announced his resignation.","mnemonic_en":"Picture a broken clock at the hour, shouting the latest breaking news.","cloze_distractors_en":["Historical fiction","Yesterday weather","Fictional comedy","Scheduled silence"],"examples":[{"es":"¡Noticia de última hora! El presidente ha anunciado su renuncia.","en":"Breaking news! The president has announced his resignation."},{"es":"Interrumpimos la programación habitual para presentar una noticia de última hora sobre el incendio forestal.","en":"We are interrupting our regular programming to bring you breaking news about the forest fire."},{"es":"Los periodistas corrieron hacia el lugar tras recibir una noticia de última hora sobre el accidente ferroviario.","en":"Journalists rushed to the scene after receiving breaking news regarding the train accident."}]},{"spanish_text":"Cobertura en directo","english_text":"Live coverage","section_name":"News and Society","part_of_speech":"noun phrase","definition_en":"Live coverage is the real-time reporting or broadcasting of an event as it happens.","main_translations_es":["Cobertura en vivo","Transmisión en directo","Cobertura en tiempo real"],"collocations":["live coverage of the event","live coverage on TV","live coverage updates","live coverage broadcast"],"synonyms_en":["real-time reporting","on‑air reporting","instant coverage"],"example_sentence":"The live coverage of the concert will be streamed on our website.","example_es":"La cobertura en directo del concierto se transmitirá en nuestro sitio web.","example_en":"The live coverage of the concert will be streamed on our website.","mnemonic_en":"Picture a cover (cobertura) being broadcast live, like a TV show unfolding in real time.","cloze_distractors_en":["Static biography","Vague atmosphere","Hidden philosophy","Silent biography"],"examples":[{"es":"La cobertura en directo del concierto se transmitirá en nuestro sitio web.","en":"The live coverage of the concert will be streamed on our website."},{"es":"El canal de noticias interrumpió su programación habitual para ofrecer una cobertura en directo del desastre natural.","en":"The news channel interrupted its regular programming to provide live coverage of the natural disaster."},{"es":"Los periodistas deportivos están preparando una cobertura en directo desde el estadio antes del inicio del partido.","en":"The sports journalists are preparing live coverage from the stadium before the match begins."}]},{"spanish_text":"Actualización","english_text":"Update","section_name":"News and Society","part_of_speech":"noun","definition_en":"A change that adds new information or improves something to make it current.","main_translations_es":["Actualización","Puesta al día","Renovación"],"collocations":["software update","latest update","update the record","update your status"],"synonyms_en":["Refresh","Upgrade","Revise"],"example_sentence":"The update of the software improved the device''s performance.","example_es":"La actualización del software mejoró el rendimiento del dispositivo.","example_en":"The update of the software improved the device''s performance.","mnemonic_en":"Update feels like saying actual, so picture installing the latest actual news as an actualización.","cloze_distractors_en":["Outtake","Uptake","Undertow","Updraft"],"examples":[{"es":"La actualización del software mejoró el rendimiento del dispositivo.","en":"The update of the software improved the device''s performance."},{"es":"El periodista publicó una actualización sobre la situación en la zona de conflicto.","en":"The journalist published an update regarding the situation in the conflict zone."},{"es":"Recibimos una actualización constante sobre los resultados de las elecciones nacionales.","en":"We received a constant update on the results of the national elections."}]},{"spanish_text":"Encuesta de opinión","english_text":"Opinion poll","section_name":"News and Society","part_of_speech":"noun","definition_en":"A survey that asks people for their views on a particular topic.","main_translations_es":["Encuesta de opinión","Sondeo de opinión","Encuesta de percepción"],"collocations":["conduct an opinion poll","opinion poll results","national opinion poll","opinion poll survey"],"synonyms_en":["survey","poll","public poll"],"example_sentence":"The opinion poll showed that the majority supports the measure.","example_es":"La encuesta de opinión mostró que la mayoría apoya la medida.","example_en":"The opinion poll showed that the majority supports the measure.","mnemonic_en":"Picture a poll where everyone shouts their opinión like a noisy encuesta","cloze_distractors_en":["Political bias","Social mandate","Public verdict"],"examples":[{"es":"La encuesta de opinión mostró que la mayoría apoya la medida.","en":"The opinion poll showed that the majority supports the measure."},{"es":"El candidato lidera la última encuesta de opinión antes de las elecciones presidenciales.","en":"The candidate is leading the latest opinion poll before the presidential election."},{"es":"Los medios publicaron una encuesta de opinión sobre los hábitos de consumo de los jóvenes.","en":"The media published an opinion poll regarding the consumption habits of young people."}]},{"spanish_text":"Participación electoral","english_text":"Voter turnout","section_name":"News and Society","part_of_speech":"noun","definition_en":"The percentage or number of eligible voters who actually cast a ballot in an election.","main_translations_es":["Participación en las elecciones","Tasa de participación","Participación de los votantes"],"collocations":["low voter turnout","increase voter turnout","voter turnout rates","boost voter turnout"],"synonyms_en":["electoral participation","voting rate","ballot participation"],"example_sentence":"Voter turnout in the last election was 70%.","example_es":"La participación electoral en las últimas elecciones fue del 70%.","example_en":"Voter turnout in the last election was 70%.","mnemonic_en":"Imagine voters turning out, the same as participación electoral in a bustling poll.","cloze_distractors_en":["Political apathy","Public mandate","Civic deadlock","Election surplus"],"examples":[{"es":"La participación electoral en las últimas elecciones fue del 70%.","en":"Voter turnout in the last election was 70%."},{"es":"El gobierno está preocupado por la baja participación electoral entre los ciudadanos más jóvenes.","en":"The government is concerned about the low voter turnout among younger citizens."},{"es":"Se espera que una mayor participación electoral cambie el resultado de la votación este domingo.","en":"A higher voter turnout is expected to change the outcome of the vote this Sunday."}]},{"spanish_text":"Campaña electoral","english_text":"Election campaign","section_name":"News and Society","part_of_speech":"noun","definition_en":"A coordinated effort by a candidate or political party to win votes in an upcoming election.","main_translations_es":["Campaña electoral","Campaña de elecciones","Campaña política"],"collocations":["run an election campaign","launch an election campaign","election campaign strategy","election campaign finance"],"synonyms_en":["political campaign","campaign trail","voting drive"],"example_sentence":"The election campaign began last week and the debates are already being heard.","example_es":"La campaña electoral comenzó la semana pasada y ya se están escuchando los debates.","example_en":"The election campaign began last week and the debates are already being heard.","mnemonic_en":"Picture a field (campo) full of voters electing a leader during the campaign.","cloze_distractors_en":["Legislative mandate","Diplomatic stalemate","Bureaucratic oversight","Constitutional amendment"],"examples":[{"es":"La campaña electoral comenzó la semana pasada y ya se están escuchando los debates.","en":"The election campaign began last week and the debates are already being heard."},{"es":"Los candidatos recorren todo el país durante la campaña electoral para ganar votos.","en":"The candidates travel across the country during the election campaign to win votes."},{"es":"El partido político gastó millones de dólares en publicidad para su campaña electoral.","en":"The political party spent millions of dollars on advertising for its election campaign."}]},{"spanish_text":"Debate público","english_text":"Public debate","section_name":"News and Society","part_of_speech":"noun","definition_en":"A public debate is an open discussion where participants exchange differing views on a topic in front of an audience.","main_translations_es":["Foro público","Discusión pública","Debate abierto"],"collocations":["public debate on","open public debate","national public debate"],"synonyms_en":["open discussion","public discourse","forum"],"example_sentence":"The public debate on climate change attracted thousands of viewers.","example_es":"El debate público sobre el cambio climático atrajo a miles de espectadores.","example_en":"The public debate on climate change attracted thousands of viewers.","mnemonic_en":"Picture a public square where a de-bate of speakers shout the word public.","cloze_distractors_en":["Silent broadcast","Digital monument","Global consensus"],"examples":[{"es":"El debate público sobre el cambio climático atrajo a miles de espectadores.","en":"The public debate on climate change attracted thousands of viewers."},{"es":"La nueva ley de educación ha generado un intenso debate público en todo el país.","en":"The new education law has sparked an intense public debate across the country."},{"es":"Los candidatos presidenciales se preparan para participar en un debate público televisado esta noche.","en":"The presidential candidates are preparing to participate in a televised public debate tonight."}]},{"spanish_text":"Polarización","english_text":"Polarization","section_name":"News and Society","part_of_speech":"noun","definition_en":"The process of dividing something into opposing groups or of aligning electric charges in opposite directions.","main_translations_es":["Polarización","División polar","Polarización política"],"collocations":["political polarization","cultural polarization","polarization of opinions","polarization effect"],"synonyms_en":["division","splitting","segregation"],"example_sentence":"Political polarization in the country has increased in recent years.","example_es":"La polarización política en el país ha aumentado en los últimos años.","example_en":"Political polarization in the country has increased in recent years.","mnemonic_en":"Visualize a pole emitting a bright beam that polarizes everything, echoing the Spanish polarización.","cloze_distractors_en":["Fabrication","Vegetation","Calibration","Delegation"],"examples":[{"es":"La polarización política en el país ha aumentado en los últimos años.","en":"Political polarization in the country has increased in recent years."},{"es":"Las redes sociales han acelerado la polarización de la opinión pública sobre temas controvertidos.","en":"Social media has accelerated the polarization of public opinion on controversial topics."},{"es":"El debate electoral reflejó una profunda polarización entre los votantes de ambos partidos.","en":"The electoral debate reflected a deep polarization between the voters of both parties."}]},{"spanish_text":"Populismo","english_text":"Populism","section_name":"News and Society","part_of_speech":"noun","definition_en":"A political approach that seeks to appeal to ordinary people who feel their concerns are ignored by established elites.","main_translations_es":["populismo","movimiento populista","corriente populista"],"collocations":["rise of populism","populist rhetoric","populist movements","anti‑establishment populism"],"synonyms_en":["people''s movement","mass politics","demagoguery"],"example_sentence":"Populism has gained ground in several Latin American countries.","example_es":"El populismo ha ganado terreno en varios países de América Latina.","example_en":"Populism has gained ground in several Latin American countries.","mnemonic_en":"Populism sounds like Spanish ''populismo'', picture a crowd popping popcorn for a charismatic leader.","cloze_distractors_en":["Vegetation","Punctuation","Architecture"],"examples":[{"es":"El populismo ha ganado terreno en varios países de América Latina.","en":"Populism has gained ground in several Latin American countries."},{"es":"Los analistas políticos debaten sobre cómo el populismo influye en las elecciones modernas.","en":"Political analysts debate how populism influences modern elections."},{"es":"El discurso del candidato se basó principalmente en el populismo para atraer a los votantes descontentos.","en":"The candidate''s speech relied heavily on populism to appeal to disgruntled voters."}]},{"spanish_text":"Gobernanza","english_text":"Governance","section_name":"News and Society","part_of_speech":"noun","definition_en":"The act or system of governing, or the way an organization or society is managed and controlled.","main_translations_es":["Gestión","Administración","Dirección"],"collocations":["corporate governance","good governance","governance structure","governance framework"],"synonyms_en":["administration","management","rule"],"example_sentence":"The governance of the company is based on transparency and employee participation.","example_es":"La gobernanza de la empresa se basa en la transparencia y la participación de los empleados.","example_en":"The governance of the company is based on transparency and employee participation.","mnemonic_en":"Picture a governor handing a SA map, showing his governance","cloze_distractors_en":["Resilience","Tolerance","Innocence"],"examples":[{"es":"La gobernanza de la empresa se basa en la transparencia y la participación de los empleados.","en":"The governance of the company is based on transparency and employee participation."},{"es":"El nuevo tratado internacional busca mejorar la gobernanza global sobre el uso de la inteligencia artificial.","en":"The new international treaty seeks to improve global governance regarding the use of artificial intelligence."},{"es":"Los ciudadanos exigieron una mejor gobernanza en la gestión de los recursos hídricos durante la sequía.","en":"Citizens demanded better governance in the management of water resources during the drought."}]},{"spanish_text":"Transparencia","english_text":"Transparency","section_name":"News and Society","part_of_speech":"noun","definition_en":"The quality of being clear, open, or easily understood, or the condition of allowing light to pass through so that objects behind can be seen.","main_translations_es":["Claridad","Limpidez","Visibilidad"],"collocations":["transparency in government","financial transparency","transparency and accountability","transparency report"],"synonyms_en":["openness","clarity","candor"],"example_sentence":"Government transparency is essential for citizens'' trust.","example_es":"La transparencia del gobierno es esencial para la confianza de los ciudadanos.","example_en":"Government transparency is essential for citizens'' trust.","mnemonic_en":"Imagine a clear glass that lets all transparencia shine through, showing everything inside.","cloze_distractors_en":["Opacity","Ambiguity","Concealment","Discretion"],"examples":[{"es":"La transparencia del gobierno es esencial para la confianza de los ciudadanos.","en":"Government transparency is essential for citizens'' trust."},{"es":"La empresa prometió mayor transparencia en sus procesos de contratación para evitar el favoritismo.","en":"The company promised greater transparency in its hiring processes to avoid favoritism."},{"es":"Los periodistas exigen transparencia sobre el uso de los fondos públicos durante la crisis.","en":"Journalists are demanding transparency regarding the use of public funds during the crisis."}]},{"spanish_text":"Rendición de cuentas","english_text":"Accountability","section_name":"News and Society","part_of_speech":"noun","definition_en":"The obligation to accept responsibility for one''s actions and decisions.","main_translations_es":["Responsabilidad","Justificación","Transparencia"],"collocations":["accountability measures","accountability framework","accountability for actions"],"synonyms_en":["responsibility","answerability","liability"],"example_sentence":"Accountability is essential for transparency in government.","example_es":"La rendición de cuentas es fundamental para la transparencia en el gobierno.","example_en":"Accountability is essential for transparency in government.","mnemonic_en":"Picture a ledger where each cuenta is an account you must hand over, making you fully accountable","cloze_distractors_en":["Adaptability","Availability","Affordability"],"examples":[{"es":"La rendición de cuentas es fundamental para la transparencia en el gobierno.","en":"Accountability is essential for transparency in government."},{"es":"Los ciudadanos exigen mayor rendición de cuentas a las empresas que contaminan el medio ambiente.","en":"Citizens are demanding greater accountability from companies that pollute the environment."},{"es":"El nuevo director implementó un sistema de rendición de cuentas para evaluar el desempeño de cada departamento.","en":"The new director implemented an accountability system to evaluate the performance of each department."}]},{"spanish_text":"Corrupción","english_text":"Corruption","section_name":"News and Society","part_of_speech":"noun","definition_en":"Dishonest or fraudulent conduct by those in power, often involving bribery or the misuse of authority for personal gain.","main_translations_es":["Corrupción","Deshonestidad","Mala conducta"],"collocations":["corruption scandal","corruption charges","fight against corruption","corruption in politics"],"synonyms_en":["dishonesty","bribery","graft"],"example_sentence":"Corruption in the government has decreased thanks to the new laws.","example_es":"La corrupción en el gobierno ha disminuido gracias a las nuevas leyes.","example_en":"Corruption in the government has decreased thanks to the new laws.","mnemonic_en":"Imagine a corrupt ion sneaking into the core of power.","cloze_distractors_en":["Prosperity","Efficiency","Hospitality","Legitimacy"],"examples":[{"es":"La corrupción en el gobierno ha disminuido gracias a las nuevas leyes.","en":"Corruption in the government has decreased thanks to the new laws."},{"es":"El periodista publicó un informe detallado sobre la corrupción dentro de la empresa constructora.","en":"The journalist published a detailed report about the corruption within the construction company."},{"es":"Muchos ciudadanos protestaron en las calles para exigir el fin de la corrupción en el sistema judicial.","en":"Many citizens protested in the streets to demand an end to the corruption in the judicial system."}]},{"spanish_text":"Desigualdad","english_text":"Inequality","section_name":"News and Society","part_of_speech":"noun","definition_en":"A condition of being unequal, especially in status, rights, or opportunities.","main_translations_es":["Desigualdad","Desigualdad social","Desigualdad económica"],"collocations":["income inequality","gender inequality","social inequality","racial inequality"],"synonyms_en":["disparity","imbalance","unequal treatment"],"example_sentence":"Salary inequality between men and women remains a serious problem.","example_es":"La desigualdad salarial entre hombres y mujeres sigue siendo un problema grave.","example_en":"Salary inequality between men and women remains a serious problem.","mnemonic_en":"Picture a broken scale labeled Desigualdad, its pans uneven, showing inequality.","cloze_distractors_en":["Uniformity","Integrity","Prosperity","Solidarity"],"examples":[{"es":"La desigualdad salarial entre hombres y mujeres sigue siendo un problema grave.","en":"Salary inequality between men and women remains a serious problem."},{"es":"El gobierno implementó nuevas políticas para reducir la desigualdad en el acceso a la educación.","en":"The government implemented new policies to reduce inequality in access to education."},{"es":"Los manifestantes salieron a las calles para protestar contra la creciente desigualdad económica en el país.","en":"Protesters took to the streets to demonstrate against the growing economic inequality in the country."}]},{"spanish_text":"Movilidad social","english_text":"Social mobility","section_name":"News and Society","part_of_speech":"noun","definition_en":"The movement of individuals or groups within or between social classes in a society.","main_translations_es":["Movilidad social","Ascenso social","Movilidad de clase"],"collocations":["intergenerational social mobility","enhance social mobility","promote social mobility"],"synonyms_en":["class movement","upward mobility","intergenerational mobility"],"example_sentence":"Social mobility is a key indicator of equal opportunity in a society.","example_es":"La movilidad social es un indicador clave de la igualdad de oportunidades en una sociedad.","example_en":"Social mobility is a key indicator of equal opportunity in a society.","mnemonic_en":"Picture a social ladder on a moving bus called movilidad climbing upward","cloze_distractors_en":["Political apathy","Economic isolation","Cultural stagnation"],"examples":[{"es":"La movilidad social es un indicador clave de la igualdad de oportunidades en una sociedad.","en":"Social mobility is a key indicator of equal opportunity in a society."},{"es":"El acceso a una educación de calidad es fundamental para fomentar la movilidad social en las comunidades desfavorecidas.","en":"Access to quality education is essential to foster social mobility in disadvantaged communities."},{"es":"Muchos economistas argumentan que el estancamiento de los salarios está limitando la movilidad social de la clase trabajadora.","en":"Many economists argue that stagnant wages are limiting social mobility for the working class."}]},{"spanish_text":"Costo de vida","english_text":"Cost of living","section_name":"News and Society","part_of_speech":"noun","definition_en":"The amount of money required to cover basic expenses such as housing, food, taxes, and healthcare in a specific location.","main_translations_es":["Costo de vida"],"collocations":["cost of living index","cost of living adjustment","cost of living expenses","cost of living in"],"synonyms_en":["living expenses","household costs","daily expenses"],"example_sentence":"The constant increase in the cost of living makes it difficult for many families to make ends meet.","example_es":"El aumento constante en el costo de vida dificulta que muchas familias lleguen a fin de mes.","example_en":"The constant increase in the cost of living makes it difficult for many families to make ends meet.","mnemonic_en":"Imagine paying the cost (costo) of a lively (living) party.","cloze_distractors_en":["State of grace","Point of origin","Lack of vision","Rate of return"],"examples":[{"es":"El aumento constante en el costo de vida dificulta que muchas familias lleguen a fin de mes.","en":"The constant increase in the cost of living makes it difficult for many families to make ends meet."},{"es":"Debido al alto costo de vida en la ciudad, muchos jóvenes deciden mudarse a las afueras.","en":"Due to the high cost of living in the city, many young people decide to move to the suburbs."},{"es":"El gobierno anunció nuevas medidas para frenar el impacto del costo de vida en los sectores más vulnerables.","en":"The government announced new measures to curb the impact of the cost of living on the most vulnerable sectors."}]},{"spanish_text":"Inflación","english_text":"Inflation","section_name":"News and Society","part_of_speech":"noun","definition_en":"A general increase in prices and a corresponding decline in the purchasing power of money.","main_translations_es":["Alza de precios","Aumento de precios","Crecimiento de precios"],"collocations":["inflation rate","inflationary pressure","inflation-adjusted","inflation targeting"],"synonyms_en":["price rise","cost increase","rising prices"],"example_sentence":"Inflation has increased the cost of food.","example_es":"La inflación ha aumentado el costo de los alimentos.","example_en":"Inflation has increased the cost of food.","mnemonic_en":"Picture a balloon inflating as ''inflación'' lifts prices.","cloze_distractors_en":["Affluence","Solvency","Dividend"],"examples":[{"es":"La inflación ha aumentado el costo de los alimentos.","en":"Inflation has increased the cost of food."},{"es":"El banco central subió las tasas de interés para frenar la inflación.","en":"The central bank raised interest rates to curb inflation."},{"es":"Muchos ciudadanos están preocupados por cómo la inflación afecta sus ahorros.","en":"Many citizens are worried about how inflation affects their savings."}]},{"spanish_text":"Recesión","english_text":"Recession","section_name":"News and Society","part_of_speech":"noun","definition_en":"A period of economic decline marked by reduced trade, production, and rising unemployment.","main_translations_es":["Depresión económica","Contracción económica","Crisis económica"],"collocations":["recession fears","deep recession","recession hit","recessionary pressures"],"synonyms_en":["economic downturn","downturn","contraction"],"example_sentence":"The recession has caused an increase in unemployment in the country.","example_es":"La recesión ha provocado un aumento del desempleo en el país.","example_en":"The recession has caused an increase in unemployment in the country.","mnemonic_en":"When the economy goes into recession it takes a recess like a broken tooth, and recesión sounds just like recess.","cloze_distractors_en":["Prosperity","Affluence","Expansion","Abundance"],"examples":[{"es":"La recesión ha provocado un aumento del desempleo en el país.","en":"The recession has caused an increase in unemployment in the country."},{"es":"Muchos pequeños negocios cerraron sus puertas debido a la grave recesión económica.","en":"Many small businesses closed their doors due to the severe economic recession."},{"es":"El gobierno implementó nuevas medidas fiscales para intentar salir de la recesión.","en":"The government implemented new fiscal measures to try to emerge from the recession."}]},{"spanish_text":"Recuperación económica","english_text":"Economic recovery","section_name":"News and Society","part_of_speech":"noun","definition_en":"A period when an economy regains growth and improves after a downturn.","main_translations_es":["Reactivación económica","Recuperación de la economía","Rebote económico"],"collocations":["spur economic recovery","support economic recovery","accelerate economic recovery"],"synonyms_en":["rebound","revival","upturn"],"example_sentence":"The country''s economic recovery has been faster than expected.","example_es":"La recuperación económica del país ha sido más rápida de lo esperado.","example_en":"The country''s economic recovery has been faster than expected.","mnemonic_en":"Eco‑nomics recovered: picture a shattered piggy bank being glued back together.","cloze_distractors_en":["Political bankruptcy","Social stagnation","Cultural negligence","Fiscal abandonment"],"examples":[{"es":"La recuperación económica del país ha sido más rápida de lo esperado.","en":"The country''s economic recovery has been faster than expected."},{"es":"El gobierno anunció nuevas medidas para fomentar la recuperación económica tras la crisis financiera.","en":"The government announced new measures to foster economic recovery after the financial crisis."},{"es":"Muchos analistas coinciden en que la recuperación económica depende de la estabilidad del mercado laboral.","en":"Many analysts agree that economic recovery depends on the stability of the labor market."}]},{"spanish_text":"Mercado laboral","english_text":"Labor market","section_name":"News and Society","part_of_speech":"noun","definition_en":"The supply of workers and the demand for jobs in an economy, encompassing employment conditions and opportunities.","main_translations_es":["mercado de trabajo","mercado de empleo","mercado laboral"],"collocations":["tight labor market","labor market conditions","labor market trends","labor market analysis"],"synonyms_en":["job market","employment market","workforce market"],"example_sentence":"The labor market is experiencing a high demand for technology professionals.","example_es":"El mercado laboral está experimentando una alta demanda de profesionales de tecnología.","example_en":"The labor market is experiencing a high demand for technology professionals.","mnemonic_en":"A lab rat in the mercado sells job offers.","cloze_distractors_en":["Consumer surplus","Product lifecycle","Capital turnover","Revenue pipeline"],"examples":[{"es":"El mercado laboral está experimentando una alta demanda de profesionales de tecnología.","en":"The labor market is experiencing a high demand for technology professionals."},{"es":"La crisis económica ha provocado una gran inestabilidad en el mercado laboral actual.","en":"The economic crisis has caused great instability in the current labor market."},{"es":"El gobierno ha implementado nuevas reformas para fomentar la flexibilidad en el mercado laboral.","en":"The government has implemented new reforms to encourage flexibility in the labor market."}]},{"spanish_text":"Crisis habitacional","english_text":"Housing crisis","section_name":"News and Society","part_of_speech":"noun","definition_en":"A situation in which the supply of affordable housing is insufficient to meet demand, causing widespread difficulty in obtaining suitable homes.","main_translations_es":["Crisis de la vivienda","Escasez de vivienda","Problema de vivienda"],"collocations":["address the housing crisis","housing crisis is worsening","impact of the housing crisis","solve the housing crisis"],"synonyms_en":["housing shortage","home affordability crisis","residential crisis"],"example_sentence":"The housing crisis is forcing many families to seek shelter in temporary homes.","example_es":"La crisis habitacional está obligando a muchas familias a buscar refugio en viviendas temporales.","example_en":"The housing crisis is forcing many families to seek shelter in temporary homes.","mnemonic_en":"Imagine a house collapsing in a crisis, like a broken habit‑home emergency.","cloze_distractors_en":["Digital literacy","Global warming","Public transport","Social etiquette"],"examples":[{"es":"La crisis habitacional está obligando a muchas familias a buscar refugio en viviendas temporales.","en":"The housing crisis is forcing many families to seek shelter in temporary homes."},{"es":"El gobierno ha anunciado nuevas medidas para frenar la crisis habitacional en las grandes ciudades.","en":"The government has announced new measures to curb the housing crisis in major cities."},{"es":"Los jóvenes tienen dificultades para independizarse debido a la grave crisis habitacional que afecta al país.","en":"Young people struggle to move out on their own due to the severe housing crisis affecting the country."}]},{"spanish_text":"Sin techo","english_text":"Homeless","section_name":"News and Society","part_of_speech":"noun","definition_en":"A person who lacks a permanent residence or home.","main_translations_es":["Sin hogar","Desamparado","Persona sin techo"],"collocations":["homeless shelter","homeless population","homeless crisis","homeless youth"],"synonyms_en":["without a home","roofless","vagrant"],"example_sentence":"The city council has launched an assistance program to help homeless people during the winter.","example_es":"El ayuntamiento ha lanzado un programa de asistencia para ayudar a las personas sin techo durante el invierno.","example_en":"The city council has launched an assistance program to help homeless people during the winter.","mnemonic_en":"Picture a homeless person under the sky, sin techo, with no roof over their head.","cloze_distractors_en":["Wealthy","Employed","Housed","Sturdy"],"examples":[{"es":"El ayuntamiento ha lanzado un programa de asistencia para ayudar a las personas sin techo durante el invierno.","en":"The city council has launched an assistance program to help homeless people during the winter."},{"es":"Muchos voluntarios reparten comida caliente en la plaza principal a la población sin techo cada noche.","en":"Many volunteers distribute hot food in the main square to the homeless population every night."},{"es":"La organización benéfica construyó nuevos albergues para ofrecer un lugar seguro a quienes se encuentran sin techo.","en":"The charity built new shelters to offer a safe place to those who are homeless."}]},{"spanish_text":"Atención sanitaria","english_text":"Healthcare","section_name":"News and Society","part_of_speech":"noun","definition_en":"The organized provision of medical services to maintain or improve people''s health.","main_translations_es":["Cuidado de la salud","Servicios de salud","Asistencia sanitaria"],"collocations":["healthcare system","healthcare provider","affordable healthcare","healthcare industry"],"synonyms_en":["medical care","health services","medical services"],"example_sentence":"Access to healthcare is a fundamental right.","example_es":"El acceso a la atención sanitaria es un derecho fundamental.","example_en":"Access to healthcare is a fundamental right.","mnemonic_en":"Healthcare sounds like heal and care, picture a doctor healing a patient with a sanitary mask.","cloze_distractors_en":["Vandalism","Bureaucracy","Extravagance","Negligence"],"examples":[{"es":"El acceso a la atención sanitaria es un derecho fundamental.","en":"Access to healthcare is a fundamental right."},{"es":"El gobierno anunció un aumento en el presupuesto destinado a la atención sanitaria pública.","en":"The government announced an increase in the budget allocated for public healthcare."},{"es":"Las nuevas reformas buscan mejorar la calidad de la atención sanitaria en las zonas rurales.","en":"The new reforms aim to improve the quality of healthcare in rural areas."}]},{"spanish_text":"Salud mental","english_text":"Mental health","section_name":"News and Society","part_of_speech":"noun","definition_en":"A state of psychological well‑being that enables a person to handle daily stresses, work productively, and contribute to society.","main_translations_es":["Bienestar mental","Salud psicológica","Salud de la mente"],"collocations":["mental health care","mental health issues","mental health awareness","mental health services"],"synonyms_en":["psychological well-being","emotional health","mental well-being"],"example_sentence":"Mental health is as important as physical health.","example_es":"La salud mental es tan importante como la salud física.","example_en":"Mental health is as important as physical health.","mnemonic_en":"Picture a therapist serving a giant salad to boost mental health.","cloze_distractors_en":["Public transport","Financial deficit","Urban planning","Global warming"],"examples":[{"es":"La salud mental es tan importante como la salud física.","en":"Mental health is as important as physical health."},{"es":"Las empresas modernas ofrecen programas de apoyo para mejorar la salud mental de sus empleados.","en":"Modern companies offer support programs to improve the mental health of their employees."},{"es":"El gobierno ha lanzado una campaña nacional para reducir el estigma asociado a la salud mental.","en":"The government has launched a national campaign to reduce the stigma associated with mental health."}]},{"spanish_text":"Bienestar","english_text":"Well-being","section_name":"News and Society","part_of_speech":"noun","definition_en":"A state of being comfortable, healthy, or happy.","main_translations_es":["Salud","Plenitud","Bienestar"],"collocations":["mental well-being","physical well-being","overall well-being","well-being of the community"],"synonyms_en":["health","welfare","prosperity"],"example_sentence":"The exercise program improves the participants'' well-being.","example_es":"El programa de ejercicios mejora el bienestar de los participantes.","example_en":"The exercise program improves the participants'' well-being.","mnemonic_en":"Picture a well that says bien and a statue that stands estar, together they form well-being.","cloze_distractors_en":["Malfunction","Negligence","Stagnation","Turbulence"],"examples":[{"es":"El programa de ejercicios mejora el bienestar de los participantes.","en":"The exercise program improves the participants'' well-being."},{"es":"El gobierno implementó nuevas políticas para proteger el bienestar de los ciudadanos.","en":"The government implemented new policies to protect the well-being of the citizens."},{"es":"Los expertos advierten que el estrés laboral afecta negativamente el bienestar de los empleados.","en":"Experts warn that work stress negatively affects the well-being of employees."}]},{"spanish_text":"Envejecimiento de la población","english_text":"Aging population","section_name":"News and Society","part_of_speech":"noun phrase","definition_en":"A demographic situation in which a large proportion of the population is elderly.","main_translations_es":["Envejecimiento demográfico","Población envejecida","Envejecimiento de la población"],"collocations":["aging population trend","aging population challenges","aging population growth"],"synonyms_en":["elderly demographic","senior population","older population"],"example_sentence":"The aging population is a challenge for health systems.","example_es":"El envejecimiento de la población es un desafío para los sistemas de salud.","example_en":"The aging population is a challenge for health systems.","mnemonic_en":"Picture an aging crowd, a senior población marching together.","cloze_distractors_en":["Floral arrangement","Musical composition","Culinary experimentation","Meteorological observation"],"examples":[{"es":"El envejecimiento de la población es un desafío para los sistemas de salud.","en":"The aging population is a challenge for health systems."},{"es":"Muchos países europeos están implementando reformas en las pensiones debido al envejecimiento de la población.","en":"Many European countries are implementing pension reforms due to the aging population."},{"es":"La escasez de mano de obra joven es una consecuencia directa del envejecimiento de la población en esta región.","en":"The shortage of young labor is a direct consequence of the aging population in this region."}]},{"spanish_text":"Migración","english_text":"Migration","section_name":"News and Society","part_of_speech":"noun","definition_en":"The movement of people or groups from one location to another, typically for settlement, work, or environmental reasons.","main_translations_es":["Desplazamiento","Traslado","Emigración"],"collocations":["human migration","migration patterns","migration crisis","migration policy"],"synonyms_en":["relocation","movement","exodus"],"example_sentence":"The migration of birds to the south begins in autumn.","example_es":"La migración de aves hacia el sur comienza en otoño.","example_en":"The migration of birds to the south begins in autumn.","mnemonic_en":"Picture a flock of birds on a ''migra''tion, flying south together.","cloze_distractors_en":["Invasion","Isolation","Inflation","Irrigation"],"examples":[{"es":"La migración de aves hacia el sur comienza en otoño.","en":"The migration of birds to the south begins in autumn."},{"es":"El gobierno implementó nuevas políticas para gestionar la migración en la frontera.","en":"The government implemented new policies to manage migration at the border."},{"es":"Muchos expertos analizan las causas económicas que provocan la migración masiva de trabajadores.","en":"Many experts analyze the economic causes that trigger the mass migration of workers."}]},{"spanish_text":"Refugiado","english_text":"Refugee","section_name":"News and Society","part_of_speech":"noun","definition_en":"A person who has been forced to leave their country to escape war, persecution, or disaster.","main_translations_es":["Desplazado","Exiliado","Refugiado"],"collocations":["refugee crisis","refugee camp","refugee status","refugee resettlement"],"synonyms_en":["asylum seeker","displaced person","exile"],"example_sentence":"The refugee found a new home in the city.","example_es":"El refugiado encontró un nuevo hogar en la ciudad.","example_en":"The refugee found a new home in the city.","mnemonic_en":"Imagine a refugee clutching a sign that reads refugio, the Spanish word that sounds just like refugee.","cloze_distractors_en":["Refectory","Refinery","Repertoire","Referendum"],"examples":[{"es":"El refugiado encontró un nuevo hogar en la ciudad.","en":"The refugee found a new home in the city."},{"es":"La organización humanitaria proporcionó comida y mantas a cada refugiado en el campamento.","en":"The humanitarian organization provided food and blankets to every refugee in the camp."},{"es":"El gobierno aprobó una nueva ley para facilitar la integración de cualquier refugiado que llegue al país.","en":"The government passed a new law to facilitate the integration of any refugee who arrives in the country."}]},{"spanish_text":"Integración","english_text":"Integration","section_name":"News and Society","part_of_speech":"noun","definition_en":"The process of combining separate parts into a unified whole.","main_translations_es":["Integración","Incorporación","Unificación"],"collocations":["system integration","cultural integration","integration testing","integration process"],"synonyms_en":["combination","merging","unification"],"example_sentence":"The integration of the new employees into the company was very quick.","example_es":"La integración de los nuevos empleados en la empresa fue muy rápida.","example_en":"The integration of the new employees into the company was very quick.","mnemonic_en":"Visualize a giant gear labeled integral joining smoothly, symbolizing the Spanish integración.","cloze_distractors_en":["Segregation","Exclusion","Fragmentation","Alienation"],"examples":[{"es":"La integración de los nuevos empleados en la empresa fue muy rápida.","en":"The integration of the new employees into the company was very quick."},{"es":"El gobierno busca fomentar la integración de los inmigrantes en la comunidad local.","en":"The government seeks to foster the integration of immigrants into the local community."},{"es":"La integración de las nuevas tecnologías en el aula mejora el aprendizaje de los estudiantes.","en":"The integration of new technologies into the classroom improves student learning."}]},{"spanish_text":"Discriminación","english_text":"Discrimination","section_name":"News and Society","part_of_speech":"noun","definition_en":"Unfair or prejudicial treatment of individuals or groups based on characteristics such as race, gender, age, or other attributes.","main_translations_es":["Segregación","Prejuicio","Exclusión"],"collocations":["racial discrimination","gender discrimination","discrimination lawsuit","discrimination policy"],"synonyms_en":["bias","prejudice","bigotry"],"example_sentence":"Discrimination in the workplace is unacceptable.","example_es":"La discriminación en el lugar de trabajo es inaceptable.","example_en":"Discrimination in the workplace is unacceptable.","mnemonic_en":"Picture a disc ringing a nation, sorting people into groups.","cloze_distractors_en":["Distribution","Contribution","Constitution","Substitution"],"examples":[{"es":"La discriminación en el lugar de trabajo es inaceptable.","en":"Discrimination in the workplace is unacceptable."},{"es":"El gobierno aprobó nuevas leyes para combatir la discriminación racial en las escuelas.","en":"The government passed new laws to combat racial discrimination in schools."},{"es":"Muchos activistas luchan diariamente contra la discriminación de género en el acceso a puestos directivos.","en":"Many activists fight daily against gender discrimination in access to management positions."}]},{"spanish_text":"Inclusión","english_text":"Inclusion","section_name":"News and Society","part_of_speech":"noun","definition_en":"The act or state of including someone or something, or the condition of being included.","main_translations_es":["Integración","Participación","Incorporación"],"collocations":["inclusion criteria","social inclusion","inclusion policy","inclusion in the classroom"],"synonyms_en":["integration","incorporation","admission"],"example_sentence":"The inclusion of students with special needs in the classroom benefits all students.","example_es":"La inclusión de estudiantes con necesidades especiales en el aula beneficia a todos los alumnos.","example_en":"The inclusion of students with special needs in the classroom benefits all students.","mnemonic_en":"Picture a club door open for all, the sign reads INCLUE SION, showing inclusion.","cloze_distractors_en":["Exclusion","Isolation","Segregation","Alienation"],"examples":[{"es":"La inclusión de estudiantes con necesidades especiales en el aula beneficia a todos los alumnos.","en":"The inclusion of students with special needs in the classroom benefits all students."},{"es":"La empresa implementó nuevas políticas para promover la inclusión de personas de diversos orígenes en el equipo de trabajo.","en":"The company implemented new policies to promote the inclusion of people from diverse backgrounds in the work team."},{"es":"El ayuntamiento aprobó un plan de urbanismo centrado en la inclusión de rampas y ascensores en todos los edificios públicos.","en":"The city council approved an urban planning project focused on the inclusion of ramps and elevators in all public buildings."}]},{"spanish_text":"Accesibilidad","english_text":"Accessibility","section_name":"News and Society","part_of_speech":"noun","definition_en":"The quality of being easy to reach, use, understand, or obtain, especially for people with disabilities.","main_translations_es":["Accesibilidad","Acceso","Facilidad de acceso"],"collocations":["accessibility features","accessibility standards","improve accessibility","digital accessibility"],"synonyms_en":["approachability","usability","availability"],"example_sentence":"The accessibility of the website is essential for users with disabilities.","example_es":"La accesibilidad del sitio web es fundamental para los usuarios con discapacidades.","example_en":"The accessibility of the website is essential for users with disabilities.","mnemonic_en":"Picture a wide ramp labeled Acceso letting anyone easily access the building, showing its accessibility.","cloze_distractors_en":["Incompatibility","Unreliability","Improbability","Irresponsibility"],"examples":[{"es":"La accesibilidad del sitio web es fundamental para los usuarios con discapacidades.","en":"The accessibility of the website is essential for users with disabilities."},{"es":"El ayuntamiento aprobó nuevas normas para mejorar la accesibilidad en el transporte público de la ciudad.","en":"The city council passed new regulations to improve accessibility in public transportation."},{"es":"El diseño de este edificio histórico limita la accesibilidad para las personas que utilizan sillas de ruedas.","en":"The design of this historic building limits accessibility for people who use wheelchairs."}]},{"spanish_text":"Brecha digital","english_text":"Digital divide","section_name":"News and Society","part_of_speech":"noun","definition_en":"The gap between individuals, households, or regions in access to and use of information and communication technologies.","main_translations_es":["Desigualdad digital","Brecha tecnológica","División digital"],"collocations":["bridge the digital divide","narrow the digital divide","address the digital divide","close the digital divide"],"synonyms_en":["technology gap","information gap","digital gap"],"example_sentence":"The digital divide affects rural communities.","example_es":"La brecha digital afecta a las comunidades rurales.","example_en":"The digital divide affects rural communities.","mnemonic_en":"Picture a digital gap, a broken bridge where the brecha splits the internet.","cloze_distractors_en":["Physical climate","Cultural surplus","Political harvest"],"examples":[{"es":"La brecha digital afecta a las comunidades rurales.","en":"The digital divide affects rural communities."},{"es":"El gobierno implementó nuevos programas educativos para reducir la brecha digital en las escuelas públicas.","en":"The government implemented new educational programs to reduce the digital divide in public schools."},{"es":"Muchos adultos mayores se sienten excluidos debido a la creciente brecha digital en los servicios bancarios.","en":"Many senior citizens feel excluded due to the growing digital divide in banking services."}]},{"spanish_text":"Privacidad de datos","english_text":"Data privacy","section_name":"News and Society","part_of_speech":"noun","definition_en":"The protection of personal information from unauthorized access or disclosure.","main_translations_es":["Protección de datos","Seguridad de datos","Confidencialidad de datos"],"collocations":["data privacy policy","data privacy regulations","data privacy concerns","data privacy breach"],"synonyms_en":["information privacy","data protection","privacy of data"],"example_sentence":"Data privacy is essential to protect personal information.","example_es":"La privacidad de datos es fundamental para proteger la información personal.","example_en":"Data privacy is essential to protect personal information.","mnemonic_en":"Imagine a data file locked with a privacy shield stamped datos.","cloze_distractors_en":["Digital hardware","Public relations","System overload","Global commerce"],"examples":[{"es":"La privacidad de datos es fundamental para proteger la información personal.","en":"Data privacy is essential to protect personal information."},{"es":"Las nuevas leyes europeas imponen sanciones estrictas a las empresas que no respetan la privacidad de datos.","en":"New European laws impose strict penalties on companies that do not respect data privacy."},{"es":"El usuario decidió cerrar su cuenta en la red social debido a sus constantes preocupaciones sobre la privacidad de datos.","en":"The user decided to close their social media account due to their constant concerns about data privacy."}]},{"spanish_text":"Ciberseguridad","english_text":"Cybersecurity","section_name":"News and Society","part_of_speech":"noun","definition_en":"The practice of protecting computers, networks, and data from unauthorized access, attacks, or damage.","main_translations_es":["Seguridad informática","Seguridad cibernética","Protección digital"],"collocations":["cybersecurity threat","cybersecurity measures","cybersecurity breach","cybersecurity strategy"],"synonyms_en":["information security","computer security","network security"],"example_sentence":"Cybersecurity is essential to protect the company''s data.","example_es":"La ciberseguridad es esencial para proteger los datos de la empresa.","example_en":"Cybersecurity is essential to protect the company''s data.","mnemonic_en":"Picture a cyber guard protecting a giant ciber shield over the network","cloze_distractors_en":["Omnipresence","Superfluity","Incoherence","Arbitrariness"],"examples":[{"es":"La ciberseguridad es esencial para proteger los datos de la empresa.","en":"Cybersecurity is essential to protect the company''s data."},{"es":"El gobierno anunció nuevas medidas de ciberseguridad para evitar ataques a los sistemas eléctricos.","en":"The government announced new cybersecurity measures to prevent attacks on power grids."},{"es":"Muchos estudiantes universitarios deciden especializarse en ciberseguridad debido a la alta demanda laboral.","en":"Many university students decide to specialize in cybersecurity due to the high job demand."}]},{"spanish_text":"Vigilancia","english_text":"Surveillance","section_name":"News and Society","part_of_speech":"noun","definition_en":"The close monitoring of people, places, or activities, especially for security or intelligence purposes.","main_translations_es":["Control","Supervisión","Observación"],"collocations":["under surveillance","surveillance camera","mass surveillance","electronic surveillance"],"synonyms_en":["monitoring","observation","watch"],"example_sentence":"Surveillance of the park was intensified after the robbery.","example_es":"La vigilancia del parque se intensificó después del robo.","example_en":"Surveillance of the park was intensified after the robbery.","mnemonic_en":"Picture a siren overseeing a vigil, that’s surveillance.","cloze_distractors_en":["Negligence","Tolerance","Resilience","Conveyance"],"examples":[{"es":"La vigilancia del parque se intensificó después del robo.","en":"Surveillance of the park was intensified after the robbery."},{"es":"Las cámaras de seguridad proporcionan vigilancia constante en los pasillos del banco.","en":"Security cameras provide constant surveillance in the bank hallways."},{"es":"El gobierno implementó un nuevo sistema de vigilancia para monitorear el tráfico en la ciudad.","en":"The government implemented a new surveillance system to monitor traffic in the city."}]},{"spanish_text":"Algoritmo","english_text":"Algorithm","section_name":"News and Society","part_of_speech":"noun","definition_en":"A step-by-step procedure or set of rules for solving a problem or performing a computation.","main_translations_es":["Procedimiento","Método","Secuencia"],"collocations":["sorting algorithm","search algorithm","machine learning algorithm","algorithmic complexity"],"synonyms_en":["procedure","method","process"],"example_sentence":"The algorithm found the information quickly.","example_es":"El algoritmo de búsqueda encontró la información rápidamente.","example_en":"The algorithm found the information quickly.","mnemonic_en":"Imagine a robot named Algo sorting a massive rhythm of numbers, an algorithm.","cloze_distractors_en":["Monologue","Epilogue","Analogue"],"examples":[{"es":"El algoritmo de búsqueda encontró la información rápidamente.","en":"The algorithm found the information quickly."},{"es":"La red social utiliza un algoritmo complejo para personalizar los anuncios que vemos.","en":"The social network uses a complex algorithm to personalize the ads we see."},{"es":"Los expertos analizan cómo el algoritmo influye en la difusión de noticias falsas en internet.","en":"Experts analyze how the algorithm influences the spread of fake news on the internet."}]},{"spanish_text":"Inteligencia artificial","english_text":"Artificial intelligence","section_name":"News and Society","part_of_speech":"noun","definition_en":"Artificial intelligence is the branch of computer science that develops systems capable of performing tasks that normally require human intelligence.","main_translations_es":["Inteligencia artificial","IA","Inteligencia de máquinas"],"collocations":["artificial intelligence technology","artificial intelligence applications","artificial intelligence research"],"synonyms_en":["machine intelligence","computer intelligence","AI"],"example_sentence":"Artificial intelligence is transforming the medical industry.","example_es":"La inteligencia artificial está transformando la industria médica.","example_en":"Artificial intelligence is transforming the medical industry.","mnemonic_en":"Picture a robot artist feeding a brain, because artificial art fuels inteligencia.","cloze_distractors_en":["Biological agriculture","Geological excavation","Atmospheric turbulence","Hydroelectric irrigation"],"examples":[{"es":"La inteligencia artificial está transformando la industria médica.","en":"Artificial intelligence is transforming the medical industry."},{"es":"Muchas empresas utilizan la inteligencia artificial para automatizar el servicio al cliente.","en":"Many companies use artificial intelligence to automate customer service."},{"es":"El gobierno debate nuevas leyes para regular el desarrollo de la inteligencia artificial.","en":"The government is debating new laws to regulate the development of artificial intelligence."}]},{"spanish_text":"Automatización","english_text":"Automation","section_name":"News and Society","part_of_speech":"noun","definition_en":"The use of technology or machines to perform tasks without human intervention.","main_translations_es":["Automatización","Robotización","Mecanización"],"collocations":["automation technology","automation process","automation system","automation industry"],"synonyms_en":["mechanization","computerization","robotization"],"example_sentence":"Automation of manufacturing processes has increased efficiency.","example_es":"La automatización de los procesos de fabricación ha aumentado la eficiencia.","example_en":"Automation of manufacturing processes has increased efficiency.","mnemonic_en":"Picture an auto that drives the factory itself, showing automation.","cloze_distractors_en":["Delegation","Regulation","Foundation"],"examples":[{"es":"La automatización de los procesos de fabricación ha aumentado la eficiencia.","en":"Automation of manufacturing processes has increased efficiency."},{"es":"Muchos trabajadores temen que la automatización reemplace sus puestos en la fábrica.","en":"Many workers fear that automation will replace their jobs at the factory."},{"es":"La empresa implementó la automatización para gestionar mejor el inventario en sus almacenes.","en":"The company implemented automation to better manage inventory in its warehouses."}]},{"spanish_text":"Desinformación algorítmica","english_text":"Algorithmic misinformation","section_name":"News and Society","part_of_speech":"noun","definition_en":"False or misleading information that is generated, spread, or amplified by algorithms.","main_translations_es":["Desinformación generada por algoritmos","Información errónea algorítmica"],"collocations":["combat algorithmic misinformation","address algorithmic misinformation","algorithmic misinformation campaigns","spread of algorithmic misinformation"],"synonyms_en":["AI-generated misinformation","algorithmic disinformation","automated false information"],"example_sentence":"Algorithmic misinformation spreads quickly on social media.","example_es":"La desinformación algorítmica se propaga rápidamente en las redes sociales.","example_en":"Algorithmic misinformation spreads quickly on social media.","mnemonic_en":"A sneaky algorithm robot spreads fake news like a gossiping machine","cloze_distractors_en":["Beneficial transparency","Constructive journalism","Verified authenticity","Objective commentary"],"examples":[{"es":"La desinformación algorítmica se propaga rápidamente en las redes sociales.","en":"Algorithmic misinformation spreads quickly on social media."},{"es":"Los expertos advierten que la desinformación algorítmica puede manipular la opinión pública durante las elecciones.","en":"Experts warn that algorithmic misinformation can manipulate public opinion during elections."},{"es":"Las plataformas digitales deben implementar mejores filtros para combatir la desinformación algorítmica en sus feeds de noticias.","en":"Digital platforms must implement better filters to combat algorithmic misinformation in their news feeds."}]},{"spanish_text":"Cambio climático","english_text":"Climate change","section_name":"News and Society","part_of_speech":"noun","definition_en":"A long-term alteration in Earth''s average weather patterns, primarily caused by human activities that increase greenhouse gases.","main_translations_es":["Calentamiento global","Alteración climática"],"collocations":["climate change mitigation","climate change adaptation","address climate change"],"synonyms_en":["global warming","climate shift","environmental change"],"example_sentence":"Climate change is affecting the glaciers.","example_es":"El cambio climático está afectando a los glaciares.","example_en":"Climate change is affecting the glaciers.","mnemonic_en":"Picture the climate (clima) turning a huge cambio lever.","cloze_distractors_en":["Urban planning","Market volatility","Digital literacy","Public transport"],"examples":[{"es":"El cambio climático está afectando a los glaciares.","en":"Climate change is affecting the glaciers."},{"es":"Muchos países han firmado acuerdos internacionales para frenar el cambio climático.","en":"Many countries have signed international agreements to curb climate change."},{"es":"Los científicos advierten que el aumento de las temperaturas es una consecuencia directa del cambio climático.","en":"Scientists warn that rising temperatures are a direct consequence of climate change."}]},{"spanish_text":"Calentamiento global","english_text":"Global warming","section_name":"News and Society","part_of_speech":"noun","definition_en":"A long-term rise in Earth''s average atmospheric temperature caused primarily by human activities that increase greenhouse gas concentrations.","main_translations_es":["Calentamiento del planeta","Calentamiento climático"],"collocations":["combat global warming","effects of global warming","global warming mitigation","global warming is a serious issue"],"synonyms_en":["climate change","greenhouse effect","planetary heating"],"example_sentence":"Global warming is causing extreme weather events.","example_es":"El calentamiento global está provocando fenómenos climáticos extremos.","example_en":"Global warming is causing extreme weather events.","mnemonic_en":"Imagine the globe heating up like a global sweater, a calentamiento for the whole planet.","cloze_distractors_en":["Lunar eclipse","Solar radiation","Tectonic shifting","Urban expansion"],"examples":[{"es":"El calentamiento global está provocando fenómenos climáticos extremos.","en":"Global warming is causing extreme weather events."},{"es":"Los científicos advierten que el calentamiento global acelera el derretimiento de los glaciares.","en":"Scientists warn that global warming is accelerating the melting of glaciers."},{"es":"Muchos países han firmado tratados para reducir las emisiones que causan el calentamiento global.","en":"Many countries have signed treaties to reduce the emissions that cause global warming."}]},{"spanish_text":"Emisiones","english_text":"Emissions","section_name":"News and Society","part_of_speech":"noun","definition_en":"Substances, especially gases or particles, released into the atmosphere, typically as a result of industrial processes or combustion.","main_translations_es":["Descargas","Vertidos","Emanaciones"],"collocations":["greenhouse gas emissions","carbon emissions","emissions standards","emissions testing"],"synonyms_en":["discharges","outputs","releases"],"example_sentence":"The CO₂ emissions from the factory have increased this year.","example_es":"Las emisiones de CO₂ de la fábrica han aumentado este año.","example_en":"The CO₂ emissions from the factory have increased this year.","mnemonic_en":"Picture a factory puffing out clouds, its emissions echo the Spanish word emisiones.","cloze_distractors_en":["Admissions","Omissions","Permissions","Submissions"],"examples":[{"es":"Las emisiones de CO₂ de la fábrica han aumentado este año.","en":"The CO₂ emissions from the factory have increased this year."},{"es":"El gobierno ha implementado nuevas leyes para reducir las emisiones de los vehículos.","en":"The government has implemented new laws to reduce vehicle emissions."},{"es":"La cumbre climática se centró en cómo limitar las emisiones globales de gases de efecto invernadero.","en":"The climate summit focused on how to limit global greenhouse gas emissions."}]},{"spanish_text":"Huella de carbono","english_text":"Carbon footprint","section_name":"News and Society","part_of_speech":"noun","definition_en":"The total amount of greenhouse gases emitted directly or indirectly by a person, organization, event, or product.","main_translations_es":["Huella de carbono","Impacto de carbono","Emisión de CO₂"],"collocations":["reduce your carbon footprint","measure your carbon footprint","carbon footprint calculator","carbon footprint assessment"],"synonyms_en":["greenhouse gas emissions","environmental impact","climate impact"],"example_sentence":"Reducing our carbon footprint is essential to combat climate change.","example_es":"Reducir nuestra huella de carbono es esencial para combatir el cambio climático.","example_en":"Reducing our carbon footprint is essential to combat climate change.","mnemonic_en":"Picture a coal shoe leaving a huella on the ground.","cloze_distractors_en":["Digital landscape","Economic threshold","Social benchmark","Public narrative"],"examples":[{"es":"Reducir nuestra huella de carbono es esencial para combatir el cambio climático.","en":"Reducing our carbon footprint is essential to combat climate change."},{"es":"La empresa publicó un informe detallado sobre cómo planean minimizar su huella de carbono durante el próximo año.","en":"The company published a detailed report on how they plan to minimize their carbon footprint over the next year."},{"es":"Muchos consumidores eligen productos locales para disminuir su huella de carbono al evitar el transporte de larga distancia.","en":"Many consumers choose local products to lower their carbon footprint by avoiding long-distance transportation."}]},{"spanish_text":"Energía renovable","english_text":"Renewable energy","section_name":"News and Society","part_of_speech":"noun","definition_en":"Energy obtained from naturally replenished sources such as sunlight, wind, rain, tides, waves, and geothermal heat.","main_translations_es":["Energía limpia","Energía sostenible","Energía verde"],"collocations":["renewable energy sources","renewable energy sector","renewable energy projects","renewable energy investment"],"synonyms_en":["green power","sustainable power","clean energy"],"example_sentence":"Renewable energy reduces dependence on fossil fuels.","example_es":"La energía renovable reduce la dependencia de los combustibles fósiles.","example_en":"Renewable energy reduces dependence on fossil fuels.","mnemonic_en":"Imagine a wind turbine being renewed, spilling fresh energía like endless renewable energy","cloze_distractors_en":["Industrial waste","Nuclear weaponry","Deforestation rate","Corporate lobbying"],"examples":[{"es":"La energía renovable reduce la dependencia de los combustibles fósiles.","en":"Renewable energy reduces dependence on fossil fuels."},{"es":"El gobierno ha prometido invertir millones en proyectos de energía renovable para combatir el cambio climático.","en":"The government has promised to invest millions in renewable energy projects to combat climate change."},{"es":"Muchos países están instalando parques eólicos y solares para aumentar su capacidad de energía renovable.","en":"Many countries are installing wind and solar farms to increase their renewable energy capacity."}]},{"spanish_text":"Combustibles fósiles","english_text":"Fossil fuels","section_name":"News and Society","part_of_speech":"noun","definition_en":"Natural resources such as coal, oil, and natural gas formed from ancient organic matter and used as energy sources.","main_translations_es":["Combustibles no renovables","Energías fósiles","Recursos fósiles"],"collocations":["fossil fuel consumption","fossil fuel emissions","fossil fuel industry","fossil fuel dependence"],"synonyms_en":["nonrenewable fuels","petroleum products","coal and oil"],"example_sentence":"Fossil fuels are the main source of energy in the world.","example_es":"Los combustibles fósiles son la principal fuente de energía en el mundo.","example_en":"Fossil fuels are the main source of energy in the world.","mnemonic_en":"The dinosaur fossil says fósil as it fuels the car with fossil fuels.","cloze_distractors_en":["Solar panels","Wind turbines","Hydroelectric dams","Geothermal plants"],"examples":[{"es":"Los combustibles fósiles son la principal fuente de energía en el mundo.","en":"Fossil fuels are the main source of energy in the world."},{"es":"Muchos países están intentando reducir su dependencia de los combustibles fósiles para combatir el cambio climático.","en":"Many countries are trying to reduce their dependence on fossil fuels to combat climate change."},{"es":"La industria automotriz está abandonando gradualmente los combustibles fósiles en favor de los vehículos eléctricos.","en":"The automotive industry is gradually moving away from fossil fuels in favor of electric vehicles."}]},{"spanish_text":"Sequía","english_text":"Drought","section_name":"News and Society","part_of_speech":"noun","definition_en":"A prolonged period of abnormally low rainfall that results in a shortage of water.","main_translations_es":["Escasez de agua","Falta de lluvia","Sequía prolongada"],"collocations":["drought conditions","drought relief","drought-resistant","drought-stricken"],"synonyms_en":["dry spell","water shortage","aridity"],"example_sentence":"The drought has reduced the corn harvest this year.","example_es":"La sequía ha reducido la cosecha de maíz este año.","example_en":"The drought has reduced the corn harvest this year.","mnemonic_en":"Picture a cracked earth where the rain has fled, a drought like a Spanish sequía.","cloze_distractors_en":["Blueprint","Symphony","Pinnacle","Heritage"],"examples":[{"es":"La sequía ha reducido la cosecha de maíz este año.","en":"The drought has reduced the corn harvest this year."},{"es":"El gobierno declaró el estado de emergencia debido a la sequía prolongada en la región.","en":"The government declared a state of emergency due to the prolonged drought in the region."},{"es":"Los agricultores locales están sufriendo pérdidas económicas graves por culpa de la sequía.","en":"Local farmers are suffering severe economic losses because of the drought."}]},{"spanish_text":"Inundación","english_text":"Flood","section_name":"News and Society","part_of_speech":"noun","definition_en":"A large amount of water that covers land which is normally dry.","main_translations_es":["Desbordamiento","Aluvión","Inundación"],"collocations":["flood the market","flood of complaints","flood damage","flood plain"],"synonyms_en":["deluge","inundation","overflow"],"example_sentence":"The flood destroyed several houses in the town.","example_es":"La inundación destruyó varias casas en el pueblo.","example_en":"The flood destroyed several houses in the town.","mnemonic_en":"A flood is a huge water flod that inundates everything.","cloze_distractors_en":["Glacier","Pantry","Fossil","Statue"],"examples":[{"es":"La inundación destruyó varias casas en el pueblo.","en":"The flood destroyed several houses in the town."},{"es":"El gobierno envió ayuda humanitaria tras la gran inundación.","en":"The government sent humanitarian aid after the major flood."},{"es":"Debido a la inundación, las autoridades cerraron todas las carreteras principales.","en":"Due to the flood, the authorities closed all the main roads."}]},{"spanish_text":"Ola de calor","english_text":"Heatwave","section_name":"News and Society","part_of_speech":"noun","definition_en":"A prolonged period of excessively hot weather.","main_translations_es":["ola de calor","ola de calor intensa","ola de calor extremo"],"collocations":["heatwave warning","record-breaking heatwave","heatwave conditions","heatwave season"],"synonyms_en":["hot spell","heat spell","warm snap"],"example_sentence":"This week there was a heatwave that reached 40 degrees.","example_es":"Esta semana hubo una ola de calor que alcanzó los 40 grados.","example_en":"This week there was a heatwave that reached 40 degrees.","mnemonic_en":"Picture a scorching wave, an ''ola'' of heat rolling over the city.","cloze_distractors_en":["Moonlight","Backlash","Footprint"],"examples":[{"es":"Esta semana hubo una ola de calor que alcanzó los 40 grados.","en":"This week there was a heatwave that reached 40 degrees."},{"es":"Las autoridades emitieron una alerta roja debido a la intensa ola de calor en la ciudad.","en":"Authorities issued a red alert due to the intense heatwave in the city."},{"es":"El consumo de electricidad aumentó considerablemente durante la reciente ola de calor.","en":"Electricity consumption increased significantly during the recent heatwave."}]},{"spanish_text":"Conservación","english_text":"Conservation","section_name":"News and Society","part_of_speech":"noun","definition_en":"The protection, preservation, or careful management of natural resources and the environment.","main_translations_es":["Preservación","Protección","Cuidado"],"collocations":["wildlife conservation","conservation efforts","conservation area","conservationist"],"synonyms_en":["preservation","protection","safeguarding"],"example_sentence":"The conservation of forests is essential to combat climate change.","example_es":"La conservación de los bosques es esencial para combatir el cambio climático.","example_en":"The conservation of forests is essential to combat climate change.","mnemonic_en":"Imagine a guard preserving a jar of conserva to protect the forest","cloze_distractors_en":["Consumption","Construction","Contradiction","Contamination"],"examples":[{"es":"La conservación de los bosques es esencial para combatir el cambio climático.","en":"The conservation of forests is essential to combat climate change."},{"es":"El museo recibió una subvención para la conservación de sus pinturas antiguas.","en":"The museum received a grant for the conservation of its ancient paintings."},{"es":"El gobierno aprobó nuevas leyes para la conservación de las especies en peligro de extinción.","en":"The government passed new laws for the conservation of endangered species."}]},{"spanish_text":"Biodiversidad","english_text":"Biodiversity","section_name":"News and Society","part_of_speech":"noun","definition_en":"The variety of living organisms and their ecological interactions within a given area or across the planet.","main_translations_es":["Diversidad biológica","Variedad de especies","Riqueza biológica"],"collocations":["biodiversity loss","biodiversity conservation","biodiversity hotspot","biodiversity crisis"],"synonyms_en":["biological diversity","ecological variety","species richness"],"example_sentence":"Biodiversity is essential for the balance of the ecosystem.","example_es":"La biodiversidad es esencial para el equilibrio del ecosistema.","example_en":"Biodiversity is essential for the balance of the ecosystem.","mnemonic_en":"A bio diver explores a sea of many species, reminding you of biodiversidad.","cloze_distractors_en":["Bureaucracy","Hypocrisy","Monotony","Autocracy"],"examples":[{"es":"La biodiversidad es esencial para el equilibrio del ecosistema.","en":"Biodiversity is essential for the balance of the ecosystem."},{"es":"La deforestación en la selva amazónica amenaza gravemente la biodiversidad local.","en":"Deforestation in the Amazon rainforest severely threatens local biodiversity."},{"es":"El gobierno aprobó nuevas leyes para proteger la biodiversidad en los parques nacionales.","en":"The government passed new laws to protect biodiversity in national parks."}]},{"spanish_text":"Deforestación","english_text":"Deforestation","section_name":"News and Society","part_of_speech":"noun","definition_en":"The removal or clearing of trees and forested land, typically for human use such as agriculture or development.","main_translations_es":["Desforestación","Pérdida de bosques","Talado de bosques"],"collocations":["deforestation rates","deforestation and climate change","combat deforestation","reduce deforestation"],"synonyms_en":["tree clearing","clearcutting","forest clearing"],"example_sentence":"Deforestation is causing habitat loss in the Amazon.","example_es":"La deforestación está provocando la pérdida de hábitats en la Amazonía.","example_en":"Deforestation is causing habitat loss in the Amazon.","mnemonic_en":"Imagine a forest disappearing and you chant de-forest-ación as the trees vanish","cloze_distractors_en":["Reforestation","Afforestation","Conservation"],"examples":[{"es":"La deforestación está provocando la pérdida de hábitats en la Amazonía.","en":"Deforestation is causing habitat loss in the Amazon."},{"es":"El gobierno implementó nuevas leyes para frenar la deforestación en las zonas protegidas.","en":"The government implemented new laws to curb deforestation in protected areas."},{"es":"Muchos científicos advierten que la deforestación acelera el cambio climático global.","en":"Many scientists warn that deforestation accelerates global climate change."}]},{"spanish_text":"Contaminación","english_text":"Pollution","section_name":"News and Society","part_of_speech":"noun","definition_en":"Pollution is the introduction of harmful substances or energy into the environment.","main_translations_es":["Polución","Contaminación ambiental","Contaminación del aire"],"collocations":["air pollution","water pollution","pollution control","pollution levels"],"synonyms_en":["contamination","environmental degradation","toxic waste"],"example_sentence":"Air pollution is worsening the health of the population.","example_es":"La contaminación del aire está empeorando la salud de la población.","example_en":"Air pollution is worsening the health of the population.","mnemonic_en":"Picture a poll of dirty water that contaminates the town, reminding you of pollution.","cloze_distractors_en":["Nutrition","Education","Decoration","Innovation"],"examples":[{"es":"La contaminación del aire está empeorando la salud de la población.","en":"Air pollution is worsening the health of the population."},{"es":"El vertido de petróleo en el océano ha causado una grave contaminación en la costa.","en":"The oil spill in the ocean has caused severe pollution along the coast."},{"es":"Las nuevas regulaciones industriales buscan reducir la contaminación en los ríos cercanos.","en":"New industrial regulations aim to reduce pollution in the nearby rivers."}]},{"spanish_text":"Desperdicio","english_text":"Waste","section_name":"News and Society","part_of_speech":"noun","definition_en":"Waste is material, resources, or energy that is discarded, unused, or considered useless.","main_translations_es":["Desperdicio","Derroche","Pérdida"],"collocations":["waste of time","waste management","waste disposal","waste water"],"synonyms_en":["trash","garbage","squander"],"example_sentence":"Food waste is a serious problem.","example_es":"El desperdicio de alimentos es un problema grave.","example_en":"Food waste is a serious problem.","mnemonic_en":"Picture a waste dump with a big sign that reads Desperdicio.","cloze_distractors_en":["Wealth","Growth","Health","Faith"],"examples":[{"es":"El desperdicio de alimentos es un problema grave.","en":"Food waste is a serious problem."},{"es":"Las empresas deben reducir el desperdicio de plástico en sus procesos de fabricación.","en":"Companies must reduce plastic waste in their manufacturing processes."},{"es":"El gobierno implementó nuevas políticas para controlar el desperdicio de agua durante la sequía.","en":"The government implemented new policies to control water waste during the drought."}]},{"spanish_text":"Reciclaje","english_text":"Recycling","section_name":"News and Society","part_of_speech":"noun","definition_en":"The process of collecting and converting waste materials into new, usable products.","main_translations_es":["Reciclado","Reciclaje de residuos","Gestión de reciclaje"],"collocations":["recycling program","recycling bin","recycling center","recycling industry"],"synonyms_en":["reprocessing","reuse","material recovery"],"example_sentence":"Recycling helps protect the environment.","example_es":"El reciclaje ayuda a proteger el medio ambiente.","example_en":"Recycling helps protect the environment.","mnemonic_en":"Picture a recycling robot chanting reciclaje as it turns trash into treasure.","cloze_distractors_en":["Deforestation","Urbanization","Overconsumption","Privatization"],"examples":[{"es":"El reciclaje ayuda a proteger el medio ambiente.","en":"Recycling helps protect the environment."},{"es":"Debemos separar el plástico y el papel para facilitar el reciclaje en nuestra comunidad.","en":"We must separate plastic and paper to facilitate recycling in our community."},{"es":"La nueva ley municipal obliga a todos los vecinos a participar en el programa de reciclaje.","en":"The new municipal law requires all residents to participate in the recycling program."}]},{"spanish_text":"Economía circular","english_text":"Circular economy","section_name":"News and Society","part_of_speech":"noun","definition_en":"An economic system that aims to minimize waste and maximize resource use by reusing, repairing, refurbishing, and recycling materials and products.","main_translations_es":["Economía circular","Modelo de economía circular","Sistema de economía circular"],"collocations":["circular economy model","circular economy principles","circular economy approach","circular economy initiatives"],"synonyms_en":["closed-loop economy","regenerative economy","sustainable economy"],"example_sentence":"The company has adopted the circular economy to reduce its waste.","example_es":"La empresa ha adoptado la economía circular para reducir sus residuos.","example_en":"The company has adopted the circular economy to reduce its waste.","mnemonic_en":"Picture a round wheel of money turning, because circular economy sounds like a circular wheel of cash","cloze_distractors_en":["Vertical monopoly","Fragmented industry","Volatile currency","Stagnant hierarchy"],"examples":[{"es":"La empresa ha adoptado la economía circular para reducir sus residuos.","en":"The company has adopted the circular economy to reduce its waste."},{"es":"El gobierno está incentivando a las fábricas locales a implementar un modelo de economía circular para reciclar materiales.","en":"The government is incentivizing local factories to implement a circular economy model to recycle materials."},{"es":"Muchos expertos sostienen que la economía circular es fundamental para combatir el cambio climático a largo plazo.","en":"Many experts argue that the circular economy is essential for combating climate change in the long term."}]},{"spanish_text":"Seguridad alimentaria","english_text":"Food security","section_name":"News and Society","part_of_speech":"noun","definition_en":"Food security is the condition in which all people have reliable access to sufficient, safe, and nutritious food.","main_translations_es":["Seguridad alimentaria","Seguridad en la alimentación","Garantía alimentaria"],"collocations":["food security policy","food security challenges","global food security","food security and nutrition"],"synonyms_en":["nutritional security","food availability","stable food supply"],"example_sentence":"Food security is essential for sustainable development.","example_es":"La seguridad alimentaria es esencial para el desarrollo sostenible.","example_en":"Food security is essential for sustainable development.","mnemonic_en":"Picture a locked fridge: security seal keeps the food safe, like seguridad alimentaria.","cloze_distractors_en":["Urban hostility","Digital lethargy","Global apathy","Market volatility"],"examples":[{"es":"La seguridad alimentaria es esencial para el desarrollo sostenible.","en":"Food security is essential for sustainable development."},{"es":"La sequía prolongada ha puesto en grave riesgo la seguridad alimentaria de toda la región.","en":"The prolonged drought has put the food security of the entire region at serious risk."},{"es":"El gobierno implementó nuevas políticas agrícolas para fortalecer la seguridad alimentaria del país.","en":"The government implemented new agricultural policies to strengthen the country''s food security."}]},{"spanish_text":"Escasez de agua","english_text":"Water scarcity","section_name":"News and Society","part_of_speech":"noun","definition_en":"A condition in which there is insufficient available water to meet the needs of a region or population.","main_translations_es":["Falta de agua","Déficit hídrico","Escasez hídrica"],"collocations":["address water scarcity","water scarcity crisis","combat water scarcity","water scarcity issues"],"synonyms_en":["drought","water shortage","lack of water"],"example_sentence":"Water scarcity is affecting millions of people worldwide.","example_es":"La escasez de agua está afectando a millones de personas en todo el mundo.","example_en":"Water scarcity is affecting millions of people worldwide.","mnemonic_en":"Imagine a river that escapes and leaves a cracked water scarcity desert.","cloze_distractors_en":["Musical harmony","Culinary heritage","Botanical curiosity","Architectural legacy"],"examples":[{"es":"La escasez de agua está afectando a millones de personas en todo el mundo.","en":"Water scarcity is affecting millions of people worldwide."},{"es":"Los agricultores de la región temen que la escasez de agua arruine sus cosechas este verano.","en":"Farmers in the region fear that water scarcity will ruin their crops this summer."},{"es":"El gobierno ha implementado nuevas restricciones debido a la creciente escasez de agua en las ciudades.","en":"The government has implemented new restrictions due to the growing water scarcity in cities."}]},{"spanish_text":"Cadena de suministro","english_text":"Supply chain","section_name":"News and Society","part_of_speech":"noun","definition_en":"A network of organizations, activities, and resources that moves a product or service from supplier to customer.","main_translations_es":["Red de suministro","Cadena logística","Sistema de suministro"],"collocations":["supply chain management","global supply chain","supply chain disruption","supply chain network"],"synonyms_en":["logistics network","distribution network","procurement chain"],"example_sentence":"The company is optimizing its supply chain to reduce costs.","example_es":"La empresa está optimizando su cadena de suministro para reducir costos.","example_en":"The company is optimizing its supply chain to reduce costs.","mnemonic_en":"Picture a chain of crates delivering supplies, linking the Spanish ''cadena'' to the English supply chain.","cloze_distractors_en":["Supply closet","Supply teacher","Supply station","Supply vessel"],"examples":[{"es":"La empresa está optimizando su cadena de suministro para reducir costos.","en":"The company is optimizing its supply chain to reduce costs."},{"es":"La escasez de microchips ha provocado graves interrupciones en la cadena de suministro global.","en":"The microchip shortage has caused severe disruptions in the global supply chain."},{"es":"El gobierno busca diversificar la cadena de suministro de medicamentos esenciales para evitar futuras crisis.","en":"The government is seeking to diversify the essential medicine supply chain to avoid future crises."}]},{"spanish_text":"Interrupción","english_text":"Disruption","section_name":"News and Society","part_of_speech":"noun","definition_en":"A disturbance or interruption that prevents something from continuing smoothly.","main_translations_es":["Corte","Parada","Suspensión"],"collocations":["cause disruption","disruption of services","major disruption","disruption in the market"],"synonyms_en":["disturbance","interruption","upheaval"],"example_sentence":"The disruption of the power supply left the city without electricity.","example_es":"La interrupción del suministro eléctrico dejó a la ciudad sin luz.","example_en":"The disruption of the power supply left the city without electricity.","mnemonic_en":"Imagine a loud crash disrupting a quiet room, like an Interrupción breaking the silence.","cloze_distractors_en":["Fertility","Punctuality","Tolerance","Hospitality"],"examples":[{"es":"La interrupción del suministro eléctrico dejó a la ciudad sin luz.","en":"The disruption of the power supply left the city without electricity."},{"es":"La huelga de transporte causó una gran interrupción en los servicios de autobús.","en":"The transport strike caused a major disruption to bus services."},{"es":"La nueva tecnología digital provocó una interrupción en el modelo de negocio tradicional.","en":"The new digital technology caused a disruption in the traditional business model."}]},{"spanish_text":"Escalada","english_text":"Escalation","section_name":"News and Society","part_of_speech":"noun","definition_en":"A rapid increase or intensification, especially of a conflict, problem, or situation.","main_translations_es":["Subida","Ascenso","Trepar"],"collocations":["escalation of conflict","price escalation","rapid escalation","escalation clause"],"synonyms_en":["increase","rise","amplification"],"example_sentence":"The escalation of the conflict surprised everyone.","example_es":"La escalada del conflicto sorprendió a todos.","example_en":"The escalation of the conflict surprised everyone.","mnemonic_en":"Picture a climber on an escalada rope that suddenly becomes a rising chart, showing escalation.","cloze_distractors_en":["Retraction","Inhibition","Delegation","Allocation"],"examples":[{"es":"La escalada del conflicto sorprendió a todos.","en":"The escalation of the conflict surprised everyone."},{"es":"El gobierno teme una escalada en los precios de la energía este invierno.","en":"The government fears an escalation in energy prices this winter."},{"es":"La escalada de la violencia en la frontera obligó a cerrar las rutas comerciales.","en":"The escalation of violence at the border forced the closure of trade routes."}]},{"spanish_text":"Alto el fuego","english_text":"Ceasefire","section_name":"News and Society","part_of_speech":"noun","definition_en":"A temporary suspension of fighting between opposing sides.","main_translations_es":["Cese del fuego","Alto al fuego","Alto al combate"],"collocations":["call for a ceasefire","agree to a ceasefire","observe a ceasefire","hold a ceasefire"],"synonyms_en":["truce","armistice","halt to fighting"],"example_sentence":"The warring parties have agreed to a ceasefire to allow humanitarian aid to enter.","example_es":"Las partes en conflicto han acordado un alto el fuego para permitir la entrada de ayuda humanitaria.","example_en":"The warring parties have agreed to a ceasefire to allow humanitarian aid to enter.","mnemonic_en":"Picture a ceasefire where commanders yell ''Alto el fuego!'' to halt the fire.","cloze_distractors_en":["Censorship","Stalemate","Backlash","Hardship"],"examples":[{"es":"Las partes en conflicto han acordado un alto el fuego para permitir la entrada de ayuda humanitaria.","en":"The warring parties have agreed to a ceasefire to allow humanitarian aid to enter."},{"es":"El consejo de seguridad de la ONU exige un alto el fuego inmediato en la zona de guerra.","en":"The UN Security Council is demanding an immediate ceasefire in the war zone."},{"es":"Tras semanas de intensos bombardeos, finalmente se ha declarado un alto el fuego en la región.","en":"After weeks of heavy shelling, a ceasefire has finally been declared in the region."}]},{"spanish_text":"Sanción","english_text":"Sanction","section_name":"News and Society","part_of_speech":"noun","definition_en":"A penalty imposed for violating a law, rule, or regulation.","main_translations_es":["Castigo","Multa","Penalización"],"collocations":["impose sanctions","economic sanctions","sanctioned by the UN","sanction a law"],"synonyms_en":["penalty","approval","authorization"],"example_sentence":"The committee decided to impose a sanction of ten thousand euros on the club for violating the rules.","example_es":"El comité decidió imponer una sanción de diez mil euros al club por incumplir las normas.","example_en":"The committee decided to impose a sanction of ten thousand euros on the club for violating the rules.","mnemonic_en":"Picture a judge stamping a document with a red sanction stamp that reads Sanción","cloze_distractors_en":["Pinnacle","Doctrine","Appendix","Heritage"],"examples":[{"es":"El comité decidió imponer una sanción de diez mil euros al club por incumplir las normas.","en":"The committee decided to impose a sanction of ten thousand euros on the club for violating the rules."},{"es":"El gobierno anunció una nueva sanción económica contra el país vecino debido a sus políticas nucleares.","en":"The government announced a new economic sanction against the neighboring country due to its nuclear policies."},{"es":"El jugador recibió una sanción de tres partidos tras agredir a un rival durante el encuentro.","en":"The player received a three-match sanction after assaulting an opponent during the game."}]},{"spanish_text":"Ayuda humanitaria","english_text":"Humanitarian aid","section_name":"News and Society","part_of_speech":"noun","definition_en":"Assistance given to people in need, especially during crises or disasters, to alleviate suffering and protect life and health.","main_translations_es":["Asistencia humanitaria","Socorro humanitario","Apoyo humanitario"],"collocations":["provide humanitarian aid","humanitarian aid efforts","humanitarian aid organization","humanitarian aid funding"],"synonyms_en":["relief assistance","humanitarian assistance","disaster relief"],"example_sentence":"Humanitarian aid arrived in the area affected by the earthquake.","example_es":"La ayuda humanitaria llegó a la zona afectada por el terremoto.","example_en":"Humanitarian aid arrived in the area affected by the earthquake.","mnemonic_en":"Picture a human handing out aid while yelling Ayuda to the crowd.","cloze_distractors_en":["Commercial litigation","Diplomatic immunity","Administrative oversight","Technological infrastructure"],"examples":[{"es":"La ayuda humanitaria llegó a la zona afectada por el terremoto.","en":"Humanitarian aid arrived in the area affected by the earthquake."},{"es":"Varias organizaciones internacionales enviaron ayuda humanitaria para los refugiados que huyen del conflicto.","en":"Several international organizations sent humanitarian aid for the refugees fleeing the conflict."},{"es":"El gobierno autorizó el paso de camiones con ayuda humanitaria hacia las regiones más pobres del país.","en":"The government authorized the passage of trucks with humanitarian aid to the country''s poorest regions."}]},{"spanish_text":"Desplazamiento forzado","english_text":"Forced displacement","section_name":"News and Society","part_of_speech":"noun","definition_en":"The involuntary movement of people from their homes or habitual residence, usually caused by conflict, persecution, or natural disasters.","main_translations_es":["Desplazamiento forzado","Desplazamiento involuntario","Desplazamiento obligado"],"collocations":["forced displacement crisis","forced displacement of populations","address forced displacement","prevent forced displacement"],"synonyms_en":["forced migration","involuntary relocation","compulsory eviction"],"example_sentence":"The forced displacement of thousands of families has created a humanitarian crisis.","example_es":"El desplazamiento forzado de miles de familias ha creado una crisis humanitaria.","example_en":"The forced displacement of thousands of families has created a humanitarian crisis.","mnemonic_en":"A force shoves the word des off a map, creating forced displacement.","cloze_distractors_en":["Voluntary enrichment","Spontaneous celebration","Systemic improvement","Harmonious integration"],"examples":[{"es":"El desplazamiento forzado de miles de familias ha creado una crisis humanitaria.","en":"The forced displacement of thousands of families has created a humanitarian crisis."},{"es":"Las organizaciones internacionales denuncian el desplazamiento forzado provocado por el conflicto armado en la región.","en":"International organizations denounce the forced displacement caused by the armed conflict in the region."},{"es":"El gobierno implementó nuevas políticas para asistir a las víctimas del desplazamiento forzado en las zonas rurales.","en":"The government implemented new policies to assist victims of forced displacement in rural areas."}]},{"spanish_text":"Derechos humanos","english_text":"Human rights","section_name":"News and Society","part_of_speech":"noun","definition_en":"Fundamental rights and freedoms that belong to every person simply because they are human.","main_translations_es":["Derechos fundamentales","Derechos civiles","Derechos de la persona"],"collocations":["human rights violations","human rights activist","human rights law","human rights organization"],"synonyms_en":["civil liberties","fundamental rights","basic freedoms"],"example_sentence":"Human rights must be respected worldwide.","example_es":"Los derechos humanos deben ser respetados en todo el mundo.","example_en":"Human rights must be respected worldwide.","mnemonic_en":"Think of a human holding a shield labeled derechos to guard his rights.","cloze_distractors_en":["Weather patterns","Kitchen appliances","Grocery receipts","Laundry schedules"],"examples":[{"es":"Los derechos humanos deben ser respetados en todo el mundo.","en":"Human rights must be respected worldwide."},{"es":"La organización presentó un informe detallado sobre las violaciones a los derechos humanos en la región.","en":"The organization presented a detailed report on the violations of human rights in the region."},{"es":"El activista dedicó toda su vida a la defensa de los derechos humanos frente a la opresión gubernamental.","en":"The activist dedicated his entire life to the defense of human rights against government oppression."}]},{"spanish_text":"Libertad de expresión","english_text":"Freedom of speech","section_name":"News and Society","part_of_speech":"noun","definition_en":"The right to express one''s opinions publicly without censorship or restraint.","main_translations_es":["Libertad de expresión","Derecho a la libre expresión","Libertad de opinión"],"collocations":["freedom of speech is essential","protect freedom of speech","advocate for freedom of speech","freedom of speech rights"],"synonyms_en":["free speech","speech freedom","right to speak"],"example_sentence":"Freedom of speech is a fundamental right in a democracy.","example_es":"La libertad de expresión es un derecho fundamental en una democracia.","example_en":"Freedom of speech is a fundamental right in a democracy.","mnemonic_en":"Picture a free dome where a liberty flag waves and everyone shouts Libertad","cloze_distractors_en":["Compulsory silence","Government surveillance","Unchecked censorship","Mandatory propaganda"],"examples":[{"es":"La libertad de expresión es un derecho fundamental en una democracia.","en":"Freedom of speech is a fundamental right in a democracy."},{"es":"El periodista defendió la libertad de expresión durante su entrevista en televisión.","en":"The journalist defended freedom of speech during his television interview."},{"es":"Las nuevas leyes del país restringen la libertad de expresión en las redes sociales.","en":"The country''s new laws restrict freedom of speech on social media."}]},{"spanish_text":"Estado de derecho","english_text":"Rule of law","section_name":"News and Society","part_of_speech":"noun","definition_en":"The principle that all individuals and institutions, including the government, are bound by and accountable to publicly known laws.","main_translations_es":["Estado de la ley","ordenamiento jurídico","régimen de derecho"],"collocations":["uphold the rule of law","rule of law principles","rule of law framework","rule of law and democracy"],"synonyms_en":["legal order","lawful governance","juridical system"],"example_sentence":"Strengthening the rule of law is essential to guarantee the country''s democratic stability.","example_es":"El fortalecimiento del Estado de derecho es fundamental para garantizar la estabilidad democrática del país.","example_en":"Strengthening the rule of law is essential to guarantee the country''s democratic stability.","mnemonic_en":"A ruler sits on a law book inside a grand Estado, showing the rule of law.","cloze_distractors_en":["Rule of thumb","Role of play","Rate of flow","Route of path"],"examples":[{"es":"El fortalecimiento del Estado de derecho es fundamental para garantizar la estabilidad democrática del país.","en":"Strengthening the rule of law is essential to guarantee the country''s democratic stability."},{"es":"La comunidad internacional exige que el gobierno respete el Estado de derecho para evitar abusos de poder.","en":"The international community demands that the government respect the rule of law to prevent abuses of power."},{"es":"Sin un Estado de derecho sólido, los inversores extranjeros temen que sus contratos no sean protegidos por los tribunales.","en":"Without a solid rule of law, foreign investors fear that their contracts will not be protected by the courts."}]},{"spanish_text":"Reforma","english_text":"Reform","section_name":"News and Society","part_of_speech":"noun","definition_en":"A change made to improve a system, institution, or practice.","main_translations_es":["Modificación","Cambio","Reajuste"],"collocations":["tax reform","education reform","healthcare reform"],"synonyms_en":["improvement","change","overhaul"],"example_sentence":"The reform of the education system will be approved next month.","example_es":"La reforma del sistema educativo será aprobada el próximo mes.","example_en":"The reform of the education system will be approved next month.","mnemonic_en":"Picture a broken wall being re‑form‑ed during the Reforma, like rebuilding after a quake.","cloze_distractors_en":["Refusal","Retreat","Rebound","Recital"],"examples":[{"es":"La reforma del sistema educativo será aprobada el próximo mes.","en":"The reform of the education system will be approved next month."},{"es":"El gobierno anunció una reforma profunda en las leyes laborales para reducir el desempleo.","en":"The government announced a major reform of labor laws to reduce unemployment."},{"es":"Los ciudadanos exigen una reforma urgente del sistema de salud pública.","en":"Citizens are demanding an urgent reform of the public health system."}]},{"spanish_text":"Protesta","english_text":"Protest","section_name":"News and Society","part_of_speech":"noun","definition_en":"An expression of objection or disapproval, often manifested in a public demonstration.","main_translations_es":["manifestación","marcha","rebelión"],"collocations":["peaceful protest","protest march","protest against","protest rally"],"synonyms_en":["demonstration","objection","rally"],"example_sentence":"The students organized a protest against the school policy.","example_es":"Los estudiantes organizaron una protesta contra la política escolar.","example_en":"The students organized a protest against the school policy.","mnemonic_en":"Picture a crowd holding signs shouting Pro test! as the Spanish protesta erupts.","cloze_distractors_en":["Prophecy","Protocol","Provision","Procedure"],"examples":[{"es":"Los estudiantes organizaron una protesta contra la política escolar.","en":"The students organized a protest against the school policy."},{"es":"La policía bloqueó la calle principal durante la protesta de los trabajadores.","en":"The police blocked the main street during the protest by the workers."},{"es":"Miles de ciudadanos se unieron a la protesta frente al edificio del gobierno.","en":"Thousands of citizens joined the protest in front of the government building."}]},{"spanish_text":"Manifestación","english_text":"Demonstration","section_name":"News and Society","part_of_speech":"noun","definition_en":"A public protest or a presentation that shows how something works.","main_translations_es":["Protesta","Exhibición","Muestra"],"collocations":["public demonstration","demonstration of skill","scientific demonstration"],"synonyms_en":["protest","display","exhibition"],"example_sentence":"The demonstration against the labor reform attracted thousands of people.","example_es":"La manifestación contra la reforma laboral atrajo a miles de personas.","example_en":"The demonstration against the labor reform attracted thousands of people.","mnemonic_en":"A MANI shows a DEMO, so it becomes a DEMONSTRATION.","cloze_distractors_en":["Fabrication","Consolation","Declaration","Calibration"],"examples":[{"es":"La manifestación contra la reforma laboral atrajo a miles de personas.","en":"The demonstration against the labor reform attracted thousands of people."},{"es":"Los estudiantes organizaron una manifestación pacífica frente al ayuntamiento para pedir más becas.","en":"The students organized a peaceful demonstration in front of city hall to demand more scholarships."},{"es":"La policía tuvo que cortar el tráfico en el centro debido a una manifestación masiva por el cambio climático.","en":"The police had to block traffic in the city center due to a massive demonstration for climate change."}]},{"spanish_text":"Activismo","english_text":"Activism","section_name":"News and Society","part_of_speech":"noun","definition_en":"Activism is the practice of organized efforts to promote or oppose social, political, or environmental change.","main_translations_es":["Activismo","Activismo social","Activismo político"],"collocations":["grassroots activism","environmental activism","political activism","social activism"],"synonyms_en":["advocacy","campaigning","social action"],"example_sentence":"Youth activism has driven significant changes in environmental policy.","example_es":"El activismo juvenil ha impulsado cambios significativos en la política ambiental.","example_en":"Youth activism has driven significant changes in environmental policy.","mnemonic_en":"Picture an activist shouting activo while marching, showing activism is the active movement.","cloze_distractors_en":["Apathy","Stagnation","Negligence","Futility"],"examples":[{"es":"El activismo juvenil ha impulsado cambios significativos en la política ambiental.","en":"Youth activism has driven significant changes in environmental policy."},{"es":"Muchos ciudadanos participan en el activismo local para mejorar la seguridad de sus vecindarios.","en":"Many citizens participate in local activism to improve the safety of their neighborhoods."},{"es":"La organización utiliza el activismo digital para recaudar fondos destinados a la protección de especies en peligro.","en":"The organization uses digital activism to raise funds for the protection of endangered species."}]},{"spanish_text":"Movilización","english_text":"Mobilization","section_name":"News and Society","part_of_speech":"noun","definition_en":"The act of assembling and preparing troops or resources for active service.","main_translations_es":["Movilización","Despliegue","Activación"],"collocations":["mass mobilization","resource mobilization","mobilization effort","mobilization plan"],"synonyms_en":["deployment","activation","mustering"],"example_sentence":"The mobilization of resources was key to the project''s success.","example_es":"La movilización de los recursos fue clave para el éxito del proyecto.","example_en":"The mobilization of resources was key to the project''s success.","mnemonic_en":"A mobile van leads the parade, showing the power of mobilization.","cloze_distractors_en":["Stagnation","Negligence","Fabrication","Ventilation"],"examples":[{"es":"La movilización de los recursos fue clave para el éxito del proyecto.","en":"The mobilization of resources was key to the project''s success."},{"es":"El sindicato convocó una movilización masiva para protestar contra los recortes salariales.","en":"The union called for a massive mobilization to protest against the salary cuts."},{"es":"El gobierno ordenó la movilización de las tropas hacia la frontera tras el conflicto diplomático.","en":"The government ordered the mobilization of troops to the border following the diplomatic conflict."}]},{"spanish_text":"Conciencia pública","english_text":"Public awareness","section_name":"News and Society","part_of_speech":"noun","definition_en":"the state of being informed or conscious about a particular issue among the general public","main_translations_es":["conciencia colectiva","conciencia social","conciencia ciudadana"],"collocations":["raise public awareness","public awareness campaign","increase public awareness","public awareness of"],"synonyms_en":["public knowledge","community awareness","public consciousness"],"example_sentence":"The campaign raised public awareness about climate change.","example_es":"La campaña aumentó la conciencia pública sobre el cambio climático.","example_en":"The campaign raised public awareness about climate change.","mnemonic_en":"Picture a public plaza with a giant ''aware-ness'' billboard that reads ''conciencia'' for everyone to see.","cloze_distractors_en":["Private ignorance","Global indifference","Public negligence","Social intolerance"],"examples":[{"es":"La campaña aumentó la conciencia pública sobre el cambio climático.","en":"The campaign raised public awareness about climate change."},{"es":"El gobierno lanzó un anuncio para fomentar la conciencia pública sobre la importancia de reciclar.","en":"The government launched an advertisement to foster public awareness about the importance of recycling."},{"es":"Los activistas organizaron una marcha para generar conciencia pública acerca de la desigualdad social.","en":"The activists organized a march to generate public awareness regarding social inequality."}]},{"spanish_text":"Narrativa","english_text":"Narrative","section_name":"News and Society","part_of_speech":"noun","definition_en":"A spoken or written account of connected events; a story.","main_translations_es":["Relato","Historia","Crónica"],"collocations":["narrative structure","narrative voice","narrative arc","narrative perspective"],"synonyms_en":["story","account","tale"],"example_sentence":"The narrative of the novel captures the essence of the era.","example_es":"La narrativa de la novela captura la esencia de la época.","example_en":"The narrative of the novel captures the essence of the era.","mnemonic_en":"Picture a narrator writing a story, his narrativa becomes the narrative.","cloze_distractors_en":["Diameter","Pinnacle","Velocity","Heritage"],"examples":[{"es":"La narrativa de la novela captura la esencia de la época.","en":"The narrative of the novel captures the essence of the era."},{"es":"El candidato cambió su narrativa para atraer a más votantes durante el debate.","en":"The candidate changed his narrative to appeal to more voters during the debate."},{"es":"Los medios de comunicación suelen construir una narrativa específica sobre los conflictos internacionales.","en":"The media often constructs a specific narrative about international conflicts."}]},{"spanish_text":"Sesgo mediático","english_text":"Media bias","section_name":"News and Society","part_of_speech":"noun","definition_en":"A tendency of journalists or news outlets to present information in a way that favors a particular perspective or agenda.","main_translations_es":["Parcialidad mediática","Sesgo de los medios","Tendencia mediática"],"collocations":["media bias affects public opinion","combat media bias","perceived media bias","media bias in reporting"],"synonyms_en":["press bias","news bias","journalistic bias"],"example_sentence":"Media bias affects the way we perceive the news.","example_es":"El sesgo mediático afecta la forma en que percibimos las noticias.","example_en":"Media bias affects the way we perceive the news.","mnemonic_en":"Imagine a TV news tilt, a media bias – a slanted sesgo on the screen.","cloze_distractors_en":["Urban planning","Genetic testing","Musical harmony"],"examples":[{"es":"El sesgo mediático afecta la forma en que percibimos las noticias.","en":"Media bias affects the way we perceive the news."},{"es":"Muchos lectores critican el sesgo mediático en la cobertura de las elecciones presidenciales.","en":"Many readers criticize media bias in the coverage of the presidential elections."},{"es":"Es fundamental analizar las fuentes para identificar cualquier posible sesgo mediático en los artículos de opinión.","en":"It is essential to analyze the sources to identify any potential media bias in opinion pieces."}]},{"spanish_text":"Verificación de hechos","english_text":"Fact-checking","section_name":"News and Society","part_of_speech":"noun","definition_en":"The process of verifying the accuracy of information or claims.","main_translations_es":["Chequeo de datos","Contraste de hechos","Comprobación de hechos"],"collocations":["fact-checking process","fact-checking organization","fact-checking tools","fact-checking report"],"synonyms_en":["verification","source verification","truth verification"],"example_sentence":"Fact-checking is essential to combat misinformation.","example_es":"La verificación de hechos es esencial para combatir la desinformación.","example_en":"Fact-checking is essential to combat misinformation.","mnemonic_en":"Picture a detective checking facts and stamping each hecho with a green check.","cloze_distractors_en":["Fabrication","Speculation","Exaggeration","Misdirection"],"examples":[{"es":"La verificación de hechos es esencial para combatir la desinformación.","en":"Fact-checking is essential to combat misinformation."},{"es":"El periódico implementó un riguroso proceso de verificación de hechos antes de publicar el reportaje sobre el escándalo político.","en":"The newspaper implemented a rigorous process of fact-checking before publishing the report on the political scandal."},{"es":"Las plataformas digitales han contratado a más periodistas para realizar la verificación de hechos de los contenidos virales.","en":"Digital platforms have hired more journalists to perform fact-checking on viral content."}]},{"spanish_text":"Difundirse","english_text":"Spread rapidly","section_name":"News and Society","part_of_speech":"verb","definition_en":"To become widely known or distributed quickly.","main_translations_es":["propagarse","extenderse","diseminarse"],"collocations":["spread like wildfire","spread quickly","spread fast","spread at a rapid pace"],"synonyms_en":["propagate quickly","disseminate fast","snowball"],"example_sentence":"The rumor spread rapidly throughout the neighborhood.","example_es":"El rumor se difundió rápidamente por todo el vecindario.","example_en":"The rumor spread rapidly throughout the neighborhood.","mnemonic_en":"A fast‑spreading fire is a ''difund'' of flames racing across the forest.","cloze_distractors_en":["Evaporated slowly","Calculated precisely","Constructed heavily","Inherited quietly"],"examples":[{"es":"El rumor se difundió rápidamente por todo el vecindario.","en":"The rumor spread rapidly throughout the neighborhood."},{"es":"La noticia sobre la nueva ley se difundió rápidamente en las redes sociales.","en":"The news about the new law spread rapidly on social media."},{"es":"El virus se difundió rápidamente entre los trabajadores de la fábrica durante el invierno.","en":"The virus spread rapidly among the factory workers during the winter."}]},{"spanish_text":"Volverse viral","english_text":"Go viral","section_name":"News and Society","part_of_speech":"verb phrase","definition_en":"to become widely circulated on the internet, especially through rapid sharing.","main_translations_es":["Hacerse viral","Convertirse en viral","Tornar viral"],"collocations":["go viral on social media","go viral overnight","go viral quickly","go viral instantly"],"synonyms_en":["spread rapidly","catch on online","become a hit"],"example_sentence":"The video of the peaceful protest started to go viral within hours.","example_es":"El video de la protesta pacífica se volvió viral en cuestión de horas.","example_en":"The video of the peaceful protest started to go viral within hours.","mnemonic_en":"Picture a goat (go) turning into a virus, spreading wildly like a viral video.","cloze_distractors_en":["Go extinct","Go bankrupt","Go stagnant","Go dormant"],"examples":[{"es":"El video de la protesta pacífica se volvió viral en cuestión de horas.","en":"The video of the peaceful protest started to go viral within hours."},{"es":"La noticia sobre el nuevo impuesto empezó a volverse viral en todas las redes sociales.","en":"The news about the new tax started to go viral across all social media platforms."},{"es":"Es increíble lo rápido que puede volverse viral una campaña de concienciación sobre el cambio climático.","en":"It is incredible how quickly a climate change awareness campaign can go viral."}]},{"spanish_text":"Repercusiones","english_text":"Repercussions","section_name":"News and Society","part_of_speech":"noun","definition_en":"Unintended or indirect consequences of an action or event, often negative.","main_translations_es":["Consecuencias","Efectos","Resultados"],"collocations":["face the repercussions","have repercussions","repercussions of","suffer the repercussions"],"synonyms_en":["consequences","effects","ramifications"],"example_sentence":"The repercussions of the decision will be felt for years.","example_es":"Las repercusiones de la decisión se sentirán durante años.","example_en":"The repercussions of the decision will be felt for years.","mnemonic_en":"Hear re-per-cus-iones echo and picture the fallout spreading like ripples.","cloze_distractors_en":["Resonances","Reflections","Recurrences","Rebuttals"],"examples":[{"es":"Las repercusiones de la decisión se sentirán durante años.","en":"The repercussions of the decision will be felt for years."},{"es":"El escándalo político tuvo graves repercusiones en la popularidad del gobierno.","en":"The political scandal had serious repercussions on the government''s popularity."},{"es":"Debemos analizar las repercusiones económicas de esta nueva ley antes de aprobarla.","en":"We must analyze the economic repercussions of this new law before passing it."}]},{"spanish_text":"Consecuencia imprevista","english_text":"Unintended consequence","section_name":"News and Society","part_of_speech":"noun","definition_en":"An outcome that was not intended or expected.","main_translations_es":["Resultado inesperado","Efecto inesperado","Repercusiones no previstas"],"collocations":["as an unintended consequence","the unintended consequence","unintended consequence of","unintended consequence for"],"synonyms_en":["unforeseen result","unexpected outcome","unintended result"],"example_sentence":"The unintended consequence of his policy was an unexpected rise in inflation.","example_es":"La consecuencia imprevista de su política fue un aumento inesperado de la inflación.","example_en":"The unintended consequence of his policy was an unexpected rise in inflation.","mnemonic_en":"An unexpected accident creates a \"con-sequence\" chain, like a surprise domino effect.","cloze_distractors_en":["Deliberate objective","Calculated maneuver","Intentional strategy","Premeditated initiative"],"examples":[{"es":"La consecuencia imprevista de su política fue un aumento inesperado de la inflación.","en":"The unintended consequence of his policy was an unexpected rise in inflation."},{"es":"El uso excesivo de pesticidas tuvo como consecuencia imprevista la desaparición de las abejas locales.","en":"The excessive use of pesticides had the unintended consequence of the disappearance of local bees."},{"es":"La nueva ley de tráfico tuvo la consecuencia imprevista de colapsar las rutas alternativas de la ciudad.","en":"The new traffic law had the unintended consequence of clogging the city''s alternative routes."}]},{"spanish_text":"Resiliencia","english_text":"Resilience","section_name":"News and Society","part_of_speech":"noun","definition_en":"The ability to recover quickly from difficulties or to adapt in the face of adversity.","main_translations_es":["Capacidad de recuperación","Fortaleza mental","Elasticidad"],"collocations":["building resilience","resilience in the face of adversity","show resilience","resilience training"],"synonyms_en":["toughness","hardiness","flexibility"],"example_sentence":"The community''s resilience allowed it to recover quickly after the earthquake.","example_es":"La resiliencia de la comunidad le permitió recuperarse rápidamente después del terremoto.","example_en":"The community''s resilience allowed it to recover quickly after the earthquake.","mnemonic_en":"Imagine a resilient rubber band snapping back, echoing resiliencia in a storm.","cloze_distractors_en":["Negligence","Fragility","Inertia","Stagnation"],"examples":[{"es":"La resiliencia de la comunidad le permitió recuperarse rápidamente después del terremoto.","en":"The community''s resilience allowed it to recover quickly after the earthquake."},{"es":"El atleta demostró una gran resiliencia al volver a competir tras su grave lesión.","en":"The athlete showed great resilience by returning to competition after his serious injury."},{"es":"La economía del país ha mostrado una notable resiliencia frente a la crisis financiera global.","en":"The country''s economy has shown remarkable resilience in the face of the global financial crisis."}]},{"spanish_text":"Capacidad de adaptación","english_text":"Adaptability","section_name":"News and Society","part_of_speech":"noun","definition_en":"The ability to adjust to new conditions or changes.","main_translations_es":["Flexibilidad","Capacidad de ajuste","Aptitud para adaptarse"],"collocations":["adaptability is key","high adaptability","demonstrate adaptability","adaptability skills"],"synonyms_en":["flexibility","versatility","adjustability"],"example_sentence":"His adaptability allowed him to overcome the changes at work.","example_es":"Su capacidad de adaptación le permitió superar los cambios en el trabajo.","example_en":"His adaptability allowed him to overcome the changes at work.","mnemonic_en":"Think of a flexible cap that adapts to any shape, showing the adaptability of capacidad.","cloze_distractors_en":["Incompatibility","Unreliability","Predictability","Immobility"],"examples":[{"es":"Su capacidad de adaptación le permitió superar los cambios en el trabajo.","en":"His adaptability allowed him to overcome the changes at work."},{"es":"En un mercado laboral tan cambiante, la capacidad de adaptación es una habilidad fundamental para los jóvenes.","en":"In such a shifting job market, adaptability is a fundamental skill for young people."},{"es":"La empresa sobrevivió a la crisis económica gracias a la gran capacidad de adaptación de su equipo directivo.","en":"The company survived the economic crisis thanks to the great adaptability of its management team."}]},{"spanish_text":"Interdependencia","english_text":"Interdependence","section_name":"News and Society","part_of_speech":"noun","definition_en":"the mutual reliance between two or more entities, where each depends on the others.","main_translations_es":["Mutua dependencia","Dependencia recíproca","Interrelación"],"collocations":["mutual interdependence","economic interdependence","global interdependence","interdependence theory"],"synonyms_en":["mutual reliance","reciprocal dependence","co‑dependence"],"example_sentence":"The interdependence among Latin American countries is reflected in their trade agreements.","example_es":"La interdependencia entre los países latinoamericanos se refleja en sus acuerdos comerciales.","example_en":"The interdependence among Latin American countries is reflected in their trade agreements.","mnemonic_en":"Picture two friends leaning on each other, their bond is interdependence like inter and depend together.","cloze_distractors_en":["Independence","Insolvency","Intolerance","Indifference"],"examples":[{"es":"La interdependencia entre los países latinoamericanos se refleja en sus acuerdos comerciales.","en":"The interdependence among Latin American countries is reflected in their trade agreements."},{"es":"El cambio climático demuestra la interdependencia de todas las naciones frente a una crisis global.","en":"Climate change demonstrates the interdependence of all nations in the face of a global crisis."},{"es":"La economía moderna se basa en la interdependencia de los mercados financieros internacionales.","en":"The modern economy is based on the interdependence of international financial markets."}]},{"spanish_text":"Consenso científico","english_text":"Scientific consensus","section_name":"News and Society","part_of_speech":"noun","definition_en":"General agreement among scientists about a particular scientific finding or theory.","main_translations_es":["acuerdo científico","consenso de la comunidad científica","posicionamiento científico"],"collocations":["reach a scientific consensus","scientific consensus on climate change","widely accepted scientific consensus","the scientific consensus is that"],"synonyms_en":["expert agreement","research consensus","scientific agreement"],"example_sentence":"The scientific consensus indicates that climate change is primarily caused by human activity.","example_es":"El consenso científico indica que el cambio climático es causado principalmente por la actividad humana.","example_en":"The scientific consensus indicates that climate change is primarily caused by human activity.","mnemonic_en":"Scientists sit (siéntate) together, forming a scientific consensus.","cloze_distractors_en":["Political prejudice","Economic turbulence","Historical ignorance","Individual preference"],"examples":[{"es":"El consenso científico indica que el cambio climático es causado principalmente por la actividad humana.","en":"The scientific consensus indicates that climate change is primarily caused by human activity."},{"es":"Existe un consenso científico sobre la eficacia de las vacunas para prevenir enfermedades graves.","en":"There is a scientific consensus regarding the effectiveness of vaccines in preventing serious diseases."},{"es":"Los expertos buscan llegar a un consenso científico antes de publicar las nuevas directrices de salud pública.","en":"Experts aim to reach a scientific consensus before publishing the new public health guidelines."}]},{"spanish_text":"Debate ético","english_text":"Ethical debate","section_name":"News and Society","part_of_speech":"noun","definition_en":"A discussion that examines moral principles and values.","main_translations_es":["Discusión ética","Debate moral","Diálogo ético"],"collocations":["engage in an ethical debate","participate in an ethical debate","ethical debate on climate change","ethical debate surrounding AI"],"synonyms_en":["moral discussion","ethical discussion","moral debate"],"example_sentence":"The ethical debate about genetic editing is very controversial.","example_es":"El debate ético sobre la edición genética es muy controvertido.","example_en":"The ethical debate about genetic editing is very controversial.","mnemonic_en":"Visualize an ethical debate with participants holding big signs that read ético.","cloze_distractors_en":["Biological recipe","Technical appetite","Physical heritage","Chemical sequence"],"examples":[{"es":"El debate ético sobre la edición genética es muy controvertido.","en":"The ethical debate about genetic editing is very controversial."},{"es":"La inteligencia artificial ha generado un intenso debate ético en las universidades.","en":"Artificial intelligence has sparked an intense ethical debate in universities."},{"es":"Los médicos mantienen un debate ético constante sobre el uso de tratamientos experimentales.","en":"Doctors maintain a constant ethical debate regarding the use of experimental treatments."}]},{"spanish_text":"Brecha generacional","english_text":"Generation gap","section_name":"News and Society","part_of_speech":"noun","definition_en":"A difference in attitudes, values, and experiences between people of different generations.","main_translations_es":["brecha generacional","diferencia generacional","distancia generacional"],"collocations":["bridge the generation gap","close the generation gap","widen the generation gap","generation gap issues"],"synonyms_en":["age divide","intergenerational divide","youth‑adult divide"],"example_sentence":"The generation gap between young people and their parents is evident in their use of technology.","example_es":"La brecha generacional entre los jóvenes y sus padres se hace evidente en el uso de la tecnología.","example_en":"The generation gap between young people and their parents is evident in their use of technology.","mnemonic_en":"Picture a huge gap where a generation falls into a brecha, a crack separating the old from the young.","cloze_distractors_en":["Generation shift","Generation bond","Generation merit","Generation trend"],"examples":[{"es":"La brecha generacional entre los jóvenes y sus padres se hace evidente en el uso de la tecnología.","en":"The generation gap between young people and their parents is evident in their use of technology."},{"es":"Los expertos debaten cómo cerrar la brecha generacional en el lugar de trabajo para mejorar la colaboración.","en":"Experts are debating how to bridge the generation gap in the workplace to improve collaboration."},{"es":"Las diferencias políticas entre abuelos y nietos suelen ser un claro ejemplo de la brecha generacional.","en":"The political differences between grandparents and grandchildren are often a clear example of the generation gap."}]},{"spanish_text":"Presión social","english_text":"Social pressure","section_name":"News and Society","part_of_speech":"noun","definition_en":"The influence exerted by a group or society on an individual''s behavior or decisions.","main_translations_es":["presión social","presión de grupo","presión colectiva"],"collocations":["under social pressure","succumb to social pressure","resist social pressure","social pressure to conform"],"synonyms_en":["peer pressure","societal pressure","group pressure"],"example_sentence":"Social pressure led him to quit his job.","example_es":"La presión social lo llevó a dejar su trabajo.","example_en":"Social pressure led him to quit his job.","mnemonic_en":"Picture a social crowd pressing ion batteries, showing social pressure.","cloze_distractors_en":["Digital literacy","Economic surplus","Physical stamina","National identity"],"examples":[{"es":"La presión social lo llevó a dejar su trabajo.","en":"Social pressure led him to quit his job."},{"es":"Muchos adolescentes consumen alcohol debido a la presión social en sus grupos de amigos.","en":"Many teenagers consume alcohol due to social pressure within their peer groups."},{"es":"Ella decidió no seguir la moda actual para evitar la presión social de encajar en el grupo.","en":"She decided not to follow the latest fashion to avoid the social pressure of fitting in."}]},{"spanish_text":"Cohesión social","english_text":"Social cohesion","section_name":"News and Society","part_of_speech":"noun","definition_en":"The bonds, shared values, and sense of belonging that hold members of a society together.","main_translations_es":["Cooperación social","Solidaridad social","Integración social"],"collocations":["promote social cohesion","strengthen social cohesion","enhance social cohesion","social cohesion initiatives"],"synonyms_en":["community solidarity","social unity","social integration"],"example_sentence":"Social cohesion is essential for the community''s development.","example_es":"La cohesión social es fundamental para el desarrollo de la comunidad.","example_en":"Social cohesion is essential for the community''s development.","mnemonic_en":"Picture a social gathering where people tie a rope called ''cohesión'' to stay tightly connected.","cloze_distractors_en":["Digital isolation","Political friction","Economic stagnation","Bureaucratic apathy"],"examples":[{"es":"La cohesión social es fundamental para el desarrollo de la comunidad.","en":"Social cohesion is essential for the community''s development."},{"es":"El gobierno implementó nuevos programas para fortalecer la cohesión social en los barrios marginados.","en":"The government implemented new programs to strengthen social cohesion in marginalized neighborhoods."},{"es":"La desigualdad económica extrema amenaza la cohesión social de toda la nación.","en":"Extreme economic inequality threatens the social cohesion of the entire nation."}]},{"spanish_text":"Sentimiento de pertenencia","english_text":"Sense of belonging","section_name":"News and Society","part_of_speech":"noun","definition_en":"A feeling of being accepted and valued as part of a group or community.","main_translations_es":["Sentido de pertenencia","Sensación de pertenencia","Pertenencia"],"collocations":["foster a sense of belonging","enhance the sense of belonging","create a sense of belonging","sense of belonging"],"synonyms_en":["feeling of inclusion","community feeling","belongingness"],"example_sentence":"The sense of belonging he feels in his community motivates him to participate actively.","example_es":"El sentimiento de pertenencia que experimenta en su comunidad lo motiva a participar activamente.","example_en":"The sense of belonging he feels in his community motivates him to participate actively.","mnemonic_en":"I feel a sense of belonging like a censo of people holding hands.","cloze_distractors_en":["Lack of awareness","State of confusion","Point of departure","Mode of operation"],"examples":[{"es":"El sentimiento de pertenencia que experimenta en su comunidad lo motiva a participar activamente.","en":"The sense of belonging he feels in his community motivates him to participate actively."},{"es":"Las empresas modernas buscan fomentar un sentimiento de pertenencia para retener a sus empleados más talentosos.","en":"Modern companies seek to foster a sense of belonging to retain their most talented employees."},{"es":"Muchos inmigrantes luchan por encontrar un sentimiento de pertenencia al adaptarse a una cultura completamente nueva.","en":"Many immigrants struggle to find a sense of belonging when adapting to a completely new culture."}]},{"spanish_text":"Marginalización","english_text":"Marginalization","section_name":"News and Society","part_of_speech":"noun","definition_en":"The process of treating a person or group as insignificant or peripheral.","main_translations_es":["Exclusión","Segregación","Marginación"],"collocations":["social marginalization","economic marginalization","cultural marginalization","political marginalization"],"synonyms_en":["social exclusion","ostracism","peripheralization"],"example_sentence":"The marginalization of rural communities hinders their access to basic services.","example_es":"La marginalización de las comunidades rurales dificulta su acceso a servicios básicos.","example_en":"The marginalization of rural communities hinders their access to basic services.","mnemonic_en":"Picture a margin line shoving a crowd to the side, showing marginalization.","cloze_distractors_en":["Centralization","Modernization","Standardization","Stabilization"],"examples":[{"es":"La marginalización de las comunidades rurales dificulta su acceso a servicios básicos.","en":"The marginalization of rural communities hinders their access to basic services."},{"es":"El informe destaca cómo la falta de educación contribuye a la marginalización de los jóvenes en el mercado laboral.","en":"The report highlights how the lack of education contributes to the marginalization of young people in the labor market."},{"es":"Las políticas sociales deben enfocarse en reducir la marginalización de las minorías étnicas en las grandes ciudades.","en":"Social policies must focus on reducing the marginalization of ethnic minorities in large cities."}]},{"spanish_text":"Empoderamiento","english_text":"Empowerment","section_name":"News and Society","part_of_speech":"noun","definition_en":"The process of giving someone authority, confidence, or power to act or make decisions.","main_translations_es":["Capacitación","Fortalecimiento","Autonomía"],"collocations":["women''s empowerment","employee empowerment","community empowerment","empowerment program"],"synonyms_en":["authority","enablement","self-determination"],"example_sentence":"The empowerment of women is essential for sustainable development.","example_es":"El empoderamiento de las mujeres es fundamental para el desarrollo sostenible.","example_en":"The empowerment of women is essential for sustainable development.","mnemonic_en":"Visualize a glowing power button marked empower‑ment as you shout the Spanish word empoderamiento.","cloze_distractors_en":["Encroachment","Endorsement","Entrenchment","Embellishment"],"examples":[{"es":"El empoderamiento de las mujeres es fundamental para el desarrollo sostenible.","en":"The empowerment of women is essential for sustainable development."},{"es":"Los programas de capacitación técnica buscan el empoderamiento de los jóvenes en comunidades rurales.","en":"Technical training programs aim for the empowerment of young people in rural communities."},{"es":"La educación digital es una herramienta clave para el empoderamiento de los ciudadanos en la era de la información.","en":"Digital education is a key tool for the empowerment of citizens in the information age."}]},{"spanish_text":"Justicia climática","english_text":"Climate justice","section_name":"News and Society","part_of_speech":"noun","definition_en":"Climate justice is the principle of ensuring fair and equitable treatment of all people in the distribution of climate change impacts and responsibilities.","main_translations_es":["Equidad climática","Justicia ambiental del clima"],"collocations":["climate justice movement","climate justice framework","climate justice initiatives"],"synonyms_en":["environmental justice","climate equity","environmental equity"],"example_sentence":"Climate justice demands that rich countries cut their emissions to protect the most vulnerable.","example_es":"La justicia climática exige que los países ricos reduzcan sus emisiones para proteger a los más vulnerables.","example_en":"Climate justice demands that rich countries cut their emissions to protect the most vulnerable.","mnemonic_en":"Picture a courtroom in a stormy climate where justice rains down on the earth.","cloze_distractors_en":["Corporate apathy","Economic isolation","Technological fatigue","Political stagnation"],"examples":[{"es":"La justicia climática exige que los países ricos reduzcan sus emisiones para proteger a los más vulnerables.","en":"Climate justice demands that rich countries cut their emissions to protect the most vulnerable."},{"es":"Los manifestantes marcharon por el centro de la ciudad para reclamar justicia climática ante la inacción de los líderes mundiales.","en":"Protesters marched through the city center to demand climate justice in response to the inaction of world leaders."},{"es":"El informe destaca que la justicia climática es fundamental para ayudar a las comunidades insulares a adaptarse al aumento del nivel del mar.","en":"The report highlights that climate justice is essential to help island communities adapt to rising sea levels."}]},{"spanish_text":"Justicia social","english_text":"Social justice","section_name":"News and Society","part_of_speech":"noun","definition_en":"A principle of fairness that seeks equitable distribution of resources, rights, and opportunities within a society.","main_translations_es":["Justicia social","Equidad social","Igualdad social"],"collocations":["social justice movement","social justice issues","social justice advocacy","social justice initiatives"],"synonyms_en":["equity","fairness","equal rights"],"example_sentence":"The movement fights for social justice in the community.","example_es":"El movimiento lucha por la justicia social en la comunidad.","example_en":"The movement fights for social justice in the community.","mnemonic_en":"Picture a just sea where all people share social waves.","cloze_distractors_en":["Corporate negligence","Biological stagnation","Mechanical friction","Atmospheric density"],"examples":[{"es":"El movimiento lucha por la justicia social en la comunidad.","en":"The movement fights for social justice in the community."},{"es":"La universidad organizó un seminario sobre la importancia de la justicia social en la educación moderna.","en":"The university organized a seminar on the importance of social justice in modern education."},{"es":"Muchos activistas consideran que la igualdad de oportunidades es el pilar fundamental de la justicia social.","en":"Many activists consider equal opportunity to be the fundamental pillar of social justice."}]},{"spanish_text":"Responsabilidad compartida","english_text":"Shared responsibility","section_name":"News and Society","part_of_speech":"noun","definition_en":"A situation in which two or more parties are jointly accountable for an outcome.","main_translations_es":["Responsabilidad conjunta","Responsabilidad mutua","Responsabilidad colectiva"],"collocations":["shared responsibility for","shared responsibility between","shared responsibility model","shared responsibility approach"],"synonyms_en":["joint accountability","collective duty","mutual obligation"],"example_sentence":"Shared responsibility among nations is fundamental to combat global climate change.","example_es":"La responsabilidad compartida entre los países es fundamental para combatir el cambio climático global.","example_en":"Shared responsibility among nations is fundamental to combat global climate change.","mnemonic_en":"Imagine two people sharing a heavy bag of duty—shared responsibility","cloze_distractors_en":["Unilateral negligence","Individual indifference","Fragmented sovereignty","Competitive antagonism"],"examples":[{"es":"La responsabilidad compartida entre los países es fundamental para combatir el cambio climático global.","en":"Shared responsibility among nations is fundamental to combat global climate change."},{"es":"El acuerdo de paz enfatiza la responsabilidad compartida de todas las partes involucradas en el conflicto.","en":"The peace agreement emphasizes the shared responsibility of all parties involved in the conflict."},{"es":"La seguridad en el lugar de trabajo es una responsabilidad compartida entre los empleados y la gerencia.","en":"Workplace safety is a shared responsibility between employees and management."}]},{"spanish_text":"Tema candente","english_text":"Hot-button issue","section_name":"News and Society","part_of_speech":"noun","definition_en":"A controversial or emotionally charged topic that provokes strong opinions.","main_translations_es":["Asunto polémico","Cuestión delicada","Tema controvertido"],"collocations":["raise a hot‑button issue","address a hot‑button issue","hot‑button issue in politics"],"synonyms_en":["controversial topic","contentious issue","sensitive subject"],"example_sentence":"Climate change has become a hot-button issue in international politics.","example_es":"El cambio climático se ha convertido en un tema candente en la política internacional.","example_en":"Climate change has become a hot-button issue in international politics.","mnemonic_en":"Picture a red button on fire, the hot button that sparks every heated debate","cloze_distractors_en":["Cold-shoulder tactic","Hard-wired feature","Short-circuit process","Half-baked solution"],"examples":[{"es":"El cambio climático se ha convertido en un tema candente en la política internacional.","en":"Climate change has become a hot-button issue in international politics."},{"es":"La reforma del sistema educativo es un tema candente que divide a los votantes en las elecciones.","en":"Education reform is a hot-button issue that divides voters during the election."},{"es":"El uso de la inteligencia artificial en el trabajo sigue siendo un tema candente en los debates sobre el futuro laboral.","en":"The use of artificial intelligence in the workplace remains a hot-button issue in debates about the future of work."}]},{"spanish_text":"Amplia repercusión","english_text":"Far-reaching impact","section_name":"News and Society","part_of_speech":"noun phrase","definition_en":"A significant or extensive effect or influence.","main_translations_es":["Gran repercusión","Amplio alcance","Extensa influencia"],"collocations":["has a far‑reaching impact","far‑reaching impact on society","with far‑reaching impact","far‑reaching impact on the economy"],"synonyms_en":["wide-ranging effect","significant influence","extensive consequences"],"example_sentence":"The new law will have a far-reaching impact on the country''s economy.","example_es":"La nueva ley tendrá una amplia repercusión en la economía del país.","example_en":"The new law will have a far-reaching impact on the country''s economy.","mnemonic_en":"Picture a far‑reaching arm amplifying a massive ripple, a repercussion that spreads across the world.","cloze_distractors_en":["Short-lived vacuum","Narrow-minded friction","Self-centered altitude","Light-hearted friction"],"examples":[{"es":"La nueva ley tendrá una amplia repercusión en la economía del país.","en":"The new law will have a far-reaching impact on the country''s economy."},{"es":"El descubrimiento de esta tecnología de inteligencia artificial ha tenido una amplia repercusión en el mercado laboral global.","en":"The discovery of this artificial intelligence technology has had a far-reaching impact on the global labor market."},{"es":"El escándalo de corrupción política ha generado una amplia repercusión en la confianza de los ciudadanos hacia el gobierno.","en":"The political corruption scandal has generated a far-reaching impact on the citizens'' trust in the government."}]}]'::jsonb) as x(
  spanish_text text, english_text text, section_name text, part_of_speech text, definition_en text,
  main_translations_es jsonb, collocations jsonb, synonyms_en jsonb, example_sentence text, example_es text, example_en text, mnemonic_en text, cloze_distractors_en jsonb, examples jsonb
)
where c.deck_id = dk.id
  and lower(c.spanish_text) = lower(x.spanish_text)
  and lower(c.english_text) = lower(x.english_text);

-- english-advanced-phrasal-verbs (110 cards)
update public.decks set
  title = 'Advanced Phrasal Verbs', description = 'A large deck of phrasal verbs and common advanced uses to improve fluency and natural expression.',
  language_from = 'es', language_to = 'en'
where slug = 'english-advanced-phrasal-verbs';

update public.cards c set
  section_name = x.section_name, part_of_speech = x.part_of_speech, definition_en = x.definition_en,
  main_translations_es = coalesce(x.main_translations_es, '[]'::jsonb),
  collocations = coalesce(x.collocations, '[]'::jsonb),
  synonyms_en = coalesce(x.synonyms_en, '[]'::jsonb),
  example_sentence = x.example_sentence, example_es = x.example_es, example_en = x.example_en,
  mnemonic_en = coalesce(x.mnemonic_en, c.mnemonic_en),
  cloze_distractors_en = case when jsonb_array_length(coalesce(x.cloze_distractors_en, '[]'::jsonb)) > 0
                              then x.cloze_distractors_en else c.cloze_distractors_en end,
  examples = case when jsonb_array_length(coalesce(x.examples, '[]'::jsonb)) > 0
                  then x.examples else c.examples end
from (select id from public.decks where slug = 'english-advanced-phrasal-verbs') dk
cross join jsonb_to_recordset('[{"spanish_text":"Mencionar","english_text":"Bring up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to mention or raise a topic for discussion","main_translations_es":["Citar","Aludir","Referir"],"collocations":["bring up a topic","bring up an issue","bring up a child","bring up the subject"],"synonyms_en":["raise","mention","broach"],"example_sentence":"During the meeting, Juan brought up the budget issue.","example_es":"Durante la reunión, Juan mencionó el problema del presupuesto.","example_en":"During the meeting, Juan brought up the budget issue.","mnemonic_en":"Imagine a man (men) being lifted up, so you bring him up to mention the story.","cloze_distractors_en":[],"examples":[{"es":"Durante la reunión, Juan mencionó el problema del presupuesto.","en":"During the meeting, Juan brought up the budget issue."},{"es":"Por favor, no menciones el accidente cuando hables con su madre.","en":"Please do not bring up the accident when you talk to his mother."},{"es":"Ella mencionó su ascenso inesperado mientras celebrábamos el cumpleaños.","en":"She brought up her unexpected promotion while we were celebrating the birthday."}]},{"spanish_text":"Llevar a cabo","english_text":"Carry out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to perform or execute a task or plan","main_translations_es":["realizar","ejecutar","desarrollar"],"collocations":["carry out a plan","carry out an experiment","carry out the investigation","carry out duties"],"synonyms_en":["execute","perform","implement"],"example_sentence":"The team of engineers must carry out safety tests before opening the bridge.","example_es":"El equipo de ingenieros debe llevar a cabo pruebas de seguridad antes de abrir el puente.","example_en":"The team of engineers must carry out safety tests before opening the bridge.","mnemonic_en":"Imagine a carrier delivering a cargo to a cape (cabo) – you carry out the mission.","cloze_distractors_en":["Look away","Back down","Fall apart","Give over"],"examples":[{"es":"El equipo de ingenieros debe llevar a cabo pruebas de seguridad antes de abrir el puente.","en":"The team of engineers must carry out safety tests before opening the bridge."},{"es":"La empresa decidió llevar a cabo una encuesta para conocer la opinión de sus clientes.","en":"The company decided to carry out a survey to learn the opinion of its customers."},{"es":"El científico se preparó para llevar a cabo un experimento complejo en el laboratorio durante la noche.","en":"The scientist prepared to carry out a complex experiment in the laboratory throughout the night."}]},{"spanish_text":"Encontrarse con","english_text":"Come across","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to find or meet something or someone by chance","main_translations_es":["Toparse con","Tropezar con","Dar con"],"collocations":["come across as","come across something","come across unexpectedly"],"synonyms_en":["encounter","find","stumble upon"],"example_sentence":"I came across an old friend at the market.","example_es":"Me encontré con un viejo amigo en el mercado.","example_en":"I came across an old friend at the market.","mnemonic_en":"I come across (como cruz) a friend and we meet.","cloze_distractors_en":[],"examples":[{"es":"Me encontré con un viejo amigo en el mercado.","en":"I came across an old friend at the market."},{"es":"Mientras limpiaba el desván, me encontré con una caja llena de fotografías antiguas de mis abuelos.","en":"While cleaning the attic, I came across a box full of old photographs of my grandparents."},{"es":"Me encontré con un error técnico en el informe justo antes de enviarlo a mi jefe.","en":"I came across a technical error in the report just before sending it to my boss."}]},{"spanish_text":"Idear","english_text":"Come up with","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To think of or produce an idea, plan, or solution.","main_translations_es":["concebir","inventar","elaborar"],"collocations":["come up with an idea","come up with a solution","come up with a plan","come up with a name"],"synonyms_en":["think of","devise","invent"],"example_sentence":"We need to come up with a solution before the day ends.","example_es":"Necesitamos idear una solución antes de que termine el día.","example_en":"We need to come up with a solution before the day ends.","mnemonic_en":"I see a lightbulb rise as I idear and come up with a new plan.","cloze_distractors_en":["Look down on","Pass out of","Give in to"],"examples":[{"es":"Necesitamos idear una solución antes de que termine el día.","en":"We need to come up with a solution before the day ends."},{"es":"El equipo tuvo que idear un plan de emergencia tras el fallo del sistema.","en":"The team had to come up with an emergency plan after the system failure."},{"es":"Ella siempre logra idear excusas creativas cuando llega tarde a clase.","en":"She always manages to come up with creative excuses when she arrives late to class."}]},{"spanish_text":"Reducir","english_text":"Cut down on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to reduce the amount or frequency of something","main_translations_es":["Disminuir","Recortar","Ajustar"],"collocations":["cut down on sugar","cut down on expenses","cut down on smoking"],"synonyms_en":["reduce","curtail","scale back"],"example_sentence":"I need to cut down on sugar consumption.","example_es":"Necesito reducir el consumo de azúcar.","example_en":"I need to cut down on sugar consumption.","mnemonic_en":"Picture a red cutter shrinking a pile, so you cut down on it.","cloze_distractors_en":["Look out for","Bring up with","Make off with","Hold out for"],"examples":[{"es":"Necesito reducir el consumo de azúcar.","en":"I need to cut down on sugar consumption."},{"es":"El médico me recomendó reducir el consumo de grasas saturadas para mejorar mi salud cardiovascular.","en":"The doctor recommended that I cut down on saturated fats to improve my cardiovascular health."},{"es":"Si queremos ahorrar dinero este mes, debemos reducir nuestros gastos en salidas a restaurantes.","en":"If we want to save money this month, we must cut down on our spending at restaurants."}]},{"spanish_text":"Eliminar","english_text":"Do away with","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To eliminate or get rid of something.","main_translations_es":["Borrar","Suprimir","Quitar"],"collocations":["do away with poverty","do away with the old system","do away with unnecessary rules"],"synonyms_en":["eliminate","abolish","remove"],"example_sentence":"The government decided to do away with import taxes.","example_es":"El gobierno decidió eliminar los impuestos a la importación.","example_en":"The government decided to do away with import taxes.","mnemonic_en":"Imagine a dough (do) being tossed away, eliminating it.","cloze_distractors_en":["Put up with","Look out for","Fall back on","Make up for"],"examples":[{"es":"El gobierno decidió eliminar los impuestos a la importación.","en":"The government decided to do away with import taxes."},{"es":"La empresa planea eliminar el uso de papel en todas sus oficinas.","en":"The company plans to do away with the use of paper in all its offices."},{"es":"Es necesario eliminar las reglas obsoletas para mejorar la eficiencia del equipo.","en":"It is necessary to do away with obsolete rules to improve team efficiency."}]},{"spanish_text":"Resolver","english_text":"Figure out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To understand or solve something by thinking about it.","main_translations_es":["Resolver","Solucionar","Despejar"],"collocations":["figure out the problem","figure out how","figure out why","figure out the solution"],"synonyms_en":["solve","determine","work out"],"example_sentence":"I need to figure out this problem before the meeting.","example_es":"Necesito resolver este problema antes de la reunión.","example_en":"I need to figure out this problem before the meeting.","mnemonic_en":"Imagine a figure wielding a resolver wrench to crack the puzzle.","cloze_distractors_en":["Turn across","Bring under","Hold beyond","Keep beside"],"examples":[{"es":"Necesito resolver este problema antes de la reunión.","en":"I need to figure out this problem before the meeting."},{"es":"Todavía no he podido resolver cómo funciona este nuevo software.","en":"I still haven''t been able to figure out how this new software works."},{"es":"Es difícil resolver por qué el coche no arranca esta mañana.","en":"It is difficult to figure out why the car won''t start this morning."}]},{"spanish_text":"Rellenar","english_text":"Fill in","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To complete something by adding missing information.","main_translations_es":["Completar","Llenar","Ingresar"],"collocations":["fill in the blanks","fill in the form","fill in the details"],"synonyms_en":["complete","fill out","enter"],"example_sentence":"Please fill in the form before the deadline.","example_es":"Por favor, rellena el formulario antes de la fecha límite.","example_en":"Please fill in the form before the deadline.","mnemonic_en":"Picture a reel near a paper and you fill in the blanks on it.","cloze_distractors_en":["Look over","Turn away","Break down","Hold back"],"examples":[{"es":"Por favor, rellena el formulario antes de la fecha límite.","en":"Please fill in the form before the deadline."},{"es":"Si no sabes la respuesta, puedes dejar el espacio en blanco o intentar rellenar los huecos con la información correcta.","en":"If you do not know the answer, you can leave the space blank or try to fill in the blanks with the correct information."},{"es":"El candidato tuvo que rellenar una solicitud detallada para aplicar al puesto de trabajo.","en":"The candidate had to fill in a detailed application to apply for the job position."}]},{"spanish_text":"Cumplir hasta el final","english_text":"Follow through","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To continue an action or task until it is completed.","main_translations_es":["Cumplir hasta el final","Llevar a cabo","Ver hasta el final"],"collocations":["follow through on","follow through with","see it through","carry out"],"synonyms_en":["carry out","see it through","complete"],"example_sentence":"It''s important to follow through with the projects we start.","example_es":"Es importante cumplir hasta el final con los proyectos que iniciamos.","example_en":"It''s important to follow through with the projects we start.","mnemonic_en":"Think of a ‘full’ line you must ‘through’ to the end, like Cumplir hasta el final.","cloze_distractors_en":["Break away","Turn aside","Hold back","Fall under"],"examples":[{"es":"Es importante cumplir hasta el final con los proyectos que iniciamos.","en":"It''s important to follow through with the projects we start."},{"es":"Aunque prometió ayudarme con la mudanza, no pudo cumplir hasta el final con su palabra.","en":"Although he promised to help me move, he failed to follow through on his word."},{"es":"Si decides inscribirte en el curso de maratón, debes cumplir hasta el final con el entrenamiento diario.","en":"If you decide to sign up for the marathon course, you must follow through with the daily training."}]},{"spanish_text":"Transmitir","english_text":"Get across","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To communicate or convey an idea, feeling, or message so that it is understood.","main_translations_es":["Comunicar","Transmitir","Pasar"],"collocations":["get the point across","get the message across","make sure it gets across"],"synonyms_en":["convey","communicate","express"],"example_sentence":"The teacher managed to get across the idea clearly.","example_es":"El profesor logró transmitir la idea de manera clara.","example_en":"The teacher managed to get across the idea clearly.","mnemonic_en":"Picture a goat (get) crossing a bridge, shouting the news across the river like you transmit.","cloze_distractors_en":["Get around","Get under","Get behind","Get beyond"],"examples":[{"es":"El profesor logró transmitir la idea de manera clara.","en":"The teacher managed to get across the idea clearly."},{"es":"Es difícil transmitir mis sentimientos en una carta tan breve.","en":"It is difficult to get across my feelings in such a short letter."},{"es":"El político intentó transmitir su mensaje de cambio a los votantes indecisos.","en":"The politician tried to get across his message of change to the undecided voters."}]},{"spanish_text":"Salirse con la suya","english_text":"Get away with","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb phrase","definition_en":"To succeed in doing something that is disapproved of or illegal without being punished.","main_translations_es":["Salir impune","Escapar sin castigo","Quedarse con la razón"],"collocations":["get away with murder","get away with cheating","can''t get away with that","get away with it"],"synonyms_en":["escape punishment","avoid consequences","pull off"],"example_sentence":"Juan tried to rob the store, but the police caught him before he could get away with it.","example_es":"Juan intentó robar la tienda, pero la policía lo atrapó antes de que pudiera salirse con la suya.","example_en":"Juan tried to rob the store, but the police caught him before he could get away with it.","mnemonic_en":"Picture a cat that gets away with the fish, sneaking out (salir) triumphantly.","cloze_distractors_en":["Look down on","Bring up with","Fall back on"],"examples":[{"es":"Juan intentó robar la tienda, pero la policía lo atrapó antes de que pudiera salirse con la suya.","en":"Juan tried to rob the store, but the police caught him before he could get away with it."},{"es":"El estudiante copió en el examen final y, aunque el profesor sospechaba, logró salirse con la suya.","en":"The student cheated on the final exam and, even though the teacher was suspicious, he managed to get away with it."},{"es":"Ella rompió el jarrón antiguo de su madre y escondió los trozos para intentar salirse con la suya.","en":"She broke her mother''s antique vase and hid the pieces to try to get away with it."}]},{"spanish_text":"Arreglárselas","english_text":"Get by","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to manage to survive or cope with a situation, often with limited resources.","main_translations_es":["Apañarse","Sobrevivir","Librarse"],"collocations":["get by on a salary","get by with difficulty","just get by","get by in life"],"synonyms_en":["manage","survive","cope"],"example_sentence":"With so little money, I have to get by.","example_es":"Con tan poco dinero, tengo que arreglármelas.","example_en":"With so little money, I have to get by.","mnemonic_en":"A clever guy arranges tools to get by.","cloze_distractors_en":["Get off","Get up","Get in","Get at"],"examples":[{"es":"Con tan poco dinero, tengo que arreglármelas.","en":"With so little money, I have to get by."},{"es":"Aunque no hablo francés, pude arreglármelas durante mi viaje a París.","en":"Even though I do not speak French, I managed to get by during my trip to Paris."},{"es":"Sin un coche, ella se las arregla usando el transporte público todos los días.","en":"Without a car, she manages to get by using public transportation every day."}]},{"spanish_text":"Superar","english_text":"Get over","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To recover from or move beyond something, such as an illness, difficulty, or emotional upset.","main_translations_es":["Vencer","Sobrepasar","Sobreponerse"],"collocations":["get over it","get over a cold","get over the loss","get over the hurdle"],"synonyms_en":["recover from","move past","overcome"],"example_sentence":"I had to get over my fear of flying.","example_es":"Tuve que superar mi miedo a volar.","example_en":"I had to get over my fear of flying.","mnemonic_en":"Visualize a superhero goat leaping over a wall, shouting Get over, to remember Superar","cloze_distractors_en":["Look after","Bring about","Call off","Hold onto"],"examples":[{"es":"Tuve que superar mi miedo a volar.","en":"I had to get over my fear of flying."},{"es":"Le costó mucho superar la ruptura con su pareja de hace años.","en":"It took her a long time to get over the breakup with her long-term partner."},{"es":"Es difícil superar el trauma de haber perdido su casa en el incendio.","en":"It is difficult to get over the trauma of losing his home in the fire."}]},{"spanish_text":"Ceder","english_text":"Give in","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to surrender or yield to someone or something","main_translations_es":["rendirse","ceder","conceder"],"collocations":["give in to pressure","give in to temptation","give in easily","give in finally"],"synonyms_en":["yield","surrender","succumb"],"example_sentence":"After a long argument, he decided to give in to his demands.","example_es":"Después de mucho discutir, decidió ceder a sus demandas.","example_en":"After a long argument, he decided to give in to his demands.","mnemonic_en":"Picture a cedar tree bending, it gives in to the wind.","cloze_distractors_en":["Look up","Call off","Hold on","Bring out"],"examples":[{"es":"Después de mucho discutir, decidió ceder a sus demandas.","en":"After a long argument, he decided to give in to his demands."},{"es":"Aunque el niño lloró durante horas, sus padres no quisieron ceder ante sus caprichos.","en":"Even though the child cried for hours, his parents refused to give in to his tantrums."},{"es":"La estructura del puente empezó a ceder bajo el peso excesivo de los camiones.","en":"The bridge structure started to give in under the excessive weight of the trucks."}]},{"spanish_text":"Rendirse","english_text":"Give up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To stop trying to achieve something or to surrender.","main_translations_es":["darse por vencido","ceder","abandonar"],"collocations":["give up smoking","give up on","give up the habit","give up the fight"],"synonyms_en":["quit","surrender","abandon"],"example_sentence":"I won''t give up so easily.","example_es":"No voy a rendirme tan fácilmente.","example_en":"I won''t give up so easily.","mnemonic_en":"Picture a torn (rend) rope that finally gives up and falls.","cloze_distractors_en":["Take off","Look over","Hold back","Carry out"],"examples":[{"es":"No voy a rendirme tan fácilmente.","en":"I won''t give up so easily."},{"es":"Aunque el examen era muy difícil, decidió no rendirse y terminó todos los ejercicios.","en":"Even though the exam was very difficult, he decided not to give up and finished all the exercises."},{"es":"Después de intentar arreglar la computadora durante horas, finalmente tuve que rendirme y llamar a un técnico.","en":"After trying to fix the computer for hours, I finally had to give up and call a technician."}]},{"spanish_text":"Repasar","english_text":"Go over","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To examine or review something carefully.","main_translations_es":["Revisar","Estudiar","Repasar"],"collocations":["go over the details","go over the plan","go over the results","go over the material"],"synonyms_en":["review","examine","cover"],"example_sentence":"I will go over my notes before the exam.","example_es":"Voy a repasar mis notas antes del examen.","example_en":"I will go over my notes before the exam.","mnemonic_en":"Picture a goat going over a fence, chanting re-pass ar to recall repasar","cloze_distractors_en":["Run off","Back down","Fade out","Step in"],"examples":[{"es":"Voy a repasar mis notas antes del examen.","en":"I will go over my notes before the exam."},{"es":"El abogado necesita repasar el contrato antes de firmarlo.","en":"The lawyer needs to go over the contract before signing it."},{"es":"Vamos a repasar los detalles del viaje durante la cena.","en":"We are going to go over the travel details during dinner."}]},{"spanish_text":"Crecer","english_text":"Grow up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to develop from a child into an adult","main_translations_es":["Desarrollarse","Madurar","Aumentar"],"collocations":["grow up fast","grow up to be","grow up with","grow up in"],"synonyms_en":["mature","become an adult","reach adulthood"],"example_sentence":"Children should grow up in a safe environment.","example_es":"Los niños deben crecer en un ambiente seguro.","example_en":"Children should grow up in a safe environment.","mnemonic_en":"Picture a child growing up, shouting crecer as he reaches the sky","cloze_distractors_en":["Wake up","Show up","Blow up","Hold up"],"examples":[{"es":"Los niños deben crecer en un ambiente seguro.","en":"Children should grow up in a safe environment."},{"es":"Ella quiere volver al pueblo donde pudo crecer rodeada de naturaleza.","en":"She wants to return to the village where she was able to grow up surrounded by nature."},{"es":"Es difícil ver a tus hijos crecer tan rápido mientras pasan los años.","en":"It is hard to watch your children grow up so fast as the years go by."}]},{"spanish_text":"Entregar","english_text":"Hand in","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to submit something, such as a document or assignment, to the appropriate authority.","main_translations_es":["entregar","presentar","someter"],"collocations":["hand in your assignment","hand in a report","hand in the paperwork","hand in a resignation"],"synonyms_en":["submit","turn in","deliver"],"example_sentence":"I have to hand in the report before five.","example_es":"Tengo que entregar el informe antes de las cinco.","example_en":"I have to hand in the report before five.","mnemonic_en":"Imagine handing in a rag as you enter the classroom.","cloze_distractors_en":["Look after","Bring about","Carry away","Break down"],"examples":[{"es":"Tengo que entregar el informe antes de las cinco.","en":"I have to hand in the report before five."},{"es":"Los estudiantes deben entregar sus exámenes al terminar la clase.","en":"Students must hand in their exams when they finish the class."},{"es":"No olvides entregar la solicitud firmada en la oficina de administración.","en":"Do not forget to hand in the signed application at the administration office."}]},{"spanish_text":"Reprimirse","english_text":"Hold back","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To restrain or keep something from progressing or being expressed.","main_translations_es":["contenerse","restringirse","autocontrolarse"],"collocations":["hold back tears","hold back the crowd","hold back emotions","hold back the tide"],"synonyms_en":["restrain","suppress","withhold"],"example_sentence":"You shouldn''t hold back and say what you feel.","example_es":"No deberías reprimirte y decir lo que sientes.","example_en":"You shouldn''t hold back and say what you feel.","mnemonic_en":"Picture a REPRIMe bottle trying to hold back a flood.","cloze_distractors_en":["Look down","Pass over","Turn away","Bring up"],"examples":[{"es":"No deberías reprimirte y decir lo que sientes.","en":"You shouldn''t hold back and say what you feel."},{"es":"A pesar del miedo, ella no pudo reprimirse y saltó al agua.","en":"Despite her fear, she could not hold back and jumped into the water."},{"es":"Él intentó reprimirse, pero terminó estallando de risa en medio de la reunión.","en":"He tried to hold back, but he ended up bursting into laughter in the middle of the meeting."}]},{"spanish_text":"Mantener el ritmo","english_text":"Keep up with","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To stay at the same level or pace as someone or something.","main_translations_es":["Seguir el ritmo","Mantener el paso","No quedarse atrás"],"collocations":["keep up with the latest trends","keep up with the news","keep up with your studies","keep up with the schedule"],"synonyms_en":["stay current with","maintain pace with","keep pace with"],"example_sentence":"It''s hard to keep up with the pace of the dance class.","example_es":"Es difícil mantener el ritmo de la clase de baile.","example_en":"It''s hard to keep up with the pace of the dance class.","mnemonic_en":"Picture a cup dancing, keeping the beat—keep up with the rhythm.","cloze_distractors_en":["Look down on","Give in to","Break out of","Turn away from"],"examples":[{"es":"Es difícil mantener el ritmo de la clase de baile.","en":"It''s hard to keep up with the pace of the dance class."},{"es":"No puedo mantener el ritmo de las noticias tecnológicas porque cambian cada día.","en":"I cannot keep up with the latest tech news because it changes every day."},{"es":"Ella corre muy rápido y me cuesta mantener el ritmo de su entrenamiento.","en":"She runs very fast and I struggle to keep up with her training routine."}]},{"spanish_text":"Decepcionar","english_text":"Let down","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To disappoint someone or fail to meet their expectations.","main_translations_es":["Desilusionar","Desencantar"],"collocations":["let someone down","let down the team","let down the guard"],"synonyms_en":["disappoint","fail","betray"],"example_sentence":"He didn''t want to let down his parents with his poor grades.","example_es":"No quería decepcionar a sus padres con sus malas notas.","example_en":"He didn''t want to let down his parents with his poor grades.","mnemonic_en":"Let a deceptive kite fall down, you just let down (disappointed) them.","cloze_distractors_en":["Look after","Turn over","Carry away","Bring about"],"examples":[{"es":"No quería decepcionar a sus padres con sus malas notas.","en":"He didn''t want to let down his parents with his poor grades."},{"es":"Prometió ayudarme con la mudanza, pero al final decidió decepcionar a todo el equipo.","en":"He promised to help me move, but in the end, he decided to let down the whole team."},{"es":"Si no terminas el proyecto a tiempo, vas a decepcionar a tu jefe antes de la reunión.","en":"If you don''t finish the project on time, you are going to let down your boss before the meeting."}]},{"spanish_text":"Cuidar de","english_text":"Look after","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to take care of someone or something","main_translations_es":["cuidar","velar por","tener cuidado de"],"collocations":["look after the children","look after yourself","look after the house"],"synonyms_en":["take care of","watch over","mind"],"example_sentence":"I have to look after my little brother while my parents are away.","example_es":"Tengo que cuidar de mi hermano pequeño mientras mis padres están fuera.","example_en":"I have to look after my little brother while my parents are away.","mnemonic_en":"When you look after someone, you cuidar them like a caring guard.","cloze_distractors_en":["Look across","Look against","Look around","Look beyond"],"examples":[{"es":"Tengo que cuidar de mi hermano pequeño mientras mis padres están fuera.","en":"I have to look after my little brother while my parents are away."},{"es":"La vecina se ofreció a cuidar de nuestras plantas durante las vacaciones.","en":"The neighbor offered to look after our plants while we are on vacation."},{"es":"Es difícil cuidar de un cachorro tan energético sin ayuda.","en":"It is difficult to look after such an energetic puppy without any help."}]},{"spanish_text":"Investigar","english_text":"Look into","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to examine or investigate something in order to learn more about it","main_translations_es":["Indagar","Examinar","Investigar"],"collocations":["look into the matter","look into the issue","look into the problem","look into it"],"synonyms_en":["investigate","examine","explore"],"example_sentence":"I will look into the origin of the problem.","example_es":"Voy a investigar el origen del problema.","example_en":"I will look into the origin of the problem.","mnemonic_en":"Picture a detective looking into a dark vault, thinking invest I gear as he investigates.","cloze_distractors_en":["Look away","Look up","Look back"],"examples":[{"es":"Voy a investigar el origen del problema.","en":"I will look into the origin of the problem."},{"es":"El comité va a investigar las irregularidades financieras detectadas en el informe.","en":"The committee is going to look into the financial irregularities detected in the report."},{"es":"Deberíamos investigar las quejas de los clientes antes de lanzar el nuevo producto.","en":"We should look into the customer complaints before launching the new product."}]},{"spanish_text":"Admirar","english_text":"Look up to","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to regard someone with admiration and respect","main_translations_es":["Estimar","Respetar","Venerar"],"collocations":["look up to someone","look up to his father","look up to role models","look up to as an inspiration"],"synonyms_en":["admire","respect","esteem"],"example_sentence":"I have always looked up to my grandfather for his wisdom.","example_es":"Siempre he admirado a mi abuelo por su sabiduría.","example_en":"I have always looked up to my grandfather for his wisdom.","mnemonic_en":"I look up to her, I admire her.","cloze_distractors_en":[],"examples":[{"es":"Siempre he admirado a mi abuelo por su sabiduría.","en":"I have always looked up to my grandfather for his wisdom."},{"es":"Los niños pequeños suelen admirar a los atletas profesionales que ven en la televisión.","en":"Young children often look up to the professional athletes they see on television."},{"es":"Ella admira a su mentora por la forma en que maneja los conflictos en la oficina.","en":"She looks up to her mentor for the way she handles conflicts in the office."}]},{"spanish_text":"Compensar","english_text":"Make up for","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To compensate for something; to offset or counterbalance it.","main_translations_es":["Resarcir","Reparar","Compensar"],"collocations":["make up for lost time","make up for a mistake","make up for the damage","make up for the loss"],"synonyms_en":["compensate","offset","atone for"],"example_sentence":"The raise helps to make up for the extra time he worked during the month.","example_es":"El aumento de sueldo ayuda a compensar el tiempo extra que trabajó durante el mes.","example_en":"The raise helps to make up for the extra time he worked during the month.","mnemonic_en":"A compass (compensar) corrects the wrong direction, making up for the mistake.","cloze_distractors_en":["Look down on","Bring back in","Take out of","Pass over by"],"examples":[{"es":"El aumento de sueldo ayuda a compensar el tiempo extra que trabajó durante el mes.","en":"The raise helps to make up for the extra time he worked during the month."},{"es":"Su talento natural compensa la falta de experiencia que tiene sobre el escenario.","en":"Her natural talent helps to make up for the lack of experience she has on stage."},{"es":"La excelente calidad de la comida compensa el servicio tan lento que recibimos anoche.","en":"The excellent quality of the food serves to make up for the slow service we received last night."}]},{"spanish_text":"Seguir adelante","english_text":"Move on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to continue or proceed to the next thing, especially after a difficulty or interruption","main_translations_es":["Continuar","Seguir","Avanzar"],"collocations":["move on to","move on from","move on with","move on quickly"],"synonyms_en":["continue","press forward","go ahead"],"example_sentence":"After the breakup, she decided to move on with her life.","example_es":"Después de la ruptura, decidió seguir adelante con su vida.","example_en":"After the breakup, she decided to move on with her life.","mnemonic_en":"Picture a moving train shouting ''Move on'' as it speeds forward, just like seguir adelante.","cloze_distractors_en":["Fall apart","Back down","Hold out","Give in"],"examples":[{"es":"Después de la ruptura, decidió seguir adelante con su vida.","en":"After the breakup, she decided to move on with her life."},{"es":"Aunque el proyecto fracasó, el equipo debe seguir adelante y aprender de los errores.","en":"Even though the project failed, the team must move on and learn from their mistakes."},{"es":"Es hora de dejar el pasado atrás y seguir adelante con nuestros planes de viaje.","en":"It is time to leave the past behind and move on with our travel plans."}]},{"spanish_text":"Señalar","english_text":"Point out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To draw attention to something.","main_translations_es":["indicar","mostrar","apuntar"],"collocations":["point out the mistake","point out that","point out the differences","point out the importance"],"synonyms_en":["indicate","show","highlight"],"example_sentence":"The editor had to point out a typo on the last page of the manuscript.","example_es":"El editor señaló un error tipográfico en la última página del manuscrito.","example_en":"The editor had to point out a typo on the last page of the manuscript.","mnemonic_en":"I point out the bright señal on the map, like a sign pointing the way.","cloze_distractors_en":["Look away","Turn over","Back down","Pass out"],"examples":[{"es":"El editor señaló un error tipográfico en la última página del manuscrito.","en":"The editor had to point out a typo on the last page of the manuscript."},{"es":"Mi colega señaló que el informe financiero contenía datos desactualizados.","en":"My colleague was quick to point out that the financial report contained outdated data."},{"es":"El experto señaló las ventajas de invertir en energías renovables a largo plazo.","en":"The expert took a moment to point out the long-term benefits of investing in renewable energy."}]},{"spanish_text":"Posponer","english_text":"Put off","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To delay or postpone something.","main_translations_es":["Aplazar","Postergar","Diferir"],"collocations":["put off the meeting","put off until later","put off doing something"],"synonyms_en":["postpone","delay","defer"],"example_sentence":"I will put off the meeting until tomorrow.","example_es":"Voy a posponer la reunión hasta mañana.","example_en":"I will put off the meeting until tomorrow.","mnemonic_en":"You put off the job, so you pose your plans in a pond, waiting.","cloze_distractors_en":["Look over","Turn into","Give away","Call back"],"examples":[{"es":"Voy a posponer la reunión hasta mañana.","en":"I will put off the meeting until tomorrow."},{"es":"No deberías posponer tu visita al dentista si te duele la muela.","en":"You should not put off your visit to the dentist if your tooth hurts."},{"es":"El mal tiempo obligó a los organizadores a posponer el partido de fútbol.","en":"The bad weather forced the organizers to put off the soccer match."}]},{"spanish_text":"Soportar","english_text":"Put up with","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to tolerate or endure something or someone","main_translations_es":["aguantar","tolerar","soportar"],"collocations":["put up with the noise","can''t put up with his attitude","put up with the heat"],"synonyms_en":["tolerate","endure","stand"],"example_sentence":"I can''t put up with the constant noise.","example_es":"No puedo soportar el ruido constante.","example_en":"I can''t put up with the constant noise.","mnemonic_en":"Picture a supportive porter who puts up with every heavy load, just like the Spanish soportar.","cloze_distractors_en":["Look down on","Call out for","Make up to","Turn in at"],"examples":[{"es":"No puedo soportar el ruido constante.","en":"I can''t put up with the constant noise."},{"es":"Ella decidió que ya no iba a soportar más sus malos tratos.","en":"She decided she was not going to put up with his mistreatment anymore."},{"es":"Es difícil soportar el comportamiento grosero de ese cliente durante toda la reunión.","en":"It is difficult to put up with that client''s rude behavior throughout the entire meeting."}]},{"spanish_text":"Descartar","english_text":"Rule out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To eliminate or exclude something as a possibility.","main_translations_es":["Excluir","Eliminar","Desestimar"],"collocations":["rule out the possibility","rule out a diagnosis","rule out any chance","rule out the hypothesis"],"synonyms_en":["exclude","eliminate","dismiss"],"example_sentence":"Doctors must rule out other causes before confirming the diagnosis.","example_es":"Los médicos deben descartar otras causas antes de confirmar el diagnóstico.","example_en":"Doctors must rule out other causes before confirming the diagnosis.","mnemonic_en":"Imagine a ruler striking out a card, discarding it—so you rule out the option.","cloze_distractors_en":["Rule over","Rule in","Rule up","Rule off"],"examples":[{"es":"Los médicos deben descartar otras causas antes de confirmar el diagnóstico.","en":"Doctors must rule out other causes before confirming the diagnosis."},{"es":"La policía tuvo que descartar al principal sospechoso debido a su coartada sólida.","en":"The police had to rule out the main suspect due to his solid alibi."},{"es":"No podemos descartar la posibilidad de que el proyecto se retrase por falta de fondos.","en":"We cannot rule out the possibility that the project will be delayed due to lack of funding."}]},{"spanish_text":"Toparse con","english_text":"Run into","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To meet or encounter someone or something unexpectedly.","main_translations_es":["Encontrarse con","Tropezar con","Chocar con"],"collocations":["run into trouble","run into an old friend","run into a problem","run into obstacles"],"synonyms_en":["encounter","bump into","meet unexpectedly"],"example_sentence":"I ran into my old friend at the supermarket.","example_es":"Me topé con mi viejo amigo en el supermercado.","example_en":"I ran into my old friend at the supermarket.","mnemonic_en":"Picture a spinning top that runs into a wall, reminding you of run into.","cloze_distractors_en":[],"examples":[{"es":"Me topé con mi viejo amigo en el supermercado.","en":"I ran into my old friend at the supermarket."},{"es":"Casi me topo con el director mientras salía a escondidas de la oficina.","en":"I almost ran into the director while sneaking out of the office."},{"es":"Es muy probable que te topes con algunos problemas técnicos durante la instalación.","en":"It is very likely that you will run into some technical problems during the installation."}]},{"spanish_text":"Reservar","english_text":"Set aside","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To reserve something for later use or a specific purpose.","main_translations_es":["Apartar","Guardar","Hacer una reserva"],"collocations":["set aside money","set aside time","set aside differences","set aside for later"],"synonyms_en":["reserve","allocate","put aside"],"example_sentence":"I will set aside time to study.","example_es":"Voy a reservar tiempo para estudiar.","example_en":"I will set aside time to study.","mnemonic_en":"I set aside a seat for the reservation, like reserving a spot.","cloze_distractors_en":["Look across","Turn against","Hold behind","Pass through"],"examples":[{"es":"Voy a reservar tiempo para estudiar.","en":"I will set aside time to study."},{"es":"Debes reservar algo de dinero cada mes para emergencias.","en":"You should set aside some money every month for emergencies."},{"es":"El arquitecto decidió reservar una zona del jardín para construir una piscina.","en":"The architect decided to set aside an area of the garden to build a pool."}]},{"spanish_text":"Montar","english_text":"Set up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to arrange or establish something, such as equipment, a system, or an event.","main_translations_es":["Instalar","Armar","Configurar"],"collocations":["set up a meeting","set up the equipment","set up shop","set up a system"],"synonyms_en":["establish","arrange","install"],"example_sentence":"Let''s set up the tent before it starts raining.","example_es":"Vamos a montar la carpa antes de que empiece a llover.","example_en":"Let''s set up the tent before it starts raining.","mnemonic_en":"Mount a horse, then set up the camp.","cloze_distractors_en":["Put down","Call off","Look over","Give away"],"examples":[{"es":"Vamos a montar la carpa antes de que empiece a llover.","en":"Let''s set up the tent before it starts raining."},{"es":"El técnico vino a montar el nuevo sistema de seguridad en la oficina.","en":"The technician came to set up the new security system in the office."},{"es":"Necesitamos montar una mesa adicional para los invitados que llegarán tarde.","en":"We need to set up an extra table for the guests arriving late."}]},{"spanish_text":"Aclarar","english_text":"Sort out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To organize, resolve, or clarify something.","main_translations_es":["Explicar","Despejar","Precisar"],"collocations":["sort out the problem","sort out the details","sort out the mess","sort out the paperwork"],"synonyms_en":["organize","resolve","arrange"],"example_sentence":"I need to sort out the project details before the meeting.","example_es":"Necesito aclarar los detalles del proyecto antes de la reunión.","example_en":"I need to sort out the project details before the meeting.","mnemonic_en":"Sort out the tangled cords until the room looks a clear.","cloze_distractors_en":["Blow over","Fade away","Drop back"],"examples":[{"es":"Necesito aclarar los detalles del proyecto antes de la reunión.","en":"I need to sort out the project details before the meeting."},{"es":"Tenemos que aclarar este malentendido con el cliente lo antes posible.","en":"We have to sort out this misunderstanding with the client as soon as possible."},{"es":"Mi hermano se mudará pronto y todavía tiene que aclarar sus asuntos personales.","en":"My brother is moving soon and he still needs to sort out his personal affairs."}]},{"spanish_text":"Hablar con firmeza","english_text":"Speak up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To speak louder or more assertively, especially to express an opinion.","main_translations_es":["hablar con autoridad","expresarse con firmeza","hablar con seguridad"],"collocations":["speak up for yourself","speak up against injustice","speak up in meetings"],"synonyms_en":["voice one''s opinion","assert oneself","speak out"],"example_sentence":"It''s important to speak up when defending human rights.","example_es":"Es importante hablar con firmeza cuando se defienden los derechos humanos.","example_en":"It''s important to speak up when defending human rights.","mnemonic_en":"A firm microphone shouts Speak up!","cloze_distractors_en":["Break down","Back away","Bring over","Look into"],"examples":[{"es":"Es importante hablar con firmeza cuando se defienden los derechos humanos.","en":"It''s important to speak up when defending human rights."},{"es":"Si no estás de acuerdo con la nueva política de la empresa, deberías hablar con firmeza en la próxima reunión.","en":"If you disagree with the new company policy, you should speak up at the next meeting."},{"es":"Ella decidió hablar con firmeza contra el acoso escolar para proteger a sus compañeros más jóvenes.","en":"She decided to speak up against bullying to protect her younger classmates."}]},{"spanish_text":"Dimitir","english_text":"Step down","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To resign from a position or office.","main_translations_es":["Renunciar","Abandonar el cargo","Dejar el puesto"],"collocations":["step down from","step down as","step down voluntarily","step down after"],"synonyms_en":["resign","quit","abdicate"],"example_sentence":"The president announced that he will step down after the scandal.","example_es":"El presidente anunció que va a dimitir después del escándalo.","example_en":"The president announced that he will step down after the scandal.","mnemonic_en":"Picture a timid boss taking a step down from the throne.","cloze_distractors_en":["Step across","Step around","Step behind","Step against"],"examples":[{"es":"El presidente anunció que va a dimitir después del escándalo.","en":"The president announced that he will step down after the scandal."},{"es":"La directora decidió dimitir para que un líder más joven tome el mando de la empresa.","en":"The CEO decided to step down so that a younger leader could take charge of the company."},{"es":"Tras la derrota electoral, el ministro se vio obligado a dimitir de su cargo.","en":"Following the election defeat, the minister was forced to step down from his position."}]},{"spanish_text":"Parecerse a","english_text":"Take after","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to resemble or be similar to someone, especially a family member","main_translations_es":["Asemejarse a","Se parecer a","Tener el parecido de"],"collocations":["take after his father","take after his mother","take after his brother","take after the family"],"synonyms_en":["resemble","be similar to","look like"],"example_sentence":"My son has the same blue eyes as his grandfather; he really does take after him.","example_es":"Mi hijo tiene los mismos ojos azules que su abuelo, realmente se parece a él.","example_en":"My son has the same blue eyes as his grandfather; he really does take after him.","mnemonic_en":"Picture a pair of tacos you take after, because ''take after'' sounds like a ''pair'' (pare) of tacos.","cloze_distractors_en":["Look across","Turn against","Give away","Hold onto"],"examples":[{"es":"Mi hijo tiene los mismos ojos azules que su abuelo, realmente se parece a él.","en":"My son has the same blue eyes as his grandfather; he really does take after him."},{"es":"Aunque su madre es muy reservada, la niña es muy extrovertida y no se parece a ella en absoluto.","en":"Even though her mother is very reserved, the girl is quite outgoing and does not take after her at all."},{"es":"Todos dicen que mi hermano menor se parece a nuestro padre cuando tenía esa misma edad.","en":"Everyone says that my younger brother seems to take after our father when he was that same age."}]},{"spanish_text":"Asumir","english_text":"Take on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To accept responsibility for something or to assume a task or role.","main_translations_es":["Aceptar","Encargar","Adoptar"],"collocations":["take on a challenge","take on responsibilities","take on a new role","take on board"],"synonyms_en":["assume","accept","undertake"],"example_sentence":"He decided to take on the responsibility of the project.","example_es":"Decidió asumir la responsabilidad del proyecto.","example_en":"He decided to take on the responsibility of the project.","mnemonic_en":"Take on sounds like a sum, so picture yourself taking on a huge pile of cash.","cloze_distractors_en":["Look after","Give away","Stand down","Hold back"],"examples":[{"es":"Decidió asumir la responsabilidad del proyecto.","en":"He decided to take on the responsibility of the project."},{"es":"La empresa va a asumir a diez empleados nuevos el próximo mes.","en":"The company is going to take on ten new employees next month."},{"es":"No deberías asumir tantos compromisos si ya estás muy ocupado.","en":"You should not take on so many commitments if you are already very busy."}]},{"spanish_text":"Tomar el control","english_text":"Take over","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to assume control or responsibility for something","main_translations_es":["Asumir el control","Hacerse cargo","Dominar"],"collocations":["take over the company","take over the reins","take over from","take over the project"],"synonyms_en":["assume control","seize control","take charge"],"example_sentence":"The new CEO decided to take over the company.","example_es":"El nuevo CEO decidió tomar el control de la empresa.","example_en":"The new CEO decided to take over the company.","mnemonic_en":"Picture a giant taco taking over the control console.","cloze_distractors_en":["Look down","Give back","Pass away","Hold off"],"examples":[{"es":"El nuevo CEO decidió tomar el control de la empresa.","en":"The new CEO decided to take over the company."},{"es":"El copiloto tuvo que tomar el control cuando el capitán se desmayó.","en":"The co-pilot had to take over when the captain fainted."},{"es":"Mi hermano mayor va a tomar el control de la granja familiar el próximo año.","en":"My older brother is going to take over the family farm next year."}]},{"spanish_text":"Pensarlo detenidamente","english_text":"Think over","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to consider something carefully","main_translations_es":["Reflexionar sobre ello","Considerarlo con cuidado","Meditar al respecto"],"collocations":["think it over","think over the proposal","think over the decision","think over the options"],"synonyms_en":["consider","ponder","mull over"],"example_sentence":"Before accepting the marriage proposal, she decided she needed to think over the decision during the weekend.","example_es":"Antes de aceptar la propuesta de matrimonio, ella decidió que necesitaba pensarlo detenidamente durante el fin de semana.","example_en":"Before accepting the marriage proposal, she decided she needed to think over the decision during the weekend.","mnemonic_en":"Picture a thinker standing over a pond, whispering ''pensar'' as he weighs the idea.","cloze_distractors_en":["Blow away","Turn down","Call off","Look up"],"examples":[{"es":"Antes de aceptar la propuesta de matrimonio, ella decidió que necesitaba pensarlo detenidamente durante el fin de semana.","en":"Before accepting the marriage proposal, she decided she needed to think over the decision during the weekend."},{"es":"El comité no dará una respuesta inmediata, ya que prefieren pensarlo detenidamente antes de comprometer el presupuesto anual.","en":"The committee will not give an immediate answer, as they prefer to think over the request before committing the annual budget."},{"es":"Si te ofrecen un traslado al extranjero, asegúrate de pensarlo detenidamente antes de empacar todas tus pertenencias.","en":"If you are offered a transfer abroad, make sure to think over the implications before packing up all your belongings."}]},{"spanish_text":"Rechazar","english_text":"Turn down","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To reject or refuse something.","main_translations_es":["Rehusar","Negar","Declinar"],"collocations":["turn down the volume","turn down the offer","turn down a request","turn down the lights"],"synonyms_en":["reject","refuse","decline"],"example_sentence":"He decided to turn down the job offer.","example_es":"Decidió rechazar la oferta de trabajo.","example_en":"He decided to turn down the job offer.","mnemonic_en":"I reach a jar, then turn it down, rejecting the offer.","cloze_distractors_en":["Look after","Bring about","Carry over","Hold onto"],"examples":[{"es":"Decidió rechazar la oferta de trabajo.","en":"He decided to turn down the job offer."},{"es":"Tuve que rechazar su invitación a la fiesta porque tenía mucho trabajo.","en":"I had to turn down his invitation to the party because I had too much work."},{"es":"El banco volvió a rechazar nuestra solicitud de préstamo hipotecario.","en":"The bank had to turn down our mortgage loan application again."}]},{"spanish_text":"Resultar","english_text":"Turn out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to have a particular result or outcome","main_translations_es":["acabar","salir","concluir"],"collocations":["turn out to be","turn out well","turn out for the best","turn out the lights"],"synonyms_en":["prove","result","end up"],"example_sentence":"The cake I baked for the party turned out to be a disaster because I forgot to add sugar.","example_es":"El pastel que horneé para la fiesta resultó ser un desastre porque olvidé ponerle azúcar.","example_en":"The cake I baked for the party turned out to be a disaster because I forgot to add sugar.","mnemonic_en":"The result of the experiment turned out exactly as predicted.","cloze_distractors_en":[],"examples":[{"es":"El pastel que horneé para la fiesta resultó ser un desastre porque olvidé ponerle azúcar.","en":"The cake I baked for the party turned out to be a disaster because I forgot to add sugar."},{"es":"La entrevista de trabajo resultó ser mucho más difícil de lo que esperaba inicialmente.","en":"The job interview turned out to be much more difficult than I had initially expected."},{"es":"Aunque al principio parecían enemigos, los dos vecinos resultaron ser grandes amigos con el paso del tiempo.","en":"Although they seemed like enemies at first, the two neighbors turned out to be great friends as time went by."}]},{"spanish_text":"Salirse bien","english_text":"Work out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to succeed or have a favorable outcome","main_translations_es":["Salir bien","Resultar bien","Ir bien"],"collocations":["work out at the gym","work out the details","work out a solution","work out a plan"],"synonyms_en":["succeed","turn out well","manage"],"example_sentence":"In the end, everything will work out.","example_es":"Al final, todo se salió bien.","example_en":"In the end, everything will work out.","mnemonic_en":"Sail out of the gym after a workout, feeling well.","cloze_distractors_en":["give away","look down","pass out"],"examples":[{"es":"Al final, todo se salió bien.","en":"In the end, everything will work out."},{"es":"Aunque tuvimos muchos problemas al principio, la negociación terminó por salir bien.","en":"Although we had many problems at the beginning, the negotiation managed to work out."},{"es":"Si ajustamos el presupuesto y reducimos los gastos, el proyecto debería salir bien.","en":"If we adjust the budget and cut costs, the project should work out."}]},{"spanish_text":"Retirarse","english_text":"Back out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to withdraw from an agreement, plan, or commitment","main_translations_es":["Echarse atrás","Desistir","Recuarse"],"collocations":["back out of a deal","back out of a commitment","back out at the last minute"],"synonyms_en":["withdraw","pull out","renege"],"example_sentence":"He decided to back out of the project before it was too late.","example_es":"Decidió retirarse del proyecto antes de que fuera demasiado tarde.","example_en":"He decided to back out of the project before it was too late.","mnemonic_en":"Picture a car backing out while shouting retire as it leaves the driveway.","cloze_distractors_en":["Turn over","Look into","Bring up","Hold on"],"examples":[{"es":"Decidió retirarse del proyecto antes de que fuera demasiado tarde.","en":"He decided to back out of the project before it was too late."},{"es":"No puedes retirarte ahora que ya hemos firmado el contrato de compraventa.","en":"You cannot back out now that we have already signed the sales contract."},{"es":"El candidato se retiró de la competencia a pocos días de las elecciones.","en":"The candidate had to back out of the race just days before the election."}]},{"spanish_text":"Romper con","english_text":"Break off","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb (phrasal verb)","definition_en":"To end a relationship with someone.","main_translations_es":["Terminar con","Poner fin a","Separarse de"],"collocations":["break off a relationship","break off negotiations","break off a conversation","break off the engagement"],"synonyms_en":["sever","terminate","cut off"],"example_sentence":"He decided to break off his relationship with his girlfriend after three years.","example_es":"Decidió romper con su novia después de tres años.","example_en":"He decided to break off his relationship with his girlfriend after three years.","mnemonic_en":"I break off the chain, Romper con the lock, ending its hold.","cloze_distractors_en":["Carry over","Bring about","Look after","Hold onto"],"examples":[{"es":"Decidió romper con su novia después de tres años.","en":"He decided to break off his relationship with his girlfriend after three years."},{"es":"Las dos naciones han decidido romper con sus acuerdos comerciales debido a las nuevas sanciones.","en":"The two nations have decided to break off their trade agreements due to the new sanctions."},{"es":"Durante la tensa reunión, el diplomático se levantó y decidió romper con las negociaciones de paz.","en":"During the tense meeting, the diplomat stood up and decided to break off the peace negotiations."}]},{"spanish_text":"Abrirse paso","english_text":"Break through","section_name":"Advanced Phrasal Verbs","part_of_speech":"phrasal verb","definition_en":"To succeed in overcoming an obstacle or to make a way forward.","main_translations_es":["Abrir camino","Hacer hueco","Forzar la entrada"],"collocations":["break through the barrier","break through the market","break through to the audience","break through the noise"],"synonyms_en":["penetrate","make headway","forge ahead"],"example_sentence":"The pioneers had to break through the jungle.","example_es":"Los pioneros tuvieron que abrirse paso en la selva.","example_en":"The pioneers had to break through the jungle.","mnemonic_en":"Imagine a brake breaking a wall, letting people abrirse paso.","cloze_distractors_en":["Break down","Break off","Break away"],"examples":[{"es":"Los pioneros tuvieron que abrirse paso en la selva.","en":"The pioneers had to break through the jungle."},{"es":"El sol finalmente logró abrirse paso entre las nubes grises de la mañana.","en":"The sun finally managed to break through the gray morning clouds."},{"es":"La policía tuvo que abrirse paso entre la multitud para llegar al lugar del accidente.","en":"The police had to break through the crowd to reach the accident scene."}]},{"spanish_text":"Interrumpir","english_text":"Cut in","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To interrupt someone while they are speaking.","main_translations_es":["interrumpir","intervenir","intercalar"],"collocations":["cut in line","cut in on","cut in the conversation","cut in while"],"synonyms_en":["interrupt","interject","butt in"],"example_sentence":"You shouldn''t cut in when someone is speaking.","example_es":"No deberías interrumpir cuando alguien está hablando.","example_en":"You shouldn''t cut in when someone is speaking.","mnemonic_en":"A cutter (corte) jumps in, interrupting the chat.","cloze_distractors_en":["Look up","Give in","Hold on","Pass by"],"examples":[{"es":"No deberías interrumpir cuando alguien está hablando.","en":"You shouldn''t cut in when someone is speaking."},{"es":"El coche rojo intentó interrumpir en la fila de tráfico de repente.","en":"The red car suddenly tried to cut in the line of traffic."},{"es":"Ella se sintió molesta cuando su colega decidió interrumpir durante su presentación.","en":"She felt annoyed when her colleague decided to cut in during her presentation."}]},{"spanish_text":"Agotar","english_text":"Use up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To consume something completely until none remains.","main_translations_es":["exhaustar","consumir","desgastar"],"collocations":["use up the resources","use up all the water","use up your time","use up the budget"],"synonyms_en":["exhaust","deplete","consume"],"example_sentence":"The fire managed to use up all the water supply in the area.","example_es":"El incendio logró agotar todo el suministro de agua de la zona.","example_en":"The fire managed to use up all the water supply in the area.","mnemonic_en":"When you use up the battery, it goes a‑go‑tar empty.","cloze_distractors_en":["Look after","Bring about","Hold onto","Make over"],"examples":[{"es":"El incendio logró agotar todo el suministro de agua de la zona.","en":"The fire managed to use up all the water supply in the area."},{"es":"No podemos seguir imprimiendo documentos porque vamos a agotar el tóner de la impresora.","en":"We cannot keep printing documents because we are going to use up the printer''s toner."},{"es":"Los atletas suelen agotar sus reservas de energía durante la última etapa de la maratón.","en":"Athletes tend to use up their energy reserves during the final stage of the marathon."}]},{"spanish_text":"Terminar en","english_text":"End up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to finally reach a particular place, condition, or result, often unexpectedly","main_translations_es":["acabar en","quedar en","finalizar en"],"collocations":["end up with","end up doing","end up in","end up somewhere"],"synonyms_en":["result","turn out","come to be"],"example_sentence":"If you don''t study, you could end up on the street.","example_es":"Si no estudias, podrías terminar en la calle.","example_en":"If you don''t study, you could end up on the street.","mnemonic_en":"Picture crossing the finish line and yelling ''en!'' as you finally end up there.","cloze_distractors_en":["Look over","Call off","Give away","Hold back"],"examples":[{"es":"Si no estudias, podrías terminar en la calle.","en":"If you don''t study, you could end up on the street."},{"es":"Después de buscar durante horas, terminamos en un pequeño pueblo pesquero al norte del país.","en":"After searching for hours, we end up in a small fishing village in the north of the country."},{"es":"Comenzamos viendo una comedia, pero terminamos en un maratón de películas de terror toda la noche.","en":"We started by watching a comedy, but we end up in a horror movie marathon all night long."}]},{"spanish_text":"Dar con","english_text":"Find out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To discover or learn something.","main_translations_es":["Encontrar","Toparse con","Descubrir"],"collocations":["find out the truth","find out more","find out what happened"],"synonyms_en":["discover","learn","determine"],"example_sentence":"After searching for hours, I finally find out the solution to the problem.","example_es":"Después de buscar durante horas, finalmente di con la solución al problema.","example_en":"After searching for hours, I finally find out the solution to the problem.","mnemonic_en":"When I find out, I dar con the secret like uncovering a buried chest.","cloze_distractors_en":["Give away","Turn down","Look over","Pass out"],"examples":[{"es":"Después de buscar durante horas, finalmente di con la solución al problema.","en":"After searching for hours, I finally find out the solution to the problem."},{"es":"Revisando los archivos antiguos, espero que podamos dar con la fecha exacta del contrato.","en":"While checking the old files, I hope we can find out the exact date of the contract."},{"es":"Si investigas un poco en internet, seguro que das con el nombre del autor de este libro.","en":"If you do a little research online, you will surely find out the name of the author of this book."}]},{"spanish_text":"Irse apagando","english_text":"Fade away","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To gradually disappear or lose intensity.","main_translations_es":["Desvanecerse","Ir perdiendo intensidad","Desaparecer poco a poco"],"collocations":["fade away slowly","fade away over time","fade away into the distance","fade away completely"],"synonyms_en":["diminish","die out","ebb"],"example_sentence":"Over time, the lantern''s light began to fade away.","example_es":"Con el tiempo, la luz del farol se fue apagando.","example_en":"Over time, the lantern''s light began to fade away.","mnemonic_en":"See a lamp fade away as its light apagando like a ghost slipping into darkness.","cloze_distractors_en":["flare back","surge over","bloom out","thrive on"],"examples":[{"es":"Con el tiempo, la luz del farol se fue apagando.","en":"Over time, the lantern''s light began to fade away."},{"es":"El sonido de los pasos en el pasillo se fue apagando hasta quedar en silencio.","en":"The sound of footsteps in the hallway began to fade away until it went silent."},{"es":"La esperanza de encontrar a los excursionistas se fue apagando tras varios días de búsqueda sin éxito.","en":"The hope of finding the hikers began to fade away after several days of unsuccessful searching."}]},{"spanish_text":"Aplastar","english_text":"Crack down on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to take strict or severe measures against something or someone","main_translations_es":["machacar","triturar","aplastar"],"collocations":["crack down on crime","crack down on corruption","crack down on tax evasion","crack down on illegal immigration"],"synonyms_en":["clamp down on","suppress","repress"],"example_sentence":"The government decided to crack down on tax evasion.","example_es":"El gobierno decidió aplastar la evasión fiscal.","example_en":"The government decided to crack down on tax evasion.","mnemonic_en":"Picture a crack hammer slamming down on a wall, crushing it flat like aplastar.","cloze_distractors_en":["Branch out of","Bubble over with","Fumble about in","Muddle along by"],"examples":[{"es":"El gobierno decidió aplastar la evasión fiscal.","en":"The government decided to crack down on tax evasion."},{"es":"La policía local comenzó a aplastar el consumo de alcohol en las calles durante el festival.","en":"The local police started to crack down on street drinking during the festival."},{"es":"La dirección de la empresa prometió aplastar las horas extras no autorizadas a partir del próximo mes.","en":"The company management promised to crack down on unauthorized overtime starting next month."}]},{"spanish_text":"Rechazar de plano","english_text":"Brush off","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb (phrasal verb)","definition_en":"To dismiss or reject something or someone in a casual or indifferent manner.","main_translations_es":["Desestimar","Descartar","Rechazar rotundamente"],"collocations":["brush off criticism","brush off a comment","brush off the suggestion"],"synonyms_en":["dismiss","snub","turn down"],"example_sentence":"When I suggested he seek professional help, he decided to brush off my advice entirely.","example_es":"Cuando le sugerí que buscara ayuda profesional, él rechazó de plano mi consejo.","example_en":"When I suggested he seek professional help, he decided to brush off my advice entirely.","mnemonic_en":"Brush off the plain (plano) like dust from a model plane","cloze_distractors_en":["Look after","Bring about","Hold onto","Make over"],"examples":[{"es":"Cuando le sugerí que buscara ayuda profesional, él rechazó de plano mi consejo.","en":"When I suggested he seek professional help, he decided to brush off my advice entirely."},{"es":"El gerente rechazó de plano las quejas de los clientes sobre el nuevo horario de apertura.","en":"The manager chose to brush off the customers'' complaints regarding the new opening hours."},{"es":"Aunque ella intentó explicar su versión de los hechos, él rechazó de plano cualquier intento de conversación.","en":"Even though she tried to explain her side of the story, he continued to brush off any attempt at conversation."}]},{"spanish_text":"Acompañar","english_text":"Go along with","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to agree with or support something or someone","main_translations_es":["acompañar","ir con","seguir"],"collocations":["go along with the plan","go along with the decision","go along with the idea","go along with the crowd"],"synonyms_en":["agree with","support","concur with"],"example_sentence":"He decided to go along with his brother on the hike.","example_es":"Decidió acompañar a su hermano en la caminata.","example_en":"He decided to go along with his brother on the hike.","mnemonic_en":"Picture a companion shouting Go! Along! With! as you both walk.","cloze_distractors_en":["Look down upon","Fall back into","Make off with","Turn away from"],"examples":[{"es":"Decidió acompañar a su hermano en la caminata.","en":"He decided to go along with his brother on the hike."},{"es":"Aunque no estaba convencido, aceptó acompañar la propuesta de su colega.","en":"Although he was not convinced, he agreed to go along with his colleague''s proposal."},{"es":"Si quieres que el proyecto tenga éxito, debes acompañar las nuevas reglas del equipo.","en":"If you want the project to succeed, you must go along with the team''s new rules."}]},{"spanish_text":"Tolerar","english_text":"Put up with","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to tolerate or endure something or someone","main_translations_es":["soportar","aguantar","sufrir"],"collocations":["can''t put up with","put up with the noise","put up with his behavior"],"synonyms_en":["tolerate","endure","stand"],"example_sentence":"I can''t put up with the constant construction noise.","example_es":"No puedo tolerar el ruido constante de la construcción.","example_en":"I can''t put up with the constant construction noise.","mnemonic_en":"Picture a stubborn bull you tolerate, so you literally put up with it.","cloze_distractors_en":["Look down on","Call out for","Make off with","Break in on"],"examples":[{"es":"No puedo tolerar el ruido constante de la construcción.","en":"I can''t put up with the constant construction noise."},{"es":"Ella decidió que ya no iba a tolerar más el comportamiento grosero de su jefe.","en":"She decided she was not going to put up with her boss''s rude behavior anymore."},{"es":"Es difícil tolerar el frío intenso sin una calefacción adecuada en casa.","en":"It is difficult to put up with the intense cold without proper heating at home."}]},{"spanish_text":"Intervenir","english_text":"Step in","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To intervene or become involved in a situation.","main_translations_es":["Intervenir","Interceder","Meterse"],"collocations":["step in to help","step in and take over","step in at the last minute","step in for someone"],"synonyms_en":["intervene","intercede","meddle"],"example_sentence":"The doctor had to step in quickly to save the patient.","example_es":"El médico tuvo que intervenir rápidamente para salvar al paciente.","example_en":"The doctor had to step in quickly to save the patient.","mnemonic_en":"Step in like an intervenir hero entering the scene","cloze_distractors_en":["Back off","Fade out","Look up","Pass by"],"examples":[{"es":"El médico tuvo que intervenir rápidamente para salvar al paciente.","en":"The doctor had to step in quickly to save the patient."},{"es":"Cuando la discusión se volvió agresiva, el profesor decidió intervenir para calmar los ánimos.","en":"When the argument became aggressive, the teacher decided to step in to calm things down."},{"es":"Mi jefe tuvo que intervenir en la negociación porque el cliente estaba muy insatisfecho con el contrato.","en":"My boss had to step in during the negotiation because the client was very unhappy with the contract."}]},{"spanish_text":"Retirarse gradualmente","english_text":"Phase out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To gradually stop using or providing something.","main_translations_es":["Eliminar gradualmente","Descontinuar","Ir reduciendo"],"collocations":["phase out the program","phase out subsidies","phase out gradually","phase out over time"],"synonyms_en":["gradually eliminate","wind down","discontinue"],"example_sentence":"The factory decided to phase out the old model of washing machines to launch the new product line.","example_es":"La fábrica decidió retirar gradualmente el modelo antiguo de lavadoras para lanzar la nueva línea de productos.","example_en":"The factory decided to phase out the old model of washing machines to launch the new product line.","mnemonic_en":"Picture a stage (phase) where you slowly walk out, retiring step by step.","cloze_distractors_en":["Branch out","Touch upon","Bring about"],"examples":[{"es":"La fábrica decidió retirar gradualmente el modelo antiguo de lavadoras para lanzar la nueva línea de productos.","en":"The factory decided to phase out the old model of washing machines to launch the new product line."},{"es":"El gobierno planea retirarse gradualmente del uso de combustibles fósiles para el año 2040.","en":"The government plans to phase out the use of fossil fuels by the year 2040."},{"es":"La universidad va a retirarse gradualmente de los exámenes impresos para adoptar un sistema totalmente digital.","en":"The university is going to phase out printed exams to adopt a fully digital system."}]},{"spanish_text":"Introducir gradualmente","english_text":"Phase in","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To introduce something gradually or in stages.","main_translations_es":["Implementar de forma gradual","Ir incorporando poco a poco","Introducir paulatinamente"],"collocations":["phase in gradually","phase in over time","phase in the new system","phase in the changes"],"synonyms_en":["introduce gradually","roll out","implement gradually"],"example_sentence":"The company decided to phase in the new software to avoid problems.","example_es":"La empresa decidió introducir gradualmente el nuevo software para evitar problemas.","example_en":"The company decided to phase in the new software to avoid problems.","mnemonic_en":"Imagine “fases en” – the Spanish for phases in – as you phase in something gradually.","cloze_distractors_en":["Phase out","Phase up","Phase by","Phase off"],"examples":[{"es":"La empresa decidió introducir gradualmente el nuevo software para evitar problemas.","en":"The company decided to phase in the new software to avoid problems."},{"es":"El gobierno planea introducir gradualmente los nuevos impuestos sobre el carbono durante los próximos cinco años.","en":"The government plans to phase in the new carbon taxes over the next five years."},{"es":"La escuela va a introducir gradualmente el uso de tabletas en todas las aulas a partir del próximo semestre.","en":"The school is going to phase in the use of tablets in all classrooms starting next semester."}]},{"spanish_text":"Fallar","english_text":"Break down","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to cause something to collapse, fail, or separate into its component parts.","main_translations_es":["Equivocarse","Fallarse","Desacertar"],"collocations":["break down the problem","break down into steps","break down barriers","break down in tears"],"synonyms_en":["malfunction","collapse","analyze"],"example_sentence":"The car started to break down and stopped in the middle of the road.","example_es":"El coche empezó a fallar y se detuvo en medio de la carretera.","example_en":"The car started to break down and stopped in the middle of the road.","mnemonic_en":"When it falls, it breaks down.","cloze_distractors_en":["Break away","Break into","Break off","Break out"],"examples":[{"es":"El coche empezó a fallar y se detuvo en medio de la carretera.","en":"The car started to break down and stopped in the middle of the road."},{"es":"La vieja nevera comenzó a fallar justo después de que terminara la garantía.","en":"The old fridge started to break down right after the warranty expired."},{"es":"Si el sistema de calefacción vuelve a fallar durante el invierno, tendremos que llamar a un técnico.","en":"If the heating system starts to break down again during the winter, we will have to call a technician."}]},{"spanish_text":"Separarse","english_text":"Break up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To end a romantic relationship.","main_translations_es":["Divorciarse","Romper","Terminar"],"collocations":["break up with","break up a fight","break up the band","break up the meeting"],"synonyms_en":["split","separate","disband"],"example_sentence":"After five years together, they decided to break up.","example_es":"Después de cinco años de relación, decidieron separarse.","example_en":"After five years together, they decided to break up.","mnemonic_en":"Picture a broken vase that separates into shards as the couple breaks up","cloze_distractors_en":["Break down","Break away","Break into","Break out"],"examples":[{"es":"Después de cinco años de relación, decidieron separarse.","en":"After five years together, they decided to break up."},{"es":"La banda anunció que iban a separarse tras finalizar su última gira mundial.","en":"The band announced that they were going to break up after finishing their final world tour."},{"es":"Si no dejan de discutir por tonterías, al final van a separarse.","en":"If you two do not stop arguing over nonsense, you are eventually going to break up."}]},{"spanish_text":"Calmarse","english_text":"Calm down","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to become or cause someone to become less agitated or upset","main_translations_es":["tranquilizarse","relajarse"],"collocations":["Calm down and think","Calm down, please","Calm down, it''s not a big deal"],"synonyms_en":["relax","settle down","chill out"],"example_sentence":"After the argument, John decided to calm down and take a deep breath.","example_es":"Después de la discusión, Juan decidió calmarse y respirar profundamente.","example_en":"After the argument, John decided to calm down and take a deep breath.","mnemonic_en":"Picture a calm sea whispering calm down as the waves settle.","cloze_distractors_en":["Break down","Turn over","Hold back","Give away"],"examples":[{"es":"Después de la discusión, Juan decidió calmarse y respirar profundamente.","en":"After the argument, John decided to calm down and take a deep breath."},{"es":"Por favor, intenta calmarse antes de que el bebé se despierte con tus gritos.","en":"Please try to calm down before the baby wakes up from your shouting."},{"es":"El piloto pidió a los pasajeros que se calmaran mientras la turbulencia sacudía el avión.","en":"The pilot asked the passengers to calm down while the turbulence shook the plane."}]},{"spanish_text":"Cancelar","english_text":"Call off","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To cancel or stop something that was planned.","main_translations_es":["Cancelar","Anular","Suspender"],"collocations":["call off the meeting","call off the search","call off the wedding","call off the strike"],"synonyms_en":["cancel","abort","scrap"],"example_sentence":"Due to the heavy storm, the organizers decided to call off the soccer match.","example_es":"Debido a la fuerte tormenta, los organizadores decidieron cancelar el partido de fútbol.","example_en":"Due to the heavy storm, the organizers decided to call off the soccer match.","mnemonic_en":"Picture a phone call saying cancela to end the party.","cloze_distractors_en":["Call up","Call in","Call out"],"examples":[{"es":"Debido a la fuerte tormenta, los organizadores decidieron cancelar el partido de fútbol.","en":"Due to the heavy storm, the organizers decided to call off the soccer match."},{"es":"El director tuvo que cancelar la reunión de emergencia porque el cliente no pudo llegar a tiempo.","en":"The manager had to call off the emergency meeting because the client could not arrive on time."},{"es":"Si el clima no mejora mañana, tendremos que cancelar nuestro picnic en el parque.","en":"If the weather does not improve tomorrow, we will have to call off our picnic in the park."}]},{"spanish_text":"Seguir adelante con","english_text":"Carry on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to continue doing something","main_translations_es":["Continuar con","Proseguir con","Avanzar con"],"collocations":["carry on with","carry on doing","carry on as usual","carry on regardless"],"synonyms_en":["continue","proceed","keep going"],"example_sentence":"He decided to carry on with the project despite the obstacles.","example_es":"Decidió seguir adelante con el proyecto a pesar de los obstáculos.","example_en":"He decided to carry on with the project despite the obstacles.","mnemonic_en":"Picture a cari (cariño) sprinting forward, carrying on the race.","cloze_distractors_en":["Fold away","Back down","Drop off","Give out"],"examples":[{"es":"Decidió seguir adelante con el proyecto a pesar de los obstáculos.","en":"He decided to carry on with the project despite the obstacles."},{"es":"Aunque el clima empeoró, los excursionistas decidieron seguir adelante con su ascenso a la montaña.","en":"Even though the weather worsened, the hikers decided to carry on with their climb up the mountain."},{"es":"La empresa va a seguir adelante con los planes de expansión internacional el próximo año.","en":"The company is going to carry on with the international expansion plans next year."}]},{"spanish_text":"Alcanzar","english_text":"Catch up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to reach the same level or position as someone or something after falling behind","main_translations_es":["Lograr","Conseguir","Ponerse al día"],"collocations":["catch up on","catch up with","catch up to","catch up later"],"synonyms_en":["keep up","close the gap","reach"],"example_sentence":"I need to catch up with my classmates so I don''t fall behind.","example_es":"Necesito alcanzar a mis compañeros de clase para no quedarme atrás.","example_en":"I need to catch up with my classmates so I don''t fall behind.","mnemonic_en":"Al can catch up with the runner","cloze_distractors_en":["Look down","Give away","Turn over","Hold back"],"examples":[{"es":"Necesito alcanzar a mis compañeros de clase para no quedarme atrás.","en":"I need to catch up with my classmates so I don''t fall behind."},{"es":"Me detuve un momento para alcanzar a mi amigo que caminaba más rápido que yo.","en":"I stopped for a moment to catch up with my friend who was walking faster than me."},{"es":"Después de estar enfermo toda la semana, tengo mucho trabajo que alcanzar en la oficina.","en":"After being sick all week, I have a lot of work to catch up on at the office."}]},{"spanish_text":"Comprobar","english_text":"Check out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to examine or look at something, or to borrow it from a library","main_translations_es":["verificar","confirmar","corroborar"],"collocations":["check out the new store","check out a book","check out of a hotel","check out the website"],"synonyms_en":["examine","look at","inspect"],"example_sentence":"I will check out the train schedule before leaving.","example_es":"Voy a comprobar el horario del tren antes de salir.","example_en":"I will check out the train schedule before leaving.","mnemonic_en":"I check out the giant compro bar that stamps my library books.","cloze_distractors_en":["Throw away","Bring about","Break down","Pass over"],"examples":[{"es":"Voy a comprobar el horario del tren antes de salir.","en":"I will check out the train schedule before leaving."},{"es":"Deberías comprobar ese nuevo restaurante italiano que abrieron en el centro.","en":"You should check out that new Italian restaurant they opened downtown."},{"es":"Vamos a comprobar los resultados del partido en la página web oficial.","en":"Let''s check out the match results on the official website."}]},{"spanish_text":"Contar con","english_text":"Count on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to rely on someone or something","main_translations_es":["Depender de","Confiar en","Apoyarse en"],"collocations":["count on me","count on someone","count on it","you can count on"],"synonyms_en":["rely on","depend on","trust"],"example_sentence":"You can count on my help to finish the project.","example_es":"Puedes contar con mi ayuda para terminar el proyecto.","example_en":"You can count on my help to finish the project.","mnemonic_en":"I count on you, picturing me counting coins (con) in my hand.","cloze_distractors_en":["Look after","Turn over","Call off","Give away"],"examples":[{"es":"Puedes contar con mi ayuda para terminar el proyecto.","en":"You can count on my help to finish the project."},{"es":"El equipo sabe que puede contar con ella cuando el partido se pone difícil.","en":"The team knows they can count on her when the game gets tough."},{"es":"No podemos contar con que el tren llegue a tiempo debido a la tormenta.","en":"We cannot count on the train arriving on time due to the storm."}]},{"spanish_text":"Interrumpir abruptamente","english_text":"Cut off","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To stop or interrupt something abruptly.","main_translations_es":["Cortar de golpe","Interrumpir bruscamente","Cortar abruptamente"],"collocations":["cut off the power","cut off communication","cut off at the source","cut off from"],"synonyms_en":["interrupt","discontinue","sever"],"example_sentence":"The host decided to cut off the interview abruptly when the guest became nervous.","example_es":"El presentador decidió interrumpir abruptamente la entrevista cuando el invitado se puso nervioso.","example_en":"The host decided to cut off the interview abruptly when the guest became nervous.","mnemonic_en":"Imagine a scissors cut off the conversation, a sudden corte that abruptly interrupts.","cloze_distractors_en":["Look over","Turn into","Hold back","Give away"],"examples":[{"es":"El presentador decidió interrumpir abruptamente la entrevista cuando el invitado se puso nervioso.","en":"The host decided to cut off the interview abruptly when the guest became nervous."},{"es":"La tormenta logró interrumpir abruptamente nuestra conexión a internet durante la videoconferencia.","en":"The storm managed to cut off our internet connection during the video conference."},{"es":"El locutor tuvo que cortar bruscamente la llamada telefónica porque el oyente empezó a insultar.","en":"The radio host had to cut off the caller abruptly when he started using offensive language."}]},{"spanish_text":"Lidiar con","english_text":"Deal with","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To address, manage, or handle a problem, situation, or person.","main_translations_es":["Enfrentarse a","Tratar con","Abordar"],"collocations":["deal with a problem","deal with customers","deal with the situation","deal with stress"],"synonyms_en":["handle","manage","address"],"example_sentence":"I have to deal with many problems at work.","example_es":"Tengo que lidiar con muchos problemas en el trabajo.","example_en":"I have to deal with many problems at work.","mnemonic_en":"Deal with it like dealing cards while wearing a lid on your ear.","cloze_distractors_en":["Look after","Turn over","Bring down","Give away"],"examples":[{"es":"Tengo que lidiar con muchos problemas en el trabajo.","en":"I have to deal with many problems at work."},{"es":"El servicio al cliente debe lidiar con las quejas de los usuarios insatisfechos.","en":"Customer service must deal with complaints from dissatisfied users."},{"es":"Es difícil lidiar con la pérdida de un ser querido durante las fiestas.","en":"It is difficult to deal with the loss of a loved one during the holidays."}]},{"spanish_text":"Acabar con","english_text":"Do without","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb phrase","definition_en":"To manage or survive without something.","main_translations_es":["Eliminar","Poner fin a","Deshacerse de"],"collocations":["can''t do without","do without sugar","do without help"],"synonyms_en":["forego","manage without","go without"],"example_sentence":"Since the shop closed for the holidays, we had to do without coffee for the entire weekend.","example_es":"Como la tienda cerró por vacaciones, tuvimos que arreglárnoslas sin café durante todo el fin de semana.","example_en":"Since the shop closed for the holidays, we had to do without coffee for the entire weekend.","mnemonic_en":"Picture a con being finished, so you do without the con.","cloze_distractors_en":["Look after","Bring about","Turn into"],"examples":[{"es":"Como la tienda cerró por vacaciones, tuvimos que arreglárnoslas sin café durante todo el fin de semana.","en":"Since the shop closed for the holidays, we had to do without coffee for the entire weekend."},{"es":"Durante la escasez de suministros, la familia tuvo que hacer un esfuerzo para prescindir de los lujos a los que estaban acostumbrados.","en":"During the supply shortage, the family had to make an effort to do without the luxuries they were accustomed to."},{"es":"El presupuesto se agotó por completo, así que tendremos que acabar con los gastos innecesarios este mes.","en":"The budget was completely exhausted, so we will have to do without unnecessary expenses this month."}]},{"spanish_text":"Abandonar","english_text":"Drop out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To quit a school, program, or activity before completing it.","main_translations_es":["Dejar","Renunciar","Desistir"],"collocations":["drop out of school","drop out of college","drop out of the race"],"synonyms_en":["quit","withdraw","leave school"],"example_sentence":"He decided to drop out of college after the first semester.","example_es":"Decidió abandonar la universidad después del primer semestre.","example_en":"He decided to drop out of college after the first semester.","mnemonic_en":"I dropped out, abandoning the game like a broken drop falling away.","cloze_distractors_en":["Look over","Turn into","Carry off","Hold down"],"examples":[{"es":"Decidió abandonar la universidad después del primer semestre.","en":"He decided to drop out of college after the first semester."},{"es":"Muchos atletas jóvenes suelen abandonar la carrera profesional debido a las constantes lesiones.","en":"Many young athletes tend to drop out of their professional careers due to constant injuries."},{"es":"Si el programa de entrenamiento es demasiado exigente, es probable que la mitad de los participantes decidan abandonar.","en":"If the training program is too demanding, it is likely that half of the participants will decide to drop out."}]},{"spanish_text":"Comerse todo","english_text":"Eat up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to consume something completely, especially to finish eating it","main_translations_es":["comer todo","devorarlo todo","tragarse todo"],"collocations":["eat up the leftovers","eat up the competition","eat up the information"],"synonyms_en":["devour","finish","consume"],"example_sentence":"I''m going to eat up the whole cake.","example_es":"Voy a comerme todo el pastel.","example_en":"I''m going to eat up the whole cake.","mnemonic_en":"Picture a hungry monster that eats up every crumb, just like comerse todo.","cloze_distractors_en":["Look over","Turn down","Hold back","Step aside"],"examples":[{"es":"Voy a comerme todo el pastel.","en":"I''m going to eat up the whole cake."},{"es":"Si no te terminas la cena, no podrás salir a jugar.","en":"If you don''t eat up your dinner, you won''t be able to go out and play."},{"es":"El perro tiene tanta hambre que se comió todo el plato de comida en segundos.","en":"The dog is so hungry that he managed to eat up his entire bowl of food in seconds."}]},{"spanish_text":"Explicar","english_text":"Explain away","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To dismiss or rationalize something as unimportant or untrue by offering an explanation that reduces its significance.","main_translations_es":["Aclarar","Desglosar","Ilustrar"],"collocations":["explain away the mistake","explain away the scandal","can''t explain away the evidence","explain away the problem"],"synonyms_en":["rationalize","justify","make excuses"],"example_sentence":"He tried to explain away his mistake as if it were nothing.","example_es":"Trató de explicar su error como si no fuera gran cosa.","example_en":"He tried to explain away his mistake as if it were nothing.","mnemonic_en":"Picture an ex‑plane flying away, explaining the mystery.","cloze_distractors_en":["Categorize off","Distribute over","Fabricate into","Reconcile under"],"examples":[{"es":"Trató de explicar su error como si no fuera gran cosa.","en":"He tried to explain away his mistake as if it were nothing."},{"es":"El político intentó explicar su ausencia en la votación como un problema técnico.","en":"The politician attempted to explain away his absence from the vote as a technical glitch."},{"es":"No puedes simplemente explicar tu falta de puntualidad diciendo que el tráfico estaba mal.","en":"You cannot simply explain away your lack of punctuality by claiming the traffic was bad."}]},{"spanish_text":"Llenarse","english_text":"Fill up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To cause something to become full or to become full oneself.","main_translations_es":["llenarse","completarse","colmarse"],"collocations":["fill up the tank","fill up on food","fill up the glass","fill up quickly"],"synonyms_en":["top up","replenish","load"],"example_sentence":"We decided to stop at the gas station to fill up the tank before continuing our road trip.","example_es":"Decidimos parar en la gasolinera para llenar el depósito antes de continuar nuestro viaje por carretera.","example_en":"We decided to stop at the gas station to fill up the tank before continuing our road trip.","mnemonic_en":"Picture Lena''s cup overflowing as it fills up.","cloze_distractors_en":["Break off","Fade away","Give out","Back down"],"examples":[{"es":"Decidimos parar en la gasolinera para llenar el depósito antes de continuar nuestro viaje por carretera.","en":"We decided to stop at the gas station to fill up the tank before continuing our road trip."},{"es":"La sala de espera se llenó de pacientes ansiosos durante la temporada de gripe.","en":"The waiting room began to fill up with anxious patients during the flu season."},{"es":"El disco duro de mi computadora se llenó de archivos temporales y fotos antiguas.","en":"My computer''s hard drive started to fill up with temporary files and old photos."}]},{"spanish_text":"Encajar","english_text":"Fit in","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to be accepted as part of a group or environment","main_translations_es":["Ajustar","Adaptarse","Encajar"],"collocations":["fit in with","fit in at","fit in nicely"],"synonyms_en":["blend","integrate","conform"],"example_sentence":"Even though I tried to be friendly, I felt that I never managed to fit in with my classmates.","example_es":"Aunque me esforcé por ser amable, sentí que nunca logré encajar entre mis compañeros de clase.","example_en":"Even though I tried to be friendly, I felt that I never managed to fit in with my classmates.","mnemonic_en":"Picture a key that fits in a lock, just like encajar means to fit in.","cloze_distractors_en":["Fall out","Back down","Give up","Look over"],"examples":[{"es":"Aunque me esforcé por ser amable, sentí que nunca logré encajar entre mis compañeros de clase.","en":"Even though I tried to be friendly, I felt that I never managed to fit in with my classmates."},{"es":"Aunque viste ropa de marca, nunca logró encajar en ese grupo de amigos tan exclusivo.","en":"Even though he wears designer clothes, he never managed to fit in with that exclusive group of friends."},{"es":"Como extranjero en un país nuevo, es normal que te tome tiempo encajar en la cultura local.","en":"As a foreigner in a new country, it is normal that it takes time to fit in with the local culture."}]},{"spanish_text":"Seguir adelante a pesar de","english_text":"Get on with","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb (phrasal verb)","definition_en":"to continue doing something despite obstacles or difficulties","main_translations_es":["Continuar a pesar de","Seguir adelante pese a","Prosseguir a pesar de"],"collocations":["get on with it","get on with your life","get on with the work","get on with the project"],"synonyms_en":["Proceed","Carry on","Continue"],"example_sentence":"After the rain delay, the referee signaled for us to stop waiting and get on with the match.","example_es":"Tras la interrupción por la lluvia, el árbitro nos indicó que dejáramos de esperar y siguiéramos adelante con el partido.","example_en":"After the rain delay, the referee signaled for us to stop waiting and get on with the match.","mnemonic_en":"A cat with a briefcase yells ''Get on with it!'' as it pushes forward.","cloze_distractors_en":["Look down on","Give in to","Fall back on","Put up with"],"examples":[{"es":"Tras la interrupción por la lluvia, el árbitro nos indicó que dejáramos de esperar y siguiéramos adelante con el partido.","en":"After the rain delay, the referee signaled for us to stop waiting and get on with the match."},{"es":"Después de discutir brevemente sobre quién debería conducir, decidimos dejar de perder el tiempo y seguir adelante con nuestro viaje por carretera.","en":"After arguing briefly about who should drive, we decided to stop wasting time and get on with our road trip."},{"es":"Tras la breve interrupción por el fallo técnico, el director nos pidió que dejáramos de quejarnos y siguiéramos adelante a pesar de todo con la grabación de la escena.","en":"After the technical glitch interrupted the filming, the director told us to stop complaining and get on with the scene."}]},{"spanish_text":"Bajarse de","english_text":"Get off","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To descend from or leave a vehicle, platform, or other surface.","main_translations_es":["Descender de","Salir de","Desmontarse de"],"collocations":["get off the bus","get off work","get off my back","get off the ground"],"synonyms_en":["disembark","step down","alight"],"example_sentence":"You need to get off the bus at the next stop to reach the city center.","example_es":"Tienes que bajarse del autobús en la próxima parada para llegar al centro.","example_en":"You need to get off the bus at the next stop to reach the city center.","mnemonic_en":"When you get off, imagine shouting baja as you step down the stairs.","cloze_distractors_en":["Look after","Give back","Take over"],"examples":[{"es":"Tienes que bajarse del autobús en la próxima parada para llegar al centro.","en":"You need to get off the bus at the next stop to reach the city center."},{"es":"El escalador decidió bajarse de la montaña debido a la tormenta inminente.","en":"The climber decided to get off the mountain because of the incoming storm."},{"es":"Cuando llegamos a la estación, tuvimos que bajarse de la bicicleta rápidamente.","en":"When we arrived at the station, we had to get off the bike quickly."}]},{"spanish_text":"Subirse a","english_text":"Get on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To board or mount something, such as a vehicle or animal.","main_translations_es":["Montarse en","Subir a","Entrar en"],"collocations":["get on the bus","get on board","get on with","get on the train"],"synonyms_en":["board","mount","climb aboard"],"example_sentence":"I''m going to get on the bus before it leaves.","example_es":"Voy a subirme al autobús antes de que salga.","example_en":"I''m going to get on the bus before it leaves.","mnemonic_en":"I get on the bus while shouting subir as the doors rise","cloze_distractors_en":["Look over","Turn down","Give away","Take back"],"examples":[{"es":"Voy a subirme al autobús antes de que salga.","en":"I''m going to get on the bus before it leaves."},{"es":"Tienes que subirte a la bicicleta si quieres llegar a tiempo a la clase.","en":"You have to get on the bike if you want to arrive at class on time."},{"es":"Es peligroso subirme a un tren en movimiento.","en":"It is dangerous to get on a moving train."}]},{"spanish_text":"Volver","english_text":"Go back","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To return to a previous place or condition.","main_translations_es":["Regresar","Retornar","Volver atrás"],"collocations":["go back to the drawing board","go back home","go back in time"],"synonyms_en":["return","revert","come back"],"example_sentence":"I need to go back home before the storm.","example_es":"Necesito volver a casa antes de la tormenta.","example_en":"I need to go back home before the storm.","mnemonic_en":"Picture a goat (go) backing up toward a volcano (volver).","cloze_distractors_en":["Look over","Pass away","Hold out","Turn off"],"examples":[{"es":"Necesito volver a casa antes de la tormenta.","en":"I need to go back home before the storm."},{"es":"Olvidé mi pasaporte en el hotel, así que tuve que volver a buscarlo.","en":"I forgot my passport at the hotel, so I had to go back to get it."},{"es":"Si no te gusta el trabajo, siempre puedes volver a tu antigua empresa.","en":"If you do not like the job, you can always go back to your old company."}]},{"spanish_text":"Salir","english_text":"Go out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To leave a place and go outside.","main_translations_es":["Ir afuera","Salir de casa","Ir fuera"],"collocations":["go out for dinner","go out with friends","go out on a date"],"synonyms_en":["leave","exit","step out"],"example_sentence":"We are going to go out after dinner.","example_es":"Vamos a salir después de la cena.","example_en":"We are going to go out after dinner.","mnemonic_en":"Imagine a sailor stepping out of the ship—''salir'' sounds like sailor, so you go out.","cloze_distractors_en":["Look over","Turn into","Give away","Hold back"],"examples":[{"es":"Vamos a salir después de la cena.","en":"We are going to go out after dinner."},{"es":"Ella se puso su mejor vestido para salir esta noche.","en":"She put on her best dress to go out tonight."},{"es":"No me gusta salir cuando hace tanto frío afuera.","en":"I do not like to go out when it is so cold outside."}]},{"spanish_text":"Acelerarse","english_text":"Hurry up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"A command telling someone to act more quickly.","main_translations_es":["Apurarse","Darse prisa","Acelerar"],"collocations":["Hurry up and wait","Hurry up, we''re late","Hurry up already"],"synonyms_en":["rush","step on it","make it quick"],"example_sentence":"You have to hurry up if you don''t want to miss the train.","example_es":"Debes acelerarte si no quieres perder el tren.","example_en":"You have to hurry up if you don''t want to miss the train.","mnemonic_en":"Imagine a hare hurrying up a steep hill, shouting Acelera! – that reminds you of hurry up.","cloze_distractors_en":["Slow down","Give away","Back down","Hold back"],"examples":[{"es":"Debes acelerarte si no quieres perder el tren.","en":"You have to hurry up if you don''t want to miss the train."},{"es":"El chef nos pidió acelerarnos porque la cocina está a punto de cerrar.","en":"The chef told us to hurry up because the kitchen is about to close."},{"es":"Si queremos llegar a la cima antes de que oscurezca, tenemos que acelerarnos.","en":"If we want to reach the summit before it gets dark, we need to hurry up."}]},{"spanish_text":"Posponer hasta más tarde","english_text":"Hold off","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To delay or postpone something.","main_translations_es":["Aplazar","Dejar para después","Postergar"],"collocations":["hold off on","hold off until","hold off for a while"],"synonyms_en":["delay","postpone","defer"],"example_sentence":"We decided to hold off the meeting until later.","example_es":"Decidimos posponer la reunión hasta más tarde.","example_en":"We decided to hold off the meeting until later.","mnemonic_en":"Imagine holding a post off the road to postpone it.","cloze_distractors_en":["Look over","Call down","Give away","Take back"],"examples":[{"es":"Decidimos posponer la reunión hasta más tarde.","en":"We decided to hold off the meeting until later."},{"es":"El banco me pidió posponer hasta más tarde el pago de la hipoteca.","en":"The bank asked me to hold off the mortgage payment until later."},{"es":"Debido a la incertidumbre económica, decidimos posponer hasta más tarde la inversión en el nuevo proyecto.","en":"Due to the economic uncertainty, we decided to hold off on the investment in the new project."}]},{"spanish_text":"Permanecer despierto","english_text":"Keep up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To continue doing something or maintain a certain level or pace.","main_translations_es":["Mantenerse despierto","No dormirse","Estar despierto"],"collocations":["keep up with","keep up the pace","keep up the good work","keep up the momentum"],"synonyms_en":["maintain","stay current","keep pace"],"example_sentence":"Even though the group of runners was moving very fast, I managed to keep up throughout the entire race.","example_es":"A pesar de que el grupo de corredores iba muy rápido, logré mantener el ritmo durante toda la carrera.","example_en":"Even though the group of runners was moving very fast, I managed to keep up throughout the entire race.","mnemonic_en":"I keep up with coffee, staying despierto all night.","cloze_distractors_en":["Look down","Turn over","Give away","Hold back"],"examples":[{"es":"A pesar de que el grupo de corredores iba muy rápido, logré mantener el ritmo durante toda la carrera.","en":"Even though the group of runners was moving very fast, I managed to keep up throughout the entire race."},{"es":"Aunque el ritmo de la clase es muy rápido, trato de permanecer despierto con los temas nuevos.","en":"Although the pace of the class is very fast, I try to keep up with the new topics."},{"es":"Si no estudias todos los días, será imposible permanecer despierto con el nivel de exigencia del curso.","en":"If you do not study every day, it will be impossible to keep up with the demands of the course."}]},{"spanish_text":"Irse sin pagar","english_text":"Make off","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb (phrasal verb)","definition_en":"To leave hurriedly, especially after stealing something.","main_translations_es":["Escaparse sin pagar","Huir sin pagar","Irse sin abonar"],"collocations":["make off with","make off after","make off quickly"],"synonyms_en":["flee","run away","escape"],"example_sentence":"The thieves took advantage of the confusion to make off with all the jewelry from the display case.","example_es":"Los ladrones aprovecharon la confusión para irse sin pagar con todas las joyas de la vitrina.","example_en":"The thieves took advantage of the confusion to make off with all the jewelry from the display case.","mnemonic_en":"He makes off, like a thief making the bill vanish off the table.","cloze_distractors_en":["Look over","Call down","Hold back","Give away"],"examples":[{"es":"Los ladrones aprovecharon la confusión para irse sin pagar con todas las joyas de la vitrina.","en":"The thieves took advantage of the confusion to make off with all the jewelry from the display case."},{"es":"El joven vio que el dueño estaba distraído y decidió irse sin pagar con el periódico que acababa de tomar.","en":"The young man saw that the owner was distracted and decided to make off with the newspaper he had just picked up."},{"es":"Tras robar la caja registradora, los sospechosos intentaron irse sin pagar en un coche que los esperaba afuera.","en":"After robbing the cash register, the suspects tried to make off in a car that was waiting for them outside."}]},{"spanish_text":"Inventar","english_text":"Make up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To create something false or fictitious, such as a story, excuse, or invention.","main_translations_es":["Crear","Fabricar","Idear"],"collocations":["make up a story","make up the bed","make up for","make up with"],"synonyms_en":["fabricate","invent","concoct"],"example_sentence":"You should not make up excuses every time you arrive late to work.","example_es":"No deberías inventar excusas cada vez que llegas tarde al trabajo.","example_en":"You should not make up excuses every time you arrive late to work.","mnemonic_en":"He makes up a new gadget, invent a device—just like inventar.","cloze_distractors_en":["Put down","Bring over","Look after","Hold back"],"examples":[{"es":"No deberías inventar excusas cada vez que llegas tarde al trabajo.","en":"You should not make up excuses every time you arrive late to work."},{"es":"Los niños suelen inventar historias fantásticas sobre dragones y castillos.","en":"Children often make up fantastic stories about dragons and castles."},{"es":"Tuve que inventar una razón convincente para explicar mi ausencia en la reunión.","en":"I had to make up a convincing reason to explain my absence from the meeting."}]},{"spanish_text":"Pasar por encima de","english_text":"Move past","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To go beyond or ignore something.","main_translations_es":["Superar","Dejar atrás","Pasar más allá de"],"collocations":["move past the obstacle","move past the issue","move past the pain","move past the past"],"synonyms_en":["Pass by","Go beyond","Proceed past"],"example_sentence":"Even though the trauma was difficult, she finally managed to move past that painful chapter of her life.","example_es":"Aunque el trauma fue difícil, finalmente logró pasar por encima de ese capítulo doloroso de su vida.","example_en":"Even though the trauma was difficult, she finally managed to move past that painful chapter of her life.","mnemonic_en":"Pass a rope over the fence to move past the obstacle.","cloze_distractors_en":["Turn under","Look above","Hold across","Step within"],"examples":[{"es":"Aunque el trauma fue difícil, finalmente logró pasar por encima de ese capítulo doloroso de su vida.","en":"Even though the trauma was difficult, she finally managed to move past that painful chapter of her life."},{"es":"Es difícil para ella pasar por encima de la traición de su mejor amigo.","en":"It is difficult for her to move past the betrayal of her best friend."},{"es":"Debemos pasar por encima de nuestras diferencias para trabajar juntos en el proyecto.","en":"We must move past our differences to work together on the project."}]},{"spanish_text":"Mencionar casualmente","english_text":"Pass on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to give or transmit something to someone else","main_translations_es":["Mencionar de pasada","Aludir casualmente","Hacer una mención casual"],"collocations":["pass on the message","pass on the information","pass on a tradition","pass on to the next generation"],"synonyms_en":["relay","hand over","convey"],"example_sentence":"If you speak with the boss, please pass on the message that I will not be able to attend the press conference.","example_es":"Si hablas con el jefe, por favor transmítele el mensaje de que no podré asistir a la conferencia de prensa.","example_en":"If you speak with the boss, please pass on the message that I will not be able to attend the press conference.","mnemonic_en":"Imagine saying ''pasa on'' while you casually drop a comment.","cloze_distractors_en":["Look after","Turn down","Back away"],"examples":[{"es":"Si hablas con el jefe, por favor transmítele el mensaje de que no podré asistir a la conferencia de prensa.","en":"If you speak with the boss, please pass on the message that I will not be able to attend the press conference."},{"es":"Cuando el profesor me envió las instrucciones del proyecto por correo electrónico, me pidió que se las pasara a mis compañeros de clase.","en":"When the professor emailed me the project instructions, he asked me to pass on the details to my classmates."},{"es":"Cuando el gerente me contó los cambios en el equipo, me pidió que le pasara la información a los demás empleados.","en":"When the manager told me about the team changes, he asked me to pass on the information to the other employees."}]},{"spanish_text":"Recoger","english_text":"Pick up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To lift something from a surface or to collect it.","main_translations_es":["Alcanzar","Levantar","Recoger"],"collocations":["pick up the phone","pick up where you left off","pick up the tab","pick up a habit"],"synonyms_en":["collect","gather","retrieve"],"example_sentence":"I will pick up the package from the office.","example_es":"Voy a recoger el paquete de la oficina.","example_en":"I will pick up the package from the office.","mnemonic_en":"Pick up the record gear lying on the table","cloze_distractors_en":["Look over","Turn into","Give away","Hold down"],"examples":[{"es":"Voy a recoger el paquete de la oficina.","en":"I will pick up the package from the office."},{"es":"Podrías recoger a los niños del colegio a las tres.","en":"You could pick up the kids from school at three."},{"es":"Necesito recoger los juguetes que están tirados por todo el suelo.","en":"I need to pick up the toys that are scattered all over the floor."}]},{"spanish_text":"Señalar con precisión","english_text":"Pin down","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To identify or locate something precisely, often by determining its exact nature or details.","main_translations_es":["Precisar","Detallar con exactitud","Ubicar con precisión"],"collocations":["pin down the details","pin down the location","pin down the meaning","pin down the cause"],"synonyms_en":["identify","determine","pinpoint"],"example_sentence":"The detective managed to pin down the location of the body.","example_es":"El detective logró señalar con precisión la ubicación del cuerpo.","example_en":"The detective managed to pin down the location of the body.","mnemonic_en":"Imagine a pin marking the exact spot you point at","cloze_distractors_en":["Look away","Turn over","Hold back","Step aside"],"examples":[{"es":"El detective logró señalar con precisión la ubicación del cuerpo.","en":"The detective managed to pin down the location of the body."},{"es":"Es difícil señalar con precisión la causa exacta de este error técnico en el servidor.","en":"It is difficult to pin down the exact cause of this technical error on the server."},{"es":"No pude señalar con precisión qué fue lo que me hizo sentir tan incómodo durante la reunión.","en":"I could not pin down what exactly made me feel so uncomfortable during the meeting."}]},{"spanish_text":"Presentar formalmente","english_text":"Put forward","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to propose or suggest something for consideration","main_translations_es":["exponer formalmente","proponer formalmente","someter formalmente"],"collocations":["put forward a proposal","put forward an idea","put forward a suggestion","put forward a theory"],"synonyms_en":["propose","suggest","advance"],"example_sentence":"The lawyer put forward the evidence to the jury.","example_es":"El abogado presentó formalmente la evidencia al jurado.","example_en":"The lawyer put forward the evidence to the jury.","mnemonic_en":"Picture a presenter putting a forward arrow on the screen","cloze_distractors_en":["Looked away","Turned aside","Held under","Broke across"],"examples":[{"es":"El abogado presentó formalmente la evidencia al jurado.","en":"The lawyer put forward the evidence to the jury."},{"es":"El comité decidió presentar formalmente una nueva propuesta para reducir los gastos.","en":"The committee decided to put forward a new proposal to cut costs."},{"es":"Varios científicos presentaron formalmente una teoría revolucionaria sobre el cambio climático.","en":"Several scientists put forward a revolutionary theory about climate change."}]},{"spanish_text":"Encender","english_text":"Put on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To dress oneself in something, or to cause something to be worn.","main_translations_es":["prender","activar","encender"],"collocations":["put on a coat","put on makeup","put on a show","put on weight"],"synonyms_en":["don","wear","slip on"],"example_sentence":"It is a cold morning, so you should put on a coat before going outside.","example_es":"Es una mañana fría, así que deberías ponerte un abrigo antes de salir.","example_en":"It is a cold morning, so you should put on a coat before going outside.","mnemonic_en":"Picture putting on a bright jacket that lights up, just like you encender a lamp.","cloze_distractors_en":["Look after","Turn down","Give away"],"examples":[{"es":"Es una mañana fría, así que deberías ponerte un abrigo antes de salir.","en":"It is a cold morning, so you should put on a coat before going outside."},{"es":"Ella decidió ponerse sus zapatos favoritos para la entrevista de trabajo.","en":"She decided to put on her favorite shoes for the job interview."},{"es":"No olvides ponerte el cinturón de seguridad antes de que el coche empiece a moverse.","en":"Do not forget to put on your seatbelt before the car starts moving."}]},{"spanish_text":"Apagar","english_text":"Put out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To extinguish a fire, light, or similar source.","main_translations_es":["Extinguir","Desactivar","Cerrar"],"collocations":["put out a fire","put out the lights","put out a cigarette","put out a call"],"synonyms_en":["extinguish","turn off","snuff"],"example_sentence":"Put out the candle before you leave.","example_es":"Apaga la vela antes de irte.","example_en":"Put out the candle before you leave.","mnemonic_en":"Picture a fire and hand a pager that says STOP to put it out.","cloze_distractors_en":["Look over","Call back","Give away","Hold onto"],"examples":[{"es":"Apaga la vela antes de irte.","en":"Put out the candle before you leave."},{"es":"Los bomberos tardaron horas en apagar el incendio forestal.","en":"The firefighters took hours to put out the forest fire."},{"es":"Por favor, apaga el cigarrillo antes de entrar en la gasolinera.","en":"Please put out your cigarette before entering the gas station."}]},{"spanish_text":"Expulsar","english_text":"Throw out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To discard or eject something.","main_translations_es":["Echar","Despedir","Eliminar"],"collocations":["throw out the trash","throw out a suggestion","throw out the window"],"synonyms_en":["discard","eject","expel"],"example_sentence":"The guard had to throw out the thief from the building.","example_es":"El guardia tuvo que expulsar al ladrón del edificio.","example_en":"The guard had to throw out the thief from the building.","mnemonic_en":"Visualize throwing a trash can out the door, you expel it—like the Spanish expulsar.","cloze_distractors_en":["Look after","Bring about","Grow under","Hold across"],"examples":[{"es":"El guardia tuvo que expulsar al ladrón del edificio.","en":"The guard had to throw out the thief from the building."},{"es":"Mi madre decidió expulsar toda la ropa vieja que ya no usamos del armario.","en":"My mother decided to throw out all the old clothes we no longer use from the closet."},{"es":"El entrenador tuvo que expulsar al jugador del campo tras su comportamiento agresivo.","en":"The coach had to throw out the player from the field after his aggressive behavior."}]},{"spanish_text":"Resurgir","english_text":"Crop up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb (phrasal)","definition_en":"to appear or occur unexpectedly","main_translations_es":["Aparecer","Reaparecer","Surgir de nuevo"],"collocations":["issues crop up","questions crop up","problems crop up","new ideas crop up"],"synonyms_en":["appear","arise","emerge"],"example_sentence":"Unexpected problems tend to crop up during the final phase of a major project.","example_es":"Problemas inesperados suelen resurgir durante la fase final de un proyecto importante.","example_en":"Unexpected problems tend to crop up during the final phase of a major project.","mnemonic_en":"The resurging wheat fields suddenly crop up like green fireworks.","cloze_distractors_en":["Fold away","Fade out","Back off","Drop off"],"examples":[{"es":"Problemas inesperados suelen resurgir durante la fase final de un proyecto importante.","en":"Unexpected problems tend to crop up during the final phase of a major project."},{"es":"Aunque intentamos mantener la reunión bajo control, siempre resurgir temas polémicos que no estaban en la agenda.","en":"Although we tried to keep the meeting under control, controversial topics always crop up that were not on the agenda."},{"es":"Es frustrante cuando los errores técnicos resurgir justo después de que creíamos haberlos solucionado.","en":"It is frustrating when technical bugs crop up just after we thought we had fixed them."}]},{"spanish_text":"Darse cuenta de","english_text":"Cotton on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to become aware of something","main_translations_es":["darse cuenta","percatarse de","notar"],"collocations":["cotton on to","cotton on quickly","cotton on to the fact","cotton on over time"],"synonyms_en":["realize","notice","become aware"],"example_sentence":"It took me a while to cotton on that they were trying to trick me with such a suspicious offer.","example_es":"Tardé un buen rato en darme cuenta de que me estaban tomando el pelo con esa oferta tan sospechosa.","example_en":"It took me a while to cotton on that they were trying to trick me with such a suspicious offer.","mnemonic_en":"Seeing the soft cotton pillow, I finally cotton on to the hidden clue.","cloze_distractors_en":["Fatten up","Button down","Flatten out","Settle down"],"examples":[{"es":"Tardé un buen rato en darme cuenta de que me estaban tomando el pelo con esa oferta tan sospechosa.","en":"It took me a while to cotton on that they were trying to trick me with such a suspicious offer."},{"es":"Al ver que todos sus compañeros se reían de sus chistes privados, finalmente me di cuenta de que me estaban excluyendo del grupo.","en":"Seeing my colleagues whispering and sharing private jokes, I finally began to cotton on to the fact that I was being excluded from the group."},{"es":"Tardó varios minutos en darse cuenta de que le estaban tomando el pelo.","en":"It took him several minutes to cotton on that they were pulling his leg."}]},{"spanish_text":"Enfrentarse a","english_text":"Face up to","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to confront or deal with something directly, especially a problem or difficulty.","main_translations_es":["Encarar","Hacerse cargo de","Confrontar"],"collocations":["face up to the reality","face up to the facts","face up to the consequences","face up to the problem"],"synonyms_en":["confront","deal with","address"],"example_sentence":"I have to face up to my fears.","example_es":"Tengo que enfrentarme a mis miedos.","example_en":"I have to face up to my fears.","mnemonic_en":"Picture a face looking up, ready to enfrentarse a the challenge.","cloze_distractors_en":["Look down on","Pass out of","Drop in on","Make off with"],"examples":[{"es":"Tengo que enfrentarme a mis miedos.","en":"I have to face up to my fears."},{"es":"Es hora de que enfrentes a la realidad sobre tu situación financiera.","en":"It is time you face up to the reality of your financial situation."},{"es":"Ella finalmente decidió enfrentarse a los errores que cometió en el pasado.","en":"She finally decided to face up to the mistakes she made in the past."}]},{"spanish_text":"Tomar apuntes","english_text":"Jot down","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to write something quickly, especially brief notes.","main_translations_es":["Anotar","Escribir notas","Apuntar"],"collocations":["jot down notes","jot down a reminder","jot down ideas"],"synonyms_en":["write down","note","record"],"example_sentence":"During the class, I like to jot down notes so I don''t forget anything.","example_es":"Durante la clase, me gusta tomar apuntes para no olvidar nada.","example_en":"During the class, I like to jot down notes so I don''t forget anything.","mnemonic_en":"I jot down notes while I take apuntes, picturing a tiny jot of paper.","cloze_distractors_en":["Cast away","Fade out","Give over","Hold back"],"examples":[{"es":"Durante la clase, me gusta tomar apuntes para no olvidar nada.","en":"During the class, I like to jot down notes so I don''t forget anything."},{"es":"El periodista se apresuró a tomar apuntes de las declaraciones del testigo.","en":"The reporter hurried to jot down the witness''s statements."},{"es":"Si tienes una idea brillante, es mejor tomar apuntes antes de que se te olvide.","en":"If you have a brilliant idea, it is better to jot down notes before you forget it."}]},{"spanish_text":"Reducirse a","english_text":"Boil down to","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb phrase","definition_en":"To simplify something to its essential point or main idea.","main_translations_es":["Limitarse a","Resumirse a","Condensarse en"],"collocations":["It all boils down to","The problem boils down to","Everything boils down to","In the end, it boils down to"],"synonyms_en":["reduce to","condense to","simplify to"],"example_sentence":"In the end, the entire conflict boils down to a matter of money.","example_es":"Al final, todo el conflicto se reduce a una cuestión de dinero.","example_en":"In the end, the entire conflict boils down to a matter of money.","mnemonic_en":"See a boiling bowl that shrinks down to a tiny cup.","cloze_distractors_en":[],"examples":[{"es":"Al final, todo el conflicto se reduce a una cuestión de dinero.","en":"In the end, the entire conflict boils down to a matter of money."},{"es":"El éxito de esta receta tan compleja se reduce a la calidad de los ingredientes frescos.","en":"The success of this complex recipe boils down to the quality of the fresh ingredients."},{"es":"La decisión del juez se reduce a determinar si hubo intención de engañar al cliente.","en":"The judge''s decision boils down to determining whether there was an intent to deceive the client."}]},{"spanish_text":"Salir con una idea","english_text":"Dream up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To imagine or invent something, especially an idea or plan.","main_translations_es":["Idear","Proponer una idea","Concebir una idea"],"collocations":["dream up a plan","dream up a story","dream up an excuse"],"synonyms_en":["conceive","imagine","invent"],"example_sentence":"The scientist managed to dream up a brilliant idea to solve the complex problem.","example_es":"El científico salió con una idea brillante para resolver el problema.","example_en":"The scientist managed to dream up a brilliant idea to solve the complex problem.","mnemonic_en":"Picture a dream balloon floating up, as if a Spanish sueño flies arriba with a new idea.","cloze_distractors_en":["Break down","Carry over","Fall apart","Look away"],"examples":[{"es":"El científico salió con una idea brillante para resolver el problema.","en":"The scientist managed to dream up a brilliant idea to solve the complex problem."},{"es":"Los guionistas salieron con una idea descabellada para el final de la serie.","en":"The screenwriters had to dream up a wild plot twist for the season finale."},{"es":"Ella salió con una idea creativa para decorar la oficina con poco presupuesto.","en":"She was able to dream up a creative way to decorate the office on a tight budget."}]},{"spanish_text":"Renunciar a","english_text":"Walk away from","section_name":"Advanced Phrasal Verbs","part_of_speech":"phrasal verb","definition_en":"to leave or abandon something or someone","main_translations_es":["Abandonar","Dejar","Desistir de"],"collocations":["walk away from the problem","walk away from a relationship","walk away from danger"],"synonyms_en":["leave","depart","abandon"],"example_sentence":"After working twenty years at the same company, he decided to walk away from a promotion offer to retire early.","example_es":"Después de trabajar veinte años en la misma empresa, decidió renunciar a una oferta de ascenso para jubilarse antes.","example_en":"After working twenty years at the same company, he decided to walk away from a promotion offer to retire early.","mnemonic_en":"When you renounce, you walk away from the scene.","cloze_distractors_en":["Look down upon","Bring light into","Hold fast with","Make light of"],"examples":[{"es":"Después de trabajar veinte años en la misma empresa, decidió renunciar a una oferta de ascenso para jubilarse antes.","en":"After working twenty years at the same company, he decided to walk away from a promotion offer to retire early."},{"es":"Es muy difícil renunciar a una relación tóxica cuando has invertido tanto tiempo y esfuerzo en ella.","en":"It is very difficult to walk away from a toxic relationship when you have invested so much time and effort into it."},{"es":"El jugador estrella decidió renunciar a un contrato millonario para jugar en el equipo de su ciudad natal.","en":"The star player decided to walk away from a multi-million dollar contract to play for his hometown team."}]},{"spanish_text":"Asentarse","english_text":"Settle down","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to become comfortable and stable in a place or situation, often by establishing a residence or routine","main_translations_es":["instalarse","establecerse","posarse"],"collocations":["settle down and relax","settle down in a new city","settle down with a partner"],"synonyms_en":["calm down","establish oneself","take root"],"example_sentence":"After moving to the new city, he decided to settle down in a small apartment near the park.","example_es":"Después de mudarse a la nueva ciudad, decidió asentarse en un pequeño apartamento cerca del parque.","example_en":"After moving to the new city, he decided to settle down in a small apartment near the park.","mnemonic_en":"Settle down like finding a seat (asiento) and sitting.","cloze_distractors_en":["Break away","Carry over","Stand apart","Throw back"],"examples":[{"es":"Después de mudarse a la nueva ciudad, decidió asentarse en un pequeño apartamento cerca del parque.","en":"After moving to the new city, he decided to settle down in a small apartment near the park."},{"es":"Tras años de viajar por todo el mundo, finalmente quiso asentarse y formar una familia en su pueblo natal.","en":"After years of traveling around the world, he finally wanted to settle down and start a family in his hometown."},{"es":"Después de años de vivir de fiesta en fiesta, finalmente decidió sentar cabeza y buscar un trabajo estable.","en":"After years of partying every weekend, he finally decided to settle down and find a steady job."}]},{"spanish_text":"Derivar de","english_text":"Stem from","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to originate or develop from something","main_translations_es":["Proceder de","Originarse en","Derivarse de"],"collocations":["stem from a problem","stem from the fact that","stem from years of experience","stem from underlying causes"],"synonyms_en":["originate from","derive from","come from"],"example_sentence":"The region''s economic instability stems from recent trade policies.","example_es":"La inestabilidad económica de la región deriva de las recientes políticas comerciales.","example_en":"The region''s economic instability stems from recent trade policies.","mnemonic_en":"The tree''s stem from the earth derives, just like a river (deriva) flows out.","cloze_distractors_en":[],"examples":[{"es":"La inestabilidad económica de la región deriva de las recientes políticas comerciales.","en":"The region''s economic instability stems from recent trade policies."},{"es":"El éxito de este proyecto deriva de una planificación cuidadosa y una ejecución impecable.","en":"The success of this project stems from careful planning and flawless execution."},{"es":"La desconfianza que siente hacia los extraños deriva de una mala experiencia que tuvo en el pasado.","en":"His distrust of strangers stems from a bad experience he had in the past."}]},{"spanish_text":"Asumir el mando","english_text":"Step up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to assume a higher level of responsibility or authority","main_translations_es":["Tomar el control","Asumir la dirección","Encabezar"],"collocations":["step up to the plate","step up your game","step up and take charge","step up the pace"],"synonyms_en":["take charge","assume responsibility","rise to the occasion"],"example_sentence":"When the captain fell ill, he had to step up and take command of the ship.","example_es":"Cuando el capitán cayó enfermo, tuvo que asumir el mando del barco.","example_en":"When the captain fell ill, he had to step up and take command of the ship.","mnemonic_en":"Imagine stepping up a ladder to asume the command.","cloze_distractors_en":["Step down","Step aside","Step back","Step over"],"examples":[{"es":"Cuando el capitán cayó enfermo, tuvo que asumir el mando del barco.","en":"When the captain fell ill, he had to step up and take command of the ship."},{"es":"El equipo perdía por tres goles, así que el capitán decidió asumir el mando en la segunda parte.","en":"The team was down by three goals, so the captain decided to step up and lead the comeback in the second half."},{"es":"Ante la crisis financiera, el vicepresidente tuvo que asumir el mando de la empresa.","en":"Faced with the financial crisis, the vice president had to step up to manage the company''s operations."}]},{"spanish_text":"Suprimir gradualmente","english_text":"Weed out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To gradually remove or eliminate unwanted or undesirable items or people.","main_translations_es":["Eliminar poco a poco","Deshacerse gradualmente","Ir eliminando"],"collocations":["weed out the weak","weed out candidates","weed out problems","weed out unnecessary items"],"synonyms_en":["eliminate","cull","filter out"],"example_sentence":"The company decided to weed out unnecessary positions.","example_es":"La empresa decidió suprimir gradualmente los puestos de trabajo innecesarios.","example_en":"The company decided to weed out unnecessary positions.","mnemonic_en":"Imagine pulling weeds out slowly, like you suppress (suprimir) them one by one.","cloze_distractors_en":["Grow over","Branch off","Bloom into","Root under"],"examples":[{"es":"La empresa decidió suprimir gradualmente los puestos de trabajo innecesarios.","en":"The company decided to weed out unnecessary positions."},{"es":"El entrenador tuvo que suprimir gradualmente a los jugadores que no cumplían con el nivel físico requerido.","en":"The coach had to weed out the players who did not meet the required fitness level."},{"es":"El editor dedicó horas a suprimir gradualmente los errores gramaticales del manuscrito antes de enviarlo a imprenta.","en":"The editor spent hours trying to weed out grammatical errors from the manuscript before sending it to the printer."}]},{"spanish_text":"Desmenuzar","english_text":"Break down into","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb phrase","definition_en":"to separate something into smaller parts or components","main_translations_es":["desmenuzar","desglosar","descomponer"],"collocations":["break down into pieces","break down into steps","break down into components","break down into categories"],"synonyms_en":["analyze","decompose","dissect"],"example_sentence":"The financial analyst had to break down into several categories the company''s annual expenses to identify where money was being lost.","example_es":"El analista financiero tuvo que desmenuzar en varias categorías los gastos anuales de la empresa para identificar dónde se estaba perdiendo dinero.","example_en":"The financial analyst had to break down into several categories the company''s annual expenses to identify where money was being lost.","mnemonic_en":"Break the cake into crumbs, just like desmenuzar.","cloze_distractors_en":["Look over with","Turn away from","Bring back under","Hold out against"],"examples":[{"es":"El analista financiero tuvo que desmenuzar en varias categorías los gastos anuales de la empresa para identificar dónde se estaba perdiendo dinero.","en":"The financial analyst had to break down into several categories the company''s annual expenses to identify where money was being lost."},{"es":"El profesor decidió desmenuzar en conceptos sencillos la compleja teoría física para que sus alumnos pudieran entenderla mejor.","en":"The professor decided to break down into simple concepts the complex physical theory so that his students could understand it better."},{"es":"El chef tuvo que desmenuzar en trozos minúsculos la carne dura para que el estofado quedara tierno.","en":"The chef had to break down into tiny pieces the tough meat so that the stew would be tender."}]},{"spanish_text":"Superar con esfuerzo","english_text":"Pull through","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to survive or recover from a difficult situation","main_translations_es":["Salir adelante con esfuerzo","Superar con dificultad","Lograrlo con esfuerzo"],"collocations":["pull through a crisis","pull through the tough times","pull through with help"],"synonyms_en":["survive","make it","get through"],"example_sentence":"With a lot of effort, we managed to pull through the economic crisis.","example_es":"Con mucho trabajo, logramos superar con esfuerzo la crisis económica.","example_en":"With a lot of effort, we managed to pull through the economic crisis.","mnemonic_en":"Pull the rope through, like polishing (pulir) your way past a tough wall.","cloze_distractors_en":["Fall behind","Back away","Step aside","Look ahead"],"examples":[{"es":"Con mucho trabajo, logramos superar con esfuerzo la crisis económica.","en":"With a lot of effort, we managed to pull through the economic crisis."},{"es":"El pronóstico médico era desalentador, pero tras semanas de cuidados intensivos, el enfermo finalmente logró superar con esfuerzo la enfermedad.","en":"The medical prognosis was grim, but after weeks of intensive care, the patient finally managed to pull through."},{"es":"La empresa estaba al borde de la quiebra, pero gracias a los nuevos inversores pudieron superar con esfuerzo los meses más difíciles.","en":"The company was on the verge of bankruptcy, but thanks to the new investors they were able to pull through the most difficult months."}]},{"spanish_text":"No presentarse","english_text":"Back out of","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to withdraw from a commitment or fail to follow through with a plan","main_translations_es":["ausentarse","no acudir","no comparecer"],"collocations":["back out of a deal","back out of a commitment","back out of an agreement","back out of a promise"],"synonyms_en":["withdraw","pull out of","renege on"],"example_sentence":"I had to back out of the meeting because I was feeling sick.","example_es":"No me presenté a la reunión porque me sentía enfermo.","example_en":"I had to back out of the meeting because I was feeling sick.","mnemonic_en":"Picture yourself backing out of a door, shouting No presentarse as you vanish before anyone sees you.","cloze_distractors_en":["Look up to","Carry on with","Bring down on","Check in at"],"examples":[{"es":"No me presenté a la reunión porque me sentía enfermo.","en":"I had to back out of the meeting because I was feeling sick."},{"es":"Prometió ayudarme con la mudanza, pero decidió no presentarse a último momento.","en":"He promised to help me move, but he decided to back out of the agreement at the last minute."},{"es":"El inversor decidió no presentarse al proyecto tras revisar los estados financieros.","en":"The investor decided to back out of the project after reviewing the financial statements."}]},{"spanish_text":"Tachar","english_text":"Cross out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To draw a line through text or a mark to indicate it should be deleted or ignored.","main_translations_es":["rayar","borrar","tachar"],"collocations":["cross out a mistake","cross out the word","cross out the line","cross out the name"],"synonyms_en":["delete","strike through","erase"],"example_sentence":"Please cross out the mistakes in the document.","example_es":"Por favor, tacha los errores en el documento.","example_en":"Please cross out the mistakes in the document.","mnemonic_en":"Cross out a mistake by drawing a big T over the char.","cloze_distractors_en":["Look after","Bring about","Hold onto","Stand under"],"examples":[{"es":"Por favor, tacha los errores en el documento.","en":"Please cross out the mistakes in the document."},{"es":"El profesor pidió que tacháramos los nombres de los estudiantes que no asistieron a clase.","en":"The teacher asked us to cross out the names of the students who did not attend class."},{"es":"Tacha la respuesta incorrecta en el examen antes de entregar tu hoja.","en":"Cross out the incorrect answer on the test before you hand in your paper."}]},{"spanish_text":"Ir acompañado de","english_text":"Go together with","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb phrase","definition_en":"to accompany someone or something","main_translations_es":["Ir con","Ir acompañado de","Ir en compañía de"],"collocations":["go together with friends","go together with a purpose","go together with the team","go together with the plan"],"synonyms_en":["accompany","travel with","go with"],"example_sentence":"Red wine tends to go together with red meat at elegant dinners.","example_es":"El vino tinto suele ir acompañado de carnes rojas en las cenas elegantes.","example_en":"Red wine tends to go together with red meat at elegant dinners.","mnemonic_en":"Picture a goat (go) walking together with a companion named Acompañado.","cloze_distractors_en":["Fall apart from","Look down upon","Run out of","Break away from"],"examples":[{"es":"El vino tinto suele ir acompañado de carnes rojas en las cenas elegantes.","en":"Red wine tends to go together with red meat at elegant dinners."},{"es":"El aumento de la inflación suele ir acompañado de una caída en el poder adquisitivo de las familias.","en":"The rise in inflation tends to go together with a drop in the purchasing power of families."},{"es":"Ese vestido elegante debe ir acompañado de los accesorios adecuados para destacar.","en":"That elegant dress must go together with the right accessories to stand out."}]},{"spanish_text":"Recaer en","english_text":"Fall back on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to rely again on something or someone for support or help","main_translations_es":["caer de nuevo en","volver a incurrir en","incurrir de nuevo en"],"collocations":["fall back on savings","fall back on experience","fall back on a plan","fall back on your instincts"],"synonyms_en":["rely on","depend on","turn to"],"example_sentence":"When I don''t know what to do, I always fall back on my old habits.","example_es":"Cuando no sé qué hacer, siempre recaigo en mis viejos hábitos.","example_en":"When I don''t know what to do, I always fall back on my old habits.","mnemonic_en":"Picture a falling rope you re‑cair onto when you need backup.","cloze_distractors_en":["Look down on","Bring up with","Make off with","Hold out for"],"examples":[{"es":"Cuando no sé qué hacer, siempre recaigo en mis viejos hábitos.","en":"When I don''t know what to do, I always fall back on my old habits."},{"es":"Si pierdo mi empleo, tendré que recaer en mis ahorros para pagar el alquiler.","en":"If I lose my job, I will have to fall back on my savings to pay the rent."},{"es":"El equipo no tenía un plan B y tuvo que recaer en su estrategia defensiva inicial.","en":"The team had no plan B and had to fall back on their initial defensive strategy."}]},{"spanish_text":"Insistir en","english_text":"Press ahead with","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb phrase","definition_en":"To continue doing something with determination despite obstacles.","main_translations_es":["Persistir en","Mantenerse firme en","Continuar con"],"collocations":["press ahead with the plan","press ahead with the project","press ahead with reforms","press ahead with negotiations"],"synonyms_en":["continue with","forge ahead with","push forward with"],"example_sentence":"Despite the lack of budget, the company decided to press ahead with developing the new software.","example_es":"A pesar de la falta de presupuesto, la empresa decidió insistir en desarrollar el nuevo software.","example_en":"Despite the lack of budget, the company decided to press ahead with developing the new software.","mnemonic_en":"Press a head like a stubborn insist from Spanish insistir.","cloze_distractors_en":["fall behind in","back away from","give up on"],"examples":[{"es":"A pesar de la falta de presupuesto, la empresa decidió insistir en desarrollar el nuevo software.","en":"Despite the lack of budget, the company decided to press ahead with developing the new software."},{"es":"Aunque el clima empeoró, los escaladores decidieron insistir en subir hasta la cima de la montaña.","en":"Even though the weather worsened, the climbers decided to press ahead with reaching the mountain summit."},{"es":"El director no escuchó las advertencias y prefirió insistir en implementar los cambios radicales en la oficina.","en":"The manager ignored the warnings and chose to press ahead with implementing the radical changes in the office."}]}]'::jsonb) as x(
  spanish_text text, english_text text, section_name text, part_of_speech text, definition_en text,
  main_translations_es jsonb, collocations jsonb, synonyms_en jsonb, example_sentence text, example_es text, example_en text, mnemonic_en text, cloze_distractors_en jsonb, examples jsonb
)
where c.deck_id = dk.id
  and lower(c.spanish_text) = lower(x.spanish_text)
  and lower(c.english_text) = lower(x.english_text);

-- english-discussion-and-debate (105 cards)
update public.decks set
  title = 'Discussion and Debate', description = 'Expressions for giving opinions, agreeing, disagreeing, clarifying, and structuring advanced spoken English.',
  language_from = 'es', language_to = 'en'
where slug = 'english-discussion-and-debate';

update public.cards c set
  section_name = x.section_name, part_of_speech = x.part_of_speech, definition_en = x.definition_en,
  main_translations_es = coalesce(x.main_translations_es, '[]'::jsonb),
  collocations = coalesce(x.collocations, '[]'::jsonb),
  synonyms_en = coalesce(x.synonyms_en, '[]'::jsonb),
  example_sentence = x.example_sentence, example_es = x.example_es, example_en = x.example_en,
  mnemonic_en = coalesce(x.mnemonic_en, c.mnemonic_en),
  cloze_distractors_en = case when jsonb_array_length(coalesce(x.cloze_distractors_en, '[]'::jsonb)) > 0
                              then x.cloze_distractors_en else c.cloze_distractors_en end,
  examples = case when jsonb_array_length(coalesce(x.examples, '[]'::jsonb)) > 0
                  then x.examples else c.examples end
from (select id from public.decks where slug = 'english-discussion-and-debate') dk
cross join jsonb_to_recordset('[{"spanish_text":"Estoy totalmente de acuerdo","english_text":"I completely agree","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating total agreement with something.","main_translations_es":["Estoy completamente de acuerdo","Coincido plenamente","Estoy totalmente de acuerdo"],"collocations":["I completely agree with you","I completely agree that","I completely agree, indeed"],"synonyms_en":["agree wholeheartedly","fully concur","absolutely agree"],"example_sentence":"I completely agree with your proposal to improve the work schedule.","example_es":"Estoy totalmente de acuerdo con tu propuesta para mejorar el horario de trabajo.","example_en":"I completely agree with your proposal to improve the work schedule.","mnemonic_en":"I completely nod, because agree sounds like Spanish acuerdo.","cloze_distractors_en":["I briefly evaporate","I suddenly circulate","I frequently decorate"],"examples":[{"es":"Estoy totalmente de acuerdo con tu propuesta para mejorar el horario de trabajo.","en":"I completely agree with your proposal to improve the work schedule."},{"es":"Después de escuchar los argumentos del equipo, estoy totalmente de acuerdo con su conclusión.","en":"After hearing the team''s arguments, I completely agree with their conclusion."},{"es":"Siendo honesto, estoy totalmente de acuerdo con la decisión que tomó el director hoy.","en":"To be honest, I completely agree with the decision the director made today."}]},{"spanish_text":"Estoy de acuerdo hasta cierto punto","english_text":"I agree to some extent","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"To express partial agreement with something.","main_translations_es":["Estoy de acuerdo en parte","Estoy parcialmente de acuerdo","Coincido hasta cierto punto"],"collocations":["I agree to some extent with you","I agree to some extent, however","I agree to some extent on that point"],"synonyms_en":["partially agree","somewhat agree","agree in part"],"example_sentence":"I agree to some extent with your proposal to change the meeting time.","example_es":"Estoy de acuerdo hasta cierto punto con tu propuesta de cambiar el horario de la reunión.","example_en":"I agree to some extent with your proposal to change the meeting time.","mnemonic_en":"Visualize an agrarian handshake extending just enough to pitch a tiny tent at a point.","cloze_distractors_en":["I vacuum the carpet","I calculate the radius","I butter the toast","I navigate the galaxy"],"examples":[{"es":"Estoy de acuerdo hasta cierto punto con tu propuesta de cambiar el horario de la reunión.","en":"I agree to some extent with your proposal to change the meeting time."},{"es":"Aunque el plan parece eficiente, estoy de acuerdo hasta cierto punto sobre los riesgos que mencionas.","en":"Although the plan seems efficient, I agree to some extent about the risks you mention."},{"es":"Sobre la nueva política de la empresa, estoy de acuerdo hasta cierto punto, pero faltan detalles.","en":"Regarding the new company policy, I agree to some extent, but details are missing."}]},{"spanish_text":"No lo veo así","english_text":"I do not see it that way","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that the speaker does not share that perspective.","main_translations_es":["No lo percibo de esa manera","No lo entiendo así","No lo concibo así"],"collocations":["I do not see it that way, but...","I do not see it that way at all","I do not see it that way, however"],"synonyms_en":["I disagree","I see it differently","That''s not how I view it"],"example_sentence":"Even though you think the project is a success, I do not see it that way after reviewing the numbers.","example_es":"Aunque creas que el proyecto es un éxito, no lo veo así después de revisar los números.","example_en":"Even though you think the project is a success, I do not see it that way after reviewing the numbers.","mnemonic_en":"Imagine a NO sign covering a low V while a sea says as I","cloze_distractors_en":["I am very hungry now","It is raining outside today","We love the new office","They bought a red car"],"examples":[{"es":"Aunque creas que el proyecto es un éxito, no lo veo así después de revisar los números.","en":"Even though you think the project is a success, I do not see it that way after reviewing the numbers."},{"es":"Dices que deberíamos vender la empresa ahora, pero no lo veo así porque el mercado va a mejorar pronto.","en":"You say we should sell the company now, but I do not see it that way because the market is going to improve soon."},{"es":"Él insiste en que el cambio es necesario, pero no lo veo así dado el impacto negativo en el personal.","en":"He insists that the change is necessary, but I do not see it that way given the negative impact on the staff."}]},{"spanish_text":"No estoy del todo convencido","english_text":"I am not entirely convinced","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that someone is not fully persuaded.","main_translations_es":["No estoy completamente convencido","No me convence del todo","No estoy totalmente seguro"],"collocations":["I am not entirely convinced that…","I''m not entirely convinced by…","We are not entirely convinced about…"],"synonyms_en":["I''m not fully convinced","I''m skeptical","I''m doubtful"],"example_sentence":"I am not entirely convinced that this is the best solution.","example_es":"No estoy del todo convencido de que esa sea la mejor solución.","example_en":"I am not entirely convinced that this is the best solution.","mnemonic_en":"I stare at a half‑filled glass, not entirely convinced it''s full.","cloze_distractors_en":["I am strictly prohibited","I am perpetually exhausted","I am remarkably terrified"],"examples":[{"es":"No estoy del todo convencido de que esa sea la mejor solución.","en":"I am not entirely convinced that this is the best solution."},{"es":"Aunque el plan parece lógico, no estoy del todo convencido de que podamos terminar a tiempo.","en":"Although the plan seems logical, I am not entirely convinced that we can finish on time."},{"es":"Escuché tu propuesta sobre el nuevo presupuesto, pero no estoy del todo convencido de que sea rentable.","en":"I heard your proposal about the new budget, but I am not entirely convinced that it is profitable."}]},{"spanish_text":"Discrepo","english_text":"I beg to differ","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A polite way of saying that you disagree.","main_translations_es":["No estoy de acuerdo","Me opongo","Diferir"],"collocations":["I beg to differ, but...","I beg to differ with you","I beg to differ on that point"],"synonyms_en":["I disagree","I dissent","I take exception"],"example_sentence":"I beg to differ with his opinion on the matter.","example_es":"Discrepo con su opinión sobre el tema.","example_en":"I beg to differ with his opinion on the matter.","mnemonic_en":"I beg to differ, thinking \"this crepe, oh!\" isn’t the same.","cloze_distractors_en":["I shall celebrate","I merely whisper","I deeply slumber"],"examples":[{"es":"Discrepo con su opinión sobre el tema.","en":"I beg to differ with his opinion on the matter."},{"es":"Aunque todos apoyan el plan, yo discrepo totalmente.","en":"Although everyone supports the plan, I beg to differ entirely."},{"es":"Si me permite, discrepo respecto a las cifras que acaba de presentar.","en":"If you will allow me, I beg to differ regarding the figures you just presented."}]},{"spanish_text":"Eso no refleja toda la realidad","english_text":"That does not tell the whole story","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that something fails to convey the complete truth or full situation.","main_translations_es":["Eso no muestra toda la realidad","Eso no cuenta toda la historia","Eso no refleja todo el panorama"],"collocations":["The numbers do not tell the whole story","One example does not tell the whole story","Statistics often do not tell the whole story","A single incident does not tell the whole story"],"synonyms_en":["doesn''t show the full picture","doesn''t capture everything","doesn''t convey the entire truth"],"example_sentence":"Although the sales figures are positive, that does not tell the whole story about the company''s crisis.","example_es":"Aunque las cifras de ventas son positivas, eso no refleja toda la realidad sobre la crisis de la empresa.","example_en":"Although the sales figures are positive, that does not tell the whole story about the company''s crisis.","mnemonic_en":"That does not tell the whole story, like a real idea (realidad) with missing pages.","cloze_distractors_en":["That is a very popular opinion","This makes the situation worse","You should be more optimistic","It is a completely different topic"],"examples":[{"es":"Aunque las cifras de ventas son positivas, eso no refleja toda la realidad sobre la crisis de la empresa.","en":"Although the sales figures are positive, that does not tell the whole story about the company''s crisis."},{"es":"Solo estás mirando los beneficios económicos, pero eso no refleja toda la realidad de los daños ambientales.","en":"You are only looking at the economic benefits, but that does not tell the whole story of the environmental damage."},{"es":"Su informe se centra únicamente en los éxitos del proyecto; eso no refleja toda la realidad de los problemas que enfrentamos.","en":"His report focuses only on the project''s successes; that does not tell the whole story of the problems we faced."}]},{"spanish_text":"Desde mi punto de vista","english_text":"From my perspective","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to indicate that something is being considered according to one''s own point of view.","main_translations_es":["A mi parecer","En mi opinión","Según mi punto de vista"],"collocations":["From my perspective, ...","From my perspective, the situation is clear","From my perspective, we should proceed","From my perspective, the results are promising"],"synonyms_en":["In my view","In my opinion","As I see it"],"example_sentence":"From my perspective, education should be free for everyone.","example_es":"Desde mi punto de vista, la educación debería ser gratuita para todos.","example_en":"From my perspective, education should be free for everyone.","mnemonic_en":"Picture a camera called From my pointing at a vista, reminding you of desde mi punto de vista.","cloze_distractors_en":["Against my logic","Beyond my knowledge","Without my permission","Under my instructions"],"examples":[{"es":"Desde mi punto de vista, la educación debería ser gratuita para todos.","en":"From my perspective, education should be free for everyone."},{"es":"Desde mi punto de vista, el proyecto actual no es viable debido a la falta de presupuesto.","en":"From my perspective, the current project is not viable due to the lack of budget."},{"es":"Desde mi punto de vista, trabajar desde casa mejora significativamente la productividad de los empleados.","en":"From my perspective, working from home significantly improves employee productivity."}]},{"spanish_text":"Tal como yo lo veo","english_text":"As I see it","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to introduce one''s personal opinion or perspective.","main_translations_es":["Tal como lo percibo","Según mi punto de vista","A mi modo de ver"],"collocations":["as I see it, ...","as I see it, the problem is","as I see it, we should","as I see it, that''s the case"],"synonyms_en":["in my opinion","from my perspective","the way I see it"],"example_sentence":"As I see it, the situation is unsustainable.","example_es":"Tal como yo lo veo, la situación es insostenible.","example_en":"As I see it, the situation is unsustainable.","mnemonic_en":"Picture a camera: ''As I see it''—just like saying ''tal como yo lo veo''.","cloze_distractors_en":["Regardless of","Instead of","Despite that"],"examples":[{"es":"Tal como yo lo veo, la situación es insostenible.","en":"As I see it, the situation is unsustainable."},{"es":"Tal como yo lo veo, deberíamos invertir más dinero en educación.","en":"As I see it, we should invest more money in education."},{"es":"Tal como yo lo veo, este proyecto no estará terminado a tiempo.","en":"As I see it, this project will not be finished on time."}]},{"spanish_text":"Por lo que entiendo","english_text":"As far as I understand","section_name":"Discussion and Debate","part_of_speech":"idiomatic expression","definition_en":"It indicates that the speaker is stating something based on their current understanding.","main_translations_es":["Según entiendo","Hasta donde entiendo","En lo que entiendo"],"collocations":["as far as I understand it","as far as I understand, ...","as far as I understand the situation","as far as I understand from the report"],"synonyms_en":["to my knowledge","as I see it","as I understand it"],"example_sentence":"As far as I understand, the project will be completed on time.","example_es":"Por lo que entiendo, el proyecto se completará a tiempo.","example_en":"As far as I understand, the project will be completed on time.","mnemonic_en":"From far away, I understand the ''por'' door opens.","cloze_distractors_en":["Without any hesitation","Regardless of reality","Beyond all imagination"],"examples":[{"es":"Por lo que entiendo, el proyecto se completará a tiempo.","en":"As far as I understand, the project will be completed on time."},{"es":"Por lo que entiendo, la nueva política de la empresa entrará en vigor el próximo lunes.","en":"As far as I understand, the new company policy will go into effect next Monday."},{"es":"Por lo que entiendo, todavía no han tomado una decisión sobre quién liderará el equipo de ventas.","en":"As far as I understand, they have not yet made a decision about who will lead the sales team."}]},{"spanish_text":"Hasta donde sé","english_text":"As far as I know","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that the speaker is stating something based on their current knowledge, but may not be certain.","main_translations_es":["Hasta donde tengo entendido","Según lo que sé","Según mi conocimiento"],"collocations":["as far as I know, it''s true","as far as I know, there are no issues","as far as I know, that''s the case"],"synonyms_en":["to my knowledge","as far as I''m aware","to the best of my knowledge"],"example_sentence":"As far as I know, the meeting will be tomorrow at ten.","example_es":"Hasta donde sé, la reunión será mañana a las diez.","example_en":"As far as I know, the meeting will be tomorrow at ten.","mnemonic_en":"I see a far horizon and whisper hasta while I know the answer.","cloze_distractors_en":["In light of which","On account of that","In terms of how"],"examples":[{"es":"Hasta donde sé, la reunión será mañana a las diez.","en":"As far as I know, the meeting will be tomorrow at ten."},{"es":"Hasta donde sé, el proyecto todavía no ha sido aprobado por el director.","en":"As far as I know, the project has not been approved by the director yet."},{"es":"Hasta donde sé, ellos se mudarán a otra ciudad el próximo mes.","en":"As far as I know, they are moving to another city next month."}]},{"spanish_text":"Dicho esto","english_text":"That said","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to introduce a statement that qualifies or contrasts with what was previously said.","main_translations_es":["Con eso dicho","Eso dicho","Dicho lo anterior"],"collocations":["That said, we should proceed","That said, it''s not guaranteed","That said, I think","That said, the results are inconclusive"],"synonyms_en":["Nevertheless","However","Even so"],"example_sentence":"That said, I think we should proceed with the original plan.","example_es":"Dicho esto, creo que deberíamos continuar con el plan original.","example_en":"That said, I think we should proceed with the original plan.","mnemonic_en":"Picture a hat shouting ''That said'' as you read the Spanish phrase dicho esto.","cloze_distractors_en":["In addition","For instance","As expected","Without fail"],"examples":[{"es":"Dicho esto, creo que deberíamos continuar con el plan original.","en":"That said, I think we should proceed with the original plan."},{"es":"El informe presenta datos muy positivos; dicho esto, debemos ser cautelosos con las proyecciones futuras.","en":"The report presents very positive data; that said, we must be cautious with future projections."},{"es":"Entiendo que el presupuesto es limitado, pero dicho esto, no podemos comprometer la calidad del proyecto.","en":"I understand that the budget is limited, but that said, we cannot compromise the quality of the project."}]},{"spanish_text":"Al mismo tiempo","english_text":"At the same time","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Indicates that two or more events occur simultaneously.","main_translations_es":["Simultáneamente","A la vez","En simultáneo"],"collocations":["at the same time as","at the same time, however","at the same time, too"],"synonyms_en":["simultaneously","concurrently","in tandem"],"example_sentence":"At the same time, we must consider the benefits and the risks of this new project.","example_es":"Al mismo tiempo, debemos considerar los beneficios y los riesgos de este nuevo proyecto.","example_en":"At the same time, we must consider the benefits and the risks of this new project.","mnemonic_en":"Sam and Tim are at the same time.","cloze_distractors_en":["In other words","On the contrary","For the record","By all means"],"examples":[{"es":"Al mismo tiempo, debemos considerar los beneficios y los riesgos de este nuevo proyecto.","en":"At the same time, we must consider the benefits and the risks of this new project."},{"es":"Ella estaba estudiando para su examen y, al mismo tiempo, escuchaba música clásica.","en":"She was studying for her exam and, at the same time, she was listening to classical music."},{"es":"El equipo quiere aumentar la producción y, al mismo tiempo, reducir los costos operativos.","en":"The team wants to increase production and, at the same time, reduce operating costs."}]},{"spanish_text":"Sin restarle importancia","english_text":"Without downplaying","section_name":"Discussion and Debate","part_of_speech":"phrase","definition_en":"In a way that does not diminish or lessen the importance of something.","main_translations_es":["Sin minimizar","Sin restar importancia","Sin restarle relevancia"],"collocations":["without downplaying the risks","without downplaying the importance","without downplaying the facts","without downplaying the situation"],"synonyms_en":["without minimizing","without diminishing","without belittling"],"example_sentence":"Without downplaying the minor issues, we must focus on the main solution.","example_es":"Sin restarle importancia a los problemas menores, debemos enfocarnos en la solución principal.","example_en":"Without downplaying the minor issues, we must focus on the main solution.","mnemonic_en":"Picture a sin that refuses to downplay its importance.","cloze_distractors_en":["By exaggerating","Through ignoring","After overstating"],"examples":[{"es":"Sin restarle importancia a los problemas menores, debemos enfocarnos en la solución principal.","en":"Without downplaying the minor issues, we must focus on the main solution."},{"es":"Sin restarle importancia a los logros del año pasado, debemos centrarnos en los nuevos objetivos de ventas.","en":"Without downplaying the achievements of last year, we must focus on the new sales targets."},{"es":"Sin restarle importancia a los riesgos financieros, el proyecto tiene un potencial de crecimiento enorme.","en":"Without downplaying the financial risks, the project has enormous growth potential."}]},{"spanish_text":"En otras palabras","english_text":"In other words","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to restate something in a different way.","main_translations_es":["En otras palabras","Dicho de otra forma"],"collocations":["in other words, ...","to put it another way","that is"],"synonyms_en":["that is","to put it differently","to rephrase"],"example_sentence":"The project is not generating any profit; in other words, we are losing money every month.","example_es":"El proyecto no está generando beneficios; en otras palabras, estamos perdiendo dinero cada mes.","example_en":"The project is not generating any profit; in other words, we are losing money every month.","mnemonic_en":"Picture a sign reading EN OTRAS PALABRAS and you whisper in other words to translate it.","cloze_distractors_en":["For instance","In addition","Above all"],"examples":[{"es":"El proyecto no está generando beneficios; en otras palabras, estamos perdiendo dinero cada mes.","en":"The project is not generating any profit; in other words, we are losing money every month."},{"es":"No quiere trabajar horas extra; en otras palabras, prefiere irse a casa temprano.","en":"He does not want to work overtime; in other words, he prefers to go home early."},{"es":"El informe es demasiado largo y confuso; en otras palabras, necesitamos resumirlo para la presentación.","en":"The report is too long and confusing; in other words, we need to summarize it for the presentation."}]},{"spanish_text":"Dicho de otro modo","english_text":"Put differently","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to introduce a restatement of something in other words.","main_translations_es":["En otras palabras","De otra forma","Dicho de otra manera"],"collocations":["Put differently, ...","To put it differently","Put differently, however"],"synonyms_en":["in other words","to rephrase","that is"],"example_sentence":"Put differently, the situation is unsustainable.","example_es":"Dicho de otro modo, la situación es insostenible.","example_en":"Put differently, the situation is unsustainable.","mnemonic_en":"Put a pot (put) on a different shelf labeled ''diferente''.","cloze_distractors_en":["Unwillingly","Coincidentally","Geographically","Mechanically"],"examples":[{"es":"Dicho de otro modo, la situación es insostenible.","en":"Put differently, the situation is unsustainable."},{"es":"Dicho de otro modo, no podemos permitirnos este gasto extra este mes.","en":"Put differently, we cannot afford this extra expense this month."},{"es":"Dicho de otro modo, el proyecto fracasará si no cambiamos nuestra estrategia ahora.","en":"Put differently, the project will fail if we do not change our strategy now."}]},{"spanish_text":"Para ser más preciso","english_text":"To be more precise","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to introduce a more exact statement or clarification.","main_translations_es":["Para ser más exacto","Con mayor precisión","En términos más precisos"],"collocations":["To be more precise, ...","To be more precise, the answer is ...","To be more precise, we should note that ..."],"synonyms_en":["more accurately","to be exact","in other words"],"example_sentence":"To be more precise, the initial budget needs to increase by ten percent.","example_es":"Para ser más preciso, el presupuesto inicial debe aumentar un diez por ciento.","example_en":"To be more precise, the initial budget needs to increase by ten percent.","mnemonic_en":"Picture a precise (preciso) ruler announcing, to be more precise, I measure twice.","cloze_distractors_en":["To be quite reckless","To be rather vacant","To be purely fictional","To be highly reluctant"],"examples":[{"es":"Para ser más preciso, el presupuesto inicial debe aumentar un diez por ciento.","en":"To be more precise, the initial budget needs to increase by ten percent."},{"es":"Para ser más preciso, el informe indica que las ventas cayeron durante el verano.","en":"To be more precise, the report indicates that sales dropped during the summer."},{"es":"Para ser más preciso, el evento comenzará a las ocho de la mañana en punto.","en":"To be more precise, the event will start at eight o''clock sharp in the morning."}]},{"spanish_text":"Permíteme reformularlo","english_text":"Let me rephrase that","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A polite way of saying that you will restate something using different words.","main_translations_es":["Déjame reformularlo","Permíteme decirlo de otra manera","Voy a expresarlo de nuevo"],"collocations":["Let me rephrase that for clarity","Let me rephrase that in simpler terms","Let me rephrase that to be sure","Let me rephrase that another way"],"synonyms_en":["I''ll put it another way","Allow me to restate","I''ll say it differently"],"example_sentence":"Let me rephrase that, as I think my previous explanation was a bit confusing.","example_es":"Permíteme reformularlo, ya que creo que mi explicación anterior fue un poco confusa.","example_en":"Let me rephrase that, as I think my previous explanation was a bit confusing.","mnemonic_en":"Imagine me saying let me rephrase that as I reform a broken sign, linking rephrase to reformar","cloze_distractors_en":["I reject your claim","Please ignore me now","Stop talking at once","You are totally wrong"],"examples":[{"es":"Permíteme reformularlo, ya que creo que mi explicación anterior fue un poco confusa.","en":"Let me rephrase that, as I think my previous explanation was a bit confusing."},{"es":"Si no entiendes mi punto de vista, permíteme reformularlo con otras palabras.","en":"If you do not understand my point of view, let me rephrase that using different words."},{"es":"No quiero que haya malentendidos, así que permíteme reformularlo para ser más preciso.","en":"I do not want there to be any misunderstandings, so let me rephrase that to be more precise."}]},{"spanish_text":"Lo que intento decir es","english_text":"What I am trying to say is","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to introduce or clarify what the speaker intends to convey.","main_translations_es":["Lo que quiero decir es","Lo que pretendo decir es","Lo que intento expresar es"],"collocations":["What I am trying to say is that...","What I am trying to say is, in short,...","What I am trying to say is, basically,..."],"synonyms_en":["In other words","To put it another way","My point is"],"example_sentence":"What I am trying to say is that the current budget does not cover all the project expenses.","example_es":"Lo que intento decir es que el presupuesto actual no cubre todos los gastos del proyecto.","example_en":"What I am trying to say is that the current budget does not cover all the project expenses.","mnemonic_en":"Picture an intent speaker shouting what I am trying to say is","cloze_distractors_en":["Before we start eating","Under the blue carpet","Whenever the clock rings","Behind the heavy curtains"],"examples":[{"es":"Lo que intento decir es que el presupuesto actual no cubre todos los gastos del proyecto.","en":"What I am trying to say is that the current budget does not cover all the project expenses."},{"es":"Lo que intento decir es que deberíamos posponer la reunión hasta que todos hayan leído el informe.","en":"What I am trying to say is that we should postpone the meeting until everyone has read the report."},{"es":"Lo que intento decir es que tu propuesta es interesante, pero no es viable en este momento.","en":"What I am trying to say is that your proposal is interesting, but it is not viable at this moment."}]},{"spanish_text":"Si lo analizamos","english_text":"If we break it down","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to introduce a detailed analysis or explanation of something.","main_translations_es":["Si lo desglosamos","Si lo examinamos","Si lo estudiamos"],"collocations":["If we break it down further","If we break it down step by step","If we break it down, we can see","If we break it down, the problem becomes clear"],"synonyms_en":["If we analyze it","If we examine it","If we look at it closely"],"example_sentence":"If we break it down carefully, we will find the cause of the problem.","example_es":"Si lo analizamos detenidamente, encontraremos la causa del problema.","example_en":"If we break it down carefully, we will find the cause of the problem.","mnemonic_en":"Picture a scientist saying If we break it down while whispering si lo analizamos as he dissects a puzzle.","cloze_distractors_en":["Unless we speed up","Although we run out","Since we shut down"],"examples":[{"es":"Si lo analizamos detenidamente, encontraremos la causa del problema.","en":"If we break it down carefully, we will find the cause of the problem."},{"es":"Si lo analizamos paso a paso, entenderemos mejor cómo funciona este nuevo software.","en":"If we break it down step by step, we will better understand how this new software works."},{"es":"Si lo analizamos en términos de presupuesto, veremos que el proyecto no es viable.","en":"If we break it down in terms of budget, we will see that the project is not viable."}]},{"spanish_text":"Ese es un buen punto","english_text":"That is a fair point","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement acknowledging that someone has made a valid or reasonable argument.","main_translations_es":["Eso es un punto válido","Ese es un buen argumento","Tienes un buen punto"],"collocations":["That''s a fair point, but...","Well, that''s a fair point.","I have to admit that''s a fair point.","You make a fair point."],"synonyms_en":["That''s a valid point","Good point","You have a point"],"example_sentence":"That is a fair point, we should consider it before deciding.","example_es":"Ese es un buen punto, deberíamos considerarlo antes de decidir.","example_en":"That is a fair point, we should consider it before deciding.","mnemonic_en":"At the fair the judge stamps a badge that reads Buen Point","cloze_distractors_en":["It is a heavy table","They are blue birds","She is quite hungry","We are very tired"],"examples":[{"es":"Ese es un buen punto, deberíamos considerarlo antes de decidir.","en":"That is a fair point, we should consider it before deciding."},{"es":"Aunque no estoy de acuerdo con tu conclusión, admito que ese es un buen punto.","en":"Although I disagree with your conclusion, I admit that is a fair point."},{"es":"Si propones reducir el presupuesto, ese es un buen punto para empezar la negociación.","en":"If you propose cutting the budget, that is a fair point to start the negotiation."}]},{"spanish_text":"Eso merece atención","english_text":"That is worth considering","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means something deserves attention or consideration.","main_translations_es":["Eso merece atención","Eso vale la pena","Eso merece ser considerado"],"collocations":["worth considering","worth a second look","worth taking into account"],"synonyms_en":["It''s worth thinking about","It deserves attention","It''s notable"],"example_sentence":"The budget for the new project is quite high, but that is worth considering before we turn it down.","example_es":"El presupuesto para el nuevo proyecto es muy alto, pero eso merece atención antes de rechazarlo.","example_en":"The budget for the new project is quite high, but that is worth considering before we turn it down.","mnemonic_en":"A gold coin worth checking, because it merece attention.","cloze_distractors_en":["That is rarely ignored","That is totally forbidden","That is barely mentioned"],"examples":[{"es":"El presupuesto para el nuevo proyecto es muy alto, pero eso merece atención antes de rechazarlo.","en":"The budget for the new project is quite high, but that is worth considering before we turn it down."},{"es":"Tu propuesta de cambiar el horario de trabajo es interesante y eso merece atención en la próxima reunión.","en":"Your proposal to change the work schedule is interesting and that is worth considering at the next meeting."},{"es":"Aunque la idea parece arriesgada, eso merece atención por los beneficios a largo plazo que ofrece.","en":"Although the idea seems risky, that is worth considering because of the long-term benefits it offers."}]},{"spanish_text":"No había pensado en eso","english_text":"I had not thought of that","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that one had not considered something before.","main_translations_es":["No lo había considerado","No lo había pensado","No se me había ocurrido"],"collocations":["I had not thought of that before","I had not thought of that possibility","I had not thought of that angle"],"synonyms_en":["I hadn''t considered that","That never occurred to me","I hadn''t realized that"],"example_sentence":"If we move the meeting to the afternoon so everyone can attend, I had not thought of that, but it is an excellent suggestion.","example_es":"Si trasladamos la reunión a la tarde para que todos puedan asistir, no había pensado en eso, pero es una excelente sugerencia.","example_en":"If we move the meeting to the afternoon so everyone can attend, I had not thought of that, but it is an excellent suggestion.","mnemonic_en":"Picture a bee saying no while I forget the idea","cloze_distractors_en":["I will be quiet now","It was very loud then","You are always correct","We should leave today"],"examples":[{"es":"Si trasladamos la reunión a la tarde para que todos puedan asistir, no había pensado en eso, pero es una excelente sugerencia.","en":"If we move the meeting to the afternoon so everyone can attend, I had not thought of that, but it is an excellent suggestion."},{"es":"Es una perspectiva interesante; sinceramente, no había pensado en eso hasta ahora.","en":"That is an interesting perspective; honestly, I had not thought of that until now."},{"es":"Considerar el uso de energía solar para reducir los costos operativos es una idea brillante; la verdad es que no había pensado en eso.","en":"Considering solar power to cut our operating costs is a brilliant idea; honestly, I had not thought of that."}]},{"spanish_text":"Sin embargo","english_text":"Having said that","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to introduce a statement that contrasts with or qualifies what was previously said.","main_translations_es":["No obstante","Aun así","Con todo"],"collocations":["Having said that, I think we should proceed.","Having said that, we need to consider the costs.","Having said that, it''s not a guarantee.","Having said that, let''s move on."],"synonyms_en":["that said","still","nevertheless"],"example_sentence":"The new software is incredibly fast; having said that, the user interface is very difficult to navigate.","example_es":"El nuevo software es increíblemente rápido, sin embargo, la interfaz de usuario es muy difícil de navegar.","example_en":"The new software is incredibly fast; having said that, the user interface is very difficult to navigate.","mnemonic_en":"Having said that, picture a sin without an embargo, a forbidden gate swinging open.","cloze_distractors_en":["In other words","For that matter","As a result","In the meantime"],"examples":[{"es":"El nuevo software es increíblemente rápido, sin embargo, la interfaz de usuario es muy difícil de navegar.","en":"The new software is incredibly fast; having said that, the user interface is very difficult to navigate."},{"es":"El equipo técnico es muy eficiente; sin embargo, el presupuesto es insuficiente para terminar la obra.","en":"The technical team is very efficient; having said that, the budget is insufficient to finish the work."},{"es":"Nuestras ventas han subido este trimestre; sin embargo, debemos reducir los gastos operativos para mantener la rentabilidad.","en":"Our sales have increased this quarter; having said that, we must reduce operating expenses to maintain profitability."}]},{"spanish_text":"Aun así","english_text":"Even so","section_name":"Discussion and Debate","part_of_speech":"conjunctive adverb","definition_en":"Used to introduce a statement that contrasts with or qualifies what has just been said.","main_translations_es":["Sin embargo","No obstante","Aun así"],"collocations":["even so","even so, however","even so, nevertheless"],"synonyms_en":["Nevertheless","Nonetheless","Still"],"example_sentence":"Even so, he decided to go to the concert despite the rain.","example_es":"Aun así, decidió ir al concierto a pesar de la lluvia.","example_en":"Even so, he decided to go to the concert despite the rain.","mnemonic_en":"Even so, picture a lawn (awn) still standing after rain, just like aun.","cloze_distractors_en":["Likewise","Therefore","Moreover","Similarly"],"examples":[{"es":"Aun así, decidió ir al concierto a pesar de la lluvia.","en":"Even so, he decided to go to the concert despite the rain."},{"es":"El proyecto tiene muchos errores, pero aun así, el jefe quiere presentarlo mañana.","en":"The project has many errors, but even so, the boss wants to present it tomorrow."},{"es":"Es una película muy larga y lenta; aun así, me mantuvo atento hasta el final.","en":"It is a very long and slow movie; even so, it kept me attentive until the end."}]},{"spanish_text":"Pese a ello","english_text":"Despite that","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to indicate that something is true in spite of a previously mentioned fact.","main_translations_es":["Aun así","Sin embargo","No obstante"],"collocations":["Despite that, ...","Despite that, he continued","Despite that, the results were positive"],"synonyms_en":["Nevertheless","Even so","Nonetheless"],"example_sentence":"Despite that, he decided to continue with the project.","example_es":"Pese a ello, decidió continuar con el proyecto.","example_en":"Despite that, he decided to continue with the project.","mnemonic_en":"Picture peas rolling past the word that, still moving despite that","cloze_distractors_en":["Therefore so","Because why","Unless then","Besides which"],"examples":[{"es":"Pese a ello, decidió continuar con el proyecto.","en":"Despite that, he decided to continue with the project."},{"es":"El equipo perdió el primer partido; pese a ello, siguen siendo los favoritos para ganar el campeonato.","en":"The team lost the first game; despite that, they remain the favorites to win the championship."},{"es":"La propuesta fue rechazada por el comité; pese a ello, ella planea presentarla de nuevo el próximo mes.","en":"The proposal was rejected by the committee; despite that, she plans to present it again next month."}]},{"spanish_text":"No necesariamente","english_text":"Not necessarily","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to indicate that something is not always the case or not required.","main_translations_es":["No tiene que ser","No es obligatorio","No necesariamente"],"collocations":["not necessarily true","not necessarily the case","not necessarily required","not necessarily a problem"],"synonyms_en":["maybe not","not always","perhaps not"],"example_sentence":"You don''t necessarily have to work on weekends.","example_es":"No necesariamente tienes que trabajar los fines de semana.","example_en":"You don''t necessarily have to work on weekends.","mnemonic_en":"Picture a loose knot that isn’t necessarily tied, as if the Spanish ''no'' refuses to be fixed.","cloze_distractors_en":[],"examples":[{"es":"No necesariamente tienes que trabajar los fines de semana.","en":"You don''t necessarily have to work on weekends."},{"es":"Que sea un experto en tecnología no necesariamente lo convierte en un buen profesor.","en":"Being an expert in technology does not necessarily make him a good teacher."},{"es":"Aunque el proyecto sea popular, no necesariamente significa que sea rentable.","en":"Even if the project is popular, it does not necessarily mean it is profitable."}]},{"spanish_text":"No se sigue de eso","english_text":"That does not necessarily follow","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that a conclusion cannot be assumed from the given premise.","main_translations_es":["No se deduce de eso","No se infiere de eso","No se concluye a partir de eso"],"collocations":["does not necessarily follow","necessarily follow from","does not follow logically","does not necessarily follow that"],"synonyms_en":["It may not follow","That isn’t implied","It doesn’t necessarily follow"],"example_sentence":"Just because there is high demand for electric cars, it does not mean gasoline sales will vanish; that does not necessarily follow.","example_es":"El hecho de que haya mucha demanda de coches eléctricos no implica que las ventas de gasolina vayan a desaparecer; no se sigue de eso.","example_en":"Just because there is high demand for electric cars, it does not mean gasoline sales will vanish; that does not necessarily follow.","mnemonic_en":"Picture a sign reading “No se” that refuses to follow the line.","cloze_distractors_en":["This clearly confirms everything","We must ignore those facts","It is strictly forbidden here","That remains entirely irrelevant"],"examples":[{"es":"El hecho de que haya mucha demanda de coches eléctricos no implica que las ventas de gasolina vayan a desaparecer; no se sigue de eso.","en":"Just because there is high demand for electric cars, it does not mean gasoline sales will vanish; that does not necessarily follow."},{"es":"El hecho de que el equipo haya ganado el último partido no significa que vayan a ganar el campeonato; no se sigue de eso.","en":"Just because the team won the last game, it does not mean they will win the championship; that does not necessarily follow."},{"es":"El hecho de que el candidato tenga mucha experiencia no garantiza que sea el mejor para el puesto; eso no se sigue de eso.","en":"Just because the candidate has a lot of experience, it does not guarantee they are the best fit for the job; that does not necessarily follow."}]},{"spanish_text":"Eso depende","english_text":"That depends","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It indicates that the outcome or answer varies depending on certain conditions.","main_translations_es":["Depende","Depende de eso","Eso depende de"],"collocations":["That depends on…","It depends on the situation","That depends on the context","It depends"],"synonyms_en":["It varies","Depends on","It''s conditional"],"example_sentence":"Do you think we will go to the beach this weekend? That depends on the weather forecast.","example_es":"¿Crees que iremos a la playa este fin de semana? Eso depende del pronóstico del tiempo.","example_en":"Do you think we will go to the beach this weekend? That depends on the weather forecast.","mnemonic_en":"Imagine a seesaw labeled eso that tilts each time you say that depends","cloze_distractors_en":["That disagrees","That concludes","That observes","That establishes"],"examples":[{"es":"¿Crees que iremos a la playa este fin de semana? Eso depende del pronóstico del tiempo.","en":"Do you think we will go to the beach this weekend? That depends on the weather forecast."},{"es":"¿Vas a aceptar la oferta de trabajo en otra ciudad? Eso depende de si me ofrecen un mejor salario.","en":"Are you going to accept the job offer in another city? That depends on whether they offer me a better salary."},{"es":"¿Podremos terminar el proyecto antes de la fecha límite? Eso depende de cuánta ayuda recibamos del equipo.","en":"Will we be able to finish the project before the deadline? That depends on how much help we get from the team."}]},{"spanish_text":"Depende del contexto","english_text":"It depends on the context","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that the meaning or outcome varies according to the situation.","main_translations_es":["Depende de la situación","Según el contexto","Varía según el contexto"],"collocations":["It depends on the context","That depends on the context","It all depends on the context"],"synonyms_en":["depends on the situation","varies with context","contingent on the context"],"example_sentence":"It depends on the context, but it is usually used in formal situations.","example_es":"Depende del contexto, pero generalmente se usa en situaciones formales.","example_en":"It depends on the context, but it is usually used in formal situations.","mnemonic_en":"Picture a dependent leaning on a book of text, because it depends on the context","cloze_distractors_en":["It remains fully settled","It ignores every rule","It sounds quite angry","It avoids all logic"],"examples":[{"es":"Depende del contexto, pero generalmente se usa en situaciones formales.","en":"It depends on the context, but it is usually used in formal situations."},{"es":"Si me preguntas si es correcto decir esa palabra, te diré que depende del contexto.","en":"If you ask me if it is correct to say that word, I will tell you that it depends on the context."},{"es":"No puedo darte una respuesta simple sobre si esa acción es aceptable, ya que todo depende del contexto.","en":"I cannot give you a simple answer about whether that action is acceptable, since it depends on the context."}]},{"spanish_text":"No es tan simple","english_text":"It is not that straightforward","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that something is not as simple or clear as it might seem.","main_translations_es":["No es tan sencillo","No es tan fácil","No es tan claro"],"collocations":["It is not that straightforward to explain","It is not that straightforward to solve","It is not that straightforward in practice","It is not that straightforward for beginners"],"synonyms_en":["It''s not that simple","It''s not that easy","It''s more complicated"],"example_sentence":"It is not that straightforward to implement this new company policy.","example_es":"No es tan simple como parece implementar esta nueva política en la empresa.","example_en":"It is not that straightforward to implement this new company policy.","mnemonic_en":"Picture a ''no'' sign crossing a simple line—so it''s not that straightforward.","cloze_distractors_en":["It is mostly purple","It is rarely hungry","It is rather circular","It is quite melodic"],"examples":[{"es":"No es tan simple como parece implementar esta nueva política en la empresa.","en":"It is not that straightforward to implement this new company policy."},{"es":"No es tan simple llegar a un acuerdo cuando ambas partes tienen intereses opuestos.","en":"It is not that straightforward to reach an agreement when both sides have conflicting interests."},{"es":"No es tan simple explicar las causas de este fenómeno económico complejo.","en":"It is not that straightforward to explain the causes of this complex economic phenomenon."}]},{"spanish_text":"Es una simplificación excesiva","english_text":"That is an oversimplification","section_name":"Discussion and Debate","part_of_speech":"noun","definition_en":"A statement that reduces a complex issue to overly simple terms.","main_translations_es":["Es una simplificación exagerada","Es una simplificación demasiado simple","Es una simplificación desmedida"],"collocations":["That''s an oversimplification of the issue","It''s an oversimplification of the problem","Such a view is an oversimplification","Calling it an oversimplification"],"synonyms_en":["overly simplistic","too simplistic","simplistic"],"example_sentence":"Claiming that professional success depends solely on luck is an oversimplification.","example_es":"Decir que el éxito profesional depende solo de la suerte es una simplificación excesiva.","example_en":"Claiming that professional success depends solely on luck is an oversimplification.","mnemonic_en":"Picture an over‑simplified map called oversimplification, echoing the Spanish simplificación.","cloze_distractors_en":[],"examples":[{"es":"Decir que el éxito profesional depende solo de la suerte es una simplificación excesiva.","en":"Claiming that professional success depends solely on luck is an oversimplification."},{"es":"Reducir el complejo debate sobre el cambio climático a una cuestión de impuestos es una simplificación excesiva.","en":"Reducing the complex climate change debate to a matter of taxes is an oversimplification."},{"es":"Afirmar que los videojuegos solo fomentan la violencia en los jóvenes es una simplificación excesiva.","en":"Asserting that video games only promote violence in youth is an oversimplification."}]},{"spanish_text":"Podría interpretarse de otra manera","english_text":"It could be interpreted differently","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that something may be understood in another way.","main_translations_es":["Podría entenderse de otra forma","Se podría interpretar de otra manera","Podría leerse de modo distinto"],"collocations":["This statement could be interpreted differently","The results could be interpreted differently","Such a comment could be interpreted differently","These findings could be interpreted differently"],"synonyms_en":["It may be understood differently","It could be read another way","It might be seen differently"],"example_sentence":"It could be interpreted differently if we analyze the author''s hidden intentions.","example_es":"Podría interpretarse de otra manera si analizamos las intenciones ocultas del autor.","example_en":"It could be interpreted differently if we analyze the author''s hidden intentions.","mnemonic_en":"A pod could be read as a different story.","cloze_distractors_en":["It is strictly forbidden entirely","They were definitely laughing loudly","We have already decided yesterday","You should probably leave immediately"],"examples":[{"es":"Podría interpretarse de otra manera si analizamos las intenciones ocultas del autor.","en":"It could be interpreted differently if we analyze the author''s hidden intentions."},{"es":"Aunque el contrato parece claro, podría interpretarse de otra manera según la legislación vigente.","en":"Although the contract seems clear, it could be interpreted differently according to current legislation."},{"es":"Su silencio durante la reunión fue ambiguo; podría interpretarse de otra manera por quienes no lo conocen bien.","en":"His silence during the meeting was ambiguous; it could be interpreted differently by those who do not know him well."}]},{"spanish_text":"Hay margen para debatir","english_text":"There is room for debate","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that a topic can be discussed and different opinions are possible.","main_translations_es":["Hay espacio para debatir","Se puede debatir","Existe margen para debatir"],"collocations":["There is room for debate on this issue","It leaves room for debate","This point is open to debate","The matter remains open to debate"],"synonyms_en":["Open to discussion","It''s debatable","Subject to debate"],"example_sentence":"In the meeting, there is room for debate about the proposed changes.","example_es":"En la reunión, hay margen para debatir los cambios propuestos.","example_en":"In the meeting, there is room for debate about the proposed changes.","mnemonic_en":"Picture a spacious room with a margin line where everyone debates loudly.","cloze_distractors_en":["There is zero silence","It is fully finished","They are never enough","We are strictly silent"],"examples":[{"es":"En la reunión, hay margen para debatir los cambios propuestos.","en":"In the meeting, there is room for debate about the proposed changes."},{"es":"Aunque el informe es claro, todavía hay margen para debatir sobre la estrategia a seguir.","en":"Although the report is clear, there is room for debate regarding the strategy to follow."},{"es":"Sobre la nueva política de la empresa, creo que aún hay margen para debatir antes de tomar una decisión final.","en":"Regarding the new company policy, I believe there is room for debate before we make a final decision."}]},{"spanish_text":"Eso sigue siendo discutible","english_text":"That remains debatable","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that the matter is still open to debate.","main_translations_es":["Eso sigue siendo debatible","Eso continúa siendo discutible","Eso aún es objeto de debate"],"collocations":["The issue remains debatable","His claim remains debatable","The outcome remains debatable"],"synonyms_en":["still questionable","still up for debate","still arguable"],"example_sentence":"Even after all this time, that remains debatable.","example_es":"Aunque ya pasó mucho tiempo, eso sigue siendo discutible.","example_en":"Even after all this time, that remains debatable.","mnemonic_en":"That remains debatable, as ''discutible'' sounds like ''this cute table'' that never settles.","cloze_distractors_en":["That tastes metallic","That fits perfectly","That smells unusual"],"examples":[{"es":"Aunque ya pasó mucho tiempo, eso sigue siendo discutible.","en":"Even after all this time, that remains debatable."},{"es":"El experto afirma que el cambio climático es un hecho, pero para algunos políticos eso sigue siendo discutible.","en":"The expert claims that climate change is a fact, but for some politicians that remains debatable."},{"es":"La empresa dice que el nuevo contrato es justo, pero para los trabajadores eso sigue siendo discutible.","en":"The company says the new contract is fair, but for the workers that remains debatable."}]},{"spanish_text":"Es una cuestión compleja","english_text":"It is a complex issue","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement that something is complicated or difficult.","main_translations_es":["Es un tema complejo","Se trata de un asunto complicado","Es una cuestión complicada"],"collocations":["a complex issue","address a complex issue","tackle a complex issue","the complex issue"],"synonyms_en":["It''s a complicated matter","It''s a difficult problem","It''s a tangled situation"],"example_sentence":"We cannot provide a simple answer because it is a complex issue.","example_es":"No podemos dar una respuesta simple porque es una cuestión compleja.","example_en":"We cannot provide a simple answer because it is a complex issue.","mnemonic_en":"See a complex maze with a sign that reads cuestión to remember it’s a complex issue","cloze_distractors_en":[],"examples":[{"es":"No podemos dar una respuesta simple porque es una cuestión compleja.","en":"We cannot provide a simple answer because it is a complex issue."},{"es":"La reforma del sistema educativo es una cuestión compleja que genera mucho debate.","en":"The reform of the educational system is a complex issue that generates a lot of debate."},{"es":"Debemos analizar los datos con cuidado, ya que la desigualdad económica es una cuestión compleja.","en":"We must analyze the data carefully, as economic inequality is a complex issue."}]},{"spanish_text":"No hay una respuesta única","english_text":"There is no one-size-fits-all answer","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that no single solution works for every situation.","main_translations_es":["No existe una única respuesta","No hay una solución única","No hay una respuesta universal"],"collocations":["There is no one-size-fits-all answer, so we must adapt","Because there is no one-size-fits-all answer, each case is different","There is no one-size-fits-all answer; tailor your strategy accordingly"],"synonyms_en":["no universal answer","no single solution","no blanket answer"],"example_sentence":"Regarding how to improve education, there is no one-size-fits-all answer for every country.","example_es":"Sobre cómo mejorar la educación, no hay una respuesta única para todos los países.","example_en":"Regarding how to improve education, there is no one-size-fits-all answer for every country.","mnemonic_en":"Picture a ''no hay'' sign over a one-size-fits-all answer, showing it''s not unique.","cloze_distractors_en":["There is a mandatory global standard","There exists a perfect universal method","There remains a single fixed requirement"],"examples":[{"es":"Sobre cómo mejorar la educación, no hay una respuesta única para todos los países.","en":"Regarding how to improve education, there is no one-size-fits-all answer for every country."},{"es":"Al elegir una dieta saludable, no hay una respuesta única que funcione para todo el mundo.","en":"When choosing a healthy diet, there is no one-size-fits-all answer that works for everyone."},{"es":"En cuanto a la gestión del estrés laboral, no hay una respuesta única que podamos aplicar a todos los empleados.","en":"As for managing workplace stress, there is no one-size-fits-all answer that we can apply to all employees."}]},{"spanish_text":"Estoy a favor","english_text":"I am in favor of","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to state that you support or agree with something.","main_translations_es":["Apoyo","Estoy a favor de","Me inclino por"],"collocations":["I am in favor of the proposal","I am in favor of this plan","I am in favor of change"],"synonyms_en":["I support","I approve of","I back"],"example_sentence":"I am in favor of implementing a flexible schedule at the office.","example_es":"Estoy a favor de implementar un horario flexible en la oficina.","example_en":"I am in favor of implementing a flexible schedule at the office.","mnemonic_en":"Picture yourself handing a favor to someone and saying, I am in favor of it.","cloze_distractors_en":["I am allergic to","I am allergic of","I am allergic at"],"examples":[{"es":"Estoy a favor de implementar un horario flexible en la oficina.","en":"I am in favor of implementing a flexible schedule at the office."},{"es":"Aunque otros se opongan, estoy a favor de aumentar el presupuesto para educación.","en":"Although others may oppose it, I am in favor of increasing the budget for education."},{"es":"Tras analizar los beneficios, estoy a favor de adoptar esta nueva tecnología.","en":"After analyzing the benefits, I am in favor of adopting this new technology."}]},{"spanish_text":"Estoy en contra","english_text":"I am opposed to","section_name":"Discussion and Debate","part_of_speech":"verb phrase","definition_en":"It means that I am against something.","main_translations_es":["Me opongo a","Estoy en desacuerdo con","No estoy a favor de"],"collocations":["I am opposed to the new policy","I am opposed to violence","I am opposed to that idea"],"synonyms_en":["I disagree with","I object to","I am against"],"example_sentence":"I am opposed to the government''s decision.","example_es":"Estoy en contra de la decisión del gobierno.","example_en":"I am opposed to the government''s decision.","mnemonic_en":"I am opposed to the big red ''contra'' sign on the door.","cloze_distractors_en":["I am fond of","I am keen on","I am prone to"],"examples":[{"es":"Estoy en contra de la decisión del gobierno.","en":"I am opposed to the government''s decision."},{"es":"Estoy en contra de construir una fábrica en este parque natural.","en":"I am opposed to building a factory in this nature reserve."},{"es":"Estoy en contra de cualquier medida que aumente los impuestos a los estudiantes.","en":"I am opposed to any measure that increases taxes on students."}]},{"spanish_text":"Valoro tu punto","english_text":"I appreciate your point","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A polite way of saying that you understand and value someone''s argument or opinion.","main_translations_es":["Aprecio tu punto","Valoro tu argumento","Reconozco tu punto"],"collocations":["I appreciate your point, but...","I appreciate your point of view","I really appreciate your point","I appreciate your point and will consider it"],"synonyms_en":["I see your point","I value your point","I understand your point"],"example_sentence":"I appreciate your point, but I think there''s another perspective.","example_es":"Valoro tu punto, pero creo que hay otra perspectiva.","example_en":"I appreciate your point, but I think there''s another perspective.","mnemonic_en":"Picture a valet (valoro) handing you a pointy pen, saying ''I appreciate your point''.","cloze_distractors_en":["I ignore your silence","I celebrate your weather","I calculate your furniture","I decorate your opinion"],"examples":[{"es":"Valoro tu punto, pero creo que hay otra perspectiva.","en":"I appreciate your point, but I think there''s another perspective."},{"es":"Valoro tu punto sobre el presupuesto, aunque sigo pensando que necesitamos invertir más en tecnología.","en":"I appreciate your point about the budget, although I still think we need to invest more in technology."},{"es":"Valoro tu punto respecto a la flexibilidad laboral, pero me preocupa el impacto en la productividad del equipo.","en":"I appreciate your point regarding flexible working, but I am concerned about the impact on team productivity."}]},{"spanish_text":"Entiendo de dónde vienes","english_text":"I see where you are coming from","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that you understand someone''s perspective or reasoning.","main_translations_es":["Comprendo de dónde vienes","Entiendo tu punto de vista","Sé de dónde vienes"],"collocations":["I see where you''re coming from","I get your point","I understand your perspective","I see your point"],"synonyms_en":["I understand your perspective","I get your point","I see your point"],"example_sentence":"I see where you are coming from, but I think the project budget is insufficient.","example_es":"Entiendo de dónde vienes, pero creo que el presupuesto del proyecto es insuficiente.","example_en":"I see where you are coming from, but I think the project budget is insufficient.","mnemonic_en":"I picture a vein (vien) pointing from your hometown, so I see where you come from","cloze_distractors_en":["I am completely ignoring you","I have no idea what happens","I was born yesterday morning"],"examples":[{"es":"Entiendo de dónde vienes, pero creo que el presupuesto del proyecto es insuficiente.","en":"I see where you are coming from, but I think the project budget is insufficient."},{"es":"Aunque no comparto tu opinión, entiendo de dónde vienes respecto a este conflicto laboral.","en":"Although I do not share your opinion, I see where you are coming from regarding this labor dispute."},{"es":"Entiendo de dónde vienes al sugerir que cambiemos la fecha de la reunión para evitar el fin de semana.","en":"I see where you are coming from by suggesting we move the meeting date to avoid the weekend."}]},{"spanish_text":"Eso tiene sentido","english_text":"That makes sense","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to say that something is logical or understandable.","main_translations_es":["Tiene sentido","Eso tiene lógica","Eso tiene razón"],"collocations":["makes sense of","makes sense to","makes sense now","it makes sense"],"synonyms_en":["makes sense","is logical","adds up"],"example_sentence":"That makes sense, so I''ll follow the plan.","example_es":"Eso tiene sentido, así que seguiré el plan.","example_en":"That makes sense, so I''ll follow the plan.","mnemonic_en":"Imagine a sensible hat that says sentido and nods, showing that makes sense.","cloze_distractors_en":["That feels heavy","That sounds purple","That tastes bitter","That looks sideways"],"examples":[{"es":"Eso tiene sentido, así que seguiré el plan.","en":"That makes sense, so I''ll follow the plan."},{"es":"Si explicas los datos de esa manera, eso tiene sentido para el equipo.","en":"If you explain the data that way, that makes sense to the team."},{"es":"Aunque no estoy de acuerdo con todo, admito que eso tiene sentido.","en":"Although I don''t agree with everything, I admit that that makes sense."}]},{"spanish_text":"No estoy seguro de que eso sea exacto","english_text":"I am not sure that is accurate","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement expressing uncertainty about the accuracy of something.","main_translations_es":["No estoy seguro de que sea exacto","No tengo la certeza de que eso sea exacto","Dudo que eso sea exacto"],"collocations":["I''m not sure that''s accurate","I''m not sure if that''s accurate","I''m not sure about the accuracy"],"synonyms_en":["I''m uncertain it''s correct","I doubt it''s precise","I''m not convinced it''s right"],"example_sentence":"I am not sure that is accurate, but I think it is close.","example_es":"No estoy seguro de que eso sea exacto, pero creo que está cerca.","example_en":"I am not sure that is accurate, but I think it is close.","mnemonic_en":"I''m not sure, like a doubtful cow rating exactness, so I question if it''s accurate","cloze_distractors_en":["I have forgotten my umbrella","the weather is quite pleasant","please pass the salt shaker","my bicycle needs new tires"],"examples":[{"es":"No estoy seguro de que eso sea exacto, pero creo que está cerca.","en":"I am not sure that is accurate, but I think it is close."},{"es":"Según los datos del informe, no estoy seguro de que eso sea exacto.","en":"According to the report data, I am not sure that is accurate."},{"es":"Aunque el testigo lo afirma, no estoy seguro de que eso sea exacto.","en":"Even though the witness claims it, I am not sure that is accurate."}]},{"spanish_text":"Eso no parece convincente","english_text":"That does not sound convincing","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that something is not perceived as believable or persuasive.","main_translations_es":["Eso no suena convincente","Eso no parece creíble","Eso no resulta convincente"],"collocations":["does not sound convincing","sounds unconvincing","fails to convince","lacks credibility"],"synonyms_en":["unconvincing","not persuasive","hard to believe"],"example_sentence":"The witness gave a strange excuse and that does not sound convincing to the jury.","example_es":"El testigo dio una excusa extraña y eso no parece convincente para el jurado.","example_en":"The witness gave a strange excuse and that does not sound convincing to the jury.","mnemonic_en":"Picture a speaker shouting That does not sound convincing as the word sonido shatters.","cloze_distractors_en":["That is quite refreshing","It remains fully verified","You are being extremely helpful","Everything seems perfectly logical"],"examples":[{"es":"El testigo dio una excusa extraña y eso no parece convincente para el jurado.","en":"The witness gave a strange excuse and that does not sound convincing to the jury."},{"es":"Aunque el vendedor insiste en que el coche es nuevo, eso no parece convincente después de ver el motor oxidado.","en":"Although the seller insists the car is new, that does not sound convincing after seeing the rusty engine."},{"es":"Tu explicación sobre por qué llegaste tarde a la reunión es muy vaga; eso no parece convincente.","en":"Your explanation for why you were late to the meeting is very vague; that does not sound convincing."}]},{"spanish_text":"Me cuesta aceptar esa idea","english_text":"I struggle to accept that idea","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"To have difficulty accepting that idea.","main_translations_es":["Me cuesta aceptar esa idea","Me resulta difícil aceptar esa idea","Tengo problemas para aceptar esa idea"],"collocations":["I struggle to accept that idea","It''s hard to accept that idea","I find it difficult to accept that idea","I can''t seem to accept that idea"],"synonyms_en":["find it hard to accept that idea","have trouble accepting that idea","can''t come to terms with that idea"],"example_sentence":"Although the plan to cut benefits sounds logical, I struggle to accept that idea because it will negatively impact the staff.","example_es":"Aunque el plan de reducir los beneficios suena lógico, me cuesta aceptar esa idea porque afectará a los empleados.","example_en":"Although the plan to cut benefits sounds logical, I struggle to accept that idea because it will negatively impact the staff.","mnemonic_en":"I picture a heavy cost weighing on me as I try to accept the idea.","cloze_distractors_en":["I celebrate that logic","I ignore every opinion","I demand total silence","I prefer simple answers"],"examples":[{"es":"Aunque el plan de reducir los beneficios suena lógico, me cuesta aceptar esa idea porque afectará a los empleados.","en":"Although the plan to cut benefits sounds logical, I struggle to accept that idea because it will negatively impact the staff."},{"es":"Aunque el equipo propone cambios drásticos, me cuesta aceptar esa idea por falta de pruebas.","en":"Although the team proposes drastic changes, I struggle to accept that idea due to a lack of evidence."},{"es":"Cuando escucho argumentos tan radicales, me cuesta aceptar esa idea sin analizar los datos primero.","en":"When I hear such radical arguments, I struggle to accept that idea without analyzing the data first."}]},{"spanish_text":"Podrías tener razón","english_text":"You may be right","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A polite way of saying that someone could be correct.","main_translations_es":["Quizás tengas razón","Puede que tengas razón","Tal vez tengas razón"],"collocations":["You may be right about that","You may be right, after all","You may be right, I guess"],"synonyms_en":["perhaps you''re correct","could be right","maybe correct"],"example_sentence":"You may be right, but I still want to try.","example_es":"Podrías tener razón, pero aún así quiero intentarlo.","example_en":"You may be right, but I still want to try.","mnemonic_en":"Picture a judge nodding, saying ''You may be right'', holding a big sign that reads RAZÓN.","cloze_distractors_en":["Gravity remains constant","Yesterday was Tuesday","Elephants fly south","Water boils cold"],"examples":[{"es":"Podrías tener razón, pero aún así quiero intentarlo.","en":"You may be right, but I still want to try."},{"es":"Aunque el presupuesto parece insuficiente, podrías tener razón sobre la viabilidad del proyecto.","en":"Although the budget seems insufficient, you may be right about the project''s viability."},{"es":"Si analizamos los datos de ventas, podrías tener razón al sugerir un cambio de estrategia.","en":"If we analyze the sales data, you may be right to suggest a change in strategy."}]},{"spanish_text":"Hay algo de verdad en eso","english_text":"There is some truth in that","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that the statement contains a certain amount of truth.","main_translations_es":["Hay algo de verdad en eso","Hay algo de verdad en lo que dices","Hay algo de verdad en esa afirmación"],"collocations":["There''s some truth in that.","There''s some truth to that.","There''s some truth in what you said.","There''s some truth behind that claim."],"synonyms_en":["That''s partly true","There''s some validity there","That''s somewhat true"],"example_sentence":"There is some truth in that, although not everything is accurate.","example_es":"Hay algo de verdad en eso, aunque no todo es exacto.","example_en":"There is some truth in that, although not everything is accurate.","mnemonic_en":"When you shout Hey and see a big truth sign, you remember There is some truth in that.","cloze_distractors_en":["Nothing is ever settled","Nobody cares about facts","Everything is completely false","Everyone disagrees with that"],"examples":[{"es":"Hay algo de verdad en eso, aunque no todo es exacto.","en":"There is some truth in that, although not everything is accurate."},{"es":"Admito que el presupuesto es alto, pero hay algo de verdad en eso cuando dicen que la calidad cuesta dinero.","en":"I admit the budget is high, but there is some truth in that when they say quality costs money."},{"es":"Aunque su argumento parece exagerado, hay algo de verdad en eso respecto a la falta de personal.","en":"Even though his argument seems exaggerated, there is some truth in that regarding the staff shortage."}]},{"spanish_text":"No descartaría esa posibilidad","english_text":"I would not rule that out","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that something is still considered possible.","main_translations_es":["No excluiría esa posibilidad","No descartaría esa opción","No lo descartaría"],"collocations":["I would not rule out the possibility","I would not rule out that option","I would not rule out a chance","I would not rule out the idea"],"synonyms_en":["I wouldn''t dismiss that","I wouldn''t eliminate that","I wouldn''t rule it out"],"example_sentence":"I would not rule that out, even though I''m still uncertain.","example_es":"No descartaría esa posibilidad, aunque todavía tengo dudas.","example_en":"I would not rule that out, even though I''m still uncertain.","mnemonic_en":"Picture a big sign saying No regla while I say I would not rule that out","cloze_distractors_en":["I shall rotate the table","It requires purple clouds","We calculate the weather","They dictate the kitchen"],"examples":[{"es":"No descartaría esa posibilidad, aunque todavía tengo dudas.","en":"I would not rule that out, even though I''m still uncertain."},{"es":"Aunque el presupuesto es bajo, no descartaría esa posibilidad si encontramos un patrocinador.","en":"Even though the budget is low, I would not rule that out if we find a sponsor."},{"es":"Si el mercado cambia drásticamente mañana, no descartaría esa posibilidad para nuestro plan de expansión.","en":"If the market changes drastically tomorrow, I would not rule that out for our expansion plan."}]},{"spanish_text":"Vale la pena analizarlo","english_text":"It is worth examining","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Something that should be looked at because it may be valuable or important.","main_translations_es":["Merece ser analizado","Vale la pena revisarlo","Conviene examinarlo"],"collocations":["It is worth examining further","It is worth examining the data","It is worth examining the evidence"],"synonyms_en":["deserves scrutiny","merits investigation","should be studied"],"example_sentence":"It is worth examining the engine closely to understand why it suddenly stopped working.","example_es":"Vale la pena analizarlo con detenimiento para entender por qué el motor dejó de funcionar de repente.","example_en":"It is worth examining the engine closely to understand why it suddenly stopped working.","mnemonic_en":"Imagine a valuable pen being examined under a microscope.","cloze_distractors_en":["It is rarely ignoring","It is mostly avoiding","It is surely rejecting","It is barely debating"],"examples":[{"es":"Vale la pena analizarlo con detenimiento para entender por qué el motor dejó de funcionar de repente.","en":"It is worth examining the engine closely to understand why it suddenly stopped working."},{"es":"Aunque el contrato parece muy complejo, vale la pena analizarlo antes de firmar cualquier compromiso.","en":"Although the contract seems very complex, it is worth examining before signing any commitment."},{"es":"Aunque el informe financiero parece confuso, vale la pena analizarlo para encontrar dónde se perdió el dinero.","en":"Although the financial report looks confusing, it is worth examining to find where the money was lost."}]},{"spanish_text":"No deberíamos apresurarnos","english_text":"We should not jump to conclusions","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means we ought not to form opinions before having all the facts.","main_translations_es":["No deberíamos precipitarse","No debemos apresurarnos","No hay que ir deprisa"],"collocations":["don''t jump to conclusions","avoid jumping to conclusions","stop jumping to conclusions"],"synonyms_en":["avoid assumptions","don''t assume","hold off judgment"],"example_sentence":"We should not jump to conclusions before analyzing all the data.","example_es":"No deberíamos apresurarnos a sacar conclusiones sin analizar todos los datos.","example_en":"We should not jump to conclusions before analyzing all the data.","mnemonic_en":"Visualize a frantic jumper pausing at the finish line, reminding you not to rush and jump to conclusions.","cloze_distractors_en":["We must ignore every fact","They will create more problems","You should accept the rumors","I prefer to change subjects"],"examples":[{"es":"No deberíamos apresurarnos a sacar conclusiones sin analizar todos los datos.","en":"We should not jump to conclusions before analyzing all the data."},{"es":"Aunque el testigo parezca culpable, no deberíamos apresurarnos a sacar conclusiones hasta escuchar su versión.","en":"Even if the witness seems guilty, we should not jump to conclusions until we hear his side of the story."},{"es":"Vi a mi jefe hablando con otro candidato, pero no deberíamos apresurarnos a sacar conclusiones sobre mi despido.","en":"I saw my boss talking to another candidate, but we should not jump to conclusions about me being fired."}]},{"spanish_text":"Conviene matizar","english_text":"We need to qualify that","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"To add a clarification or nuance to a statement.","main_translations_es":["Es conveniente matizar","Resulta necesario matizar","Conviene aclarar"],"collocations":["to qualify that statement","to qualify that claim","to qualify that point","to qualify that observation"],"synonyms_en":["We must clarify that","We should specify that","We have to qualify that"],"example_sentence":"We need to qualify that the report does not include all the relevant data.","example_es":"Conviene matizar que el informe no incluye todos los datos relevantes.","example_en":"We need to qualify that the report does not include all the relevant data.","mnemonic_en":"To qualify that, imagine a judge placing a mat on the document.","cloze_distractors_en":["We ignore completely that","We refuse to mention that","We rarely understand why","We forget entirely how"],"examples":[{"es":"Conviene matizar que el informe no incluye todos los datos relevantes.","en":"We need to qualify that the report does not include all the relevant data."},{"es":"Antes de aceptar la propuesta, conviene matizar que los costos podrían aumentar el próximo año.","en":"Before accepting the proposal, we need to qualify that costs could increase next year."},{"es":"Aunque el plan de expansión parece sólido, conviene matizar que no hemos tenido en cuenta el impacto de la inflación en los precios.","en":"Although the expansion plan seems solid, we need to qualify that we have not taken into account the impact of inflation on prices."}]},{"spanish_text":"Eso requiere evidencia","english_text":"That requires evidence","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It states that something needs proof or supporting evidence.","main_translations_es":["Eso necesita pruebas","Eso demanda evidencia","Eso requiere pruebas"],"collocations":["requires evidence","requires solid evidence","requires concrete evidence","requires supporting evidence"],"synonyms_en":["needs proof","calls for proof","demands proof"],"example_sentence":"You cannot simply say the project failed; that requires evidence to support your claim.","example_es":"No puedes simplemente decir que el proyecto fracasó; eso requiere evidencia para respaldar tu afirmación.","example_en":"You cannot simply say the project failed; that requires evidence to support your claim.","mnemonic_en":"Imagine a detective saying That requires evidence while holding a file labeled evidencia.","cloze_distractors_en":["That implies silence","That suggests laughter","That denotes patience","That involves feelings"],"examples":[{"es":"No puedes simplemente decir que el proyecto fracasó; eso requiere evidencia para respaldar tu afirmación.","en":"You cannot simply say the project failed; that requires evidence to support your claim."},{"es":"No puedes afirmar que el clima está cambiando sin datos, eso requiere evidencia científica para ser tomado en serio.","en":"You cannot claim the climate is changing without data; that requires evidence to be taken seriously."},{"es":"No puedes cambiar la política de la empresa, porque eso requiere evidencia de que no está funcionando.","en":"You cannot change the company policy, because that requires evidence that it is not working."}]},{"spanish_text":"¿En qué te basas?","english_text":"What are you basing that on?","section_name":"Discussion and Debate","part_of_speech":"question","definition_en":"A question asking for the basis or justification of something.","main_translations_es":["¿En qué te basas?","¿Sobre qué te apoyas?","¿Qué fundamento tiene?"],"collocations":["basing decisions on","basing your argument on","basing the plan on"],"synonyms_en":["What''s your source?","On what basis?","What evidence supports that?"],"example_sentence":"What are you basing that on when you claim sales will drop next quarter?","example_es":"¿En qué te basas para afirmar que las ventas caerán el próximo trimestre?","example_en":"What are you basing that on when you claim sales will drop next quarter?","mnemonic_en":"Picture a baseball base shouting, What are you basing that on?","cloze_distractors_en":["How are you eating that?","Who is arriving by then?","When are you leaving home?"],"examples":[{"es":"¿En qué te basas para afirmar que las ventas caerán el próximo trimestre?","en":"What are you basing that on when you claim sales will drop next quarter?"},{"es":"Dices que este candidato es el mejor, pero ¿en qué te basas?","en":"You say this candidate is the best, but what are you basing that on?"},{"es":"Si crees que la estrategia de marketing no funcionará, ¿en qué te basas?","en":"If you think the marketing strategy won''t work, what are you basing that on?"}]},{"spanish_text":"¿Podrías desarrollar esa idea?","english_text":"Could you elaborate on that?","section_name":"Discussion and Debate","part_of_speech":"question","definition_en":"A polite request for more detail about something previously mentioned.","main_translations_es":["¿Podrías ampliar esa idea?","¿Podrías profundizar en esa idea?","¿Podrías detallar esa idea?"],"collocations":["Could you elaborate on that, please?","Could you elaborate on that a bit more?","Could you elaborate on that further?"],"synonyms_en":["Can you expand on that?","Would you clarify that?","Please give more details."],"example_sentence":"Your proposal regarding the budget is interesting; could you elaborate on that?","example_es":"Tu propuesta sobre el presupuesto es interesante, ¿podrías desarrollar esa idea?","example_en":"Your proposal regarding the budget is interesting; could you elaborate on that?","mnemonic_en":"Picture a teacher asking could you elaborate while you elabora the idea on the board.","cloze_distractors_en":["Shall we ignore this entirely?","Must you repeat it again?","Why ignore the obvious facts?","Have you finished your lunch?"],"examples":[{"es":"Tu propuesta sobre el presupuesto es interesante, ¿podrías desarrollar esa idea?","en":"Your proposal regarding the budget is interesting; could you elaborate on that?"},{"es":"Mencionaste un nuevo enfoque para el proyecto, ¿podrías desarrollar esa idea?","en":"You mentioned a new approach for the project; could you elaborate on that?"},{"es":"No entiendo bien tu punto sobre la estrategia de ventas, ¿podrías desarrollar esa idea?","en":"I don''t quite understand your point about the sales strategy; could you elaborate on that?"}]},{"spanish_text":"¿Podrías dar un ejemplo?","english_text":"Could you give an example?","section_name":"Discussion and Debate","part_of_speech":"question","definition_en":"A polite request asking someone to provide an example.","main_translations_es":["¿Puedes dar un ejemplo?","¿Me podrías dar un ejemplo?","¿Podrías proporcionar un ejemplo?"],"collocations":["Could you give an example of that?","Could you give an example, please?","Could you give an example to illustrate?"],"synonyms_en":["Can you provide an example?","Would you show an example?","Please give an example."],"example_sentence":"I am not sure what you mean by ''sustainability'', so could you give an example?","example_es":"No me queda claro qué quieres decir con ''sostenibilidad'', ¿podrías dar un ejemplo?","example_en":"I am not sure what you mean by ''sustainability'', so could you give an example?","mnemonic_en":"Picture a chef handing you a sample dish, saying ejemplo as he gives an example.","cloze_distractors_en":["Are you having lunch?","Did they finish homework?","Was he feeling hungry?","Have we become experts?"],"examples":[{"es":"No me queda claro qué quieres decir con ''sostenibilidad'', ¿podrías dar un ejemplo?","en":"I am not sure what you mean by ''sustainability'', so could you give an example?"},{"es":"No entiendo tu argumento, ¿podrías dar un ejemplo para aclararlo?","en":"I do not understand your argument, so could you give an example to clarify it?"},{"es":"No entiendo cómo esta nueva política de la empresa va a reducir los gastos, ¿podrías dar un ejemplo?","en":"I do not understand how this new company policy is going to cut costs, so could you give an example?"}]},{"spanish_text":"¿Qué quieres decir exactamente?","english_text":"What exactly do you mean?","section_name":"Discussion and Debate","part_of_speech":"question","definition_en":"A request for clarification about the precise meaning of something.","main_translations_es":["¿Qué quieres decir con eso?","¿A qué te refieres exactamente?","¿Qué significa exactamente?"],"collocations":["What exactly do you mean by that?","I’m not sure what exactly you mean.","Could you explain what exactly you mean?","Tell me what exactly you mean."],"synonyms_en":["What do you mean?","What are you trying to say?","What are you saying?"],"example_sentence":"When he explained his plan, I asked, \"What exactly do you mean?\"","example_es":"Cuando me explicó su plan, le pregunté: ¿Qué quieres decir exactamente?","example_en":"When he explained his plan, I asked, \"What exactly do you mean?\"","mnemonic_en":"Picture an ex‑actly‑clear sign asking what you mean.","cloze_distractors_en":["Who decided the weather?","How much costs everything?","Which color was yesterday?","Why became the table?"],"examples":[{"es":"Cuando me explicó su plan, le pregunté: ¿Qué quieres decir exactamente?","en":"When he explained his plan, I asked, \"What exactly do you mean?\""},{"es":"No entiendo tu comentario sobre el presupuesto, ¿qué quieres decir exactamente?","en":"I don''t understand your comment about the budget; what exactly do you mean?"},{"es":"Mencionaste que el proyecto es inviable, ¿qué quieres decir exactamente?","en":"You mentioned that the project is unfeasible; what exactly do you mean?"}]},{"spanish_text":"Aclaremos un punto","english_text":"Let us clarify one point","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A polite phrase used to introduce an explanation of a specific matter.","main_translations_es":["Aclararemos un punto","Aclarar un punto","Vamos a aclarar un punto"],"collocations":["let us clarify","clarify one point","to clarify a point","let me clarify"],"synonyms_en":["Let''s clear up a point","Let''s make one thing clear","Let''s explain a point"],"example_sentence":"Let us clarify one point about the budget before we approve the project.","example_es":"Aclaremos un punto sobre el presupuesto antes de aprobar el proyecto.","example_en":"Let us clarify one point about the budget before we approve the project.","mnemonic_en":"Let us make a clear point.","cloze_distractors_en":["Let us ignore the facts","Let us avoid the consensus","Let us repeat the silence"],"examples":[{"es":"Aclaremos un punto sobre el presupuesto antes de aprobar el proyecto.","en":"Let us clarify one point about the budget before we approve the project."},{"es":"Aclaremos un punto respecto a las reglas del debate antes de empezar.","en":"Let us clarify one point regarding the debate rules before we begin."},{"es":"Aclaremos un punto sobre la fecha de entrega antes de finalizar el contrato.","en":"Let us clarify one point about the delivery date before we finalize the contract."}]},{"spanish_text":"Quiero dejar algo claro","english_text":"I want to make something clear","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement used to indicate that the speaker intends to clarify a point.","main_translations_es":["Quiero aclarar algo","Quisiera dejar algo claro","Deseo dejar algo claro"],"collocations":["to make something clear","to make it clear","to be clear","to clarify"],"synonyms_en":["I want to clarify","let me clarify","I need to clarify"],"example_sentence":"I want to make something clear: I will not accept any offer that does not include a salary raise.","example_es":"Quiero dejar algo claro: no aceptaré ninguna oferta que no incluya un aumento de sueldo.","example_en":"I want to make something clear: I will not accept any offer that does not include a salary raise.","mnemonic_en":"Picture a crystal-clear glass shouting claro as I want to make something clear.","cloze_distractors_en":["I have forgotten everything","I am feeling quite hungry","I enjoy eating cold pizza","I must go home tomorrow"],"examples":[{"es":"Quiero dejar algo claro: no aceptaré ninguna oferta que no incluya un aumento de sueldo.","en":"I want to make something clear: I will not accept any offer that does not include a salary raise."},{"es":"Antes de empezar la reunión, quiero dejar algo claro sobre los nuevos plazos del proyecto.","en":"Before we start the meeting, I want to make something clear regarding the new project deadlines."},{"es":"Quiero dejar algo claro respecto a mi postura: estoy totalmente en contra de esta nueva política.","en":"I want to make something clear regarding my position: I am strictly against this new policy."}]},{"spanish_text":"No pretendo decir que","english_text":"I am not suggesting that","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to state that the speaker is not implying or proposing something.","main_translations_es":["No quiero decir que","No intento afirmar que","No pretendo afirmar que"],"collocations":["I am not suggesting that you should quit","I am not suggesting that it''s a bad idea","I am not suggesting that we go now"],"synonyms_en":["I''m not implying that","I don''t mean that","I''m not insinuating that"],"example_sentence":"I am not suggesting that the project is a total failure, but we need to review the budget.","example_es":"No pretendo decir que el proyecto sea un fracaso total, pero necesitamos revisar el presupuesto.","example_en":"I am not suggesting that the project is a total failure, but we need to review the budget.","mnemonic_en":"Picture a no‑pretend sign stopping a suggestion.","cloze_distractors_en":["I am confirming that","I am demanding that","I am forbidding that","I am celebrating that"],"examples":[{"es":"No pretendo decir que el proyecto sea un fracaso total, pero necesitamos revisar el presupuesto.","en":"I am not suggesting that the project is a total failure, but we need to review the budget."},{"es":"No pretendo decir que debamos cancelar la reunión, solo sugiero que la pospongamos hasta mañana.","en":"I am not suggesting that we should cancel the meeting, I am just proposing that we postpone it until tomorrow."},{"es":"No pretendo decir que ella sea la única responsable, pero su equipo tomó las decisiones clave.","en":"I am not suggesting that she is the only one responsible, but her team made the key decisions."}]},{"spanish_text":"No debería interpretarse como","english_text":"It should not be interpreted as","section_name":"Discussion and Debate","part_of_speech":"verb phrase","definition_en":"Indicates that something must not be understood in a particular way.","main_translations_es":["No debe interpretarse como","No se debe interpretar como","No ha de interpretarse como"],"collocations":["It should not be interpreted as a criticism","It should not be interpreted as a guarantee","It should not be interpreted as a promise","It should not be interpreted as an endorsement"],"synonyms_en":["It shouldn''t be taken as","It must not be read as","It is not to be understood as"],"example_sentence":"It should not be interpreted as disrespect, but as constructive criticism.","example_es":"No debería interpretarse como una falta de respeto, sino como una crítica constructiva.","example_en":"It should not be interpreted as disrespect, but as constructive criticism.","mnemonic_en":"Picture a big red NO sign over a book, reminding you it should not be interpreted as true.","cloze_distractors_en":["It is fully acknowledged for","It will be clearly rejected by","It has been actively promoted as","It can be reliably measured with"],"examples":[{"es":"No debería interpretarse como una falta de respeto, sino como una crítica constructiva.","en":"It should not be interpreted as disrespect, but as constructive criticism."},{"es":"Mi silencio durante la reunión no debería interpretarse como un acuerdo con su propuesta.","en":"My silence during the meeting it should not be interpreted as agreement with your proposal."},{"es":"Este cambio en el presupuesto no debería interpretarse como una señal de inestabilidad financiera.","en":"This change in the budget it should not be interpreted as a sign of financial instability."}]},{"spanish_text":"En términos generales","english_text":"Broadly speaking","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to introduce a general statement or overview of a topic.","main_translations_es":["En general","De manera general","En líneas generales"],"collocations":["Broadly speaking, the market is expanding","Broadly speaking, we can conclude","Broadly speaking, the results are positive"],"synonyms_en":["generally","in general","overall"],"example_sentence":"Broadly speaking, the majority of students prefer in-person classes over virtual ones.","example_es":"En términos generales, la mayoría de los estudiantes prefieren las clases presenciales a las virtuales.","example_en":"Broadly speaking, the majority of students prefer in-person classes over virtual ones.","mnemonic_en":"Picture a wide speaker broadcasting general terms to a crowd.","cloze_distractors_en":["Secretly speaking","Anxiously speaking","Reluctantly speaking","Accidentally speaking"],"examples":[{"es":"En términos generales, la mayoría de los estudiantes prefieren las clases presenciales a las virtuales.","en":"Broadly speaking, the majority of students prefer in-person classes over virtual ones."},{"es":"En términos generales, el nuevo plan de marketing ha sido bien recibido por los clientes.","en":"Broadly speaking, the new marketing plan has been well received by the clients."},{"es":"En términos generales, el clima en esta región es bastante templado durante todo el año.","en":"Broadly speaking, the climate in this region is quite mild throughout the year."}]},{"spanish_text":"En términos concretos","english_text":"In practical terms","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to introduce a concrete or realistic explanation of something.","main_translations_es":["En términos prácticos","En la práctica","De manera concreta"],"collocations":["In practical terms, this means...","In practical terms, we can see...","In practical terms, the cost is...","In practical terms, it''s easier..."],"synonyms_en":["practically speaking","in practice","actually"],"example_sentence":"In practical terms, the project will cost ten thousand euros.","example_es":"En términos concretos, el proyecto costará diez mil euros.","example_en":"In practical terms, the project will cost ten thousand euros.","mnemonic_en":"Picture a concrete block labeled In practical terms on a construction plan.","cloze_distractors_en":["In theoretical dreams","In historical rumors","In emotional guesses","In accidental silence"],"examples":[{"es":"En términos concretos, el proyecto costará diez mil euros.","en":"In practical terms, the project will cost ten thousand euros."},{"es":"En términos concretos, necesitamos contratar a tres personas más para terminar la obra a tiempo.","en":"In practical terms, we need to hire three more people to finish the construction on time."},{"es":"En términos concretos, esta nueva política reducirá el consumo de energía en un veinte por ciento.","en":"In practical terms, this new policy will reduce energy consumption by twenty percent."}]},{"spanish_text":"A primera vista","english_text":"At first glance","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to indicate an initial impression based on a quick look.","main_translations_es":["A primera vista","A simple vista","A primera impresión"],"collocations":["At first glance, it seems...","At first glance, the data suggests...","At first glance, the results appear..."],"synonyms_en":["at first sight","on first look","at a glance"],"example_sentence":"At first glance, the proposal seems affordable, but the hidden costs are very high.","example_es":"A primera vista, la propuesta parece económica, pero los costos ocultos son muy elevados.","example_en":"At first glance, the proposal seems affordable, but the hidden costs are very high.","mnemonic_en":"Imagine a first‑glance view of a beautiful vista, a prima scene you see instantly.","cloze_distractors_en":["In other words","On the contrary","Without a doubt","By all means"],"examples":[{"es":"A primera vista, la propuesta parece económica, pero los costos ocultos son muy elevados.","en":"At first glance, the proposal seems affordable, but the hidden costs are very high."},{"es":"A primera vista, el candidato no parecía tener experiencia, pero su currículum demostró lo contrario.","en":"At first glance, the candidate did not seem to have experience, but his resume proved otherwise."},{"es":"A primera vista, el problema matemático parece imposible de resolver, aunque tiene una solución lógica.","en":"At first glance, the math problem seems impossible to solve, although it has a logical solution."}]},{"spanish_text":"A largo plazo","english_text":"In the long term","section_name":"Discussion and Debate","part_of_speech":"adverbial phrase","definition_en":"Refers to a period of time far in the future.","main_translations_es":["A largo plazo","A futuro","En el futuro"],"collocations":["in the long term","over the long term","in the long run","for the long term"],"synonyms_en":["over time","in the long run","eventually"],"example_sentence":"In the long term, investing in renewable energy will generate economic benefits.","example_es":"A largo plazo, la inversión en energía renovable generará beneficios económicos.","example_en":"In the long term, investing in renewable energy will generate economic benefits.","mnemonic_en":"Picture a long, endless runway labeled ''largo'' showing the future lasting forever.","cloze_distractors_en":["In the brief flash","On the wrong side","At the quiet hour","By the small margin"],"examples":[{"es":"A largo plazo, la inversión en energía renovable generará beneficios económicos.","en":"In the long term, investing in renewable energy will generate economic benefits."},{"es":"Debemos considerar los efectos de esta política a largo plazo antes de tomar una decisión final.","en":"We must consider the effects of this policy in the long term before making a final decision."},{"es":"Aunque los costos iniciales son altos, el proyecto será rentable a largo plazo.","en":"Although the initial costs are high, the project will be profitable in the long term."}]},{"spanish_text":"A corto plazo","english_text":"In the short term","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"During a brief period of time; referring to the near future.","main_translations_es":["A corto plazo","En el corto plazo","A corto término"],"collocations":["in the short term","short‑term plan","short‑term benefits","short‑term outlook"],"synonyms_en":["short‑term","temporarily","for now"],"example_sentence":"In the short term, the company plans to increase its sales by 10%.","example_es":"A corto plazo, la empresa planea aumentar sus ventas en un 10%.","example_en":"In the short term, the company plans to increase its sales by 10%.","mnemonic_en":"Picture a short‑term deadline tied to a tight ''corto'' rope.","cloze_distractors_en":["In the distant past","In the afterlife","In the wrong direction","In the hidden agenda"],"examples":[{"es":"A corto plazo, la empresa planea aumentar sus ventas en un 10%.","en":"In the short term, the company plans to increase its sales by 10%."},{"es":"A corto plazo, necesitamos reducir los gastos operativos para evitar pérdidas mayores.","en":"In the short term, we need to reduce operating expenses to avoid further losses."},{"es":"Aunque el proyecto es ambicioso, a corto plazo solo nos enfocaremos en completar la fase de diseño.","en":"Although the project is ambitious, in the short term we will only focus on completing the design phase."}]},{"spanish_text":"En el peor de los casos","english_text":"In the worst-case scenario","section_name":"Discussion and Debate","part_of_speech":"idiomatic expression","definition_en":"It refers to the most unfavorable possible outcome.","main_translations_es":["En el peor de los casos","En el peor escenario","En el caso más desfavorable"],"collocations":["In the worst-case scenario, we could lose everything.","In the worst-case scenario, the project will be delayed.","In the worst-case scenario, the system may crash."],"synonyms_en":["at worst","in the worst case","in worst-case"],"example_sentence":"In the worst-case scenario, we will have to cancel the event.","example_es":"En el peor de los casos, tendremos que cancelar el evento.","example_en":"In the worst-case scenario, we will have to cancel the event.","mnemonic_en":"Picture a worst-case scenario as a ''peor'' case spilling over the floor.","cloze_distractors_en":["In the colorful rainbow","In the silent vacuum","In the frozen fountain","In the wooden cupboard"],"examples":[{"es":"En el peor de los casos, tendremos que cancelar el evento.","en":"In the worst-case scenario, we will have to cancel the event."},{"es":"En el peor de los casos, el presupuesto no alcanzará para terminar la construcción.","en":"In the worst-case scenario, the budget will not be enough to finish the construction."},{"es":"Si el servidor falla, en el peor de los casos perderemos toda la información guardada.","en":"If the server fails, in the worst-case scenario we will lose all the saved information."}]},{"spanish_text":"En el mejor de los casos","english_text":"In the best-case scenario","section_name":"Discussion and Debate","part_of_speech":"idiomatic expression","definition_en":"Used to describe the most favorable possible outcome.","main_translations_es":["En el mejor de los casos","En el caso más favorable","En el escenario óptimo"],"collocations":["In the best-case scenario, we succeed","In the best-case scenario, costs are lower","In the best-case scenario, the project finishes early"],"synonyms_en":["at best","in the ideal case","if all goes well"],"example_sentence":"In the best-case scenario, the project will be completed in three months.","example_es":"En el mejor de los casos, el proyecto se completará en tres meses.","example_en":"In the best-case scenario, the project will be completed in three months.","mnemonic_en":"Picture a mayor (mejor) approving the best‑case scenario.","cloze_distractors_en":["In the colorful scenario","In the musical scenario","In the athletic scenario","In the geometric scenario"],"examples":[{"es":"En el mejor de los casos, el proyecto se completará en tres meses.","en":"In the best-case scenario, the project will be completed in three months."},{"es":"En el mejor de los casos, la lluvia parará antes de que empiece el partido de fútbol.","en":"In the best-case scenario, the rain will stop before the soccer match begins."},{"es":"En el mejor de los casos, lograremos recaudar suficientes fondos para renovar la biblioteca escolar.","en":"In the best-case scenario, we will manage to raise enough funds to renovate the school library."}]},{"spanish_text":"En última instancia","english_text":"Ultimately","section_name":"Discussion and Debate","part_of_speech":"adverb","definition_en":"In the end, after everything else has been considered.","main_translations_es":["Finalmente","A fin de cuentas","En definitiva"],"collocations":["Ultimately, we decided to go ahead","Ultimately, it comes down to cost","Ultimately, the results speak for themselves"],"synonyms_en":["in the end","finally","eventually"],"example_sentence":"Ultimately, we will decide whether the project continues.","example_es":"En última instancia, decidiremos si el proyecto continúa.","example_en":"Ultimately, we will decide whether the project continues.","mnemonic_en":"Picture the ultimate trophy on the final última podium, showing everything ends there.","cloze_distractors_en":["Superficially","Hypothetically","Coincidentally","Indifferently"],"examples":[{"es":"En última instancia, decidiremos si el proyecto continúa.","en":"Ultimately, we will decide whether the project continues."},{"es":"En última instancia, la responsabilidad de la seguridad recae sobre el gerente.","en":"Ultimately, the responsibility for safety rests with the manager."},{"es":"En última instancia, el éxito de la negociación depende de nuestra disposición a ceder.","en":"Ultimately, the success of the negotiation depends on our willingness to compromise."}]},{"spanish_text":"Al fin y al cabo","english_text":"After all","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to emphasize a conclusion that follows from what has been said or to point out that something is true when all factors are considered.","main_translations_es":["En definitiva","Al final","A fin de cuentas"],"collocations":["after all is said and done","after all, it''s worth trying","after all, we are human"],"synonyms_en":["in the end","ultimately","when all is said and done"],"example_sentence":"You shouldn''t be so hard on him; after all, he is only a beginner.","example_es":"No deberías ser tan duro con él; al fin y al cabo, es solo un principiante.","example_en":"You shouldn''t be so hard on him; after all, he is only a beginner.","mnemonic_en":"Picture the final curtain falling and everyone saying after al as the show ends.","cloze_distractors_en":["By contrast","Furthermore","Consequently"],"examples":[{"es":"No deberías ser tan duro con él; al fin y al cabo, es solo un principiante.","en":"You shouldn''t be so hard on him; after all, he is only a beginner."},{"es":"El proyecto terminó superando el presupuesto inicial, pero al fin y al cabo, la calidad del resultado final justifica el gasto extra.","en":"The project ended up exceeding the initial budget, but after all, the quality of the final result justifies the extra expense."},{"es":"No te preocupes por el error, al fin y al cabo todos estamos aprendiendo en este debate.","en":"Don''t worry about the mistake; after all, we are all learning in this debate."}]},{"spanish_text":"En resumen","english_text":"To sum up","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to introduce a brief summary of what has been said.","main_translations_es":["En síntesis","En pocas palabras","Resumiendo"],"collocations":["To sum up, ...","To sum up the findings","To sum up the report"],"synonyms_en":["In short","In summary","Overall"],"example_sentence":"To sum up, the project was a success.","example_es":"En resumen, el proyecto fue un éxito.","example_en":"To sum up, the project was a success.","mnemonic_en":"Picture a calculator adding a suma, then you sum up the whole story.","cloze_distractors_en":["By all means","On the house","For the record","In the dark"],"examples":[{"es":"En resumen, el proyecto fue un éxito.","en":"To sum up, the project was a success."},{"es":"En resumen, necesitamos reducir los gastos para ahorrar dinero.","en":"To sum up, we need to cut expenses to save money."},{"es":"En resumen, los argumentos presentados no son suficientes para cambiar la ley.","en":"To sum up, the arguments presented are not enough to change the law."}]},{"spanish_text":"Para resumir","english_text":"To summarize","section_name":"Discussion and Debate","part_of_speech":"verb","definition_en":"To give a brief statement of the main points.","main_translations_es":["En resumen","Resumiendo","Para concluir"],"collocations":["To summarize, ...","To summarize the findings","To summarize briefly","To summarize the main points"],"synonyms_en":["In brief","In summary","To sum up"],"example_sentence":"To summarize, the project was a success.","example_es":"Para resumir, el proyecto fue un éxito.","example_en":"To summarize, the project was a success.","mnemonic_en":"Picture a parrot giving a quick summary, shouting ''para resumir'' as it folds the paper.","cloze_distractors_en":["To exaggerate","To contradict","To complicate","To hypothesize"],"examples":[{"es":"Para resumir, el proyecto fue un éxito.","en":"To summarize, the project was a success."},{"es":"Para resumir, los puntos principales de la reunión son la reducción de costos y el aumento de ventas.","en":"To summarize, the main points of the meeting are cost reduction and increased sales."},{"es":"Para resumir, hemos decidido cambiar la fecha de la conferencia al próximo mes.","en":"To summarize, we have decided to move the conference date to next month."}]},{"spanish_text":"En esencia","english_text":"Essentially","section_name":"Discussion and Debate","part_of_speech":"adverb","definition_en":"In a basic or fundamental way; basically.","main_translations_es":["Básicamente","En resumen","En esencia"],"collocations":["essentially the same","essentially a matter of","essentially, …"],"synonyms_en":["basically","fundamentally","in essence"],"example_sentence":"Essentially, the project aims to improve air quality in the city.","example_es":"En esencia, el proyecto busca mejorar la calidad del aire en la ciudad.","example_en":"Essentially, the project aims to improve air quality in the city.","mnemonic_en":"Think of a bottle labeled en esencia, the essential core, and you’ll recall essentially.","cloze_distractors_en":["Accidentally","Hypothetically","Reluctantly","Superficially"],"examples":[{"es":"En esencia, el proyecto busca mejorar la calidad del aire en la ciudad.","en":"Essentially, the project aims to improve air quality in the city."},{"es":"En esencia, nuestra propuesta se centra en reducir los costos operativos de la empresa.","en":"Essentially, our proposal focuses on reducing the company''s operating costs."},{"es":"En esencia, el argumento del autor es que la tecnología ha cambiado nuestra forma de aprender.","en":"Essentially, the author''s argument is that technology has changed the way we learn."}]},{"spanish_text":"En pocas palabras","english_text":"In a nutshell","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Briefly; in a concise summary.","main_translations_es":["En resumen","En síntesis","Resumiendo"],"collocations":["to put it in a nutshell","in a nutshell, ...","the story in a nutshell","the whole thing in a nutshell"],"synonyms_en":["briefly","to sum up","in short"],"example_sentence":"In a nutshell, the project was a success.","example_es":"En pocas palabras, el proyecto fue un éxito.","example_en":"In a nutshell, the project was a success.","mnemonic_en":"Imagine a tiny nut shell holding just a few words.","cloze_distractors_en":["By all means","On the house","Under the rug"],"examples":[{"es":"En pocas palabras, el proyecto fue un éxito.","en":"In a nutshell, the project was a success."},{"es":"En pocas palabras, nuestra estrategia de ventas no funcionó durante el trimestre.","en":"In a nutshell, our sales strategy did not work during the quarter."},{"es":"En pocas palabras, necesitamos reducir los gastos para evitar la quiebra.","en":"In a nutshell, we need to cut expenses to avoid bankruptcy."}]},{"spanish_text":"La cuestión central es","english_text":"The key issue is","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to introduce the most important problem or topic.","main_translations_es":["El tema principal es","El asunto central es","Lo fundamental es"],"collocations":["The key issue is whether…","The key issue is how…","The key issue is that…","The key issue is the lack of…"],"synonyms_en":["The main point is","The primary concern is","The central matter is"],"example_sentence":"The key issue is how to improve education in rural areas.","example_es":"La cuestión central es cómo mejorar la educación en las zonas rurales.","example_en":"The key issue is how to improve education in rural areas.","mnemonic_en":"Picture a key opening a big issue sign, like the Spanish ''qué'' and ''cuestión''.","cloze_distractors_en":["The lucky guess is","The hidden flavor is","The silent partner is","The broken record is"],"examples":[{"es":"La cuestión central es cómo mejorar la educación en las zonas rurales.","en":"The key issue is how to improve education in rural areas."},{"es":"La cuestión central es si debemos invertir más dinero en energías renovables este año.","en":"The key issue is whether we should invest more money in renewable energy this year."},{"es":"La cuestión central es la falta de comunicación entre los departamentos de la empresa.","en":"The key issue is the lack of communication between the company departments."}]},{"spanish_text":"Eso nos lleva a","english_text":"That brings us to","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to transition to the next point or topic.","main_translations_es":["Esto nos lleva a","Esto nos conduce a","Esto nos dirige a"],"collocations":["That brings us to the next point","That brings us to a conclusion","That brings us to the final step","That brings us to the heart of the matter"],"synonyms_en":["This leads to","Now we come to","This takes us to"],"example_sentence":"We have finished talking about the budget, so that brings us to discussing the marketing plans.","example_es":"Hemos terminado de hablar sobre el presupuesto, así que eso nos lleva a discutir los planes de marketing.","example_en":"We have finished talking about the budget, so that brings us to discussing the marketing plans.","mnemonic_en":"Picture a bridge labeled That brings us to, while the Spanish chant eso nos lleva a echoes across it.","cloze_distractors_en":["That keeps away","That holds under","That breaks off"],"examples":[{"es":"Hemos terminado de hablar sobre el presupuesto, así que eso nos lleva a discutir los planes de marketing.","en":"We have finished talking about the budget, so that brings us to discussing the marketing plans."},{"es":"Ya analizamos los problemas técnicos, y eso nos lleva a considerar una solución permanente.","en":"We have already analyzed the technical problems, and that brings us to considering a permanent solution."},{"es":"Hemos terminado de revisar los resultados del primer trimestre, lo cual eso nos lleva a analizar las proyecciones para el próximo año.","en":"We have finished reviewing the first-quarter results, and that brings us to analyzing the projections for next year."}]},{"spanish_text":"Hay otro ángulo","english_text":"There is another angle to consider","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that there is an additional perspective or aspect that should be taken into account.","main_translations_es":["Existe otro ángulo","Hay otra perspectiva","Se puede observar otro ángulo"],"collocations":["We should remember there is another angle to consider","It''s important to note there is another angle to consider","Before concluding, consider that there is another angle to consider"],"synonyms_en":["another perspective","another viewpoint","another aspect to consider"],"example_sentence":"Although the design seems finished, there is another angle to consider to improve the website''s accessibility.","example_es":"Aunque el diseño parece terminado, hay otro ángulo que debemos considerar para mejorar la accesibilidad del sitio web.","example_en":"Although the design seems finished, there is another angle to consider to improve the website''s accessibility.","mnemonic_en":"Picture a fresh angle shaped like ''otro'' pointing at a triangle, reminding you there is another angle to consider","cloze_distractors_en":["They are eating lunch tomorrow","Everything is completely finished now","Nobody was listening to anyone else","These are rarely mentioned anywhere today"],"examples":[{"es":"Aunque el diseño parece terminado, hay otro ángulo que debemos considerar para mejorar la accesibilidad del sitio web.","en":"Although the design seems finished, there is another angle to consider to improve the website''s accessibility."},{"es":"Aunque el plan parece sólido, hay otro ángulo que no hemos explorado en esta reunión.","en":"Although the plan seems solid, there is another angle to consider that we haven''t explored in this meeting."},{"es":"No te apresures a juzgar el caso; hay otro ángulo que debemos considerar sobre el comportamiento del testigo.","en":"Do not rush to judge the case; there is another angle to consider regarding the witness''s behavior."}]},{"spanish_text":"No perdamos de vista que","english_text":"Let us not lose sight of the fact that","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase urging someone to keep an important point in mind.","main_translations_es":["No olvidemos que","No perdamos de vista el hecho de que","Mantengamos presente que"],"collocations":["let us not lose sight of the fact that","we must not lose sight of the fact that","do not lose sight of the fact that","it is crucial not to lose sight of the fact that"],"synonyms_en":["let''s keep in mind","let''s bear in mind","let''s not overlook"],"example_sentence":"Let us not lose sight of the fact that our primary goal is to reduce carbon emissions by 2030.","example_es":"No perdamos de vista que nuestro objetivo principal es reducir las emisiones de carbono antes de 2030.","example_en":"Let us not lose sight of the fact that our primary goal is to reduce carbon emissions by 2030.","mnemonic_en":"Let us not lose sight—imagine a lighthouse keeping the vista clear.","cloze_distractors_en":["It is highly unlikely that","We shall never pretend that","There is no evidence that"],"examples":[{"es":"No perdamos de vista que nuestro objetivo principal es reducir las emisiones de carbono antes de 2030.","en":"Let us not lose sight of the fact that our primary goal is to reduce carbon emissions by 2030."},{"es":"No perdamos de vista que, aunque la tecnología ha avanzado, la interacción humana sigue siendo esencial para el servicio al cliente.","en":"Let us not lose sight of the fact that, although technology has advanced, human interaction remains essential for customer service."},{"es":"No perdamos de vista que la seguridad de los clientes debe ser nuestra prioridad absoluta durante la renovación del hotel.","en":"Let us not lose sight of the fact that client safety must be our absolute priority during the hotel renovation."}]},{"spanish_text":"Conviene recordar que","english_text":"It is worth remembering that","section_name":"Discussion and Debate","part_of_speech":"idiomatic expression","definition_en":"A phrase used to indicate that something should be kept in mind.","main_translations_es":["Vale la pena recordar que","Hay que recordar que","Es importante recordar que"],"collocations":["It is worth remembering that...","It is worth remembering that you should...","It is worth remembering that the rules apply"],"synonyms_en":["keep in mind","remember that","note that"],"example_sentence":"It is worth remembering that punctuality is a sign of respect.","example_es":"Conviene recordar que la puntualidad es una muestra de respeto.","example_en":"It is worth remembering that punctuality is a sign of respect.","mnemonic_en":"Conveniently, I remember that it is worth noting.","cloze_distractors_en":["Despite the fact that","Regardless of the truth","Owing to the belief of"],"examples":[{"es":"Conviene recordar que la puntualidad es una muestra de respeto.","en":"It is worth remembering that punctuality is a sign of respect."},{"es":"Conviene recordar que los datos actuales contradicen nuestra hipótesis inicial.","en":"It is worth remembering that the current data contradicts our initial hypothesis."},{"es":"Conviene recordar que el presupuesto del proyecto tiene un límite estricto.","en":"It is worth remembering that the project budget has a strict limit."}]},{"spanish_text":"Si somos sinceros","english_text":"If we are being honest","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to introduce an honest statement.","main_translations_es":["Si hablamos con franqueza","Si somos francos","Si lo decimos con sinceridad"],"collocations":["If we are being honest, ...","If we are being honest, I think...","If we are being honest, the truth is...","If we are being honest, we must admit..."],"synonyms_en":["to be truthful","honestly speaking","frankly"],"example_sentence":"If we are being honest, the project will not be finished in time for the deadline.","example_es":"Si somos sinceros, el proyecto no estará terminado a tiempo para la entrega.","example_en":"If we are being honest, the project will not be finished in time for the deadline.","mnemonic_en":"Visualize a truth‑telling elf saying \"If we are being honest\" while shouting \"si somos!\"","cloze_distractors_en":["As we were sleeping","Unless you are hungry","Before they are arriving","Since we are dancing"],"examples":[{"es":"Si somos sinceros, el proyecto no estará terminado a tiempo para la entrega.","en":"If we are being honest, the project will not be finished in time for the deadline."},{"es":"Si somos sinceros, no creo que esta estrategia de marketing sea efectiva para atraer clientes.","en":"If we are being honest, I do not think this marketing strategy is effective for attracting customers."},{"es":"Si somos sinceros, la calidad del servicio en este restaurante ha bajado mucho últimamente.","en":"If we are being honest, the quality of service at this restaurant has dropped significantly lately."}]},{"spanish_text":"En rigor","english_text":"Strictly speaking","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to indicate that a statement is true only when considered in a precise or technical sense.","main_translations_es":["En realidad","En términos estrictos","En sentido estricto"],"collocations":["strictly speaking, ...","strictly speaking, the answer is","strictly speaking, it''s not","strictly speaking, we should"],"synonyms_en":["technically","in strict terms","to be precise"],"example_sentence":"Strictly speaking, the project is not finished.","example_es":"En rigor, el proyecto no está terminado.","example_en":"Strictly speaking, the project is not finished.","mnemonic_en":"Picture a strict ruler shouting En rigor as the rule for every word.","cloze_distractors_en":["Happily speaking","Colorfully speaking","Indifferently speaking","Gently speaking"],"examples":[{"es":"En rigor, el proyecto no está terminado.","en":"Strictly speaking, the project is not finished."},{"es":"En rigor, no podemos considerar este acuerdo como definitivo hasta que ambas partes firmen.","en":"Strictly speaking, we cannot consider this agreement final until both parties sign."},{"es":"En rigor, el candidato no cumple con todos los requisitos académicos para el puesto.","en":"Strictly speaking, the candidate does not meet all the academic requirements for the position."}]},{"spanish_text":"A decir verdad","english_text":"To be honest","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to indicate that the speaker is about to speak truthfully or sincerely.","main_translations_es":["A decir verdad","Para ser sincero","Siendo honesto"],"collocations":["to be honest, I think","to be honest with you","to be honest about","to be honest, it''s"],"synonyms_en":["frankly","honestly","in all honesty"],"example_sentence":"To be honest, I didn''t like the movie.","example_es":"A decir verdad, no me gustó la película.","example_en":"To be honest, I didn''t like the movie.","mnemonic_en":"Imagine an honest man chanting a decir verdad as his truth motto.","cloze_distractors_en":["Consequently","Furthermore","Substantially"],"examples":[{"es":"A decir verdad, no me gustó la película.","en":"To be honest, I didn''t like the movie."},{"es":"A decir verdad, no tengo ni idea de cómo arreglar este problema técnico.","en":"To be honest, I have no idea how to fix this technical problem."},{"es":"A decir verdad, prefiero trabajar solo en este proyecto.","en":"To be honest, I prefer to work alone on this project."}]},{"spanish_text":"No me malinterpretes","english_text":"Do not get me wrong","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A request for the listener to avoid misunderstanding what the speaker means.","main_translations_es":["No me tomes a mal","No me saques conclusiones equivocadas","No me malinterpretes"],"collocations":["Do not get me wrong, but…","Do not get me wrong, I’m not…","Do not get me wrong, I love it","Do not get me wrong, it’s just…"],"synonyms_en":["don''t misunderstand me","don''t take me the wrong way","don''t misinterpret me"],"example_sentence":"Do not get me wrong, but I think your proposal needs more technical details.","example_es":"No me malinterpretes, pero creo que tu propuesta necesita más detalles técnicos.","example_en":"Do not get me wrong, but I think your proposal needs more technical details.","mnemonic_en":"Picture a sign No me blocking a wrong road, reminding you: Do not get me wrong.","cloze_distractors_en":["Do not get me right","Do not get me lost","Do not get me found","Do not get me bored"],"examples":[{"es":"No me malinterpretes, pero creo que tu propuesta necesita más detalles técnicos.","en":"Do not get me wrong, but I think your proposal needs more technical details."},{"es":"No me malinterpretes, respeto mucho tu trabajo, aunque no esté de acuerdo con tu conclusión.","en":"Do not get me wrong, I respect your work a lot, even if I disagree with your conclusion."},{"es":"No me malinterpretes, no estoy diciendo que el plan sea malo, solo que es demasiado costoso.","en":"Do not get me wrong, I am not saying the plan is bad, just that it is too expensive."}]},{"spanish_text":"Sin ánimo de ofender","english_text":"No offense intended","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement used to indicate that the speaker does not mean to offend anyone.","main_translations_es":["Sin intención de ofender","No es mi intención ofender","No pretendo ofender"],"collocations":["no offense, but…","no offense taken","no offense, just saying","no offense, I’m being honest"],"synonyms_en":["no offense","not meant to offend","no disrespect intended"],"example_sentence":"No offense intended, I think you should reconsider your decision.","example_es":"Sin ánimo de ofender, creo que deberías reconsiderar tu decisión.","example_en":"No offense intended, I think you should reconsider your decision.","mnemonic_en":"Picture a No offense sign being torn by a sad Sin ánimo de ofender banner.","cloze_distractors_en":["Always remember that","With great enthusiasm","Because of everything"],"examples":[{"es":"Sin ánimo de ofender, creo que deberías reconsiderar tu decisión.","en":"No offense intended, I think you should reconsider your decision."},{"es":"Sin ánimo de ofender, tu propuesta no parece muy realista para este proyecto.","en":"No offense intended, but your proposal does not seem very realistic for this project."},{"es":"Sin ánimo de ofender, pero tu forma de organizar el equipo está causando retrasos.","en":"No offense intended, but your way of organizing the team is causing delays."}]},{"spanish_text":"Con el debido respeto","english_text":"With all due respect","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A polite phrase used to preface a statement that may be critical or contrary, showing respect while disagreeing.","main_translations_es":["Con todo respeto","Con el mayor respeto","Con el debido respeto"],"collocations":["With all due respect, I must disagree","With all due respect, that''s not accurate","With all due respect, here''s my opinion"],"synonyms_en":["respectfully","if I may be frank","no offense but"],"example_sentence":"With all due respect, I think your proposal is not feasible.","example_es":"Con el debido respeto, creo que su propuesta no es viable.","example_en":"With all due respect, I think your proposal is not feasible.","mnemonic_en":"Picture a polite bow, saying ''due'' (debido) while handing over a ''respect'' (respeto) badge.","cloze_distractors_en":["In the same breath","By all means","On the house"],"examples":[{"es":"Con el debido respeto, creo que su propuesta no es viable.","en":"With all due respect, I think your proposal is not feasible."},{"es":"Con el debido respeto, no estoy de acuerdo con su análisis de los datos.","en":"With all due respect, I disagree with your analysis of the data."},{"es":"Con el debido respeto, su comentario está fuera de lugar en esta reunión.","en":"With all due respect, your comment is out of place in this meeting."}]},{"spanish_text":"Permíteme disentir","english_text":"Allow me to disagree","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A polite way of saying that you do not share someone''s opinion.","main_translations_es":["Déjame disentir","Permíteme estar en desacuerdo","Permíteme discrepar"],"collocations":["Allow me to disagree, but...","Allow me to disagree with you","Allow me to disagree for a moment","Allow me to disagree on this point"],"synonyms_en":["I beg to differ","If I may object","I must disagree"],"example_sentence":"Allow me to disagree, but I think that solution won''t work.","example_es":"Permíteme disentir, pero creo que esa solución no funcionará.","example_en":"Allow me to disagree, but I think that solution won''t work.","mnemonic_en":"I raise my hand and say Allow me while a big red DISAGREE sign flashes over DISENTIR","cloze_distractors_en":["Kindly start laughing","Simply ignore everything","Hardly ever complain"],"examples":[{"es":"Permíteme disentir, pero creo que esa solución no funcionará.","en":"Allow me to disagree, but I think that solution won''t work."},{"es":"Aunque respeto tu punto de vista, permíteme disentir sobre la eficacia de este nuevo plan.","en":"While I respect your point of view, allow me to disagree regarding the effectiveness of this new plan."},{"es":"Si me lo permites, permíteme disentir con la conclusión que acabas de presentar ante el comité.","en":"If you will, allow me to disagree with the conclusion you just presented to the committee."}]},{"spanish_text":"Lo plantearía de otra forma","english_text":"I would frame it differently","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"To present something using different wording or perspective.","main_translations_es":["Lo expresaría de otra manera","Lo diría de otro modo","Lo presentaría de forma distinta"],"collocations":["to frame it differently","frame it in a different way","reframe the issue","look at it from another angle"],"synonyms_en":["rephrase it","present it another way","put it another way"],"example_sentence":"If I had to explain the problem, I would frame it differently.","example_es":"Si tuviera que explicar el problema, lo plantearía de otra forma.","example_en":"If I had to explain the problem, I would frame it differently.","mnemonic_en":"Picture a plant in a frame, then swap the frame for a different one.","cloze_distractors_en":["I shall ignore the facts","we must cancel the meeting","they are eating dinner now","you should avoid the truth"],"examples":[{"es":"Si tuviera que explicar el problema, lo plantearía de otra forma.","en":"If I had to explain the problem, I would frame it differently."},{"es":"Aunque entiendo tu punto, lo plantearía de otra forma para que el cliente no se sienta atacado.","en":"Although I understand your point, I would frame it differently so the client doesn''t feel attacked."},{"es":"No creo que el argumento sea incorrecto, pero lo plantearía de otra forma para enfatizar los beneficios.","en":"I don''t think the argument is wrong, but I would frame it differently to emphasize the benefits."}]},{"spanish_text":"Eso cambia las cosas","english_text":"That changes the picture","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that the situation or understanding is altered.","main_translations_es":["Eso altera la situación","Eso modifica las cosas","Eso cambia el panorama"],"collocations":["That changes the picture completely","That changes the picture significantly","That changes the picture dramatically"],"synonyms_en":["That alters the situation","That shifts the perspective","That modifies the view"],"example_sentence":"That changes the picture, so we’ll have to rethink the plan.","example_es":"Eso cambia las cosas, así que tendremos que replantear el plan.","example_en":"That changes the picture, so we’ll have to rethink the plan.","mnemonic_en":"That changes the picture, like a photo that suddenly says ''cambia'' and flips.","cloze_distractors_en":["That paints the ceiling","That folds the laundry","That breaks the window","That waters the garden"],"examples":[{"es":"Eso cambia las cosas, así que tendremos que replantear el plan.","en":"That changes the picture, so we’ll have to rethink the plan."},{"es":"Si el testigo principal ha cambiado su declaración, eso cambia las cosas para nuestra defensa.","en":"If the main witness has changed their statement, that changes the picture for our defense."},{"es":"Ahora que sabemos que el presupuesto fue recortado, eso cambia las cosas para nuestro proyecto.","en":"Now that we know the budget was cut, that changes the picture for our project."}]},{"spanish_text":"Eso fortalece tu argumento","english_text":"That strengthens your argument","section_name":"Discussion and Debate","part_of_speech":"statement","definition_en":"It indicates that something makes your argument more convincing.","main_translations_es":["Eso refuerza tu argumento","Eso consolida tu argumento","Eso respalda tu argumento"],"collocations":["This evidence strengthens your argument","A strong example strengthens your argument","Such data strengthens your argument","That point strengthens your argument"],"synonyms_en":["bolsters your case","reinforces your point","supports your claim"],"example_sentence":"When you present concrete data, that strengthens your argument.","example_es":"Cuando presentas datos concretos, eso fortalece tu argumento.","example_en":"When you present concrete data, that strengthens your argument.","mnemonic_en":"That weight adds fuerza, strengthening your argument.","cloze_distractors_en":["That confuses the audience","That ignores the evidence","That complicates the process","That contradicts the findings"],"examples":[{"es":"Cuando presentas datos concretos, eso fortalece tu argumento.","en":"When you present concrete data, that strengthens your argument."},{"es":"Citar fuentes académicas en tu ensayo es vital porque eso fortalece tu argumento.","en":"Citing academic sources in your essay is vital because that strengthens your argument."},{"es":"Si añades un testimonio personal a tu presentación, verás que eso fortalece tu argumento.","en":"If you add a personal testimonial to your presentation, you will see that that strengthens your argument."}]},{"spanish_text":"Eso debilita la postura","english_text":"That weakens the case","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that something reduces the strength or persuasiveness of an argument.","main_translations_es":["Eso debilita la posición","Eso debilita el argumento","Eso debilita la postura"],"collocations":["This evidence weakens the case","Such arguments weaken the case","It weakens the case considerably","These facts weaken the case"],"synonyms_en":["undermines the argument","undercuts the case","diminishes the case"],"example_sentence":"If the witness lies, that weakens the case.","example_es":"Si el testigo miente, eso debilita la postura.","example_en":"If the witness lies, that weakens the case.","mnemonic_en":"Visualize a cracked case that slouches, because that weakens the case just like a bad posture.","cloze_distractors_en":["That strengthens the law","It clarifies the verdict","They support the motion","This validates the claim"],"examples":[{"es":"Si el testigo miente, eso debilita la postura.","en":"If the witness lies, that weakens the case."},{"es":"Presentar pruebas falsas ante el juez, eso debilita la postura.","en":"Presenting fake evidence to the judge, that weakens the case."},{"es":"Al contradecir sus propias declaraciones previas, eso debilita la postura.","en":"By contradicting your own previous statements, that weakens the case."}]},{"spanish_text":"Eso respalda la idea","english_text":"That supports the claim","section_name":"Discussion and Debate","part_of_speech":"sentence","definition_en":"It indicates that something provides evidence for or backs up a particular claim.","main_translations_es":["Eso respalda la idea","Eso sustenta la idea","Eso avala la idea"],"collocations":["as evidence that supports the claim","which supports the claim","to support the claim"],"synonyms_en":["backs the claim","reinforces the argument","substantiates the claim"],"example_sentence":"That supports the claim that climate change is real.","example_es":"Eso respalda la idea de que el cambio climático es real.","example_en":"That supports the claim that climate change is real.","mnemonic_en":"Picture a sturdy back (respaldo) holding up a claim.","cloze_distractors_en":["That denies the fact","That ignores the logic","That rejects the evidence","That dismisses the theory"],"examples":[{"es":"Eso respalda la idea de que el cambio climático es real.","en":"That supports the claim that climate change is real."},{"es":"El informe financiero muestra un aumento en las ventas, y eso respalda la idea de que la empresa está creciendo.","en":"The financial report shows an increase in sales, and that supports the claim that the company is growing."},{"es":"Aunque no hay pruebas definitivas, eso respalda la idea de que el sospechoso estaba en la escena del crimen.","en":"Although there is no definitive proof, that supports the claim that the suspect was at the crime scene."}]},{"spanish_text":"Eso entra en conflicto con","english_text":"That conflicts with","section_name":"Discussion and Debate","part_of_speech":"verb","definition_en":"To be in disagreement or incompatibility with something.","main_translations_es":["Eso está en conflicto con","Eso contradice a","Eso choca con"],"collocations":["conflicts with","is at odds with","clashes with","contradicts"],"synonyms_en":["contradicts","is at odds with","clashes with"],"example_sentence":"Your budget proposal conflicts with our current savings policies.","example_es":"Tu propuesta de presupuesto entra en conflicto con nuestras políticas de ahorro actuales.","example_en":"Your budget proposal conflicts with our current savings policies.","mnemonic_en":"Picture a conflict as a door that enters the room, clashing with everything inside.","cloze_distractors_en":[],"examples":[{"es":"Tu propuesta de presupuesto entra en conflicto con nuestras políticas de ahorro actuales.","en":"Your budget proposal conflicts with our current savings policies."},{"es":"El nuevo horario de trabajo entra en conflicto con mis responsabilidades familiares.","en":"The new work schedule conflicts with my family responsibilities."},{"es":"Esta decisión estratégica entra en conflicto con los valores fundamentales de nuestra empresa.","en":"This strategic decision conflicts with the core values of our company."}]},{"spanish_text":"Parece contradictorio","english_text":"That appears contradictory","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that something seems to be in conflict or inconsistent.","main_translations_es":["Resulta contradictorio","Se muestra contradictorio","Parece contradictorio"],"collocations":["That appears contradictory to the earlier statement","That appears contradictory at first glance","That appears contradictory, but further analysis clarifies","That appears contradictory in context"],"synonyms_en":["seems inconsistent","looks conflicting","appears paradoxical"],"example_sentence":"That appears contradictory for the company to promote environmental sustainability while using single-use plastic packaging for all its products.","example_es":"Parece contradictorio que la empresa promueva la sostenibilidad ambiental mientras utiliza envases de plástico de un solo uso en todos sus productos.","example_en":"That appears contradictory for the company to promote environmental sustainability while using single-use plastic packaging for all its products.","mnemonic_en":"Visualize a billboard that appears, flashing the word ''contradictorio'' in bright colors.","cloze_distractors_en":["That remains harmonious","It seems entirely logical","This feels quite consistent","One finds perfectly aligned"],"examples":[{"es":"Parece contradictorio que la empresa promueva la sostenibilidad ambiental mientras utiliza envases de plástico de un solo uso en todos sus productos.","en":"That appears contradictory for the company to promote environmental sustainability while using single-use plastic packaging for all its products."},{"es":"Parece contradictorio que el gimnasio ofrezca clases de bienestar integral y al mismo tiempo venda bebidas azucaradas y comida ultraprocesada.","en":"That appears contradictory for the gym to offer holistic wellness classes while simultaneously selling sugary drinks and ultra-processed food."},{"es":"Defiendes la importancia de la puntualidad, pero siempre llegas tarde a las reuniones; parece contradictorio.","en":"You advocate for the importance of punctuality but always arrive late to meetings; That appears contradictory."}]},{"spanish_text":"No estoy cerrado a esa idea","english_text":"I am open to that idea","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating willingness to consider or accept a suggestion.","main_translations_es":["Estoy abierto a esa idea","No me opongo a esa idea","No rechazo esa idea"],"collocations":["open to suggestions","open to new ideas","open to possibilities","open to feedback"],"synonyms_en":["I''m receptive","I''m willing","I consider it"],"example_sentence":"I am open to that idea, although I prefer to explore other options first.","example_es":"No estoy cerrado a esa idea, aunque prefiero explorar otras opciones primero.","example_en":"I am open to that idea, although I prefer to explore other options first.","mnemonic_en":"Picture a door swinging open as you say I am open to that idea, opposite of cerrado","cloze_distractors_en":["I refuse that notion","I ignore your logic","I reject every choice","I avoid that matter"],"examples":[{"es":"No estoy cerrado a esa idea, aunque prefiero explorar otras opciones primero.","en":"I am open to that idea, although I prefer to explore other options first."},{"es":"Si quieres cambiar el horario de la reunión, no estoy cerrado a esa idea.","en":"If you want to change the meeting schedule, I am open to that idea."},{"es":"Aunque inicialmente dudaba sobre el teletrabajo, no estoy cerrado a esa idea si mantenemos las reuniones semanales.","en":"Although I was initially skeptical about remote work, I am open to that idea if we keep the weekly meetings."}]},{"spanish_text":"Estoy dispuesto a reconsiderarlo","english_text":"I am willing to reconsider","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating readiness to think about something again.","main_translations_es":["Estoy dispuesto a reconsiderar","Podría reconsiderarlo","Estoy abierto a reconsiderar"],"collocations":["I am willing to reconsider the proposal","I am willing to reconsider my decision","I am willing to reconsider the terms","I am willing to reconsider the offer"],"synonyms_en":["I am open to reconsidering","I am prepared to rethink","I am ready to review"],"example_sentence":"I am willing to reconsider it if you present me with new arguments.","example_es":"Estoy dispuesto a reconsiderarlo si me presentas nuevos argumentos.","example_en":"I am willing to reconsider it if you present me with new arguments.","mnemonic_en":"I''m willing to reconsider, like a Spanish dispuesto chef tasting a new recipe.","cloze_distractors_en":["I am strictly forbidden","I am completely oblivious","I am perpetually exhausted","I am fundamentally incapable"],"examples":[{"es":"Estoy dispuesto a reconsiderarlo si me presentas nuevos argumentos.","en":"I am willing to reconsider it if you present me with new arguments."},{"es":"Aunque mi postura inicial era firme, estoy dispuesto a reconsiderarlo tras escuchar tu propuesta.","en":"Although my initial stance was firm, I am willing to reconsider it after hearing your proposal."},{"es":"Si el presupuesto cambia, estoy dispuesto a reconsiderarlo para que el proyecto sea viable.","en":"If the budget changes, I am willing to reconsider it so that the project is viable."}]},{"spanish_text":"Eso es discutible","english_text":"That is open to debate","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that something is arguable or not settled.","main_translations_es":["Eso es debatible","Eso es cuestionable","Eso es discutible"],"collocations":["open to debate","subject to debate","open for debate"],"synonyms_en":["debatable","questionable","up for discussion"],"example_sentence":"The effectiveness of this new economic policy is open to debate, as many experts doubt its long-term results.","example_es":"La eficacia de esta nueva política económica es discutible, ya que muchos expertos dudan de sus resultados a largo plazo.","example_en":"The effectiveness of this new economic policy is open to debate, as many experts doubt its long-term results.","mnemonic_en":"Picture a door labeled Debate swinging open, reminding you that discutible means open to debate.","cloze_distractors_en":[],"examples":[{"es":"La eficacia de esta nueva política económica es discutible, ya que muchos expertos dudan de sus resultados a largo plazo.","en":"The effectiveness of this new economic policy is open to debate, as many experts doubt its long-term results."},{"es":"Si el candidato realmente tiene la experiencia necesaria para el puesto es discutible, considerando su historial laboral reciente.","en":"Whether the candidate truly has the necessary experience for the position is open to debate, considering his recent work history."},{"es":"La idea de que la tecnología siempre mejora la calidad de vida es discutible, especialmente cuando observamos el impacto en la salud mental.","en":"The idea that technology always improves quality of life is open to debate, especially when we observe the impact on mental health."}]},{"spanish_text":"No me convence del todo","english_text":"I am not fully persuaded","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that one is not completely convinced.","main_translations_es":["No me convence del todo","No me convence completamente","No me convence por completo"],"collocations":["I am not fully persuaded by his argument","I am not fully persuaded yet","I am not fully persuaded about the decision"],"synonyms_en":["unconvinced","not convinced","skeptical"],"example_sentence":"I am not fully persuaded by the theory presented at the conference.","example_es":"No me convence del todo la teoría que presentaron en la conferencia.","example_en":"I am not fully persuaded by the theory presented at the conference.","mnemonic_en":"Picture a con trying to convince me, but only half the story reaches me, so I''m not fully persuaded.","cloze_distractors_en":["I am perpetually hungry","I am currently invisible","I am biologically extinct","I am mathematically circular"],"examples":[{"es":"No me convence del todo la teoría que presentaron en la conferencia.","en":"I am not fully persuaded by the theory presented at the conference."},{"es":"Aunque el plan de negocios parece sólido, no me convence del todo la estrategia de marketing propuesta.","en":"Although the business plan seems solid, I am not fully persuaded by the proposed marketing strategy."},{"es":"He escuchado sus argumentos sobre el cambio de horario, pero no me convence del todo su justificación.","en":"I have heard your arguments regarding the schedule change, but I am not fully persuaded by your justification."}]},{"spanish_text":"Tu argumento es sólido","english_text":"Your argument is sound","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that someone''s reasoning or evidence is solid and reliable.","main_translations_es":["Tu razonamiento es sólido","Tu argumento es firme","Tu argumento está bien fundamentado"],"collocations":["Your argument is sound, so we can move forward","If your argument is sound, the conclusion follows","A sound argument is persuasive","Your argument is sound and convincing"],"synonyms_en":["Your argument is solid","Your reasoning is valid","Your case is convincing"],"example_sentence":"Based on the logical evidence you presented, your argument is sound and difficult to refute.","example_es":"Basado en la evidencia lógica que presentaste, tu argumento es sólido y difícil de refutar.","example_en":"Based on the logical evidence you presented, your argument is sound and difficult to refute.","mnemonic_en":"A solid argument sounds like a sturdy drum echoing certainty","cloze_distractors_en":["Your opinion is hollow","Your evidence is absent","Your logic is circular","Your theory is baseless"],"examples":[{"es":"Basado en la evidencia lógica que presentaste, tu argumento es sólido y difícil de refutar.","en":"Based on the logical evidence you presented, your argument is sound and difficult to refute."},{"es":"Aunque no estoy de acuerdo con tu conclusión, admito que tu argumento es sólido.","en":"Although I disagree with your conclusion, I admit that your argument is sound."},{"es":"Presentaste datos muy precisos y tu argumento es sólido frente a las críticas.","en":"You presented very precise data and your argument is sound in the face of criticism."}]},{"spanish_text":"Eso carece de fundamento","english_text":"That lacks foundation","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means something is unsupported or has no basis.","main_translations_es":["No tiene fundamento","Carece de base","No está fundamentado"],"collocations":["lacks a solid foundation","lacks any foundation","lacks foundational support"],"synonyms_en":["baseless","groundless","unfounded"],"example_sentence":"The accusation that he stole the bank is unfounded; that lacks foundation.","example_es":"La acusación de que él robó el banco es infundada; eso carece de fundamento.","example_en":"The accusation that he stole the bank is unfounded; that lacks foundation.","mnemonic_en":"Picture a shaky house: that lacks foundation, just like a broken Spanish fundamento.","cloze_distractors_en":["That sounds delicious","It remains highly probable","Everything seems quite logical","We should celebrate that"],"examples":[{"es":"La acusación de que él robó el banco es infundada; eso carece de fundamento.","en":"The accusation that he stole the bank is unfounded; that lacks foundation."},{"es":"Tu teoría sobre el origen de los dinosaurios es pura especulación; eso carece de fundamento.","en":"Your theory about the origin of dinosaurs is pure speculation; that lacks foundation."},{"es":"Afirmar que la empresa va a quebrar mañana es alarmista; eso carece de fundamento.","en":"Claiming that the company will go bankrupt tomorrow is alarmist; that lacks foundation."}]},{"spanish_text":"No es una conclusión inevitable","english_text":"That is not an inevitable conclusion","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement asserting that a particular outcome is not unavoidable.","main_translations_es":["No es una conclusión inevitable","No constituye una conclusión inevitable","No resulta una conclusión inevitable"],"collocations":["However, that is not an inevitable conclusion.","Thus, that is not an inevitable conclusion.","In any case, that is not an inevitable conclusion."],"synonyms_en":["It''s not a foregone conclusion","It''s not unavoidable","It''s not predetermined"],"example_sentence":"That is not an inevitable conclusion, but we should keep investigating.","example_es":"No es una conclusión inevitable, pero debemos seguir investigando.","example_en":"That is not an inevitable conclusion, but we should keep investigating.","mnemonic_en":"Imagine a nose shaking its head, saying that conclusion is not inevitable.","cloze_distractors_en":["That is a completely verified fact","It is a significantly improved strategy","Those are the most predictable results"],"examples":[{"es":"No es una conclusión inevitable, pero debemos seguir investigando.","en":"That is not an inevitable conclusion, but we should keep investigating."},{"es":"Aunque los datos parecen claros, no es una conclusión inevitable para el equipo de expertos.","en":"Although the data seems clear, that is not an inevitable conclusion for the team of experts."},{"es":"Que el mercado esté saturado no significa que el fracaso sea seguro; no es una conclusión inevitable.","en":"Just because the market is saturated does not mean failure is certain; that is not an inevitable conclusion."}]},{"spanish_text":"Puede haber una explicación alternativa","english_text":"There may be an alternative explanation","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It suggests that an alternative explanation could exist.","main_translations_es":["Podría existir una explicación alternativa","Existe la posibilidad de una explicación alternativa","Hay una posible explicación alternativa"],"collocations":["Consider that there may be an alternative explanation","It''s possible that there may be an alternative explanation","We should keep in mind there may be an alternative explanation"],"synonyms_en":["An alternative explanation might exist","Possibly another explanation","There could be another explanation"],"example_sentence":"There may be an alternative explanation for the sudden drop in sales.","example_es":"Puede haber una explicación alternativa para el repentino descenso en las ventas.","example_en":"There may be an alternative explanation for the sudden drop in sales.","mnemonic_en":"Picture a native altering the story while giving an explanation.","cloze_distractors_en":["They are definitely the culprit","We ignore the obvious evidence","Everything is completely settled","Nobody asked for the report"],"examples":[{"es":"Puede haber una explicación alternativa para el repentino descenso en las ventas.","en":"There may be an alternative explanation for the sudden drop in sales."},{"es":"Aunque los datos parecen claros, puede haber una explicación alternativa que no hemos considerado.","en":"Although the data seems clear, there may be an alternative explanation that we haven''t considered."},{"es":"No saques conclusiones precipitadas; puede haber una explicación alternativa sobre por qué no llegó el correo.","en":"Don''t jump to conclusions; there may be an alternative explanation as to why the email didn''t arrive."}]},{"spanish_text":"Lo dejaría en que","english_text":"I would put it this way","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to introduce a particular way of stating something.","main_translations_es":["Lo expresaría así","Lo diría de esta manera","Lo plantearía así"],"collocations":["I would put it this way: ...","Let me put it this way","I would put it this way, if you will"],"synonyms_en":["I would phrase it like this","That''s how I''d put it","I would say it like this"],"example_sentence":"I would put it this way: the project needs more time to be successful.","example_es":"Lo dejaría en que el proyecto necesita más tiempo para ser exitoso.","example_en":"I would put it this way: the project needs more time to be successful.","mnemonic_en":"Picture a low jar where you put the idea, like saying ''I would put it this way''.","cloze_distractors_en":["I am eating that meal","It was never finished","They went home early","You are being silent"],"examples":[{"es":"Lo dejaría en que el proyecto necesita más tiempo para ser exitoso.","en":"I would put it this way: the project needs more time to be successful."},{"es":"Sobre la decisión final, lo dejaría en que debemos esperar a los resultados.","en":"Regarding the final decision, I would put it this way: we must wait for the results."},{"es":"Si me preguntas por el problema, lo dejaría en que hubo una falta de comunicación.","en":"If you ask me about the problem, I would put it this way: there was a lack of communication."}]},{"spanish_text":"Estoy de acuerdo en lo esencial","english_text":"I agree in principle","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"To express agreement with the general idea or underlying principle, without committing to all specifics.","main_translations_es":["Coincido en lo esencial","Estoy de acuerdo en lo fundamental","Comparto la idea esencial"],"collocations":["I agree in principle, but...","We can move forward; I agree in principle","I agree in principle with your suggestion"],"synonyms_en":["agree in theory","agree fundamentally","agree on the basics"],"example_sentence":"I agree in principle, although some details may vary.","example_es":"Estoy de acuerdo en lo esencial, aunque algunos detalles pueden variar.","example_en":"I agree in principle, although some details may vary.","mnemonic_en":"Picture a principal (principle) shaking hands, saying I agree—like saying acuerdo in Spanish.","cloze_distractors_en":["I refute the logic","I concede the defeat","I ignore the premise","I doubt the outcome"],"examples":[{"es":"Estoy de acuerdo en lo esencial, aunque algunos detalles pueden variar.","en":"I agree in principle, although some details may vary."},{"es":"Aunque el plan tiene algunos fallos, estoy de acuerdo en lo esencial sobre la estrategia general.","en":"While the plan has some flaws, I agree in principle with the overall strategy."},{"es":"La propuesta es interesante y estoy de acuerdo en lo esencial, pero necesitamos revisar el presupuesto.","en":"The proposal is interesting and I agree in principle, but we need to review the budget."}]},{"spanish_text":"No estoy en desacuerdo con eso","english_text":"I do not disagree with that","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that the speaker does not oppose or contradict that.","main_translations_es":["Estoy de acuerdo con eso","Comparto esa opinión","No difiero con eso"],"collocations":["I do not disagree with that point","I do not disagree with that view","I do not disagree with that statement","I do not disagree with that assessment"],"synonyms_en":["I agree","I concur","I''m in agreement"],"example_sentence":"If the client insists on changing the design, I do not disagree with that as long as it does not affect the delivery date.","example_es":"Si el cliente insiste en cambiar el diseño, no estoy en desacuerdo con eso siempre que no afecte la fecha de entrega.","example_en":"If the client insists on changing the design, I do not disagree with that as long as it does not affect the delivery date.","mnemonic_en":"Imagine I tie a knot that refuses to split, so I do not disagree.","cloze_distractors_en":["I am never hungry today","It was raining quite hard","They will finish very soon","We have seen better days"],"examples":[{"es":"Si el cliente insiste en cambiar el diseño, no estoy en desacuerdo con eso siempre que no afecte la fecha de entrega.","en":"If the client insists on changing the design, I do not disagree with that as long as it does not affect the delivery date."},{"es":"Aunque el plan tiene riesgos, no estoy en desacuerdo con eso si nos ayuda a reducir costos.","en":"Although the plan has risks, I do not disagree with that if it helps us reduce costs."},{"es":"Siendo honesto, no estoy en desacuerdo con eso, ya que los datos respaldan tu conclusión.","en":"To be honest, I do not disagree with that, since the data supports your conclusion."}]},{"spanish_text":"Eso es justamente el problema","english_text":"That is precisely the problem","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that something exactly constitutes the issue.","main_translations_es":["Ese es precisamente el problema","Eso es exactamente el problema","Ese es el problema justo"],"collocations":["That''s precisely the problem","And that''s precisely the problem","Which is precisely the problem","That''s precisely the problem we face"],"synonyms_en":["That''s exactly the issue","That''s the exact problem","That''s the crux"],"example_sentence":"The team cannot agree on the budget, and that is precisely the problem delaying the project launch.","example_es":"El equipo no logra ponerse de acuerdo sobre el presupuesto, y eso es justamente el problema que está retrasando el lanzamiento del proyecto.","example_en":"The team cannot agree on the budget, and that is precisely the problem delaying the project launch.","mnemonic_en":"Imagine a precise judge saying that is precisely the problem while holding a just scale","cloze_distractors_en":["This is rarely the solution","They are mostly the question","Which is possibly the answer"],"examples":[{"es":"El equipo no logra ponerse de acuerdo sobre el presupuesto, y eso es justamente el problema que está retrasando el lanzamiento del proyecto.","en":"The team cannot agree on the budget, and that is precisely the problem delaying the project launch."},{"es":"El software se bloquea cada vez que intentamos exportar el archivo, y eso es justamente el problema que nos impide terminar el informe a tiempo.","en":"The software crashes every time we try to export the file, and that is precisely the problem preventing us from finishing the report on time."},{"es":"La falta de comunicación causa malentendidos; eso es justamente el problema en nuestra oficina.","en":"The lack of communication causes misunderstandings; that is precisely the problem in our office."}]},{"spanish_text":"Eso va al corazón del asunto","english_text":"That goes to the heart of the matter","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that something addresses the most important or central point of an issue.","main_translations_es":["Eso llega al meollo del asunto","Eso toca el punto clave","Eso va al fondo del asunto"],"collocations":["gets to the heart of the matter","goes straight to the heart of the matter","hits the heart of the matter","addresses the heart of the matter"],"synonyms_en":["gets to the crux","gets to the point","hits the nail on the head"],"example_sentence":"Your analysis of economic inequality is brilliant, because that goes to the heart of the matter.","example_es":"Tu análisis sobre la desigualdad económica es brillante, porque eso va al corazón del asunto.","example_en":"Your analysis of economic inequality is brilliant, because that goes to the heart of the matter.","mnemonic_en":"Picture a core (corazón) heart that slides straight into the matter","cloze_distractors_en":["That walks around the edge of the table","That flies over the moon of the galaxy","That swims beneath the surface of the ocean","That dances across the floor of the room"],"examples":[{"es":"Tu análisis sobre la desigualdad económica es brillante, porque eso va al corazón del asunto.","en":"Your analysis of economic inequality is brilliant, because that goes to the heart of the matter."},{"es":"No perdamos tiempo con detalles técnicos; eso va al corazón del asunto de nuestra crisis actual.","en":"Let''s not waste time on technical details; that goes to the heart of the matter regarding our current crisis."},{"es":"Al señalar que nuestro presupuesto no cubre los salarios, tu comentario va al corazón del asunto.","en":"By pointing out that our budget does not cover the salaries, your comment that goes to the heart of the matter."}]},{"spanish_text":"Da que pensar","english_text":"That gives food for thought","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means something that provokes reflection or consideration.","main_translations_es":["Da que reflexionar","Invita a la reflexión","Hace pensar"],"collocations":["gives me food for thought","provides food for thought","offers food for thought"],"synonyms_en":["thought‑provoking","makes you think","gives pause"],"example_sentence":"The youth unemployment figure presented by the minister gives food for thought regarding the effectiveness of our current policies.","example_es":"La cifra de desempleo juvenil que presentó el ministro da que pensar sobre la eficacia de nuestras políticas actuales.","example_en":"The youth unemployment figure presented by the minister gives food for thought regarding the effectiveness of our current policies.","mnemonic_en":"Picture a queue of pens serving tasty ideas on a plate","cloze_distractors_en":[],"examples":[{"es":"La cifra de desempleo juvenil que presentó el ministro da que pensar sobre la eficacia de nuestras políticas actuales.","en":"The youth unemployment figure presented by the minister gives food for thought regarding the effectiveness of our current policies."},{"es":"El documental sobre el impacto de la inteligencia artificial en el mercado laboral realmente da que pensar.","en":"The documentary about the impact of artificial intelligence on the job market really gives food for thought."},{"es":"Su propuesta de reducir la jornada laboral a cuatro días a la semana da que pensar sobre nuestra productividad.","en":"His proposal to reduce the work week to four days gives food for thought regarding our productivity."}]}]'::jsonb) as x(
  spanish_text text, english_text text, section_name text, part_of_speech text, definition_en text,
  main_translations_es jsonb, collocations jsonb, synonyms_en jsonb, example_sentence text, example_es text, example_en text, mnemonic_en text, cloze_distractors_en jsonb, examples jsonb
)
where c.deck_id = dk.id
  and lower(c.spanish_text) = lower(x.spanish_text)
  and lower(c.english_text) = lower(x.english_text);

